-- Aarakocra (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Aarakocra sind eine Rasse intelligenter Vogelmenschen, die auf den Gipfeln der höchsten Berge leben und ihre Tage damit verbringen, friedlich und einsam auf den Thermikwinden zu gleiten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Im Luftkampf kämpft ein Aarakocra entweder mit Krallen oder mit den schweren befiederten Speeren, die er in seinen unteren Händen umklammert. Ein Aarakocra trägt typischerweise ein halbes Dutzend Speere in einzelnen Scheiden an seine Brust geschnallt. Die Speere, die zum Werfen oder Stechen verwendet werden können, verursachen 2W4 Schadenspunkte. Aufgrund der bemerkenswerten Fertigkeit des Aarakocra beim Speerwerfen in der Luft erleidet er keine Angriffsmali für Luftgeschossfeuer. Ein Aarakocra wird seinen letzten Speer immer zum Stechen aufheben, anstatt ihn zu werfen. Sein Lieblingsangriff ist es, mit einem Speer in jeder Hand auf ein Opfer herabzustürzen, dann kurz vor dem Erreichen des Ziels aus dem Sturzflug auszubrechen und mit einem markerschütternden Schrei zuzuschlagen. Dieser Angriff erhält einen +4 Bonus auf den Angriffswurf und verursacht doppelten Schaden, aber ein Aarakocra muss mindestens 61 m stürzen, um ihn ordnungsgemäß auszuführen.'),
  habitat_society = COALESCE(habitat_society, 'Aarakocra leben in kleinen Stämmen von etwa 11-30 (1W20+10) Mitgliedern. Jeder Stamm hat ein Jagdrevier von etwa 26.000 Quadratkilometern mit bunten Bannern und Wimpeln, die die Grenzen markieren.'),
  ecology         = COALESCE(ecology, 'Aarakocra haben wenig mit anderen Arten zu schaffen, einschließlich benachbarter Aarakocra-Stämme, und verlassen ihr Heimatgebiet nur unter extremen Umständen. Sie begegnen Menschen selten, außer bei gelegentlichen Vorstößen in ländliche Gemeinden, um ein verirrtes Nutztier zu schnappen; dies ist keine absichtlich bösartige Handlung, da Aarakocra nicht zwischen Haus- und Wildtieren unterscheiden können. Ein Mensch, der in Aarakocra-Territorium eindringt, kann möglicherweise einen davon überzeugen, als Führer oder Späher im Austausch gegen einen glänzenden Edelstein oder eine Münze zu dienen.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = 'fef166a6-0bff-4830-99e5-b43edb6606c7' AND is_custom = FALSE;

-- Aboleth (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Geistesverbindung, Massenbeherrschung; Hingabe: falsche Sinneswahrnehmung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Aboleth greift mit seinen Tentakeln an und verursacht jeweils 1W6 Schadenspunkte. Wenn ein von einem Tentakel getroffenes Opfer einen Rettungswurf gegen Zauber verfehlt, verwandelt sich die Haut des Opfers in 1W4+1 Runden in eine klare, schleimige Membran. Geschieht dies, muss das Opfer die Membran mit kühlem Wasser feucht halten oder erleidet 1W12 Schadenspunkte pro Runde. Ein auf das Opfer gewirkter Krankheit heilen-Zauber, bevor sich die Membran vollständig gebildet hat, stoppt die Verwandlung. Andernfalls bewirkt schwere Wunden heilen, dass die Membran wieder zu normaler Haut wird.'),
  habitat_society = COALESCE(habitat_society, 'Eine Aboleth-Brut besteht aus einem Elternteil und einem bis drei Nachkommen. Obwohl die Nachkommen genauso groß und stark wie das Elternteil sind, ordnen sie sich dem Elternteil in allen Belangen unter und gehorchen ihm bedingungslos.'),
  ecology         = COALESCE(ecology, 'Der allesfressende Aboleth frisst jede organische Materie, gewöhnlich Algen und Mikroorganismen, aber er bevorzugt auch intelligente Beute, damit er gleichzeitig Nährstoffe und Informationen aufnehmen kann. Aboleth haben keine natürlichen Feinde, da selbst die mächtigsten Meereskreaturen ihnen aus dem Weg gehen. Aboleth-Schleim wird manchmal als Komponente für Tränke des Wasseratmens verwendet.'),
  no_appearing    = COALESCE(no_appearing, '1d4')
WHERE id = '505bceb1-21a8-46f1-a062-2d04c1d7d848' AND is_custom = FALSE;

-- Ankheg (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Ankheg ist ein grabendes Monster, das gewöhnlich in Wäldern oder erstklassigem Ackerland zu finden ist. Aufgrund seiner Vorliebe für frisches Fleisch stellt der Ankheg eine Bedrohung für jede Kreatur dar, die das Unglück hat, ihm zu begegnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die bevorzugte Angriffsmethode des Ankhegs ist es, 1,5 bis 3 m unter der Erdoberfläche zu liegen, bis seine Antennen die Annäherung eines Opfers wahrnehmen. Er gräbt sich dann unter dem Opfer nach oben und versucht, es mit seinen Mandibeln zu packen, wobei er es zerquetscht und zermahlt und dabei 3W6 Schadenspunkte pro Runde verursacht, während er ätzende Verdauungsenzyme absondert, die zusätzliche 1W4 Schadenspunkte pro Runde verursachen, bis das Opfer aufgelöst ist. Der Ankheg kann alle sechs Stunden einen Strahl ätzender Enzyme auf eine Distanz von 9,1 m spritzen. Da er jedoch sechs Stunden lang keine Nahrung verdauen kann, nachdem er Enzyme gespritzt hat, nutzt er diese Angriffstechnik nur in verzweifelten Situationen. Ein Opfer, das von dem Strahl ätzender Enzyme getroffen wird, erleidet 8W4 Schadenspunkte (halber Schaden, wenn das Opfer einen erfolgreichen Rettungswurf gegen Gift schafft).'),
  habitat_society = COALESCE(habitat_society, 'Der Ankheg nutzt seine Mandibeln, um kontinuierlich gewundene Tunnel von 9,1-12,2 m Tiefe in die reiche Erde von Wäldern oder Ackerland zu graben. Das ausgehöhlte Ende eines Tunnels dient als temporärer Bau zum Schlafen, Fressen oder für den Winterschlaf. Wenn ein Ankheg die Nahrungsversorgung in einem bestimmten Wald oder Feld erschöpft hat, zieht er zu einem anderen weiter.'),
  ecology         = COALESCE(ecology, 'Obwohl ein hungriger Ankheg für einen Bauern tödlich sein kann, kann er für das Ackerland sehr vorteilhaft sein. Sein Tunnelsystem durchzieht den Boden mit Gängen für Luft und Wasser, während die Abfallprodukte des Ankhegs reiche Nährstoffe hinzufügen. Der Ankheg frisst verrottende organische Materie in der Erde, bevorzugt aber frisches Fleisch. Alle bis auf die wildesten Raubtiere meiden Ankhegs. Getrocknete und gehärtete Ankhegpanzer können zu Rüstung mit einer RK von 2 verarbeitet werden, und seine Verdauungsenzyme können als gewöhnliche Säure verwendet werden.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '9cbaef5e-b8c7-4bec-a09b-2b487589b40d' AND is_custom = FALSE;

-- Ant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenameisen bilden kooperative Kolonien in tropischen Regionen. Normalerweise sind sie friedlich, können aber erbitterte Kämpfer werden, wenn ihr Nest bedroht wird.'),
  combat_tactics  = COALESCE(combat_tactics, 'Sowohl Arbeiter- als auch Kriegerameisen werden kämpfen. Wenn es einer Kriegerameise gelingt zu beißen, wird sie auch versuchen zu stechen und dabei 3W4 Schadenspunkte verursachen. Ein erfolgreicher Rettungswurf gegen Gift reduziert den Stichschaden auf 1W4 TP. Die Königin hat 10 Trefferwürfel, bewegt sich aber nicht und greift nicht an. Wird sie getötet, werden die verbleibenden Ameisen für sechs Runden verwirrt (als wären sie vom Zauber betroffen) und stürmen dann aus dem Nest.'),
  habitat_society = COALESCE(habitat_society, 'Eine Riesenameisenkolonie baut ihr Nest unterirdisch in einer Reihe von Kammern und Gängen. Haufen aus Erde und Zweigen markieren die Eingänge. Die Gänge können eine Tiefe von 4,9 m erreichen, und das gesamte Nest kann sich über ein Gebiet von mehreren tausend Quadratmetern erstrecken.'),
  ecology         = COALESCE(ecology, 'Riesenameisen fressen bevorzugt Samen und Gräser, aber sie werden auch Fleisch fressen, wenn sich die Gelegenheit bietet. Weder Riesenameisen noch ihre Eier haben einen kommerziellen Wert, obwohl einige Feinschmecker ihren Honig genießen. Im Notfall sind Riesenameisen eine gute Proteinquelle.'),
  no_appearing    = COALESCE(no_appearing, '1-100')
WHERE id = '85628220-33ca-4a69-9c52-3616520035c5' AND is_custom = FALSE;

-- Ant Lion, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Ameisenlöwe ist ein riesiges, bösartiges Insekt, das auf dem Grund tiefer Gruben lauert und sich von Kreaturen ernährt, die das Pech haben, hineinzufallen. Ameisenlöwen leben in Ödland, Wüstenrändern und anderen Gebieten mit lockerem Boden und Sand.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Ameisenlöwe pirscht oder verfolgt selten Beute. Stattdessen gräbt er tiefe, sich verjüngende Gruben von etwa 18,3 m Durchmesser, vergräbt sich am Boden unter einer Abdeckung aus Sand, Kies und Steinen und wartet dann geduldig auf fallende Opfer. Etwa 50% der Zeit sieht der Eingang zur Grube wie ein mit Sand ausgekleideter Trichter aus. Den Rest der Zeit sieht er wie der Eingang zu einer Höhle oder einem Bau aus. Eine Kreatur, die sich bis auf 0,9 m an den Rand des Eingangs nähert, hat eine 20%ige Chance, im lockeren Boden und Sand auszurutschen und in die Grube zu rutschen. Eine Kreatur, die die Grube betritt, hat eine 50%ige Chance pro Runde, zum Boden zu rutschen. Ein Charakter, der Vorsichtsmaßnahmen beim Nähern oder Betreten der Grube trifft, wie sich mit einem Seil an einem Baum zu sichern, wird nicht in die Grube rutschen.'),
  habitat_society = COALESCE(habitat_society, 'Ameisenlöwen paaren sich einmal pro Jahr im Hochsommer. Das männliche Exemplar wird vom Weibchen durch aromatische Sekrete angezogen, die sie freisetzt, wenn sie ihren Paarungszyklus beginnt. Nur Ameisenlöwen können diese Sekrete riechen. Sobald ein Männchen das Weibchens Bau betritt, hört sie auf zu sezernieren, und das Paar beginnt, mit ihren Mandibeln gegeneinander zu klicken. Dieses rituelle Klicken dauert drei volle Tage, während der das Paar weder schläft noch frisst. Das Klicken hat eine tranceartige Wirkung auf die Ameisenlöwen; selbst wenn sie angegriffen werden, dauert es 1W4 Runden, bis die Ameisenlöwen ihre Trance brechen und auf einen Eindringling reagieren. Am Ende des Klick-Rituals befruchtet das Männchen das Weibchen und verlässt dann ihr Nest. Innerhalb einer Woche legt das Weibchen zwischen einem und vier Eiern und vergräbt sie in einem Loch im Boden. Die jungen Ameisenlöwen schlüpfen nach etwa sechs Monaten und graben sich sofort weg, um eigene Baue zu errichten. Ein junger Ameisenlöwe hat 4 Trefferwürfel, besitzt aber ansonsten alle Fähigkeiten eines Erwachsenen. Er erreicht die volle Reife in etwa einem Jahr.'),
  ecology         = COALESCE(ecology, 'Ameisenlöwen in der Nähe zivilisierter Regionen gelten als gefährliche Raubtiere. Belohnungen sind oft für den Beweis ihrer Vernichtung verfügbar. Ameisenlöwen fressen jede Kreatur, die in ihre Gruben fällt, obwohl sie Rieseninsekten bevorzugen und normalerweise eine oder mehrere Riesenameisen pro Tag verzehren. Ameisenlöwen haben keinen kommerziellen Wert, obwohl Bauern einiger primitiver Kulturen ihre Mandibeln als Pflüge verwenden.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'ee1a9aff-350e-4edc-9164-ce8f76d2ce28' AND is_custom = FALSE;

-- Ape, Carnivorous (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der fleischfressende Affe ist ein größerer, stärkerer und aggressiverer Verwandter des Gorillas. Er lebt in tropischen Dschungeln und Ebenen und hält sich manchmal in hohen Bäumen auf.'),
  combat_tactics  = COALESCE(combat_tactics, 'Fleischfressende Affen besitzen eine angemessene Intelligenz und sind sehr gerissen. Aufgrund ihrer scharfen Sinne erhalten sie einen Bonus von +2 auf ihren Überraschungswurf. Typischerweise verstecken sie sich in Bäumen und verfolgen ihre Beute meilenweit, um dann herabzuspringen und anzugreifen, wenn ihr Opfer anhält, um aus einem Bach zu trinken oder anderweitig unaufmerksam ist. In Ebenen oder anderen baumfreien Gebieten verstecken sie sich in hohem Gras und dichtem Gebüsch und springen ihr Opfer von hinten an. Fleischfressende Affen greifen an, indem sie sich auf ihre Hinterbeine aufrichten, mit ihren massigen Armen schlagen und mit ihren kräftigen Kiefern zubeißen. Wenn ein Affe seinen Gegner in derselben Runde mit beiden Händen trifft, fügt er zusätzlich 1W8 Punkte Zerreißschaden zu. Wenn ein fleischfressender Affe einen Gegner besiegt oder einen Eindringling einschüchtern will, richtet er sich auf seine Hinterbeine auf, schlägt mit den Händen gegen seine Brust und brüllt donnernd. Das Gebrüll eines Affen kann bekanntlich Feiglinge in Panik versetzen.'),
  habitat_society = COALESCE(habitat_society, 'Fleischfressende Affen leben in Familien von zwei bis 20 Mitgliedern mit etwa doppelt so vielen Weibchen wie Männchen. Ein trächtiges Weibchen gebiert nach etwa neun Monaten. Ein Jungtier verlässt seine Mutter niemals in den ersten drei Lebensjahren, klammert sich fest an ihr langes Haar und reitet auf ihrem Rücken, wohin auch immer die Familie geht. Das größte Männchen dient als Anführer, bestimmt den Tagesablauf und verteidigt die Familie vor Gefahren. Der Anführer wird gelegentlich von jüngeren Männchen herausgefordert, wobei die Herausforderung durch einen brutalen, aber nicht tödlichen Ringkampf entschieden wird. Der Verlierer verlässt die Familie in Schande; ein geschlagener Herausforderer schließt sich schließlich einer anderen Familie an, aber ein geschlagener Anführer bleibt allein und verbringt den Rest seines Lebens in Verbitterung.'),
  ecology         = COALESCE(ecology, 'Obwohl von Natur aus aggressiv, töten fleischfressende Affen normalerweise nur für Nahrung oder zur Verteidigung ihrer Familien. Sie mögen Früchte und Nüsse, aber der größte Teil ihrer Nahrung besteht aus Nagetieren, kleinen Reptilien, Eiern und Fischen sowie gelegentlichen Rieseninsekten oder Aas. Wild ergänzt den Familienspielplan: Antilopen, Büffel, Hirsche und Löwen und andere Raubtiere. Es ist nicht ungewöhnlich, dass ein Löwenrudel eine Familie fleischfressender Affen gewaltsam um Jagdrechte in strittigen Gebieten herausfordert; die Affen werden meist umziehen, anstatt das Leben ihrer Familien zu riskieren.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '52f38e71-4152-471a-b6f6-1eaf26b61687' AND is_custom = FALSE;

-- Arcane (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Arkane sind eine Rasse von Händlern, die überall dort zu finden sind, wo es potenziellen Handel mit magischen Gegenständen gibt. Sie erscheinen als große, hagere, blaue Riesen mit länglichen Gesichtern und dünnen Fingern; jeder Finger hat ein Gelenk mehr, als bei den meisten humanoiden Lebewesen üblich ist. Die Arkane kleiden sich in Roben, obwohl es Individuen gibt, die in schwererer Rüstung anzutreffen sind, einer Kombination aus Kettengliedern mit Plattenteilen (RK 3).'),
  combat_tactics  = COALESCE(combat_tactics, 'Für Kreaturen ihrer Größe sind die Arkane bemerkenswert schwach und nicht kampflustig. Sie können sich bei Bedarf verteidigen, ziehen es aber vor, sich aus gefährlichen Situationen herauszureden und/oder freizukaufen. Wenn sie ein potenziell gefährliches Gebiet betreten (wie die meisten menschlichen Städte), heuert der Arkane eine Gruppe von Abenteurern als sein Gefolge an.'),
  habitat_society = COALESCE(habitat_society, 'Nichts ist über die Herkunft der Arkane bekannt; sie kommen und gehen, wie es ihnen beliebt, und sind in den bekannten Welten zu finden. Wenn sie reisen, tun sie dies auf den Schiffen und Fahrzeugen anderer Rassen. Solche Schiffe mit Arkane an Bord zu finden ist selten, und es wird vermutet, dass die Arkane eine andere Art haben, über große Entfernungen zu reisen.'),
  ecology         = COALESCE(ecology, 'Die Arkane als Rasse müssen essen und atmen wie alle normalen Kreaturen: sie können nicht die Leere atmen oder für längere Zeit ohne Nahrung überleben. Sie werden oft Geschäfte mit beiden Seiten in einem Konflikt machen und sind sich völlig bewusst, dass die Menge an Feuerkraft, die sie liefern, alle ihre potenziellen Kunden in einer Sphäre vernichten wird. Ihr Markt ist groß genug, dass solche kleinen Verluste wie ein ganzer Planet und eine Rasse keine ernsthafte Auswirkung auf ihren Handel haben.'),
  no_appearing    = COALESCE(no_appearing, '1 (1-6)')
WHERE id = 'ccdd5d45-e0c5-4b43-8159-c2a496a2ba0f' AND is_custom = FALSE;

-- Aurumvorax (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Obwohl der Aurumvorax oder Goldschlucker nur die Größe eines großen Dachses hat, ist er eine unglaublich gefährliche Kreatur. Das Tier ist mit grobem goldenen Haar bedeckt und hat kleine silberne Augen mit goldenen Pupillen. Es hat acht kräftige Beine, die in 7,5 cm langen kupfernen Klauen enden. Die Schultern des Aurumvorax sind massiv bemuskelt, während sein schwerer Kiefer voller kupferfarbener Zähne ist.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Aurumvorax stürmt auf jede Kreatur los, die sein Territorium betritt, und verursacht einen Malus von -3 auf die Überraschungswürfe der Gegner, wenn er aus seinem Bau angreift. Ein Weibchen der Art erhält einen Bonus von +2 auf Angriffswürfe, wenn es seine Jungen bewacht.'),
  habitat_society = COALESCE(habitat_society, 'Der Aurumvorax macht sein einsames Zuhause in lichten Wäldern, Hügeln und an der Baumgrenze an Berghängen. Ein Aurumvorax wählt einen geeigneten Platz und nutzt dann seine kraftvoll bekrallten Beine, um einen Bau zu schaffen, manchmal in festen Fels hinein.'),
  ecology         = COALESCE(ecology, 'Um zu überleben, ergänzt der Aurumvorax seine fleischfressende Ernährung mit Mengen von Gold. Die Fähigkeit, Gold und andere Erze zu verdauen und zu verwerten, ermöglicht es der Kreatur, das dichte Fell, die Haut und die Knochen zu entwickeln, die sie so gut schützen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '6003b255-d15a-467b-bee1-80e3d2ab940a' AND is_custom = FALSE;

-- Baatezu, Lesser, Abishai (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Abishai sind auf der ersten und zweiten Ebene von Baator weit verbreitet. Sie sehen aus wie gotische Wasserspeier, dünn und reptilienartig, mit langen, greiffähigen Schwänzen und großen Flügeln. Die drei Varietäten der Abishai haben unterschiedliche Hautfarben - in aufsteigender Rangordnung schwarz, grün und rot. Alle haben einen essigartigen Geruch und kratzende Stimmen. Die Luft scheint in ihrer Gegenwart spürbar wärmer zu werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Im Kampf schlägt der Abishai mit zwei Klauen zu (jeweils 1W4 Schadenspunkte) und seinem beweglichen Schwanz (1W4+1 Schadenspunkte und Gift; zu beachten ist, dass das Gift tödlich ist, es sei denn, ein erfolgreicher Rettungswurf gegen Gift wird geschafft).'),
  habitat_society = COALESCE(habitat_society, 'Abishai sind gefräßig und böse. Sie ergötzen sich daran, jene wenigen Baatezu zu quälen, die niedriger in der Rangordnung stehen als sie selbst. Abishai versuchen Sterbliche, die kühn genug sind, nach Baator zu reisen, indem sie ihre Fähigkeiten Gestalt wechseln und Person bezaubern verwenden, um sich als mächtigere Baatezu auszugeben.'),
  ecology         = COALESCE(ecology, 'Die Abishai bilden große, böse Armeen, die gegen die Tanar''ri und Eindringlinge in Baator kämpfen. In manchen Fällen kann sich ein roter Abishai als würdig genug erweisen, eine Streitmacht von Lemuren zu befehligen. Wenn erfolgreich, kann der rote Abishai zu einer höheren Form der Baatezu befördert werden.'),
  no_appearing    = COALESCE(no_appearing, '2-20')
WHERE id = 'f006beed-78ff-4ac7-a3c8-358bfa73fa72' AND is_custom = FALSE;

-- Baatezu, General Information (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Baatezu sind eine starke, böswillige, wohlorganisierte Rasse von Unholden. In ihrem starren Kastensystem leitet sich Autorität nicht nur aus Macht ab, sondern auch aus der Stellung. Veränderungen in der Stellung ergeben sich aus der Teilnahme am Blutkrieg oder (wie häufiger der Fall) aus der hohen Verlustrate in den oberen Rängen. Wenn ein Baatezu eine große Tat vollbringt, die dem Feind schadet, wird er durch eine Beförderung belohnt - tatsächlich eine körperliche Verwandlung - zu einer höheren Stellung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle Baatezu außer Lemuren, Nupperibo und Spinagons haben die zauberähnlichen Fähigkeiten fortgeschrittene Illusion, Tote beleben, Person bezaubern, Infrasicht, Gesinnung erkennen (immer aktiv), Suggestion und Teleportation ohne Fehler.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = 'cc00c71c-e092-4d40-99bb-33a0a0a98282' AND is_custom = FALSE;

-- Baatezu, Greater, Pit Fiend (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die schrecklichsten Baatezu, Grubendrachen sind riesige geflügelte Humanoide, gargoylenhaft in ihrer Erscheinung, mit gewaltigen Fledermausflügeln, die sich um ihren Körper zur Verteidigung schlingen können, großen Reißzähnen, die von widerwärtiger, grüner Flüssigkeit triefen, und massigen roten, schuppigen Körpern, die in Flammen ausbrechen, wenn sie erzürnt oder erregt sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Kein Baatezu ist im Kampf schrecklicher als ein Grubendrache. Der Grubendrache nutzt seine 18/00 Stärke (+6 Schadensmodifikation), um sechs Mal pro Runde anzugreifen und teilt seine Angriffe bei Bedarf auf bis zu sechs verschiedene Gegner auf. Er kann mit zwei harten, schuppigen Flügelschlägen angreifen (je 1W4 Schadenspunkte), mächtigen Klauen (1W6 Punkte) und einem Biss (2W6 Punkte und Gift; Rettungswurf gegen Gift oder Tod in 1W4 Runden). Der Biss infiziert das Opfer auch mit einer Krankheit, unabhängig davon, ob es den Rettungswurf gegen das Gift besteht.'),
  habitat_society = COALESCE(habitat_society, 'Grubendrachen sind die Herren von Baator, die Baatezu mit der größten Macht und dem höchsten Rang. Grubendrachen sind in ganz Baator zu finden, aber sehr selten in den oberen Schichten und in der eisigen Kälte von Caina, der achten Schicht. Grubendrachen sind sehr selten in Avernus, Dis und Minauros. Sie sind selten in Phlegethos, Stygia, Malbolge und Maladomini. Im furchtbaren Reich von Nessus sind die Grubendrachen häufig.'),
  ecology         = COALESCE(ecology, 'Grubendrachen entstehen aus den mächtigen Gelugons von Baators achter Schicht. Wenn Gelugons für würdig befunden werden, werden sie für 1001 Tage in die Grube der Flammen geworfen. Sie gehen als Grubendrachen hervor.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '485d4c87-7cc8-4769-91ee-2eb752b2c916' AND is_custom = FALSE;

-- Baboon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Paviane sind große, pflanzenfressende Affen. Sie leben normalerweise in den Bäumen tropischer und subtropischer Dschungel, aber Stämme findet man manchmal auch in tropischen Bergen und Ebenen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn das Heimatgebiet des Stammes betreten wird, versuchen die Paviane, die Eindringlinge zu vertreiben, aber es ist zu 90% wahrscheinlich, dass ein Pavianstamm flieht, wenn er bedroht oder überrascht wird, sich in Bäumen oder hinter Bodenvegetation versteckend, bis die Gefahr vorüber ist. Extrem beweglich können Paviane in fünf Runden langen Schüben mit doppelter normaler Bewegungsrate klettern, wenn sie vor einem Feind fliehen. Jedoch können Paviane, wenn sie in die Enge getrieben werden oder wenn ein Jungtier gefährdet ist, bösartige Kämpfer sein, besonders die größeren Männchen. Paviane greifen an, indem sie sich von oben auf ihre Opfer fallen lassen oder anstürmen und springen, beißend mit ihren scharfen Zähnen für 1W4 Schadenspunkte. Der Stamm wird von 2W4 großen Männchen angeführt, die als erste Verteidigungslinie dienen und einen +1 Schadensbonus auf ihre Angriffe erhalten. Männliche Paviane versuchen manchmal, Eindringlinge abzuschrecken, indem sie ihre Fangzähne entblößen und kreischen.'),
  habitat_society = COALESCE(habitat_society, 'Paviane leben in Stämmen von 10-40, obwohl manche Stämme bis zu 100 Mitglieder umfassen. Etwa die Hälfte des Stammes sind Jugendliche oder Jungtiere; der Rest sind erwachsene Männchen und Weibchen. Die Jungen greifen nicht an, und Weibchen greifen generell nur an, wenn ihre Kinder bedroht sind. Weibchen gebären jedes Jahr ein Kind.'),
  ecology         = COALESCE(ecology, 'Paviane fressen Früchte, Samen, Gras, Wurzeln und Blätter. Sie mögen auch Vogeleier und Insekten. Wenn Nahrung knapp ist, fressen Paviane lebende Beute wie Mäuse und Frösche. Gruppen großer Männchen sind dafür bekannt, kleine Antilopen und Leoparden zu jagen und zu töten, obwohl dies extrem ungewöhnlich ist. Bei Gelegenheit fressen die meisten Raubtiere Paviane. Da Dschungelpaviane die meiste Zeit in den hohen Bäumen verbringen, sind sie generell vor Angriffen sicher. Riesenschlangen sind ihre meistgefürchteten natürlichen Feinde. Bergpaviane haben es schwerer; ihre Feinde umfassen Berglöwen, Säbelzahntiger und Wolfsrudel.'),
  no_appearing    = COALESCE(no_appearing, '10-40')
WHERE id = '4e0786db-f5c7-4ea7-85c9-3ee725fda8d7' AND is_custom = FALSE;

-- Badger (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dachse sind fleischfressende grabende Tiere, die unterirdisch leben und nachts jagen. Dachse sind jähzornig und mutig; wenn sie bedroht werden, greifen Dachse ohne zu zögern Kreaturen an, die um ein Vielfaches größer sind als sie selbst.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn ein Dachs außerhalb seines Baus angetroffen wird, versucht er normalerweise wegzulaufen und sich zu verstecken. Wird er jedoch in seinem Bau gestört oder in die Enge getrieben, kämpft er mit überraschender Bösartigkeit, unabhängig von der Größe oder Stärke seines Gegners. Der Dachs greift an, indem er seine scharfen Zähne bleckt und sich auf seinen Gegner stürzt und versucht zu beißen und zu krallen. Schnappend, kauend und schlagend geht der Dachs an die Kehle seines Gegners, wenn sie in Reichweite ist, andernfalls greift er den Bauch des Gegners an; alle ungeschützten Bereiche eines Gegners, wie Gesicht oder Arme, sind ebenfalls wahrscheinliche Ziele eines Dachsangriffs. Ein Dachs knurrt und sabbert während des Angriffs und kämpft in den meisten Fällen bis zum Tod.'),
  habitat_society = COALESCE(habitat_society, 'Dachse sind extrem geschickte Gräber. Sie graben ihre Baue bevorzugt in die weiche Erde von Waldböden und Ackerland, aber sie können auch in Bergen und an Hügelhängen gedeihen. Der Eingang zu einem Dachsbau ist ein kreisrundes Loch von etwa 30 bis 60 cm Durchmesser, umgeben von einem Erdring aus der ursprünglichen Ausgrabung. Der Tunnel führt sanft in die Erde hinab, ist meist etwa 1,2 bis 1,8 m lang und endet in einer Kammer, die je nach Größe der Familie nur 1,2 m breit oder bis zu 3 m breit sein kann. Der Boden des Baus ist typischerweise übersät mit Überresten früherer Mahlzeiten und Lagern aus Blättern und Gras zum Schlafen. Dachse sind keine besonders guten Haushalter; wenn ein Bau übermäßig schmutzig wird, kann die Familie in ein nahegelegenes Gebiet umziehen und neue Wohnräume graben.'),
  ecology         = COALESCE(ecology, 'Dachsfleisch ist fettig, zäh und nicht besonders appetitlich. Wegen ihrer bösartigen Natur ist die Jagd auf Dachse für die meisten Raubtiere nicht der Mühe wert, obwohl gelegentlich ein hungriger Wolf oder Fuchs dabei beobachtet werden kann, wie er am Eingang eines Dachsbaus scharrt. Dachse fressen Nagetiere, Eichhörnchen, Gopher und andere kleine Tiere.'),
  no_appearing    = COALESCE(no_appearing, '2-5')
WHERE id = '3b7016ad-3c17-43c7-b273-97305c77218a' AND is_custom = FALSE;

-- Banshee (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Banshee oder Klagendes Gespenst ist der Geist einer bösen weiblichen Elfe - etwas sehr seltenes. Banshees hassen die Lebenden, empfinden deren Anwesenheit als schmerzhaft und versuchen jedem zu schaden, dem sie begegnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Banshees sind furchtbare Gegner. Schon ihr Anblick verursacht Furcht, es sei denn, ein erfolgreicher Rettungswurf gegen Zauber wird gewürfelt. Jene, die versagen, müssen 10 Runden lang vor Schrecken fliehen und lassen mit 50%iger Wahrscheinlichkeit alle Gegenstände fallen, die sie in den Händen trugen.'),
  habitat_society = COALESCE(habitat_society, 'Banshees verabscheuen alle lebenden Dinge und machen daher ihre Heime in trostloser Landschaft oder alten Ruinen. Dort verstecken sie sich tagsüber, wenn sie nicht klagen können, und wandern nachts durch die umgebende Landschaft. Das Land rund um den Bau eines Klagenden Gespenstes ist übersät mit den Knochen von Tieren, die den Schrei des Klagenden Gespenstes hörten. Einmal etabliert ein Klagendes Gespenst ihren Bau, bleibt sie dort.'),
  ecology         = COALESCE(ecology, 'Banshees sind eine Plage, wo immer sie sich niederlassen. Sie töten wahllos und ihr einziges Vergnügen ist das Unglück und Elend anderer. Zusätzlich zum Töten von Mensch und Tier hat das Klagen eines Klagenden Gespenstes eine mächtige Wirkung auf die Vegetation. Blumen und zarte Pflanzen verwelken und sterben, und Bäume wachsen verdreht und krank, während widerstandsfähigere Pflanzen, Disteln und dergleichen, gedeihen. Nach einigen Jahren bleibt im Umkreis von acht Kilometern um den Bau eines Klagenden Gespenstes nur eine trostlose Wildnis aus verkrüppelten Bäumen und Dornen gemischt mit den Knochen jener Kreaturen übrig, die es wagten, in das Gebiet des Klagenden Gespenstes einzudringen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '3fe4449b-f076-46ed-b5af-102709c4644d' AND is_custom = FALSE;

-- Barracuda (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Barrakudas bewohnen warme Salzgewässer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Barrakuda-Körper sind wie ein Pfeil geformt und können in tropischen Ozeanen ebenso tödlich sein. Diese Fische können sich sehr schnell bewegen, blitzartig heranschießen für einen Biss und dann genauso plötzlich wieder fortschwimmen. Diese Raubfische sind blitzschnell und können von einem bewegungslosen Zustand auf Höchstgeschwindigkeit in einer einzigen Nahkampfrunde beschleunigen.'),
  habitat_society = COALESCE(habitat_society, 'Wie oben erwähnt, begegnet man Barrakudas normalerweise in kleinen Schwärmen in tropischen Ozeanen, obwohl manche Arten gelegentlich auch in gemäßigteren Meeren gefunden werden.'),
  ecology         = COALESCE(ecology, 'Barrakudas teilen sich die Spitze der Nahrungskette mit anderen großen, räuberischen Meereskreaturen und ernähren sich von kleineren Fischen und Meeressäugern, die schwach oder verletzt erscheinen.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '81719f11-3cc7-4d58-8179-0a341876c1aa' AND is_custom = FALSE;

-- Basilisk (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese reptilienartigen Monster besitzen alle einen Blick, der es ihnen ermöglicht, jede fleischliche Kreatur zu Stein zu verwandeln; ihr Blick reicht bis in die Astral- und Ätherebene.'),
  combat_tactics  = COALESCE(combat_tactics, 'Während er starke, bezahnte Kiefer hat, ist der Blick die Hauptwaffe des Basilisks. Wenn jedoch sein Blick reflektiert wird und er seine eigenen Augen sieht, wird er selbst versteinert, aber dies erfordert Licht, das mindestens hellem Fackelschein entspricht, und einen guten, glatten Reflektor. In der Astralebene tötet sein Blick; in der Ätherebene verwandelt er Opfer in ätherischen Stein. Diese werden nur von jenen gesehen, die sich in der Ätherebene befinden oder ätherische Objekte sehen können.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '7b933cd7-6d39-4d90-a0ea-fcfa0dd6005c' AND is_custom = FALSE;

-- Beetle, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenkäfer ähneln ihren gewöhnlicheren Artgenossen, sind aber tausende Male größer - mit kauenden Mandibeln und harten Flügeln, die beträchtlichen Rüstungsschutz bieten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn er angegriffen oder gestört wird, besteht jede Runde eine 50%ige Chance, dass er sein Hinterteil seinem Angreifer zuwendet und eine 2,4 m große, kugelförmige Wolke aus stinkendem, rötlichem, ätzendendem Dampf aus seinem Abdomen abfeuert. Diese Wolke verursacht 3W4 Schadenspunkte pro Runde bei jeder Kreatur in Reichweite. Außerdem hat das Geräusch, das durch die Freisetzung des Dampfes verursacht wird, eine 20%ige Chance, jede Kreatur mit einem Gehörsinn in einem 4,6 m Radius zu betäuben, und eine gleiche Chance, jede Kreatur zu ertauben, die nicht betäubt wurde. Betäubung dauert 2W4 Runden an, plus zusätzliche 2W4 Runden Taubheit danach. Ertaubung dauert 2W6 Runden an. Der Riesenbombardierkäfer kann seine Dampfwolke jede dritte Runde abfeuern, aber nicht mehr als zweimal in acht Stunden.'),
  habitat_society = COALESCE(habitat_society, 'Einzeln sind diese Kreaturen nicht viel intelligenter als andere Riesenkäfer, aber es wird gemunkelt, dass Nester von ihnen eine Gemeinschaftsintelligenz entwickeln können mit einem Bewusstseinsniveau und Denkvermögen, das dem menschlichen Gehirn entspricht. Das bedeutet nicht, dass jeder Käfer die Intelligenz eines Menschen hat, sondern vielmehr, dass das gesamte Nest gemeinsam dieses Niveau erreicht hat. In diesen Fällen sammeln die Käfer wahrscheinlich Schätze und magische Gegenstände von ihren Opfern.'),
  ecology         = COALESCE(ecology, 'Die Bombardieraktion dieses Käfers wird durch die explosive Mischung zweier Substanzen verursacht, die intern produziert und in einem dritten Organ kombiniert werden. Wenn ein Bombardierkäfer getötet wird, bevor er die Gelegenheit hatte, beide Salven abzufeuern, ist es möglich, die Kreatur aufzuschneiden und die Chemikalien zu bergen. Diese Chemikalien können dann kombiniert werden, um mit der richtigen Ausrüstung einen kleinen Sprengstoff herzustellen oder ein Geschoss abzufeuern.'),
  no_appearing    = COALESCE(no_appearing, '3-12')
WHERE id = 'd196bd28-e1ae-4fb9-a14f-5358b38b8307' AND is_custom = FALSE;

-- Behir (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Behir ist ein schlangenähnliches reptilisches Monster, dessen zwölf Beine es ihm ermöglichen, sich mit beträchtlicher Geschwindigkeit zu bewegen und mit der vollen Hälfte seiner normalen Bewegungsrate zu klettern. Er kann seine Gliedmaßen eng an seinen langen, schmalen Körper legen und nach Schlangenart gleiten, wenn er möchte. Der Kopf sieht eher krokodilhaft als schlangenartig aus, hat aber keine Schwierigkeiten, seinen Mund weit genug zu öffnen, um Beute im Ganzen zu verschlingen, wie es eine Schlange tut.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Behir greift seine Beute an, indem er zuerst zubeißt und dann seinen Körper um das Opfer schlingt und zudrückt. Wenn der letztere Angriff gelingt, ist das Opfer in der nächsten Runde sechs Krallenhieben ausgesetzt.'),
  habitat_society = COALESCE(habitat_society, 'Behir sind Einzelgänger, die andere ihrer Art nur treffen, um sich zu paaren und ein Gelege von 1-4 Eiern auszubrüten. Das Weibchen bewacht diese Eier acht Monate lang, während das Männchen für das Paar jagt. Wenn die Jungen schlüpfen, werden sie sofort aus dem Nest geworfen, um für sich selbst zu sorgen, und die Erwachsenen trennen sich.'),
  ecology         = COALESCE(ecology, 'Behir sind für Magier, Priester und Alchemisten für eine Reihe von Zubereitungen nützlich. Die Hörner eines Behir können verwendet werden, um die Tinte zu brauen, die nötig ist, um eine Blitzschlagschriftrolle zu beschriften, und die scharfen Krallen können ebenfalls von einem Priester verwendet werden, um die Tinte für eine Schriftrolle der Giftunschädlichmachung herzustellen. Das Herz des Behir ist eine der häufigeren Zutaten für Tinte für eine Schriftrolle des Giftschutzes.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '36447632-95fe-492b-9a44-955a1d7223b2' AND is_custom = FALSE;

-- Beholder and Beholder-kin I (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Betrachter ist der Stoff, aus dem Albträume gemacht sind. Diese Kreatur, auch Sphäre der vielen Augen oder Augentyrann genannt, erscheint als große Kugel, die von einem zentralen Auge und einem großen zahnbesetzten Schlund dominiert wird und 10 kleinere Augen auf Stielen hat, die aus der Oberseite der Kugel sprießen. Unter Abenteurern sind Betrachter als tödliche Widersacher bekannt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Betrachter hat verschiedene Rüstungsklassen für verschiedene Teile seines Körpers. Beim Angriff auf einen Betrachter bestimme die Stelle des Angriffs vor dem Schlag (da die verschiedenen Rüstungsklassen einen Treffer in einem Bereich und einen Fehlschlag in einem anderen bedeuten können):'),
  habitat_society = COALESCE(habitat_society, 'Die Betrachter sind eine hasserfüllte, aggressive und habgierige Rasse, die andere Rassen angreift oder dominiert, einschließlich anderer Betrachter und vieler Betrachterverwandter. Dies liegt an einer fremdenfeindlichen Intoleranz unter Betrachtern, die sie dazu bringt, alle Kreaturen zu hassen, die ihnen nicht gleichen. Der grundlegende Betrachter-Körpertyp (eine Sphäre mit einem Mund und einem zentralen Auge, augenbekrönte Tentakel) erlaubt eine große Vielfalt von Betrachter-Unterarten. Einige haben offensichtliche Unterschiede, es gibt solche, die mit überlappenden Chitinplatten bedeckt sind, und solche mit glatten Häuten oder schlangenartigen Augententakeln und einige mit krebsartigen Gelenken. Aber etwas so Geringes wie eine Änderung der Hautfarbe oder Größe des zentralen Auges kann zwei Gruppen von Betrachtern zu Todfeinden machen. Jeder Betrachter erklärt seine eigene einzigartige Körperform zum wahren Ideal des Betrachterdaseins, die anderen seien nichts als hässliche Kopien, die nur dazu taugen, eliminiert zu werden.'),
  ecology         = COALESCE(ecology, 'Der exakte Fortpflanzungsprozess des Betrachters ist unbekannt. Der Kern-Rassenhass der Betrachter könnte aus der Natur ihrer Fortpflanzung stammen, die identische (oder nahezu identische) Individuen mit nur geringem Spielraum für Variation zu erzeugen scheint. Betrachter könnten parthenogenetische Fortpflanzung nutzen, um sich zu duplizieren, und lebend gebären (keine Betrachtereier wurden gefunden). Betrachter können auch (selten) mit Arten von Betrachterverwandten paaren.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '4f7de8af-6abb-4a4f-b1e6-b118d65f54e3' AND is_custom = FALSE;

-- Bird (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Vögel, ob magisch oder gewöhnlich, gehören zu den interessantesten Kreaturen, die je entstanden sind. Ihre einzigartige Physiologie hebt sie von allem anderen Leben ab, und ihre Anmut und Schönheit haben ihnen einen Platz des Respekts und der Verehrung in den Geschichten vieler Völker eingebracht.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = '32d4f9f9-b78c-4300-a688-602f9884264e' AND is_custom = FALSE;

-- Boar (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wildschweine, eine Art von Wildschweinen, sind die Vorfahren unserer domestizierten Schweine. Wildschweine sind natürlich aggressiver als die Hoftiere, und eine unerwartete Begegnung mit einer Familie dieser Kreaturen oder einem großen Individuum kann tödlich enden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wildschweine sind gefährliche Gegner, wenn sie gereizt werden. Sie haben einen bösartigen Biss und diejenigen mit Hauern können diese einsetzen, um ungeschütztes Fleisch mit großer Wirksamkeit aufzureißen.'),
  habitat_society = COALESCE(habitat_society, 'Wildschweine leben in der Regel in Familienverbänden. Wenn mehr als ein Wildschwein angetroffen wird, werden die anderen Bachen sein (3 Trefferwürfel, 2-8 (2W4) Trefferpunkte Schaden/Angriff) oder Frischlinge, mit einem 1:4 Verhältnis (Bachen:Frischlinge). Wenn also 12 angetroffen werden, wird es 1 Wildschwein, 3 Bachen und 8 Jungtiere geben.'),
  ecology         = COALESCE(ecology, 'Wildschweine sind echte Allesfresser, die praktisch alles fressen. Während das Essen einer Vielfalt von Nahrungsmitteln allgemein als gesund gilt, kann dies im Fall des Wildschweins zu Problemen führen. Ein kleiner Rundwurm, Trichinella spiralis, ist ein Parasit, der den Körper eines Wildschweins bewohnen kann. Dies schafft ein Problem, wenn ein Mensch das Wildschwein isst, ohne es richtig zu kochen, da Trichinose, die durch diesen Parasiten verursachte Krankheit, leicht auf Menschen übertragbar ist. Einmal mit dem Parasiten infiziert, leidet der Wirt unter Fieber, Schwitzen und schmerzenden Muskeln, bis ein Krankheit heilen Zauber gewirkt wird.'),
  no_appearing    = COALESCE(no_appearing, '1-12')
WHERE id = '101036eb-4cf6-4612-b9e9-ad83c02a3b8b' AND is_custom = FALSE;

-- Bookworm (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dieser kleine Wurm, nur 2,5 cm lang, wird von Magiern sehr gefürchtet, da er von Papier in allen Formen angezogen wird. Er kann Schriftrollen, Karten, arkane Folianten und Zauberbücher auf eine Entfernung von 18,3 m riechen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Bücherwurm verhängt anfangs einen Malus von -7 auf die Überraschungswürfe von Abenteurern aufgrund seiner Farbwechselfähigkeit. Kann das Opfer unsichtbare Dinge sehen, reduziert sich der Modifikator des Bücherwurms auf -4. Diese Chancen gelten sogar für Kreaturen, die normalerweise schwer zu überraschen sind (wie Waldläufer und Mönche), wegen seiner geringen Größe, Geschwindigkeit (sehr hoch im Verhältnis zu seiner Größe) und harmlosen Natur. Gelingt dem Bücherwurm zunächst die Überraschung, kann er dann (25%) an der Außenseite des Beins oder Rucksacks eines Opfers entdeckt werden. Andernfalls bleibt er unbemerkt, es sei denn, das Opfer, das Papier bei sich trägt, hört das laute Kauen der Kreatur (Grundchance 50% pro Runde). Ein fressender Bücherwurm bleibt reglos, bis er angegriffen wird. Nach jedem Angriff flieht er (falls möglich), indem er zunächst 3 m springt und dann mit Höchstgeschwindigkeit zu seinem Bau zurückkriecht.'),
  habitat_society = COALESCE(habitat_society, 'Ein Bücherwurmbau ist immer eine Bibliothek oder ein Lagerraum irgendeiner Art, sei er in Benutzung oder längst vergessen. Wird ein Bücherwurm angetroffen, können noch unbeschädigte Papiergegenstände übrig sein (30% Chance). In solchen Fällen sind die überlebenden Objekte wie folgt: eine Karte (60%), Schriftrolle (30%) oder ein arkanes Werk der Magierstufe 1-8 (10%). Werden Zauberbücher angezeigt, sollten sie für die Stufe der Charaktere angemessen sein, die sie finden, aber zu 0-90% (1W10-1) von den Würmern zerstört sein.'),
  ecology         = COALESCE(ecology, 'Ein Bücherwurm wird immer von der größten Papiermenge in einem Bereich angezogen.'),
  no_appearing    = COALESCE(no_appearing, '1-2 (10-40)')
WHERE id = 'bdd2a6a6-3200-4b37-a54f-455b21fd7804' AND is_custom = FALSE;

-- Brain Mole (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Geistesverbindung, Gedächtnislöschung; Hingabe: Kontakt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Gehirnmaulwurf greift sein Opfer gewöhnlich in Wäldern oder im Untergrund an; in beiden Fällen befindet sich die Kreatur normalerweise außerhalb der direkten Sichtlinie. Der Maulwurf wartet darauf, dass ein psionisch begabtes Wesen über ihm erscheint, oder er gräbt sich auf der Suche nach Beute durch die Erde.'),
  habitat_society = COALESCE(habitat_society, 'Gehirnmaulwürfe leben in Familienverbänden, die ein Männchen, ein Weibchen und 1W6 Junge umfassen (von denen eines alt genug sein kann, um sich selbst zu nähren). Große Gehirnmaulwurf-Siedlungen von bis zu 3W6 Familienverbänden wurden berichtet. Natürlich kommen diese nur an Orten vor, die häufig von psionisch Begabten bereist werden.'),
  ecology         = COALESCE(ecology, 'Obwohl Gehirnmaulwürfe für manche gefährlich sein können, halten andere sie als Haustiere. Die Maulwürfe sind ziemlich freundlich und leicht zu zähmen. Sie werden von Adeligen bevorzugt, die den besonderen Schutz schätzen, den nur Gehirnmaulwürfe bieten können. Einige Gelehrte behaupten, dass sogar ein toter Gehirnmaulwurf Schutz vor psionischen Angriffen bieten kann, vorausgesetzt, der Kadaver wird als Medaillon um den Hals getragen. Manchmal schicken Adelige, die von einem bestimmten Psioniker belästigt wurden, Helden auf Questen nach den kleinen pelzigen Nagetieren aus. Auf dem freien Markt verkaufen sich ausgewachsene Gehirnmaulwürfe für 50 GM. Jungtiere verkaufen sich für je 5 GM.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = 'd717a9dc-86b5-4351-952c-d4f0cb5747d0' AND is_custom = FALSE;

-- Broken One (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gebrochene (oder Tiermenschen) sind die tragischen Überlebenden wissenschaftlicher und magischer Experimente, die fehlschlugen. Während sie einst Menschen waren, sind ihre Wesen mit denen von Tieren vermischt worden und ihre wahre Natur wurde durch den Schock dieses Ereignisses für immer verändert. Es wird gemunkelt, dass manche Gebrochene das Ergebnis fehlgeschlagener Versuche der Auferstehung, Reinkarnation oder Verwandlungsmagie sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gebrochene neigen dazu, zurückgezogene Kreaturen zu sein und Kämpfe mit ihnen sind selten. Dennoch sind sie starke Gegner. Gebrochene sind fast immer mit größerer als menschlicher Ausdauer gesegnet, was sich darin widerspiegelt, dass sie immer mindestens 5 Trefferpunkte pro Trefferwürfel haben. Somit hat der schwächste Gebrochene mindestens 15 Trefferpunkte. Zusätzlich heilen Gebrochene mit stark beschleunigter Geschwindigkeit und regenerieren 1 Trefferpunkt pro Runde.'),
  habitat_society = COALESCE(habitat_society, 'Gebrochene neigen dazu, sich in Gruppen von 10 bis 60 Personen zu sammeln. Da sie selten Akzeptanz in menschlichen Gesellschaften finden, suchen sie Ihresgleichen auf und wohnen in abgelegenen Gebieten dichter Wälder oder felsiger Ödländer, weit entfernt von den Heimen der Menschen. Von Zeit zu Zeit werden sie ein menschliches Dorf oder eine Karawane angreifen, entweder für Vorräte, zur Selbstverteidigung oder einfach aus Rache für wirkliche oder eingebildete Kränkungen. Wenn möglich, werden sie versuchen, ihren Schöpfer aufzuspüren und ihn für die Verwandlungen zu vernichten, die er über sie gebracht hat.'),
  ecology         = COALESCE(ecology, 'Gebrochene sind unnatürliche Kombinationen aus Menschen und Tieren. Ihre individuellen Ernährungsweisen und Gewohnheiten werden größtenteils von ihrer tierischen Natur bestimmt. Somit wäre ein Gebrochener mit löwenartigen Eigenschaften fleischfressend, während einer, der mit der Essenz eines Pferdes durchdrungen ist, Vegetarier wäre. Es gibt keine bekannten Beispiele eines Gebrochenen, der mit der Essenz einer intelligenten nichtmenschlichen Kreatur geformt wurde.'),
  no_appearing    = COALESCE(no_appearing, '3-12 (3d4)')
WHERE id = 'b6313384-ce4b-4625-884b-6342e8348233' AND is_custom = FALSE;

-- Brownie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Brownies sind kleine, gutartige Humanoide, die möglicherweise sehr entfernt mit Halblingen verwandt sind. Friedlich und freundlich leben Brownies in ländlichen Gebieten, wo sie ihr Futter sammeln und zusammentragen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Brownies ziehen es vor, sich nicht auf Kämpfe einzulassen und tun dies nur, wenn sie bedroht werden. Verärgerte Brownies stellen sich selten ihren Feinden im Nahkampf, sondern verlassen sich stattdessen auf Magie.'),
  habitat_society = COALESCE(habitat_society, 'Brownies leben in ländlichen Gebieten und richten ihre Behausungen in kleinen Erdbauten oder verlassenen Gebäuden ein. Oft leben sie nahe bei Bauernhöfen oder auf diesen, da sie vom Landleben fasziniert sind.'),
  ecology         = COALESCE(ecology, 'Brownies sind im Wesentlichen Vegetarier, die sehr komfortabel von den Resten des landwirtschaftlichen Lebens leben. Sie nutzen effizient Überbleibsel, die zu klein sind, als dass Menschen sie bemerken würden. Wenn Brownies von den Feldern sammeln, tun sie dies nach der Ernte und sammeln Getreide und Früchte, die andernfalls verschwendet würden.'),
  no_appearing    = COALESCE(no_appearing, '4-16')
WHERE id = 'de323c3c-95c0-4fc0-b638-17ad2a1a10ad' AND is_custom = FALSE;

-- Bugbear (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Bugbears sind riesige, haarige Vettern der Goblins, die dieselben Gebiete wie ihre kleineren Verwandten bewohnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wann immer möglich, ziehen es Bugbears vor, ihre Feinde aus dem Hinterhalt anzugreifen. Sie verhängen einen Malus von -3 auf die Überraschungswürfe anderer.'),
  habitat_society = COALESCE(habitat_society, 'Bugbears bevorzugen es, in Höhlen und an unterirdischen Orten zu leben. Ein Bau kann aus einer großen Höhle oder einer Gruppe von Höhlen bestehen. Sie sind gut an dieses Leben angepasst, da sie gleichermaßen gut bei Tageslicht und in der Dunkelheit agieren.'),
  ecology         = COALESCE(ecology, 'Bugbears haben zwei Hauptziele im Leben: Überleben und Schätze. Sie sind hervorragende Fleischfresser, die schwache und unvorsichtige Abenteurer, Monster und Tiere aussortieren. Goblins sind immer auf der Hut, wenn Bugbears anwesend sind, denn die Schwachen oder Dummen landen schnell im Eintopf.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (2d4)')
WHERE id = '25e1722c-44ed-4c53-a80a-38f0582dc732' AND is_custom = FALSE;

-- Bulette (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Treffend als Landhai bezeichnet, ist die Bulette (ausgesprochen Boo-lay) ein furchterregender Räuber, der nur lebt, um zu fressen. Die Bulette wird allgemein gemieden, sogar von anderen Monstern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Eine Bulette greift alles an, was sie als essbar betrachtet. Die einzigen Wesen, die sie zu fressen verweigert, sind Elfen, und sie mag keine Zwerge. Die Bulette ist immer hungrig und streift ständig durch ihr Territorium auf der Suche nach Nahrung. Wenn sie unterirdisch gräbt, verlässt sich der Landhai auf Vibrationen, um Beute zu entdecken. Wenn sie etwas Essbares wahrnimmt (d.h. Bewegung spürt), bricht die Bulette mit dem Kamm voran an die Oberfläche und beginnt ihren Angriff. Der Landhai hat ein Temperament wie ein Vielfraß - dumm, gemein und furchtlos. Die Größe, Stärke und Anzahl seiner Gegner bedeutet nichts. Die Bulette greift immer an und wählt als Ziel die einfachste oder nächste Beute. Beim Angriff setzt die Bulette ihre großen Kiefer und Vorderfüße ein.'),
  habitat_society = COALESCE(habitat_society, 'Glücklicherweise für den Rest der Welt ist die Bulette ein Einzelgänger, obwohl Pärchen (sehr selten) das gleiche Territorium teilen. Zudem teilen andere Raubtiere selten ein Territorium mit einem Landhai aus Angst, gefressen zu werden. Die Bulette hat keinen Bau und zieht es vor, über ihr Territorium zu wandern, ober- und unterirdisch, und gräbt sich zum Ausruhen unter die Erde. Da ihr Appetit so unersättlich ist, hat jeder Landhai ein großes Territorium von bis zu 78 Quadratkilometern.'),
  ecology         = COALESCE(ecology, 'Die Bulette hat verheerende Auswirkungen auf das Ökosystem jedes Gebiets, das sie bewohnt. Buchstäblich nichts, was sich bewegt, ist vor ihr sicher - Mensch, Tier oder Monster. Beim Jagen und Umherstreifen entwurzelt der Landhai Bäume beträchtlicher Größe. In hügeligem und felsigem Gelände können die unterirdischen Bewegungen der Bulette kleine Erdrutsche auslösen. Ogger, Trolle und sogar manche Riesen ziehen auf der Suche nach grüneren und sichereren Weiden weiter, wenn eine Bulette auftaucht. Eine Bulette kann eine friedliche Bauerngemeinde in wenigen Wochen in ein Ödland verwandeln, denn kein vernünftiger Mensch oder Halbmensch wird in einer Region bleiben, wo eine Bulette gesichtet wurde.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '8c380a49-ba6a-4800-a9be-a301491c0515' AND is_custom = FALSE;

-- Bullywug (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Bullywugs sind eine Rasse zweibeiniger, froschähnlicher Amphibien. Sie bewohnen Sümpfe, Marschen, Seen oder andere feuchte Orte.'),
  combat_tactics  = COALESCE(combat_tactics, 'Bullywugs greifen immer in Gruppen an und versuchen, ihre zahlenmäßige Überlegenheit zu nutzen, um ihre Feinde zu umzingeln. Wann immer möglich, greifen Bullywugs mit ihrem Sprung an, der bis zu 9,1 m nach vorn und 4,6 m nach oben reichen kann. Beim Angriff mit einem Sprung erhalten Bullywugs einen +1 Bonus auf ihre Angriffswürfe (nicht Schaden), und verdoppeln den Schaden bei Verwendung einer durchbohrenden Waffe. Diese Fähigkeit, kombiniert mit ihren hervorragenden Tarnfähigkeiten, bringt die Bullywugs häufig in eine ideale Position für einen Hinterhalt (-2 Malus auf die Überraschungswürfe der Gegner).'),
  habitat_society = COALESCE(habitat_society, 'Intelligenter als Frösche leben alle Bullywugs in organisierten oder halborganisierten sozial-faschistischen Gruppen und arbeiten zum Zweck der Jagd und des Überlebens zusammen. Sie leben hauptsächlich von Fisch und anderem Wild und bevorzugen eine Fleischnahrung. Sie sind geschickte Jäger und Fischer und geübt im Gebrauch und der Herstellung von Fallen und Netzen.'),
  ecology         = COALESCE(ecology, 'Bullywugs neigen dazu, Ökosysteme zu stören, anstatt eine Nische in ihnen zu füllen. Sie haben nicht die Intelligenz, ihre Nahrungsvorräte vernünftig zu ernten, und werden in einem Gebiet fischen und jagen, bis dessen natürliche Ressourcen erschöpft sind, um dann in ein neues Territorium zu ziehen. Sie hassen Menschen und greifen sie bei Sicht an, aber glücklicherweise bevorzugen sie es, in abgelegenen Regionen fernab von Menschen zu leben.'),
  no_appearing    = COALESCE(no_appearing, '10-80')
WHERE id = '184f3e85-17dc-402d-84d6-b685c3bdf79b' AND is_custom = FALSE;

-- Carrion Crawler (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Aaskrabbler ist ein Aasfresser unterirdischer Gebiete, der sich hauptsächlich von Aas ernährt. Wenn solche Nahrung jedoch knapp wird, greift er lebende Kreaturen an und tötet sie.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Aaskrabbler kann sich sehr schnell entlang Wänden, Decken und Gängen bewegen, wobei er seine vielen bekrallten Füße für Halt nutzt.'),
  habitat_society = COALESCE(habitat_society, 'Aaskrabbler sind sehr gefürchtete Bewohner der Unterwelt. Sie leben in Bauen und wagen sich alle paar Tage auf die Suche nach Aas oder Nahrung hinaus. Manche unterirdische Bewohner wie Goblins und Trolle nutzen Aaskrabbler, indem sie die Leichen toter Feinde an bestimmten Stellen auslegen. Das hält die Kreaturen in guter Entfernung von ihren eigenen Behausungen und ermutigt sie, bestimmte Gebiete zu "patrouillieren". Manche Orks sind dafür bekannt, lebende Gefangene nahe den Bauen dieser furchtbaren Monster anzuketten.'),
  ecology         = COALESCE(ecology, 'Der Aaskrabbler erfüllt die gleiche nützliche, wenn auch unangenehme Funktion, die Schakale, Geier und Krähen erfüllen. Wie so viele andere Raubtiere jagen Aaskrabbler instinktiv die Schwachen, Kranken und Törichten. Langfristig hat das einen günstigen Effekt auf die Beute und stärkt ihren Genpool. Der Aaskrabbler bewirkt auch Wunder in überfüllten Höhlen und beseitigt schnell Überbevölkerungsprobleme unter den schwächeren Monstern. So ist der Lebenszyklus des Krabblers untrennbar mit dem seiner Beute verknüpft - wenn die Beute gedeiht, gedeiht auch der Krabbler.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = 'ce6b1b2b-7a45-4790-8c34-31b625c52cc8' AND is_custom = FALSE;

-- Cat, Small (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Katzen verschiedener Größen und Färbungen sind überall auf der Welt verbreitet. Einige sind Haustiere, während viele wild leben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Katzen sind effiziente Jäger, die sich mit Anmut und Heimlichkeit bewegen; Gegner erleiden einen Malus von -3 auf Überraschungswürfe. Die ausgezeichneten Sinne und Beweglichkeit einer Katze erlauben es, dass sie nur bei einer 1 oder 2 überrascht wird. Ihre Sinne ermöglichen es ihr auch, nachts effizient zu jagen.'),
  habitat_society = COALESCE(habitat_society, 'Katzen sind in besiedelten Gebieten verbreitet. Viele Kulturen halten sie als Haustiere, und sie können in den Häusern von Adligen und Bauern gleichermaßen gefunden werden. Einige Gesellschaften verehren Katzen als göttliche Wesen, während andere Nationen sie als Diener des Bösen fürchten und hassen.'),
  ecology         = COALESCE(ecology, 'Katzen werden häufig zur Kontrolle von Nagerpopulationen eingesetzt, obwohl manche Jäger sie verwenden, um erlegte Vögel und andere kleine Beute zu apportieren.'),
  no_appearing    = COALESCE(no_appearing, '1 (1-12)')
WHERE id = 'cdbbaa45-872f-4242-b468-4bb06f0d2b86' AND is_custom = FALSE;

-- Cave Fisher (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Höhlenfischer ist ein großes Insektoid, das sich an das Leben unter der Erde angepasst hat. Er vereint viele Eigenschaften einer Spinne und eines Hummers.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Höhlenfischer hat zwei Jagdmethoden. Seine bevorzugte Methode ist es, seinen langen Faden in der Nähe seines Baus zu spannen. Die Fäden sind dünn und stark, wodurch sie äußerst schwer zu entdecken oder zu durchtrennen sind. Es besteht nur eine 20%ige Chance, den Faden auf 3 m zu bemerken, und gar keine Chance, ihn auf größere Entfernung zu sehen. Ein Fallen und Gruben entdecken Zauber wird einen Faden enthüllen. Der Faden ist mit einem Klebstoff überzogen, der nur durch Flüssigkeiten mit hohem Alkoholgehalt aufgelöst werden kann, wie das Blut des Höhlenfischers. Die Fäden können nur mit +1 oder besseren Klingenwaffen durchschnitten werden.'),
  habitat_society = COALESCE(habitat_society, 'Höhlenfischer bevorzugen das Leben auf Vorsprüngen und in Höhlen oberhalb viel begangener Pfade und teilen ihre Baue mit anderen ihrer Art. Nicht mehr als vier Höhlenfischer werden in einem Bau gefunden. Ihre Fäden sind immer vor ihrem Bau gespannt, und sie versuchen alles zu töten, was sie fangen, oft lagern sie Nahrung für zukünftigen Gebrauch.'),
  ecology         = COALESCE(ecology, 'Der Höhlenfischer erbeutet hauptsächlich kleine fliegende Beute, und in der unterirdischen Welt bedeutet das häufig eine Ernährung aus Fledermäusen. Er ist nicht der Spitzenräuber in seiner ökologischen Nische und hat Vorsicht im Umgang mit anderen Monstern gelernt. Der Höhlenfischer ist intelligent genug, um die Gefahren zu kennen, die entstehen, wenn er große, gut organisierte Gruppen bejagt, die seiner Plünderungen überdrüssig werden und ihn bis zur Ausrottung jagen könnten. Das Monster wählt instinktiv den einfachsten Weg zum Überleben und verlässt sich auf Heimlichkeit und Gerissenheit, um seine Beute zu fangen und zu vermeiden, selbst gefressen zu werden.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '9163f72b-79f5-4b4c-9382-2d608f84b57d' AND is_custom = FALSE;

-- Centaur (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Zentauren sind Waldbewohner, die die Gesellschaft der Menschen meiden. Sie leben in abgelegenen, versteckten Lichtungen und Weiden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Eine Gruppe von Zentauren ist stets bewaffnet, und die Anführer tragen Schilde. Die Hälfte der Zentauren führt eichene Keulen (gleichwertig mit Morgenstern), ein Viertel trägt Kompositbögen und hat 10-30 Pfeile (entweder Flug- oder Bündelpfeile, je nach aktueller Lage in der Gegend). Der Rest der Gruppe sind Anführer (RK4; TW5), die mittlere Schilde und mittlere Reiterlanzen verwenden. Zentauren führen im Nahkampf 3 Angriffe pro Runde aus: einmal mit ihren Waffen und zweimal mit ihren Hufen.'),
  habitat_society = COALESCE(habitat_society, 'Zentauren sind gesellige Wesen, die große Freude an der Gesellschaft ihrer Artgenossen finden. Ihre Gesamtorganisation ist stammesartig, wobei ein Stamm in Familiengruppen unterteilt ist, die harmonisch zusammenleben. Die Größe des Stammes variiert von 3-4 Familien bis zu über 20 Familien. Da Männchen die gefährlichen Rollen als Jäger und Beschützer übernehmen, übersteigen Weibchen die Männchen im Verhältnis zwei zu eins. Der Zentaur paart sich fürs Leben, und der gesamte Stamm beteiligt sich an der Erziehung der Jungen.'),
  ecology         = COALESCE(ecology, 'Der Zentaur lebt in enger Harmonie mit der Natur und verbringt sein Leben damit, die natürlichen Ressourcen um seinen Bau sorgfältig zu bewahren. Die Rasse scheint ein angeborenes Wissen darüber zu besitzen, wie dieses kostbare Gleichgewicht erreicht werden kann. Wenn sie gezwungen sind, einen Baum zu fällen, pflanzen Zentauren einen anderen als Ersatz. Zentauren überjagen oder überfischen ein Gebiet nie, wie es eine Menschengruppe tun könnte, sondern wählen ihre Beute sorgfältig aus und begrenzen die Menge, die sie verzehren.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = 'a2d55d8a-362e-418d-8be3-005eb171afa2' AND is_custom = FALSE;

-- Centipede (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesentausendfüßer sind widerliche, kriechende Gliederfüßer, die bei fast allen intelligenten Kreaturen (sogar anderen Monstern) universellen Ekel hervorrufen. Sie sind in den meisten Regionen heimisch.'),
  combat_tactics  = COALESCE(combat_tactics, 'Bei der Jagd nutzen Tausendfüßer ihre natürliche Färbung, um ungesehen zu bleiben, bis sie sich auf ihre Beute von oben fallen lassen oder aus ihrem Versteck herauskriechen können, um Nahrung zu verfolgen. Sie greifen an, indem sie ihre Feinde beißen und ein lähmendes Gift injizieren. Das Gift kann ein Opfer für 2W6 Stunden lähmen, ist aber so schwach, dass Opfer einen +4-Bonus auf ihren Rettungswurf erhalten.'),
  habitat_society = COALESCE(habitat_society, 'Der Tausendfüßer verhält sich wie die meisten anderen Insekten und wandert von Ort zu Ort auf der Suche nach Nahrung; er hat kein festes Territorium oder keine feste Behausung. Der Tausendfüßer geht einfach dorthin, wohin sein Hunger ihn führt. Er ist ein aggressiver und hungriger Fleischfresser, der mindestens einmal täglich fressen muss, um zu überleben. Hungrige Tausendfüßer greifen oft zu Kannibalismus.'),
  ecology         = COALESCE(ecology, 'Riesentausendfüßer haben mehrere natürliche Vorteile, einschließlich Gift und Schutzfärbung, die es ihnen ermöglichen, mit anderen kleinen Raubtieren um Wild zu konkurrieren. Ihr Gift verleiht ihnen eine gewisse Immunität davor, gejagt zu werden, aber hungrige und geschickte Tiere wie Kojoten und große Raubvögel jagen sie in mageren Zeiten effektiv.'),
  no_appearing    = COALESCE(no_appearing, '2-24')
WHERE id = 'b648f2bb-8451-469f-bcfa-eb465162f92b' AND is_custom = FALSE;

-- Chimera (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wie Chimären erschaffen wurden, ist ein dunkles Geheimnis, das besser unerforscht bleibt. Die Chimäre hat die Hinterläufe einer großen, schwarzen Ziege und die Vorderläufe eines riesigen, gelbbraunen Löwen. Ihr Körper hat bräunlich-schwarze Flügel wie die eines Drachen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ihre vielen Köpfe und ihre mächtige Statur machen die Chimäre zu einem tödlichen Feind im Kampf. Das Monster bevorzugt es, seine Opfer zu überraschen, oft indem es vom Himmel auf sie herabstößt. Sie kann 6 Mal pro Runde angreifen: mit den Klauen ihrer Vorderläufe, mit ihren beiden Hörnern stoßend und mit ihren Löwen- und Drachenköpfen beißend. Falls sie es wünscht, kann der Drachenkopf anstelle des Beißens einen etwa 4,6 m langen Flammenstrahl ausspeien. Das Feuer des Drachen verursacht 3-24 (3W8) Schadenspunkte, obwohl ein erfolgreicher Rettungswurf gegen Atemwaffen den Schaden halbiert. Die Chimäre wird immer zu atmen versuchen, wenn ihre Gegner in Reichweite sind. Falls mehr als eine Chimäre angetroffen wird, werden sie gemeinsam angreifen.'),
  habitat_society = COALESCE(habitat_society, 'Die Chimäre vereint als Hybridwesen die Vorlieben des Löwen, der Ziege und des Drachen in ihrem Lebensraum, ihrer Gesellschaft und Ökologie. Der drachenhafte Teil ihrer Natur gibt der Chimäre eine deutliche Vorliebe für Höhlen als Baue. Die Drachen- und Löwenteile scheinen miteinander zu streiten, denn manche Chimären sind drachenähnlich in ihrer Vorliebe für Einsamkeit, während andere in kleinen Rudeln leben. Selbst wenn sie sich paaren, sind Nachkommen selten.'),
  ecology         = COALESCE(ecology, 'Die Chimäre erfüllt die Rolle sowohl eines Allesfressers als auch eines Spitzenjägers in ihrem Ökosystem. Sie ist sehr anpassungsfähig. In Zeiten, in denen ihre Beute knapp oder nicht vorhanden ist, kann die Chimäre mit einer vegetarischen Ernährung auskommen.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '2fa8824e-cc97-47ae-879f-7c571b9ee144' AND is_custom = FALSE;

-- Cloaker (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Verhüller sind teuflische Schrecken, verwandt mit den Fallensteller, die an dunklen Orten weit unter der Erdoberfläche hausen. Sie versuchen generell, diejenigen zu töten, die ihre Baue betreten, außer sie können sich eine andere, amüsantere Art ausdenken, die Eindringlinge zu bestrafen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn ein Verhüller sein Opfer angreift, bewegt er sich mit blendender Geschwindigkeit. Ohne Vorwarnung fliegt der Verhüller auf sein Ziel zu und, wenn der Angriffswurf erfolgreich ist, umhüllt er seine Beute in seinen Falten. Jede Kreatur, die diesem Angriff zum Opfer fällt, ist nahezu hilflos und kann leicht gebissen werden (kein Wurf erforderlich) für 1W4 Schadenspunkte plus der unmodifizierten Rüstungsklasse des Opfers. So erleidet ein Abenteurer in Kettenrüstung (RK 5) 1W4+5 Schadenspunkte pro Runde. Schilde bieten keinen Schutz gegen solche Angriffe.'),
  habitat_society = COALESCE(habitat_society, 'Die Denkprozesse von Verhüllern sind für die meisten anderen Lebensformen völlig fremd. Als solche können sie nur von Magiern kontaktiert werden, die lange Stunden damit verbracht haben, ihre Gedanken in der arkanen Disziplin zu schulen, die notwendig ist, um diese Kreaturen zu verstehen.'),
  ecology         = COALESCE(ecology, 'Es wird angenommen, dass Verhüller geschlechtslos sind, obwohl hierfür nie ein definitiver Beweis gefunden wurde.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '0a370bd8-1736-4d13-a8c0-a1a1835d5f78' AND is_custom = FALSE;

-- Cockatrice (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Cockatrice ist eine unheimliche, abstoßende Kreuzung aus Echse, Hahn und Fledermaus. Er ist berüchtigt für seine Fähigkeit, Fleisch zu Stein zu verwandeln.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Cockatrice greift alles erbittert an, Mensch oder anderes, was er als Bedrohung für sich selbst oder seinen Bau ansieht. Beim Angriff versucht der Cockatrice, seinen Gegner zu packen, entblößtes Fleisch zu berühren und es zu Stein zu verwandeln. Schwärme von Cockatrices werden ihr Äußerstes geben, um ihre Gegner zu überwältigen und zu verwirren, und sie fliegen manchmal direkt in die Gesichter ihrer Opfer.'),
  habitat_society = COALESCE(habitat_society, 'Der Cockatrice ist immun gegen die Versteinerungskräfte anderer seiner Art.'),
  ecology         = COALESCE(ecology, 'Der Cockatrice gedeiht in der Wildnis. Seine Versteinerungskraft macht ihn immun gegen die meisten Raubtiere und befähigt ihn, mit anderen Vögeln um Nahrung zu konkurrieren. Die Federn des Cockatrice werden von bestimmten Magiern geschätzt, da viele magische Schriftrollen mit Federn geschrieben werden müssen, die aus solchen Kielen gemacht sind. Viele Menschen suchen auch nach ungeschlüpften Eiern oder sogar lebenden Cockatrices als ungewöhnliche Haustiere oder Wächter.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '6c685aaa-012b-407e-87ef-71a4c080a28f' AND is_custom = FALSE;

-- Couatl (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaft: Aurasicht; Andachten: Rundumblick, Schall sehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Couatl greift selten ohne Provokation an, obwohl er stets Übeltäter attackiert, die auf frischer Tat ertappt werden. Wann immer möglich, greift ein Couatl aus der Luft an.'),
  habitat_society = COALESCE(habitat_society, 'Diese geflügelte Schlange ist in warmen, dschungelartigen Gebieten heimisch, kann aber auch durch den Äther fliegend angetroffen werden. Ihre Intelligenz und Güte haben sie zu Objekten der Verehrung durch die Einheimischen der Gebiete gemacht, die sie bewohnen. Als göttlich betrachtet, gibt es viele Legenden, in denen der Couatl der Wohltäter der Menschheit und der Verleiher so kostbarer Gaben wie Ackerbau und Medizin ist. Es gibt sogar Schreine in bestimmten Gebieten, die dem Couatl geweiht sind, und jeder, der einen Couatl angreift oder verletzt, wird automatisch als der schwärzeste Schurke betrachtet.'),
  ecology         = COALESCE(ecology, 'Der Couatl herrscht gewöhnlich unumschränkt in seinem Dschungel und hat von den meisten anderen Monstern wenig zu befürchten.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '9279a170-81c7-4985-918d-146a51571f94' AND is_custom = FALSE;

-- Crabman (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Krabbenmänner sind menschengroße intelligente Krabben. Sie gehen aufrecht auf zwei Beinpaaren. Die kleinen Scheren an den Enden der kurzen Arme über ihren Beinen werden für feine Manipulationen verwendet. Die zwei längeren Arme enden in großen Klauen. Zwei schlanke Augenstiele wippen über der schnabelartigen Ansammlung von Mandibeln, die das Maul des Krabbenmannes bildet. Männliche Krabbenmänner sind oft leuchtend gefärbt und Weibchen können rötlich-braun, grün oder schwarz sein.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl generell friedlich, werden Krabbenmänner mit ihren großen Klauen zurückschlagen, wenn sie angegriffen werden, und dabei 1W6 Schadenspunkte pro Treffer verursachen. Männchen bestimmter Unterarten haben eine vergrößerte Klaue auf einer Seite, die 1W8 Schaden verursacht. Es ist nie bekannt geworden, dass Krabbenmänner Waffen führen.'),
  habitat_society = COALESCE(habitat_society, 'Krabbenmänner leben als einfache Jäger und Sammler und ernähren sich hauptsächlich von Aas und Algen. Ein Großteil des Tages jedes Krabbenmannes wird mit Jagen, Algenfiltern oder Plündern entlang der Küste verbracht. Krabbenmänner sammeln oft große Mengen Sand in ihre Mäuler, saugen das gesamte organische Material heraus und spucken faustgroße Pellets aus Sand und Schmutz aus. Diese gehärteten Pellets verraten die Anwesenheit eines nahen Krabbenmann-Baus.'),
  ecology         = COALESCE(ecology, 'Krabbenmann-Artefakte können manchmal gute Preise von Sammlern erzielen, obwohl sie oft zerbrechlich sind und leicht zerfallen, falls sie aus Pflanzen gemacht sind.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '4c6fa081-5dfb-4b36-8e2a-95d06b62efba' AND is_custom = FALSE;

-- Crawling Claw (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die sehr gefürchtete kriechende Klaue wird häufig als Wächter von jenen Magiern und Priestern eingesetzt, die das Geheimnis ihrer Erschaffung erlernt haben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn eine Klaue ein potentielles Opfer entdeckt, springt sie zum Angriff. Obwohl es nicht so aussehen mag, als wäre sie zu einer solchen Leistung imstande, ermöglicht ihr ihre große Stärke dies zu tun. Die maximale Entfernung, die eine Klaue springen kann, beträgt 4,6 m.'),
  habitat_society = COALESCE(habitat_society, 'Kriechende Klauen sind nichts weiter als die belebten Hände und Pfoten einst lebender Kreaturen. Als solche haben sie keine nennenswerte Kultur oder Gesellschaft. Trotzdem haben kriechende Klauen eine begrenzte Fähigkeit, miteinander zu kommunizieren. Dies erfolgt in Form einer grundlegenden telepathischen Verbindung zwischen allen Klauen einer einzelnen "Charge". Wann immer eine Klaue ein Opfer findet, bewegen sich alle anderen in der Gegend, die zur gleichen Zeit erschaffen wurden, herbei, um ihr zu helfen.'),
  ecology         = COALESCE(ecology, 'Kriechende Klauen können von jedem Magier oder Priester erschaffen werden, der Kenntnis der dafür erforderlichen Techniken besitzt. Zu Beginn muss der Erschaffer die abgetrennten Gliedmaßen sammeln, die belebt werden sollen. Die maximale Anzahl von Klauen, die zu einem beliebigen Zeitpunkt erschaffen werden kann, entspricht der Stufe der Person, die sie verzaubert. Die Hände (oder Pfoten) können entweder frisch, skelettartig oder in jedem Verwesungsstadium dazwischen sein.'),
  no_appearing    = COALESCE(no_appearing, '1-20')
WHERE id = '2afc8b7d-7c8e-45f7-9044-72f37e129f20' AND is_custom = FALSE;

-- Crocodile (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Das Krokodil ist ein großes, gefährliches Raubtierreptil, das in tropischen und subtropischen Gebieten heimisch ist. Es verbringt die meiste Zeit untergetaucht in Sümpfen, Flüssen oder anderen großen Gewässern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Stets gefräßig greifen hungrige Krokodile alles an, was essbar aussieht, einschließlich Menschen. Sie ziehen es vor, auf ihre Beute zu lauern (-2 Malus auf den Überraschungswurf des Gegners) und sind außergewöhnlich empfindlich für Bewegungen im Wasser. Es ist bekannt, dass sie schnell und lautlos zum Ufer schwimmen und einen Menschen packen, um ihn unter die Wasseroberfläche zu zerren. Sie greifen bevorzugt mit ihren kraftvollen Kiefern an, die 2W4 Schadenspunkte verursachen, und schlagen mit ihren Schwänzen für 1W12 Schadenspunkte zu. Krokodile kämpfen untereinander um jede Beute, die sie in ihren Kiefern packen, und reißen ihr Opfer manchmal in Stücke. Das Einzige, was ein Krokodil verlangsamen kann, ist Kälte. Sie werden langsam und träge (auf 50% ihrer normalen Bewegung reduziert), wenn die Temperatur unter 4°C fällt.'),
  habitat_society = COALESCE(habitat_society, 'Krokodile versammeln sich manchmal in großer Zahl, aber sie sind von Natur aus nicht gesellig und kooperieren nicht bei der Jagd. Sie haben gut verborgene Baue und schleppen ihre Beute oft in ihre Baue, bevor sie sie fressen. Wenn ein leckerer Bissen ihren Weg kreuzt, gerät eine Gruppe von Krokodilen in einen Fressrausch, wobei jedes versucht, einen Teil des Festmahls zu ergattern. Sie jagen fast täglich, hauptsächlich im Wasser, selten an Land. Ihre Geschmäcker sind vielfältig: Fische, Menschen, kleine Säugetiere, Wasservögel und sogar ein unvorsichtiger Löwe ist gelegentlich in ihre Fänge geraten. Hungrige Krokodile lassen manchmal Boote kentern, um zu sehen, was herausfällt.'),
  ecology         = COALESCE(ecology, 'Das Krokodil ist ein gewaltiger Jäger und hat wenig Konkurrenz um Nahrung von anderen Wasserkreaturen. Eines der wenigen Monster, die mit ihm konkurrieren können, ist die Drachenschildkröte. Selbst an den Flussufern hat es wenig von rivalisierenden Raubtieren zu befürchten; die meisten würden es vorziehen, sich nicht mit einem Krokodil anzulegen. Der einzige Jäger, den das Krokodil fürchten muss, ist der Mensch, der es wegen seiner zähen Haut jagt, die in schönes, glänzendes Leder verwandelt werden kann. Krokodile werden auch gejagt, um die Gefahr zu beseitigen, die sie für Gemeinden am Flussufer darstellen.'),
  no_appearing    = COALESCE(no_appearing, '3-24')
WHERE id = '8dd720a8-56e8-48f1-abf3-524abf428686' AND is_custom = FALSE;

-- Crustacean, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenkrebstiere sind eigenartige Mutationen von Krabben und Süßwasser-Flusskrebsen. Erstere bewohnen Salzwasserregionen, während letztere nur in Süßwasser zu finden sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Krabben sind stets hungrig und bevorzugen es, ihre Beute zu beschleichen (-3 Malus auf den Überraschungswurf des Gegners) und sie mit ihren Scheren zu packen, zu zerstückeln und zu fressen. Ein erfolgreicher Angriff mit den Scheren verursacht 2W4 Schadenspunkte. Sobald sie etwas Essbares gefangen haben, halten sie inne, um es zu fressen, außer sie werden angegriffen. Falls eine Krabbe ihre Mahlzeit in Frage stellt, versucht sie mit der Beute davonzuschwirren, möglicherweise in ihren Bau.'),
  habitat_society = COALESCE(habitat_society, 'Die Riesenkrabbe lebt an der Küste, durchsucht Strände nach Nahrung und wagt sich ins Wasser auf der Suche nach Fischen und anderen Wassertieren. Sie ist gut an diese Lebensweise angepasst, da sie sowohl Luft als auch Wasser atmen kann. Riesenkrabben fressen häufig große tote Fische und anderes Aas, das an die Küste gespült wird. Sie funktionieren gleichermaßen gut an Land und im Wasser. Riesenkrabben graben sich manchmal tagsüber in den Sand ein und tauchen nur bei Dämmerung und Morgendämmerung auf, um zu fressen. Zu diesen Zeiten ist der Strand nicht nur von den Riesenkrabben belebt, sondern auch von ihren winzigen Verwandten. Die Riesen können auch tagsüber und nachts jagen.'),
  ecology         = COALESCE(ecology, 'Die Riesenkrabbe erfüllt eine nützliche ökologische Funktion, indem sie die Meeresküsten von großem Aas befreit, das andernfalls verrotten würde. An der Küste wird sie von den ultimativen Räubern gejagt - Menschen und Halbmenschen - wegen ihres hervorragenden Fleisches und ihres harten chitinösen Panzers, der von manchen für die Herstellung von Rüstungen und Schilden geschätzt wird.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = 'f3706ebb-3389-4139-aee8-f7305438d022' AND is_custom = FALSE;

-- Crypt Thing (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gruftdinge sind seltsame untote Kreaturen, die manchmal Gräber, Grüfte und Leichname bewachen. Es gibt zwei Arten von Gruftdingen - ahnenhafte und beschworene. Die erstere Art sind „natürliche" Kreaturen, während die anderen von einem Magier oder Priester mindestens der 14. Stufe ins Dasein gerufen werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Gruftding existiert nur, um die Körper derer zu beschützen, die in seinem Bau zur letzten Ruhe gebettet wurden. Es handelt nur, um seine Gruft zu verteidigen. Sollten Grabräuber oder Vandalen versuchen einzudringen und die Heiligkeit seines Grabes zu entweihen, wird das Gruftding augenblicklich aktiv.'),
  habitat_society = COALESCE(habitat_society, 'Gruftdinge sind kein natürlicher Teil unserer Welt; sie haben keine organisierte Gesellschaft oder Kultur. Sie finden sich überall dort, wo Gräber und Grüfte liegen.'),
  ecology         = COALESCE(ecology, 'Das Gruftding ist kein Wesen dieser Welt und hat daher keine echte ökologische Nische. Es wird gemunkelt, dass das pulverisierte Mark aus den Knochen eines Gruftdings zur Herstellung eines Tranks der Untotenbeherrschung verwendet werden kann. Außerdem hat jeder, der die Knochen eines Gruftdings zur Herstellung von Pfeifen der Besessenheit verwendet, eine 80%ige Wahrscheinlichkeit, einen magischen Gegenstand zu erschaffen, der seinen Opfern einen Malus von -2 auf ihre Rettungswürfe auferlegt und doppelte normale Wirksamkeit besitzt, falls die Rettungswürfe fehlschlagen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '284a8820-f9cf-4b2a-bef7-336c33c53c5d' AND is_custom = FALSE;

-- Death Knight (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein Todesritter ist die schreckliche Verderbnis eines Paladins oder rechtschaffen guten Kriegers, der von den Göttern zu seiner furchtbaren Gestalt verflucht wurde als Strafe dafür, dass er den Ehrenkodex verraten hat, den er zu Lebzeiten befolgte.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Todesritter behält die Kampffertigkeiten, die er in seinem früheren Leben hatte. Da er wenig Rücksicht auf seine eigene Sicherheit nimmt und einen intensiven Hass auf die meisten lebenden Kreaturen hegt, ist er ein äußerst gefährlicher Gegner. Dennoch behält ein Todesritter einen Anschein des Stolzes, den er als guter Krieger besaß, und kämpft ehrenhaft: Er überfällt Gegner niemals von hinten, noch greift er an, bevor ein Gegner die Gelegenheit hatte, seine Waffe bereitzumachen. Kapitulation ist einem Todesritter unbekannt, und er wird nur verhandeln, wenn er spürt, dass sein Gegner entscheidende Informationen hat (wie das Schicksal eines ehemaligen Familienmitglieds).'),
  habitat_society = COALESCE(habitat_society, 'Todesritter sind ehemalige gute Krieger, die von den Göttern schuldig unverzeihlicher Verbrechen wie Mord oder Verrat befunden wurden. (Zum Beispiel ermordete Krinns Lord Soth, der berühmteste aller Todesritter, seine Frau, damit er eine Affäre mit einer Elfenfrau fortsetzen konnte.) Todesritter sind verflucht, in ihren ehemaligen Domänen zu verbleiben, gewöhnlich Burgen oder andere Festungen. Sie sind ferner dazu verdammt, ihr Verbrechen in einem Lied an jeder Nacht zu erinnern, in der der Mond voll ist; wenige Geräusche sind so furchteinflößend wie die eisige Melodie eines Todesritters, die durch die mondscheinbeleuchtete Landschaft hallt. Todesritter greifen wahrscheinlich jede Kreatur an, die ihre Lieder unterbricht oder in ihre Domänen eindringt.'),
  ecology         = COALESCE(ecology, 'Todesritter haben keine physiologischen Funktionen. Sie werden manchmal von Skelettkriegern, Lichs und anderen Untoten begleitet, die ihnen als Gehilfen dienen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '9aa11f9a-3004-4328-b6ef-1355ebec85a6' AND is_custom = FALSE;

-- Dinosaur I (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dinosaurier sind auf alternativen Existenzebenen oder sogar auf verlorenen Kontinenten zu finden. Die angegebenen Häufigkeitszahlen gelten für Gebiete, wo Dinosaurier normalerweise vorkommen; an allen anderen Orten sind sie bestenfalls sehr selten. Dinosaurier oder "schreckliche Echsen" sind Reptilien, die von urtümlichen Reptilien namens Thecodontier abstammen. Die zwei Arten von Dinosauriern sind Saurischia ("Echsenhüfter") und Ornithischia ("Vogelhüfter"), benannt nach Begriffen, die ihre Beckenstruktur beschreiben. Zu den Saurischia gehören die fleischfressenden Theropoden, hier vertreten durch den Tyrannosaurus, und die pflanzenfressenden Sauropoden, hier vertreten durch den Diplodocus. Zu den Saurischia gehören auch Ornithomimosaurier und die verwandten Dromaeosaurier, hier vertreten durch den Deinonychus.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dinosaurier scheinen eine Mischung aus endothermen ("warmblütigen") und exothermen ("kaltblütigen") Wesen zu sein. Sie regulieren ihre Körpertemperatur innerlich, sind aber auch etwas von externer Wärme abhängig. Obwohl sie an einem kalten Morgen langsam sein mögen, sind sie vielleicht nicht so langsam wie ein typisches Reptil.'),
  habitat_society = COALESCE(habitat_society, 'Dinosaurier können in fast jeder Art von Umgebung gefunden werden, außer Wüsten, hohen Bergen und gefrorenen Einöden. Sie haben keine Gesellschaft und wenig Familienleben, wobei die meisten Arten ihre Eier verlassen, bevor sie ausschlüpfen.'),
  ecology         = COALESCE(ecology, 'Gelehrte verstehen nicht, was Dinosaurier auf bestimmten Welten aussterben ließ, aber sie existieren in den "verlorenen Landen" auf mehreren Welten. Es mag Orte geben, wo Dinosaurier sich weiter zu verschiedenen Formen entwickelt haben; sie könnten Vorfahren moderner Echsenmenschen sein.'),
  no_appearing    = COALESCE(no_appearing, '2-5')
WHERE id = '4307cdce-f7f4-4374-90e2-88fff22cee3d' AND is_custom = FALSE;

-- Displacer Beast (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Das Scheintierwesen ist ein magisches Geschöpf, das einem Puma mit zwei mächtigen schwarzen Tentakeln ähnelt, die aus seinen Schultern wachsen. Sehr selten, bleiben sie fern von menschlichen Siedlungen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Das Scheintierwesen ist ein wilder, grausamer Geschöpf, das alle Lebensformen hasst. Äußerst aggressiv, wird das Scheintierwesen bei Sichtkontakt angreifen und seine Tentakel einsetzen, um seinen Opfern 2-8 (2W4) Schadenspunkte zuzufügen.'),
  habitat_society = COALESCE(habitat_society, 'Scheintierwesen sind Fleischfresser. Außer wenn sie Junge aufziehen, laufen sie gewöhnlich in Rudeln und hinterlassen eine grausame Schneise der Zerstörung. Sie hassen alles Leben und töten manchmal rein aus Vergnügen. So wild und bösartig sie auch sind, kämpfen Scheintierwesen jedoch niemals untereinander. Das Rudel ist eine gut geführte und höchst effiziente Tötungsmaschine. Wenn sie in Rudeln angetroffen werden, sind Scheintierwesen mehr als ein ebenbürtiger Gegner für viele große Geschöpfe und es ist bekannt, dass sie eine Mahlzeit aus Orks, Goblins und Menschenbanden gemacht haben. Jedes Geschöpf, das ihr Territorium betritt, wird als potentielle Beute betrachtet.'),
  ecology         = COALESCE(ecology, 'Scheintierwesen haben wenig von anderen großen Raubtieren zu befürchten, außer vielleicht Trollen oder Riesen. Einige Magier und Alchemisten schätzen ihre Häute für die Verwendung in bestimmten magischen Zubereitungen und bieten großzügige Belohnungen dafür. Die Augen eines Scheintierwesens sind hochgeschätzte, wenn auch seltene Glücksbringer unter Dieben, die glauben, dass sie den Träger vor Entdeckung schützen werden.'),
  no_appearing    = COALESCE(no_appearing, '2-5 (1d4+1)')
WHERE id = '98744640-137b-4aff-97a6-bdd37c276be3' AND is_custom = FALSE;

-- Dog (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kleiner als Wölfe variiert das Aussehen des wilden Hundes von Ort zu Ort. Die meisten erscheinen sehr wolfsähnlich, während andere das Aussehen eines Wolfes und eines Schakals zu kombinieren scheinen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wilde Hunde kämpfen als organisiertes Rudel. Sie bevorzugen kleines Wild und greifen Menschen und menschliche Siedlungen nur in Zeiten großen Hungers an. Der Biss eines wilden Hundes verursacht 1-4 Schadenspunkte.'),
  habitat_society = COALESCE(habitat_society, 'Wilde Hunde findet man fast überall. Sie laufen in Rudeln und werden vom dominanten Männchen angeführt. Das Rudel jagt normalerweise verschiedenes Wild und greift sogar Hirsche oder Antilopen an. Welpen werden im Frühling geboren. Wilde Hunde können gezähmt werden, wenn sie von ihrem Rudel getrennt werden.'),
  ecology         = COALESCE(ecology, 'Wilde Hunde sind Allesfresser, die normalerweise von einer Kombination aus Jagen und Sammeln leben.'),
  no_appearing    = COALESCE(no_appearing, '4-16 (4d4)')
WHERE id = '904b79ba-c126-49c7-bba6-5e57d6ef9ac0' AND is_custom = FALSE;

-- Dolphin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Delfine sind intelligente Meeressäugetiere.'),
  combat_tactics  = COALESCE(combat_tactics, 'Von Natur aus friedlich, greifen Delfine im Allgemeinen nur an, wenn sie bedroht werden. Außer wenn sie 2 zu 1 in der Unterzahl sind, greifen Delfine immer Haie an. Ob sie einen Feind angreifen oder ihre Schule verteidigen, Delfine kämpfen als organisierte Einheit und reagieren auf Befehle ihres Anführers. Sie kämpfen mit besonderer Vehemenz zum Schutz ihrer Jungen, und eine ausgewählte Anzahl von Delfinen kann manchmal ein Verzögerungsgefecht führen und sich selbst opfern, damit der Rest der Schule in Sicherheit schwimmen kann.'),
  habitat_society = COALESCE(habitat_society, 'Delfine sind vollständig fleischfressend und leben von einer Diät aus Fischen. Obwohl sie mehrere Minuten lang unter Wasser bleiben können, müssen sie regelmäßig zum Atmen an die Oberfläche. Anders als bei den meisten Säugetieren ist das Atmen bei Delfinen eine bewusste, nicht unbewusste Handlung; mit anderen Worten, sie müssen sich buchstäblich daran erinnern zu atmen. Neugeborene Delfine werden von ihren Müttern und einer weiblichen Delfin-Geburtshelferin zum Atmen an die Oberfläche gebracht. Delfine sind von Natur aus verspielt, gutmütig und rechtschaffen gut, sie verachten böse Kreaturen. Die meisten durchstreifen die Ozeane in Schulen von bis zu 20 Delfinen und schwimmen, wohin ihre Laune sie führt. Sie kämpfen niemals untereinander oder mit anderen Delfinarten. Delfine sind berühmt für die große Freude, die sie am Leben haben; beim Schwimmen führen sie oft blendende Wasserstunts auf und springen auf spektakuläre Weise in und aus dem Wasser. Sie spielen auch mit Gegenständen, die sie finden, und erfreuen sich an Spielen. Delfine folgen manchmal Schiffen und unterhalten Besatzung und Passagiere mit ihren Kapriolen.'),
  ecology         = COALESCE(ecology, 'Der Delfin ist sowohl Jäger als auch Gejagter in seiner Meereswelt. Haie und andere große böse Meereskreaturen jagen den Delfin mit Begeisterung. Trotz seiner vielen Feinde hat der Delfin viele ausgeprägte Vorteile, die es ihm ermöglichen zu überleben und sogar zu gedeihen. Er ist nicht nur ein starker, schneller Schwimmer, sondern seine Intelligenz und sein organisierter Lebensstil sind hocheffektive Verteidigungen gegen seine Feinde.'),
  no_appearing    = COALESCE(no_appearing, '2-20')
WHERE id = '85ef3210-4db4-476f-b4cf-d920b765daec' AND is_custom = FALSE;

-- Doppelganger (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Doppelgänger ist ein Meister der Nachahmung, der überlebt, indem er die Gestalt von Menschen, Halbmenschen und Humanoiden annimmt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dieses Monster ist imstande, die Gestalt jeder humanoiden Kreatur zwischen 1,2 und 2,4 m Größe anzunehmen. Der Doppelgänger wählt ein Opfer aus, kopiert dessen Gestalt und versucht dann, das Original zu töten und dessen Platz einzunehmen. Der Doppelgänger kann Gedankenlesen einsetzen und sein Opfer mit 90%iger Genauigkeit nachahmen, sogar dessen Kleidung und Ausrüstung duplizieren. Falls er nicht erfolgreich den Platz seines Opfers einnehmen kann, greift der Doppelgänger an und verlässt sich auf die entstehende Verwirrung, um ununterscheidbar von seinem Opfer zu werden. Ein Doppelgänger ist immun gegen Schlaf- und Bezauberungszauber und würfelt alle Rettungswürfe, als wäre er ein Kämpfer der 10. Stufe.'),
  habitat_society = COALESCE(habitat_society, 'Doppelgänger sollen künstliche Wesen sein, die vor langer Zeit von einem mächtigen Magier oder einer gottähnlichen Kreatur erschaffen wurden. Ursprünglich waren sie als Spione und Attentäter in einem uralten, höchst magischen Krieg gedacht. Ihr Schöpfer starb vor langer Zeit, aber sie leben weiter und arbeiten noch immer als Spione für böse Mächte, Diebe und Regierungen. Es ist sogar bekannt, dass sie als Attentäter arbeiten.'),
  ecology         = COALESCE(ecology, 'Doppelgänger sind raffinierte und gefährliche Parasiten, die von der Arbeit anderer leben. Sie müssen auch als clevere und effektive Spione und Attentäter gewertet werden, die in Machtpositionen politisches Chaos anrichten können. Böse Magier haben bei seltenen Gelegenheiten ganze Königreiche für kurze Zeiträume kontrolliert, indem sie einen König, Prinzen oder Ratsherren durch einen Doppelgänger ersetzten.'),
  no_appearing    = COALESCE(no_appearing, '3-12')
WHERE id = '6542721a-fd42-4579-9ed6-fa42584ba3f8' AND is_custom = FALSE;

-- Dracolich (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Dracolich ist eine untote Kreatur, die aus der unnatürlichen Verwandlung eines Drachen entsteht. Der geheimnisvolle Kult des Drachen beherrscht die mächtige Magie, die zur Erschaffung des Dracolich notwendig ist, obwohl auch andere Praktizierende existieren sollen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dracoliche sind immun gegen Bezauberung, Schlaf, Schwächung, Verwandlung, Kälte (magisch oder normal), Elektrizität, Lähmung, Wahnsinn oder Todes-Zauber oder -Symbole. Sie können nicht vergiftet oder gelähmt werden und nicht von Priestern vertrieben werden. Sie haben dieselbe Magieresistenz wie ihre ursprünglichen Formen, aber nur magische Angriffe von Magiern der 6. Stufe oder höher oder Angriffe von Monstern mit 6 oder mehr Trefferwürfeln können Dracoliche verletzen.'),
  habitat_society = COALESCE(habitat_society, 'Die Erschaffung eines Dracolich ist ein komplexer Prozess, der die Verwandlung eines bösen oder neutralen Drachen durch arkane magische Kräfte beinhaltet, deren berüchtigtste Praktizierende die Mitglieder des Kults des Drachen sind. Der Prozess ist normalerweise eine Zusammenarbeit zwischen dem bösen Drachen und Magiern und/oder Priestern, aber besonders mächtige Magier und Priester sind dafür bekannt, einen bösen Drachen zu zwingen, die Verwandlung gegen seinen Willen zu durchlaufen. Priesterversionen dieses Verfahrens sind den magischen Versionen ähnlich, die hier beschrieben werden, aber Priester brauchen noch immer die Hilfe eines Magiers für bestimmte Aspekte des Verwandlungsprozesses, während Magier niemals die Hilfe eines Priesters benötigen - obwohl sie manchmal willkommen ist. Insbesondere die Kirche von Tiamat arbeitet daran, die Anforderungen für magische Unterstützung zu eliminieren.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '41630ff4-7acc-4309-a46e-0a8b18e8ed11' AND is_custom = FALSE;

-- Dragon, Brown (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Braune Drachen, auch als große Wüstendrachen bekannt, wanderten aus der Wüste Raurin ab und frequentieren nun große Teile der Ödlande im östlichen Mulhorand. Braune Drachen sind wilde Bestien; obwohl sie intelligent sind, betrachten sie Menschen als Nahrung und finden es eigenartig, mit ihrer Mahlzeit zu sprechen. Sie haben keine Flügel und können nicht fliegen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Braune Drachen graben bevorzugt tiefe Gräben in den Sand und warten, bis Beute erscheint, um sie zu überfallen. Sie haben eine 90%ige Chance, die Schritte einer menschengroßen Kreatur auf dem Wüstensand aus einer Tiefe von bis zu 152,4 m zu hören.'),
  habitat_society = COALESCE(habitat_society, 'Braune Drachen findet man in Wüsten, oft nahe besiedelten Gebieten. Sie wohnen typischerweise in tiefen Bauten fast 0,3 m unter dem Sand, wo sie sich weitläufige Kammern aushöhlen.'),
  ecology         = COALESCE(ecology, 'Braune Drachen können Sand und andere mineralische Materialien verdauen, um sich über lange Zeiträume zu erhalten. Jedoch ist Fleisch die bevorzugte Nahrung, wobei Pferdefleisch ein besonderer Favorit ist.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'ea9d0799-e7bd-404d-aa7c-aa190144796f' AND is_custom = FALSE;

-- Dragon, Chromatic, Black (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schwarze Drachen sind tyrannisch, jähzornig und verabscheuen jede Art von Eindringen. Sie mögen düstere Umgebung, dichte Vegetation und bevorzugen Dunkelheit gegenüber Tageslicht. Obwohl sie nicht so intelligent sind wie andere Drachen, sind schwarze Drachen instinktiv gerissen und bösartig.'),
  combat_tactics  = COALESCE(combat_tactics, 'Schwarze Drachen ziehen es vor, ihre Ziele aus dem Hinterhalt anzugreifen und nutzen ihre Umgebung als Deckung. Ihre bevorzugten Ziele sind Menschen, die sie manchmal mehrere Minuten lang verfolgen, um ihre Stärke und ihren Reichtum einzuschätzen, bevor sie angreifen. Gegen eine Gruppe von Menschen oder eine beeindruckende Kreatur kann der Sumpf die Ziele schwächen, bevor der Drache in den Kampf eingreift. Schwarze Drachen setzen auch ihre Atemwaffe ein, bevor sie in den Nahkampf gehen. Beim Kampf in stark bewachsenen Sümpfen und Mooren versuchen schwarze Drachen, im Wasser oder am Boden zu bleiben; die zahlreichen Bäume und belaubten Baumkronen beschränken ihre Flugmanövrierfähigkeit. Wenn sie einem Gegner gegenüberstehen, der eine zu große Bedrohung darstellt, wird ein schwarzer Drache versuchen, außer Sichtweite zu fliegen, damit er keine Spuren hinterlässt, und sich in einem tiefen Teich oder Sumpf verstecken.'),
  habitat_society = COALESCE(habitat_society, 'Schwarze Drachen findet man in Sümpfen, Mooren, Regenwäldern und Dschungeln. Sie schwelgen in einer dampfigen Umgebung, wo Baumkronen das meiste Sonnenlicht herausfiltern, Schwärme von Insekten die Luft erfüllen und stagnierende, moosbewachsene Teiche in Hülle und Fülle liegen. Schwarze Drachen sind ausgezeichnete Schwimmer und genießen es, in den düsteren Tiefen von Sümpfen und Mooren zu lauern. Sie sind auch anmutige Flieger; jedoch ziehen sie es vor, nachts zu fliegen, wenn ihre gewaltigen Gestalten von der Dunkelheit des Himmels verborgen werden. Schwarze Drachen sind extrem selbstsüchtig, und die Mehrheit der angetroffenen wird allein sein. Wenn eine Familie schwarzer Drachen angetroffen wird, werden die Erwachsenen ihre Jungen beschützen. Falls es jedoch so aussieht, als wären die Leben der Erwachsenen in Gefahr, werden sie ihre Jungen im Stich lassen, um sich selbst zu retten.'),
  ecology         = COALESCE(ecology, 'Schwarze Drachen können fast alles fressen, obwohl sie es vorziehen, sich hauptsächlich von Fischen, Weichtieren und anderen aquatischen Kreaturen zu ernähren. Sie sind gern von Aalen angetan, besonders von den Riesenvarianten. Sie jagen auch nach rotem Fleisch, aber sie mögen es, es zu "pökeln", indem sie es tagelang in Teichen innerhalb ihres Baus liegen lassen, bevor sie es fressen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'e71ad1b4-9c1a-4435-be38-a3571152d95a' AND is_custom = FALSE;

-- Dragon, Chromatic, Blue (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Blaue Drachen sind extrem territorial und gefräßig. Sie lieben es, lange Stunden damit zu verbringen, Hinterhalte für Herdentiere und unvorsichtige Reisende vorzubereiten, und sie verbringen ebenso lange Stunden damit, über ihre Erfolge zu grübeln und ihre Trophäen zu bewundern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Blaue Drachen kämpfen bevorzugt aus der Distanz, damit ihre Gegner deutlich die volle Kraft ihrer Odemwaffe miterleben können und damit für sie selbst wenig oder gar keine Bedrohung besteht. Oft greifen blaue Drachen von direkt oben an oder graben sich unter den Sand ein, bis Gegner in 30,5 m Entfernung kommen. Ältere blaue Drachen werden ihre besonderen Fähigkeiten, wie trügerisches Gelände, in Verbindung mit diesen Taktiken einsetzen, um das Land zu verschleiern und ihre Chancen auf Überraschung zu erhöhen. Blaue Drachen werden nur aus einem Kampf fliehen, wenn sie schwer verwundet sind, da sie Rückzug als feige betrachten.'),
  habitat_society = COALESCE(habitat_society, 'Blaue Drachen findet man in Wüsten; trockenen, windgepeitschten Ebenen; und heißen, feuchten Ödlanden. Sie genießen das karge Gelände, weil es nur wenige Hindernisse gibt - nur gelegentliche Felsvorsprünge oder Dünen - die den Blick auf ihre Territorien unterbrechen. Sie verbringen Stunden damit, über ihre Gebiete zu blicken, nach Eindringlingen Ausschau zu halten und ihr Eigentum zu bewundern. Die meisten der angetroffenen blauen Drachen werden allein sein, weil sie ihre Territorien nicht mit anderen teilen wollen. Jedoch, wenn eine Familie angetroffen wird, wird der männliche Drache erbittert angreifen und sein Eigentum - seine Gefährtin und Jungen - beschützen. Der weibliche Drache wird ebenfalls in den Angriff eingreifen, wenn sich die Bedrohung als bedeutend erweist.'),
  ecology         = COALESCE(ecology, 'Blaue Drachen können fast alles verzehren und sind manchmal gezwungen, Schlangen, Echsen und Wüstenpflanzen zu fressen, um ihren großen Hunger zu stillen. Jedoch sind sie besonders von Herdentieren wie Kamelen angetan, und sie werden sich an Karawanen dieser Kreaturen überfressen, die sie mit einem Blitzschlag garen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '016bfcc1-3757-44d2-9e73-144007973401' AND is_custom = FALSE;

-- Dragon, Chromatic, Green (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Grüne Drachen sind schlecht gelaunt, gemein, grausam und rüde. Sie hassen Güte und gut gesinnte Kreaturen. Sie lieben Intrigen und streben danach, andere Waldkreaturen zu versklaven, wobei sie jene töten, die nicht kontrolliert oder eingeschüchtert werden können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Grüne Drachen beginnen Kämpfe mit wenig oder gar keiner Provokation und greifen Kreaturen jeder Größe an. Wenn die Zielkreatur den Drachen fasziniert oder schwer zu handhaben erscheint, wird der Drache die Kreatur verfolgen und seine Umgebung als Deckung nutzen, bis er den besten Zeitpunkt zum Angriff und die geeignetsten Taktiken bestimmt hat. Erscheint das Ziel bedrohlich, wird der Drache zuerst mit seiner Atemwaffe, magischen Fähigkeiten und Zaubern angreifen. Erscheint das Ziel jedoch schwach, wird der Drache seine Anwesenheit schnell bekannt machen, da er es genießt, Terror in seinen Zielen hervorzurufen. Wenn der Drache dieses Spiel satt hat, wird er die Kreatur mit seinen körperlichen Angriffen niederstrecken, damit der Kampf länger dauert und die Qual der Kreatur verlängert wird.'),
  habitat_society = COALESCE(habitat_society, 'Grüne Drachen findet man in subtropischen und gemäßigten Wäldern, je älter der Wald und größer die Bäume, desto besser. Die Anblicke und Gerüche der Wälder gefallen dem Drachen, und er betrachtet den gesamten Wald oder die Wälder als sein Territorium. Manchmal geht der Drache eine Beziehung mit anderen bösen waldlebenden Kreaturen ein, die den Drachen über die Geschehnisse im Wald und der Umgebung informieren im Austausch für ihr Leben. Wenn ein grüner Drache in einem Wald an einem Berghang lebt, wird er versuchen, Hügelriesen zu versklaven, die der Drache als seinen größten Feind betrachtet. Ein grüner Drache macht seinen Bau in unterirdischen Kammern tief unter seinem Wald.'),
  ecology         = COALESCE(ecology, 'Obwohl bekannt ist, dass grüne Drachen praktisch alles fressen, einschließlich Sträucher und kleine Bäume, wenn sie hungrig genug sind, schätzen sie besonders Elfen. Wenn der Wald an einem Berghang liegt, werden Hügelriesen die jüngeren Drachen jagen, die sie als Delikatesse betrachten.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '737b66d6-8137-42f4-bc8d-3cded31e17e3' AND is_custom = FALSE;

-- Dragon, Chromatic, Red (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rote Drachen sind die habgierigsten und gierigsten aller Drachen, die unaufhörlich danach streben, ihre Schatzhörter zu vergrößern. Sie sind von ihrem Reichtum besessen und prägen sich ein Inventar ein, das bis zum letzten Kupferstück genau ist. Sie sind außergewöhnlich eitel und selbstbewusst und betrachten sich nicht nur anderen Drachen, sondern allem anderen Leben im Allgemeinen als überlegen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Da rote Drachen so selbstbewusst sind, halten sie niemals inne, um einen Gegner einzuschätzen. Wenn sie ein Ziel bemerken, treffen sie eine spontane Entscheidung, ob sie angreifen, wobei sie eine von vielen "perfekten" Strategien verwenden, die sie vorher in der Einsamkeit ihrer Baue ausgearbeitet haben. Wenn die Kreatur klein und unbedeutend erscheint, wie etwa ein ungepanzerter Mann, wird der Drache landen, um mit seinen Klauen und seinem Biss anzugreifen, da er die Kreatur nicht mit seiner Atemwaffe vernichten möchte, weil jeder Schatz von den Flammen verschlungen werden könnte. Jedoch wird ein roter Drache, wenn er auf eine Gruppe gepanzerter Männer trifft, seine Atemwaffe, besonderen Fähigkeiten und Zauber (falls er alt genug ist, um sie zu haben) einsetzen, bevor er landet.'),
  habitat_society = COALESCE(habitat_society, 'Rote Drachen können auf großen Hügeln oder auf ragenden Bergen gefunden werden. Von einer hohen Warte aus überblicken sie hochmütig ihr Territorium, das sie als alles betrachten, was von ihrer Position aus gesehen werden kann. Sie bevorzugen es, in großen Höhlen zu hausen, die tief in die Erde hineinreichen.'),
  ecology         = COALESCE(ecology, 'Rote Drachen sind Fleischfresser, obwohl sie in der Lage sind, fast alles zu verdauen. Ihr Lieblingsfutter ist eine Jungfrau jedweder menschlichen oder halbmenschlichen Rasse. Manchmal sind die Drachen imstande, wichtige Dorfbewohner zu bezaubern, damit diese ihnen regelmäßig Jungfrauen opfern.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'a1fbec0d-d22c-44b5-a80e-1cd1991a4ef8' AND is_custom = FALSE;

-- Dragon, Chromatic, White (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Weiße Drachen, die kleinsten und schwächsten der bösen Drachen, sind schwerfällig, aber effiziente Jäger. Sie sind impulsiv, bösartig und animalisch, neigen dazu, nur die Bedürfnisse und Emotionen des Augenblicks zu berücksichtigen und haben weder Voraussicht noch Reue. Trotz ihrer geringen Intelligenz sind sie ebenso gierig und böse wie die anderen bösen Drachen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Unabhängig von der Größe eines Ziels besteht die bevorzugte Angriffsmethode eines weißen Drachen darin, seine Atemwaffe und Sonderfähigkeiten einzusetzen, bevor er zum Nahkampf übergeht. Diese Taktik wirkt manchmal zum Nachteil des Drachen, da er seine Atemwaffe an kleinerer Beute erschöpfen kann und dann einem größeren Wesen gegenübersteht, das er körperlich angreifen muss. Wenn ein weißer Drache Kreaturen im Wasser verfolgt, wie Eisbären oder Robben, wird er sie in ihrem Element im Nahkampf bekämpfen und mit seinen Klauen und seinem Biss kämpfen.'),
  habitat_society = COALESCE(habitat_society, 'Weiße Drachen leben in kühlen oder kalten Regionen und bevorzugen Länder, wo die Temperatur selten über den Gefrierpunkt steigt und Eis und Schnee immer den Boden bedecken. Wenn die Temperaturen zu warm werden, werden die Drachen träge. Weiße Drachen sonnen sich in den eisigen Winden, die über die Landschaft peitschen, und sie wälzen sich und spielen in tiefen Schneehaufen.'),
  ecology         = COALESCE(ecology, 'Obwohl weiße Drachen, wie alle anderen Drachen, in der Lage sind, fast alles zu fressen, sind sie sehr wählerisch und verzehren nur Nahrung, die gefroren wurde. Normalerweise, nachdem ein Drache eine Kreatur mit seiner Atemwaffe getötet hat, wird er sich daran machen, sie zu verschlingen, während der Kadaver noch steif und eisig ist. Er wird andere Beute in Schneehaufen vergraben, bis sie angemessen gefroren sind.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'ec697d78-9c4b-4857-a350-4507a9b33fd7' AND is_custom = FALSE;

-- Dragon, Deep (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Tiefendrachen sind an der Oberfläche kaum bekannt. Sie sind die Jäger der Schattenlande. Verschlagen und geduldig stellen sie ihr Überleben, gefolgt von ihrer Jagdfreude, über alles andere. Tiefendrachen sammeln sorgfältig Schätze und verstecken sie in verschiedenen Verstecken, die mit Fallen und Magie bewacht werden. Sie können die meisten magischen Gegenstände benutzen und behalten jene, die sie erbeuten, für den persönlichen Gebrauch.'),
  combat_tactics  = COALESCE(combat_tactics, 'Tiefendrachen graben sich durch den Boden und kämpfen mit ihren mächtigen, steinzerreißenden Klauen. Sie lieben es zu kämpfen und Beute durch die lichtlosen Höhlen der Schattenlande zu jagen, wobei sie ihre verschiedenen Formen einsetzen. In Schlangenform haben sie RK 6, BW 3, Fl 1(S), Schw 3,3, verlieren Klauenangriffe, erhalten aber einen Umschlingungsangriff (Angriffswurf erforderlich, verursacht 3W8 Schadenspunkte pro Runde, behindert Bewegung, Zauberwirken und verursacht -1 auf Angriffswürfe und 1 Punkt RK-Malus).'),
  habitat_society = COALESCE(habitat_society, 'Tiefendrachen durchstreifen die Schattenlande. Sie sind große Erforscher und wagen sich sogar (besonders wenn sie junge Erwachsene sind) von Zeit zu Zeit an die Oberfläche - besonders um gestohlene Schätze zurückzuholen, sich an Feinden zu rächen und Magie zu erbeuten oder zu stehlen.'),
  ecology         = COALESCE(ecology, 'Es ist bekannt, dass Tiefendrachen fast alles fressen, aber sie schätzen besonders das Fleisch von Muscheln, Fischen, Kuo-Toa und Aboleth. Sie betrachten Mantelwesen und Gedankenschinder als gefährliche Rivalen in den Schattenlanden. Tiefendrachen meiden Konfrontationen mit anderen Drachen und kämpfen niemals gegen andere ihrer Art oder bestehlen sie.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '1ed8b61a-70e9-4075-8969-2be5ec32f2fd' AND is_custom = FALSE;

-- Dragon, Gem, Amethyst (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: detonieren, Kraft projizieren, Telekinese; Andachten: Körper kontrollieren, Trägheitsbarriere, molekulare Erregung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Amethystdrachen ziehen Verhandlungen dem Kampf vor. Wenn Verhandlungen schlecht verlaufen, greift der Drache zuerst mit seiner Atemwaffe an, dann mit Psionik und Zaubern. Sie verstecken sich nie oder versuchen einen Hinterhalt. Amethystdrachen betrachten Rückzug als unehrenhaft, tun es aber, wenn sie dem Tod gegenüberstehen.'),
  habitat_society = COALESCE(habitat_society, 'Amethystdrachen leben an den Ufern abgelegener Bergseen und -tümpel, manche in Höhlen unter dem Wasser. Sie sind gute Eltern, glauben aber, dass ihre Jungen für sich selbst sorgen sollten, sobald sie junge Erwachsene werden. Amethystdrachen mögen rote und weiße Drachen nicht und betrachten silberne und kupferne Drachen als töricht.'),
  ecology         = COALESCE(ecology, 'Amethystdrachen fressen bevorzugt Fisch und eine große Anzahl von Edelsteinen. Sie sind nicht von Natur aus Feinde irgendeiner Lebensform.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'c904f43f-48ef-4b5d-8109-3997466b3d79' AND is_custom = FALSE;

-- Dragon, Gem, Crystal (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Hellhören, Hellsehen, Präkognition; Hingabe: beliebig.'),
  combat_tactics  = COALESCE(combat_tactics, 'Kristalldrachen bevorzugen Unterhaltung stark gegenüber Kampf und setzen oft früh in jedem Gespräch Person bezaubern ein. Sie verstecken sich anfangs nicht, aber falls Besucher feindselig werden, zieht sich ein Kristalldrache sofort zurück, um seine Feinde mit seinen besonderen Fähigkeiten zu beobachten und einen Angriff zu planen. Oft setzt er zuerst seine Atemwaffe ein, um Feinde zu schwächen und zu verwirren. Zauber und andere Fähigkeiten werden nach Bedarf eingesetzt, wobei Klauen und Biss das letzte Mittel sind.'),
  habitat_society = COALESCE(habitat_society, 'Kristalldrachen bevorzugen kalte, offene Gebiete mit klarem Himmel und schauen gerne zu den Sternen. Es ist bekannt, dass sie Schneefestungen bauen, schöne Schneeskulpturen erschaffen und Schneebälle auf verschiedene Ziele werfen. Sie sind lebenslustig und schelmisch. Kristalldrachen sind einigermaßen gute Eltern, wenn auch etwas verantwortungslos.'),
  ecology         = COALESCE(ecology, 'Kristalldrachen bevorzugen Edelsteine und Metallerze vor allen anderen Nahrungsmitteln.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '7d45eee7-f32e-4b88-8dc9-188e05362261' AND is_custom = FALSE;

-- Dragon, Gem, Emerald (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Aura-Sicht, Objektlesung, Präkognition; Hingaben: Rundumsicht, Kampfgeist, Gefahrensinn.'),
  combat_tactics  = COALESCE(combat_tactics, 'Smaragddrachen errichten normalerweise Fallen und Alarmanlagen um ihre Baue, um sie vor Besuchern zu warnen. Sie verstecken sich oft vor Eindringlingen, nutzen besondere Fähigkeiten zur Beobachtung und kommen selten heraus, um zu sprechen. Wenn Eindringlinge angreifen oder sich dem Schatz des Drachen nähern, gräbt sich der Drache darunter ein, um seine Opfer zu überraschen, dann setzt er Atemwaffe und Klauen ein und versucht, so viele wie möglich schnell kampfunfähig zu machen. Wenn er überlegenen Streitkräften gegenübersteht, zieht sich der Drache zurück und wartet notfalls Jahre auf Rache.'),
  habitat_society = COALESCE(habitat_society, 'Smaragddrachen sind zurückgezogen lebend und errichten ihre Baue in den Kegeln erloschener oder selten aktiver Vulkane. Diese Drachen sind beschützende Eltern und bevorzugen es, dass ihre Jungen so lange wie möglich im Bau bleiben, um sich gegenseitig zu schützen. Smaragddrachen leben manchmal in der Nähe von Saphirdrachen und sie fürchten die gefräßige Gier der Roten Drachen.'),
  ecology         = COALESCE(ecology, 'Smaragddrachen fressen alles, bevorzugen aber Echsen und Riesen. Sie sind aktiv feindselig gegenüber Feuerriesen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '5dcdf672-9789-41c0-9eb6-921c69d412d3' AND is_custom = FALSE;

-- Dragon, Gem, Sapphire (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Hellhören, Hellsehen; Hingaben: Richtung erkennen, radiale Navigation.'),
  combat_tactics  = COALESCE(combat_tactics, 'Saphirdrachen beobachten Eindringlinge im Allgemeinen, bevor sie entscheiden, was sie mit ihnen tun sollen, es sei denn, bekannte Feinde wie Drow oder Zwerge sind anwesend. Wenn andere nicht aktiv feindselig sind, versucht der Drache Gespräche und Zaubergebrauch, um ihre Absichten zu bestimmen und sie zum Gehen zu überreden. Wenn der Drache oder sein Schatz bedroht wird, greift er sofort mit Atemwaffe, Zaubern und körperlichen Angriffen an. Er nutzt Psionik oder andere besondere Fähigkeiten zur Flucht, wenn sein Leben in Gefahr ist.'),
  habitat_society = COALESCE(habitat_society, 'Saphirdrachen leben tief unter der Erde und platzieren ihre Schätze oft in Höhlen, die nur durch Magie oder Psionik zugänglich sind. Sie teilen manchmal ihr Territorium mit Smaragddrachen.'),
  ecology         = COALESCE(ecology, 'Saphirdrachen betrachten Riesenspinnen als große Delikatesse und jagen sie oft. Tiefendrachen, Drow, Zwerge, Gedankenschinder und Aboleth sind große Feinde der Saphirdrachen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '0bcee064-db60-4dc7-919d-cef062cb99a0' AND is_custom = FALSE;

-- Dragon, Gem, Topaz (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaft: Telekinese; Hingaben: Objekt beleben, Winde kontrollieren, Molekulare Manipulation, Erweichen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Topazdrachen mögen keine Eindringlinge, vermeiden aber Kampf und führen oft Gespräche, um den Einsatz von Psionik oder Magie zu verbergen. Wenn Eindringlinge feindlich sind oder der Drache ihrer überdrüssig wird, greift er an, wenn möglich zuerst psionisch, und setzt Zauber nach Bedarf ein. Sie haben Freude daran, Zähne und Klauen zu verwenden, und heben sich ihre Atemwaffe normalerweise auf, bis sie verwundet sind. Der Drache mag sich ergeben, um Zeit zu gewinnen, und zieht sich zurück, wenn er stark bedroht wird. Gewöhnlich führt er einen oder mehrere Scheinrückzüge aus und versucht, zurückzukehren und mit Überraschung anzugreifen.'),
  habitat_society = COALESCE(habitat_society, 'Topazdrachen leben am Meer und bauen oder beanspruchen oft Höhlen unterhalb der Wasserlinie; sie halten ihre Höhlen vollständig trocken. Diese Drachen sonnen sich gerne auf felsigen Vorsprüngen und genießen Wind und Gischt. Sie mögen Wasser wenig und schwimmen nur zum Jagen oder Angreifen. Sie sind bestenfalls gleichgültige Eltern und verlassen ihre Jungen, um sich selbst zu schützen. Sie mögen Bronzedrachen nicht und greifen sie bei Sichtung an.'),
  ecology         = COALESCE(ecology, 'Topazdrachen bevorzugen Fisch und andere aquatische Kreaturen als Nahrung, besonders Riesenkraken.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '244e6dd8-29f9-4f68-8542-2209215acdbc' AND is_custom = FALSE;

-- Dragon, Metallic, Brass (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Messingdrachen sind große Schwätzer, aber nicht besonders gute Gesprächspartner. Sie sind egozentrisch und oft grob. Sie verfügen oft über nützliche Informationen, aber geben diese nur preis, nachdem sie viele Male vom Thema abgeschweift sind und nachdem sie Andeutungen gemacht haben, dass ein Geschenk geschätzt würde.'),
  combat_tactics  = COALESCE(combat_tactics, 'Messingdrachen reden lieber als zu kämpfen. Wenn eine intelligente Kreatur versucht, einen Messingdrachen zu verlassen, ohne ausführlich mit ihm zu sprechen, könnte der Drache einen Anfall von Verärgerung bekommen und versuchen, ein Gespräch mit Suggestion zu erzwingen oder indem er dem Opfer eine Dosis Schlafgas verabreicht. Falls das Opfer einschläft, erwacht es und stellt fest, dass es unter dem Drachen eingeklemmt oder bis zum Hals im Sand vergraben ist, bis der Drang des Drachen nach Smalltalk gestillt ist. Vor dem Nahkampf erzeugen Messingdrachen eine Staubwolke mit Staubteufel oder Winde kontrollieren, dann greifen sie an oder schnappen zu. Messingdrachen nutzen oft Temperatur kontrollieren, um Hitze zu erzeugen und ihre Gegner zu belästigen. Wenn sie echter Gefahr gegenüberstehen, fliegen jüngere Messingdrachen außer Sichtweite und verstecken sich dann durch Eingraben. Ältere Drachen verschmähen diese List.'),
  habitat_society = COALESCE(habitat_society, 'Messingdrachen findet man in trockenen, warmen Klimazonen; von Sandwüsten bis zu trockenen Steppen. Sie lieben intensive, trockene Hitze und verbringen die meiste Zeit damit, in der Sonne zu baden. Sie nisten in hohen Höhlen, vorzugsweise nach Osten ausgerichtet, wo die Sonne die Felsen erwärmen kann, und ihre Territorien enthalten immer mehrere Stellen, wo sie sich sonnen und unwissende Reisende in Gespräche locken können.'),
  ecology         = COALESCE(ecology, 'Wie andere Drachen können und werden Messingdrachen fast alles essen, wenn die Notwendigkeit entsteht. In der Praxis jedoch essen sie sehr wenig. Sie können Nahrung aus dem Morgentau gewinnen, einer seltenen Kostbarkeit in ihrem Lebensraum, und wurden dabei gesehen, wie sie ihn vorsichtig mit ihren langen Zungen von Pflanzen ableckten.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '071fedc3-323c-46a0-b96e-c347fb42c451' AND is_custom = FALSE;

-- Dragon, Metallic, Bronze (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Bronzedrachen sind neugierig und mögen Menschen und Halbmenschen. Sie erfreuen sich daran, sich in kleine, freundliche Tiere zu verwandeln, damit sie Menschen und Halbmenschen, besonders Abenteurer, unaufdringlich beobachten können. Bronzedrachen gedeihen bei einfachen Herausforderungen wie Rätseln und harmlosen Wettkämpfen. Sie sind von Kriegsführung fasziniert und werden sich eifrig einer Armee anschließen, wenn die Sache gerecht und die Bezahlung gut ist.'),
  combat_tactics  = COALESCE(combat_tactics, 'Bronzedrachen mögen es nicht, Kreaturen mit tierischer Intelligenz zu töten und würden sie lieber bestechen (vielleicht mit Futter) oder sie mit Abstoßung vertreiben. Wenn sie intelligenten Gegnern gegenüberstehen, nutzen Bronzedrachen ihre GSP-Fähigkeit, um die Absichten ihrer Gegner zu erfahren. Beim Angriff blenden sie ihre Gegner mit Nebelwand und stürmen dann vor. Oder, falls sie fliegen, werden sie Gegner packen. Beim Kampf unter Wasser nutzen sie Luftiges Wasser, um die Wirksamkeit ihrer Atemwaffen zu erhalten und rein aquatische Gegner fernzuhalten. Gegen Boote oder Schiffe beschwören sie einen Sturm oder nutzen ihren Schwanzschlag, um die Rümpfe der Schiffe zu zertrümmern. Falls der Drache zu Milde neigt, könnten sich seefahrende Gegner lediglich in einer Flaute, nebelgebunden oder mit gebrochenen Masten wiederfinden.'),
  habitat_society = COALESCE(habitat_society, 'Bronzedrachen mögen es, in der Nähe von tiefem Süß- oder Salzwasser zu sein. Sie sind gute Schwimmer und besuchen oft die Tiefen, um sich abzukühlen oder um nach Perlen oder Schätzen von gesunkenen Schiffen zu jagen. Sie bevorzugen Höhlen, die nur vom Wasser aus zugänglich sind, aber ihre Baue sind immer trocken - sie legen keine Eier, schlafen nicht und lagern keine Schätze unter Wasser.'),
  ecology         = COALESCE(ecology, 'Bronzedrachen fressen Wasserpflanzen und einige Sorten von Meeresfrüchten. Sie schätzen besonders Haifischfleisch. Sie speisen auch gelegentlich eine Perle und können, wie andere Drachen, im Notfall fast alles fressen. Böse, amphibische Meereskreaturen (besonders Sahuagin), die ihre luftgefüllten Baue überfallen können, sind ihre größten Feinde.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'e6e6cf4f-d456-4ba1-8f2b-b81c704620a0' AND is_custom = FALSE;

-- Dragon, Metallic, Copper (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kupferdrachen sind unverbesserliche Schelme, Witzeerzähler und Rätselsteller. Sie sind stolz und keine guten Verlierer, obwohl sie einigermaßen gute Gewinner sind. Sie sind besonders selbstsüchtig und für ihre Gesinnung gierig und haben eine fast neutrale Einstellung, was Reichtum angeht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Kupferdrachen verspotten und ärgern gerne ihre Gegner, in der Hoffnung, dass sie aufgeben oder wütend werden und töricht handeln. Früh in einer Begegnung wird ein Kupferdrache von einer Seite eines Gegners zur anderen springen und auf unzugänglichen oder senkrechten Steinoberflächen landen. Wenn es keine solchen Plätze um den Bau eines Drachens gibt, wird der Drache sie im Voraus mit Stein formen, Erde bewegen und Steinwand erschaffen. Ein wütender Kupferdrache wird seine Gegner mit Fels zu Schlamm einschließen und Opfer, die dem Schlamm entkommen, mit Tritten hinein zwingen. Sobald Gegner im Schlamm gefangen sind, wird der Drache sie mit einer Steinwand zerquetschen oder sie packen und in die Luft tragen. Beim Kampf gegen fliegende Gegner wird ein Drache seine Feinde in enge, steinige Schluchten locken, wo er seine Spinnenklettern-Fähigkeit nutzen kann, um zu versuchen, den Feind dazu zu bringen, mit den Wänden zu kollidieren.'),
  habitat_society = COALESCE(habitat_society, 'Kupferdrachen mögen trockene, felsige Hochländer und Berge. Sie bauen ihre Höhlen in schmalen Grotten und verbergen oft die Eingänge mit Erde bewegen und Stein formen. Innerhalb des Baus konstruieren sie gewundene Labyrinthe mit offenen Decken. Diese ermöglichen es dem Drachen, über Eindringlinge hinwegzufliegen oder zu springen, die sich durch das Labyrinth kämpfen.'),
  ecology         = COALESCE(ecology, 'Kupferdrachen sind entschlossene Jäger, der gute Sport, den eine Jagd bietet, ist mindestens genauso wichtig wie die Nahrung, die sie bekommen. Sie sind dafür bekannt, fast alles zu fressen, einschließlich Metallerze. Jedoch schätzen sie riesige Skorpione und andere große giftige Kreaturen (sie sagen, das Gift schärft ihren Verstand). Das Verdauungssystem des Drachens kann das Gift sicher verarbeiten, obwohl injizierte Gifte sie normal beeinträchtigen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'de365c54-39e5-4a5d-85c8-e7b71ea96bdb' AND is_custom = FALSE;

-- Dragon, Mercury (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Quecksilberdrachen sind schnelle, hochmanövrierfähige Kreaturen mit verhältnismäßig kleinen Körpern und langen Schwänzen. Obwohl gut in der Gesinnung, sind sie sehr launisch und treffen und ändern Entscheidungen häufig.'),
  combat_tactics  = COALESCE(combat_tactics, 'Quecksilberdrachen sind im Kampf genauso unberechenbar wie in jeder anderen Situation. Sie können verhandeln, sofort angreifen oder vielleicht den Kampf ganz vermeiden. Sie greifen niemals rechtschaffen gesinnte Kreaturen an, es sei denn, sie werden stark provoziert.'),
  habitat_society = COALESCE(habitat_society, 'Quecksilberdrachen sind von Natur aus Einzelgänger. Ihr Paarungsverhalten ist ungehemmt, vergnügungssüchtig und generell verantwortungslos. Wenn jedoch ein Weibchen schwanger wird, übernehmen die Schutzinstinkte des Männchens. Quecksilberdrachen beschützen ihre Nachkommen sehr stark und würden ihr Leben geben, um sie zu retten. Nachkommen bleiben normalerweise bei ihren Eltern, bis sie die jugendliche Alterskategorie erreichen.'),
  ecology         = COALESCE(ecology, 'Quecksilberdrachen fressen alles, aber sie ziehen es vor, sich von Metallerzen zu ernähren. Obwohl sie keine Giftangriffe haben, ist das Fleisch von Quecksilberdrachen hochgiftig.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'eea1341b-d665-4a91-b5ce-5a6ed702e469' AND is_custom = FALSE;

-- Dragon, Metallic, Gold (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Golddrachen sind weise, besonnen und wohlwollend. Sie begeben sich oft auf selbst auferlegte Questen, um das Gute zu fördern, und lassen sich nicht leicht davon abbringen. Sie hassen Ungerechtigkeit und Falschspiel. Ein Golddrache nimmt häufig menschliche oder tierische Gestalt an und wird normalerweise in Verkleidung angetroffen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Golddrachen verhandeln normalerweise vor dem Kampf. Wenn sie sich mit intelligenten Geschöpfen unterhalten, setzen sie Lüge entdecken- und Edelsteine entdecken-Zauber ein, um die Oberhand zu gewinnen. Im Kampf nutzen sie schnell Segen und Glücksbonus. Ältere Drachen verwenden den Glücksbonus zu Beginn jeden Tages, wenn die Dauer einen Tag oder mehr beträgt. Sie machen im Kampf ausgiebig Gebrauch von Zaubern. Zu ihren Favoriten gehören Schlaf, Stinkende Wolke, Verlangsamung, Feuerschild, Giftwolke, Kugel der Unverletzlichkeit, Verzögerte Explosion, Feuerball und Labyrinth.'),
  habitat_society = COALESCE(habitat_society, 'Golddrachen können überall leben. Ihre Baue sind abgeschieden und immer aus solidem Stein gebaut, entweder Höhlen oder Burgen. Diese haben normalerweise treue Wachen: entweder Tiere, die zum Gelände passen, oder Sturm- oder gute Wolkenriesen. Die Riesen dienen normalerweise als Wachen durch ein gegenseitiges Verteidigungsabkommen.'),
  ecology         = COALESCE(ecology, 'Golddrachen können fast alles fressen, jedoch ernähren sie sich normalerweise von Perlen oder kleinen Edelsteinen. Golddrachen, die Perlen und Edelsteine von guten oder neutralen Geschöpfen erhalten, werden den Schenkenden normalerweise wohlwollend gesinnt sein, solange das Geschenk nicht als plumpe Bestechung dargebracht wird. Im letzteren Fall wird der Drache das Geschenk annehmen, aber zynisch auf alle Bitten reagieren, die der Geber äußert.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = 'c8d0744e-5ff6-4ba5-a423-3ccc0cb67672' AND is_custom = FALSE;

-- Dragon, Mist (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Nebeldrachen sind Einzelgänger und philosophisch veranlagt. Ihre liebste Beschäftigung ist es, ruhig zu sitzen und zu denken. Sie hassen es, gestört zu werden, und mögen keine Unterhaltungen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Nebeldrachen versuchen, Begegnungen zu vermeiden, indem sie Nebelgestalt annehmen. Im Kampf setzen sie schnell ihre Atemwaffen ein, nehmen dann Nebelgestalt an und verstecken sich im Dampf, wo sie einen Zauberangriff starten.'),
  habitat_society = COALESCE(habitat_society, 'Nebeldrachen leben in der Nähe von Wasserfällen, Stromschnellen, Küstenlinien oder wo Niederschlag häufig und stark ist. Ihre Baue sind meist große natürliche Höhlen oder Grotten, die nebelverhangen und feucht sind. Im Wald lebende Nebeldrachen ärgern sich sehr über die Vorstöße der Grünen Drachen, bevor sie alle Geduld verlieren und einen Generalangriff starten. Nebeldrachen könnten Bronzedrachen als Nachbarn haben. Dies führt jedoch selten zu Konflikten, da beide Drachen zufrieden sind, wenn sie einander in Ruhe lassen.'),
  ecology         = COALESCE(ecology, 'Nebeldrachen können fast alles fressen, einschließlich holziger Pflanzen und sogar Schlamm. Dennoch beziehen sie den Großteil ihrer Nahrung direkt aus natürlichem Nebel oder Sprühregen. Sie liegen oft an nebligen oder dunsigen Orten, denken nach und sonnen sich in der Feuchtigkeit.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '004afbcb-f0ce-4a1e-916f-8c74c20ada58' AND is_custom = FALSE;

-- Dragon, Metallic, Silver (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Silberdrachen sind gütig und hilfsbereit. Sie unterstützen gerne gutgesinnte Kreaturen, wenn deren Not aufrichtig ist. Sie nehmen oft die Gestalt freundlicher alter Männer oder schöner Jungfrauen an, wenn sie mit Menschen verkehren.'),
  combat_tactics  = COALESCE(combat_tactics, 'Silberdrachen sind nicht gewalttätig und vermeiden Kämpfe, außer wenn sie hochgradig bösen oder aggressiven Feinden gegenüberstehen. Falls nötig, nutzen sie Federfall, um Geschosse abzuwehren, die auf sie abgefeuert werden. Sie setzen Nebelwand oder Wetter beherrschen ein, um Gegner zu blenden oder zu verwirren, bevor sie Nahkampfangriffe durchführen. Wenn sie zornig sind, nutzen sie Schwerkraft umkehren, um Feinde hilflos in die Luft zu schleudern, wo sie geschnappt werden können. Gegen fliegende Gegner versteckt sich ein Silberdrache in Wolken (oft erschafft er welche mit Wetter beherrschen an klaren Tagen), bleibt dort mittels Wolkenwandeln und springt dann zum Angriff, wenn er im Vorteil ist.'),
  habitat_society = COALESCE(habitat_society, 'Silberdrachen bevorzugen Luftbaue auf abgelegenen Berggipfeln oder inmitten der Wolken selbst. Wenn sie in Wolken hausen, gibt es immer einen verzauberten Bereich mit festem Boden zum Eierlegen und zur Schatzlagerung.'),
  ecology         = COALESCE(ecology, 'Silberdrachen bevorzugen menschliche Nahrung und können unbegrenzt von solcher Kost leben.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '17fe4c9b-cc38-43f8-ae49-3b920c777843' AND is_custom = FALSE;

-- Dragon, General Information (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Drachen sind eine uralte, geflügelte Echsenrasse. Sie sind bekannt und gefürchtet für ihre Größe, ihre körperliche Stärke und ihre magischen Fähigkeiten. Die ältesten Drachen gehören zu den mächtigsten Kreaturen der Welt.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = '8df7adde-909f-4950-94b2-1a2a53f2f668' AND is_custom = FALSE;

-- Dragon, Shadow (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schattendrachen sind verschlagen und hinterhältig. Sie sind instinktiv gerissen und neigen nicht dazu, Risiken einzugehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Schattendrachen greifen bevorzugt aus dem Hinterhalt an und nutzen gewöhnlich Unsichtbarkeit oder verstecken sich in Schatten. Sie verwenden Illusions-/Phantasmazauber, um Feinde zu verwirren und in die Irre zu führen. Ältere Drachen sind besonders stolz auf ihre Fähigkeit der Entdeckungsimmunität.'),
  habitat_society = COALESCE(habitat_society, 'Schattendrachen hassen sowohl helles Licht als auch völlige Dunkelheit und bevorzugen abwechslungsreiche Beleuchtung mit Flecken diffusen Lichts und tiefen, tintenartigen Schatten. Auf der Primär-Materiellen Ebene sind ihre Baue immer Orte, die für den größten Teil des Tages schattiges Licht bieten. Sie bevorzugen alte Ruinen, wo sie sich unterirdisch verstecken können, wenn die Sonne hell scheint, und dennoch bei Sonnenauf- und -untergang Schatten über der Erde finden können. Auf der Ebene der Schatten leben sie in dichten Dickichten aus Bäumen und Dornengestrüpp, befestigten Burgen oder labyrinthartigen Höhlen. Auf beiden Ebenen ziehen sie es vor, ihre Baue in der Nähe von Kolonien anderer Kreaturen anzulegen, die sie vor potentiellen Feinden oder Opfern warnen können. Die Drachen kooperieren jedoch selten tatsächlich mit diesen Verbündeten, obwohl die Drachen sie gewöhnlich als Beute betrachten.'),
  ecology         = COALESCE(ecology, 'Schattendrachen fressen fast alles. Ihr Lieblingsfutter ist verwesendes Aas, obwohl sie oft zum Vergnügen töten. Getötete Opfer werden zum Verwesen liegen gelassen, bis sie entsprechend faulig werden. Diese Drachen mögen ebenso gern frostgetötete, durchnässte oder salzverseuchte Pflanzen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-5)')
WHERE id = '3447c7e6-2699-4acb-a204-e1cd69c6d142' AND is_custom = FALSE;

-- Dragon, Steel (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Stahldrachen lieben es, menschliche und halbmenschliche Gefährten zu haben, und sie ziehen es vor, inmitten des geschäftigen Treibens großer Städte zu leben. Sie geben sich oft als Gelehrte, Wissenschaftler, Magier oder andere Intellektuelle aus.'),
  combat_tactics  = COALESCE(combat_tactics, 'Stahldrachen bevorzugen Wortgefechte gegenüber dem Kampf. Wenn sie bedrängt werden, beginnen sie gewöhnlich mit einem Zauberangriff und vermeiden den Nahkampf. Wenn sie ernsthaft verletzt oder bedroht werden, nehmen sie wieder Drachengestalt an und setzen ihre Atemwaffen ein. Sie hauchen jeden Gegner an, den sie im Nahkampf bekämpfen wollen, und sie suchen ihre Feinde in der Wolke zu halten, bis das Gas seine Wirksamkeit verliert.'),
  habitat_society = COALESCE(habitat_society, 'Stahldrachen bevorzugen menschliche Unterkünfte, die gut mit starken Räumen oder Gewölben ausgestattet sind, um ihre Schätze zu schützen.'),
  ecology         = COALESCE(ecology, 'Stahldrachen bevorzugen menschliche Nahrung. Anders als andere gestaltwandelnde Drachen können sie nicht unbegrenzt von solcher Kost leben, da sie genug essen müssen, um ihre wahre Körpermasse zu erhalten. Ein- oder zweimal im Monat verlassen sie ihre angenommenen Städte und gehen in die Wildnis, um Nahrung zu jagen. Sie erklären ihre Abwesenheit auf eine Weise, die mit ihren menschlichen Identitäten vereinbar ist.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '95f0222c-2f3d-4872-9902-b1757403adf9' AND is_custom = FALSE;

-- Dragon, Yellow (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Obwohl die Existenz gelber Drachen von Gelehrten schon lange vorhergesagt wurde (basierend auf Theorien der Grundfarben), wurde das erste Exemplar erst vor etwa fünf Jahren gesichtet. Diese Kreaturen sind einzelgängerisch und verschwiegen und ziehen es vor, in sorgfältig vorbereiteten Fallen auf Beute zu lauern, anstatt aktiv zu jagen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl sie List dem Kampf und Hinterhalt dem Angriff vorziehen, sind gelbe Drachen wilde und gerissene Kämpfer. Selbst wenn sie in eine Situation gedrängt werden, in der direkter Kampf unvermeidlich ist, setzen sie immer noch ihre Zauber und angeborenen Fähigkeiten ein, um ihre Gegner irrezuführen, fehlzuleiten und abzulenken.'),
  habitat_society = COALESCE(habitat_society, 'Gelbe Drachen lieben Wüsten und bevorzugen Gebiete sandiger, windgepeitschter Trostlosigkeit. Sie fühlen sich bei Tagestemperaturen von 40 Grad und darüber am wohlsten, obwohl sie problemlos Temperaturen unter dem Gefrierpunkt in der Nacht überleben können. Sie teilen sich weitgehend dasselbe Territorium wie Messingdrachen; daher geraten die Arten gelegentlich in Konflikt.'),
  ecology         = COALESCE(ecology, 'Obwohl sie alles fressen können, bevorzugen gelbe Drachen frisches Fleisch. (Halb)Menschen gelten als Delikatesse, ebenso wie die ungeschlüpften Eier von Messingdrachen. (Gelbe kommen selten in den Genuss dieser letzteren Mahlzeit.)'),
  no_appearing    = COALESCE(no_appearing, '1 (1-4)')
WHERE id = 'db8afd84-0925-4841-a77b-3b5a8f4133ee' AND is_custom = FALSE;

-- Dragonfish (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese scheuen, einzelgängerischen Aasfresser sind nur daran interessiert, am Leben zu bleiben und zu fressen. Dennoch machen die zwei ausgezeichneten Selbstverteidigungsmethoden, die diese Kreaturen entwickelt haben, sie zu einem potentiell tödlichen Feind für ungeschickte, unaufmerksame Abenteurer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Drachenfische sind in ihrer natürlichen Umgebung extrem schwer zu entdecken. Ihre gesprenkelte braune Färbung erlaubt es ihnen, mit den Felsen und dem Schlamm am Grund der Gewässer, die sie bewohnen, zu verschmelzen. Da ihre natürliche Tarnung so erfolgreich ist, können Drachenfische nur zu 15% der Zeit entdeckt werden, und auch nur, wenn die Suchenden wissen, wonach sie suchen. Da Drachenfische außerdem dazu neigen, nachts aktiv zu sein, ist es immer extrem schwierig, einen zu finden.'),
  habitat_society = COALESCE(habitat_society, 'Drachenfische neigen dazu, nahe dem Grund seichter Gewässer zu leben. Ihre Nahrung besteht größtenteils aus langsamen Schnecken, kleinen Fischen und den Überresten anderer Kreaturen, die kürzlich im Wasser gestorben sind. Jedoch ist bekannt, dass der Drachenfisch fast alles frisst, was er schlucken kann, einschließlich kleiner Metallstücke wie Münzen oder Ringe. Die starken Verdauungssäuren im Magen des Fisches zersetzen alles, was er schluckt, sehr schnell, wodurch es fast unmöglich wird, unbeschädigte Schätze aus dem Magen eines Drachenfisches zu bergen.'),
  ecology         = COALESCE(ecology, 'Intelligente Rassen haben eine große Anzahl von Verwendungsmöglichkeiten für den Drachenfisch entdeckt. Drachenfischgift ist hochgiftig und ein ausgewachsener Drachenfisch kann genug liefern, um eine große Anzahl von Kreaturen zu töten. Es ist natürlich, dass Kreaturen, die häufig Gift verwenden, eine Standardmethode zum Fangen von Drachenfischen haben. Außerdem ergeben Drachenfischstacheln ausgezeichnete Wurfpfeile, da sie extrem stark und sehr scharf sind. (Die Stacheln wachsen auch am Fisch nach, so dass ihre Ernte möglich ist.) Die Drachenfischhaut wird auch nicht verschwendet, da sie ausgezeichnetes Material für Schuppenpanzer abgibt. Die Verwendung jedes Teils des Drachenfisches ist potentiell tödlich, es sei denn, die Giftsäcke und Stacheln werden zuerst sorgfältig entfernt.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '24302787-a7d0-49b6-b23b-5841ec0822b9' AND is_custom = FALSE;

-- Dragonne (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Dragonne vereint einige der gefährlichsten Eigenschaften eines Löwen und eines Messingdrachen und ist ein bösartiger und tödlicher Jäger sowie eine Bedrohung für viele, die in wärmeren Klimazonen reisen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dragonnes greifen normalerweise zuerst mit ihren Vorderklauen an und verursachen mit jedem Satz 1W8 Schadenspunkte, sowie mit ihren furchtbaren Kiefern, die 3W6 Schadenspunkte verursachen. Dies reicht normalerweise aus, um die meisten Kreaturen zu töten, denen der Dragonne begegnet. Falls ein Dragonne jedoch gegen einen besonders tödlichen Gegner kämpft oder in einer Schlacht mit einem schwächeren Gegner verwundet wird, setzt er sein tödliches Brüllen ein.'),
  habitat_society = COALESCE(habitat_society, 'Dragonnes bevorzugen es, in felsigen Vorgebirgen und Wüsten zu leben. Sie nehmen große, natürliche Höhlen als ihre Baue und lagern ihre kleinen Mengen an Schätzen, normalerweise von getöteten Abenteurern genommen, in lockeren Haufen um ihre felsigen Heime. Ihre Territorien sind normalerweise sehr groß, da sie generell öde Gebiete bewohnen.'),
  ecology         = COALESCE(ecology, 'Der Dragonne bevorzugt Herdentiere wie Ziegen als Nahrung, besonders da sie nicht so heftig zurückkämpfen wie Menschen. Er greift einen Menschen oder Halbmenschen nur dann als Nahrung an, wenn kein anderes Wild verfügbar ist. Dragonnes sind nicht zwangsläufig aggressiv gegenüber Fremden, und der Ruf der Kreatur als gedankenloser Verschlinger hilfloser Reisender ist mehr das Produkt von Unwissen als gut erforschte Tatsache. Ein Dragonne wird fast immer jede Kreatur angreifen, die in seinen Bau eindringt oder sein Territorium bedroht. Das bedeutet, dass Abenteurer, die über eine Dragonne-Höhle stolpern, oder Siedler, die entscheiden, im Territorium eines Dragonnes zu bauen, oft heftigem und sofortigem Angriff ausgesetzt sind. Kreaturen, die den Bau des Dragonnes nicht bedrohen oder einfach durch sein Territorium ziehen, werden normalerweise in Ruhe gelassen. Obwohl die Intelligenz des Dragonnes niedrig ist, kann er den Unterschied zwischen einem harmlosen Reisenden und einem potentiell problematischen Siedler erkennen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'e07a6d30-f72e-4abd-8af0-a0186e00dad1' AND is_custom = FALSE;

-- Dragon Turtle (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Drachenschildkröten sind eine der schönsten, ehrfurchtgebietendsten und gefürchtetsten Kreaturen des Wassers. Mit ihren tödlichen Kiefern und ihrer Atemwaffe und ihrer Neigung, Schiffe zum Kentern zu bringen, werden Drachenschildkröten von Seefahrern auf großen Gewässern gefürchtet, sowohl in Süß- als auch Salzwasser.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl Drachenschildkröten für den angenehmen Anblick von Licht, das auf Wasser glitzert, gehalten werden können, wird diese Illusion niemals lange aufrechterhalten. Drachenschildkröten sind wilde Kämpfer und greifen generell jede Kreatur an, die ihr Territorium bedroht oder sich als potenzielle Mahlzeit präsentiert. Im Kampf werden Drachenschildkröten gewöhnlich (90%) zuerst mit ihren furchtbaren Klauen und Zähnen angreifen. Ihr Panzer bietet der Schildkröte exzellenten Schutz, obwohl sie, sobald die Drachenschildkröte ein Opfer trifft, selten auf diese Sicherheitsvorkehrung angewiesen ist.'),
  habitat_society = COALESCE(habitat_society, 'Drachenschildkröten sind extrem einzelgängerische Kreaturen. Große, trostlose Meereshöhlen und geheime unterirdische Kavernen, die nur durch das Wasser erreichbar sind, sind ihre bevorzugten Baue. Diese Baue sind schwer zu finden, aber Abenteurer, die die Höhle einer Drachenschildkröte ausfindig machen, werden sie voller Schätze aller Art finden. Die Schildkröte sammelt diese Schätze, die sie bis zum Tod verteidigen wird, von den in ihrem Territorium versunkenen Schiffen.'),
  ecology         = COALESCE(ecology, 'Drachenschildkröten sind fleischfressend und werden fast jede Kreatur fressen, einschließlich Menschen oder andere Drachenschildkröten, um ihren unersättlichen Appetit zu befriedigen. Große Fische scheinen die bevorzugte Nahrung für Drachenschildkröten zu sein, und die Schildkröten können oft dabei angetroffen werden, wie sie im Unkraut und Schlamm am Boden eines Sees oder Meeres lauern und auf vorbeiziehende Fische warten. In besonders schlechten Jahren für Fische war es bekannt, dass Drachenschildkröten ihre Atemwaffe einsetzen, um große Gruppen von Seevögeln zu töten, die sich zu nah an das Wasser wagen, um Nahrung zu suchen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '420f276d-4f13-4298-8215-97426f08e953' AND is_custom = FALSE;

-- Dragonet, Faerie Dragon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein chaotischer Ableger des Pseudodrachens, der Feendrache lebt in friedlichen, verworrenen Wäldern und gedeiht durch Streiche, Unfug und praktische Scherze.'),
  combat_tactics  = COALESCE(combat_tactics, 'Feendrachen können nach Belieben unsichtbar werden und können angreifen, Zaubersprüche verwenden und Atemwaffen einsetzen, während sie unsichtbar sind. Sie greifen als 4-TW-Monster an und beißen für 1-2 Schadenspunkte. Die meisten (65%) Feendrachen verwenden Magierzauber als Magier der auf der beigefügten Tabelle angegebenen Stufe; 35% verwenden Priesterzauber der folgenden Sphären: Tier, Pflanze, Elementar und Wetter. Fast alle Zaubersprüche werden wegen ihres Unfugpotentials gewählt. Die zwei häufigsten Zaubersprüche der Feendrachen sind Wasseratmung und Legendenwissen; andere Favoriten sind Bauchreden, Unsichtbarer Diener, Vergessen, Suggestion, Entfernungsverzerrung, Begrenzter Wunsch, Verschleierung, Tierwachstum und Fels beleben.'),
  habitat_society = COALESCE(habitat_society, 'Feendrachen bauen ihre Baue in den Höhlen hoher Bäume, vorzugsweise in der Nähe eines Teichs oder Bachs, da sie sehr gerne schwimmen und tauchen. Sie leben oft in Gesellschaft einer Gruppe von Feen oder Kobolden.'),
  ecology         = COALESCE(ecology, 'Feendrachen fressen Obst, Gemüse, Nüsse, Wurzeln, Honig und Getreide. Sie sind besonders gerne Obstkuchen zugetan und sind dafür bekannt, große Anstrengungen zu unternehmen, um einen frischen Apfelkuchen zu bekommen.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = 'f7952f05-fa23-4b93-9d70-aeb7f6526a1a' AND is_custom = FALSE;

-- Dragonet, Fire Drake (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Obwohl er bei der ersten Sichtung häufig für einen jungen roten Drachen gehalten wird, ist der Feuerdrache weder so intelligent noch so mächtig wie sein drachischer Verwandter. Er reagiert mit Flammen auf jeden Reiz.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn ein Feuerdrache gestört wird, besteht eine 50-prozentige Chance, dass er angreift. Sein Hauptangriff ist seine Atemwaffe (Feuer), die er bis zu fünfmal täglich einsetzen kann. Das Feuer bildet einen Kegel von der Schnauze des Drachen zu einem 3 m großen Kreis am äußersten Ende seiner 18 m Reichweite und verursacht 2-16 Schadenspunkte bei allen Betroffenen (Rettungswurf gegen Atemwaffe für halben Schaden). Die Klauen des Feuerdrachen werden nicht im Kampf eingesetzt, aber sein Biss verursacht 2-8 Schadenspunkte.'),
  habitat_society = COALESCE(habitat_society, 'Feuerdrachen sind familiäre Kreaturen, wobei ein verpaartes Männchen und Weibchen Wohnsitz in einem Bau nehmen, der gewöhnlich eine kleine Höhle oder ein Felssims unter einem Vorsprung oder Felsüberhang ist. Gewöhnlich werden sechs bis acht Eier gelegt und vom Paar gehütet, wobei sie durch die reichliche Körperwärme der Eltern warm gehalten werden. Die Eier, die im Frühsommer gelegt werden, brauchen etwa 60 Tage zum Ausbrüten. Die jungen Feuerdrachen lernen Feuer zu speien, noch bevor sie fliegen lernen, und sind sogar nervöser als die Erwachsenen, wobei sie während dieser Zeit mehrmals täglich Flammen im Bau oder in der Nähe ausspeien. Der erste Flug erfolgt etwa 60 Tage nach dem Schlüpfen.'),
  ecology         = COALESCE(ecology, 'Feuerdrachen haben eine kurze Lebensspanne im Vergleich zu ihren größeren Verwandten, den Drachen, und leben gewöhnlich nur 75 bis 100 Jahre.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '78b41afd-e7d8-4b81-8b4c-d8482eb5fa1c' AND is_custom = FALSE;

-- Dragonet, Pseudodragon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Pseudodrachen sind eine Art kleiner fliegender Echsen, die in dicht bewaldeten Wildnisgebieten leben. Diese verspielten, gutartigen Kreaturen haben magische Kräfte, die sie mit anderen teilen können, weshalb sie oft als Begleiter gesucht werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Pseudodrache kann mit seinen kleinen, drachenartigen Kiefern einen bösartigen Biss austeilen, aber seine Hauptwaffe ist sein mit einem Stachel ausgerüsteter Schwanz. Die Kreatur kann ihn mit blitzartiger Geschwindigkeit bewegen und trifft mit +4 auf Angriffswürfe. Jede getroffene Kreatur muss einen Rettungswurf gegen Gift bestehen oder in einen Zustand der Katalepsie fallen, der 1-6 Tage anhält. Das Opfer scheint vollkommen tot, aber am Ende dieser Zeit wird der Charakter entweder unversehrt aufwachen (75% Chance) oder sterben (25% Chance).'),
  habitat_society = COALESCE(habitat_society, 'Diese waldbewohnenden Kreaturen errichten ihre Baue in den Höhlen großer Bäume oder in großen Höhlen.'),
  ecology         = COALESCE(ecology, 'Pseudodrachen sind Allesfresser, bevorzugen aber Fleisch. Ihre Nahrung besteht hauptsächlich aus Nagetieren und kleinen Vögeln mit gelegentlichen Blättern, Früchten und Beeren. In der Wildnis leben Pseudodrachen ein Einzelgängerleben und beschützen kleine persönliche Schatzhörter in ihren Nestern. Sie versammeln sich einmal im Jahr zur Paarung, im frühen Frühling, wenn Zusammenkünfte von Dutzenden von Pseudodrachen nicht ungewöhnlich sind. Nach der Paarung trennen sich Männchen und Weibchen; die Weibchen legen gesprenkelten braune Eier in Gelegen von vier bis sechs, die im Hochsommer schlüpfen; die Weibchen ziehen die Jungen allein auf. Pseudodrachen halten Winterschlaf; die Jungen verlassen das Nest im Frühling zur Paarung.'),
  no_appearing    = COALESCE(no_appearing, '1 (50% chance of 1-8 in nests)')
WHERE id = 'd8f51b58-aa6a-4b81-8845-5c768e97888a' AND is_custom = FALSE;

-- Dryad (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dryaden sind wunderschöne, intelligente Baumkobolde. Sie sind jedoch so schwer fassbar wie verführerisch, und Dryaden werden selten gesehen, außer sie werden überrascht - oder sie wollen entdeckt werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dryaden sind scheue, gewaltlose Wesen. Sie tragen selten Waffen, aber manchmal führen sie Messer als Werkzeuge mit sich. Obwohl eine Dryade dies als Waffe in einem Kampf verwenden kann, wird sie nicht zum Einsatz eines Messers greifen, außer sie ist ernsthaft bedroht.'),
  habitat_society = COALESCE(habitat_society, 'Einige Legenden behaupten, dass Dryaden die belebten Seelen sehr alter Eichen sind. Ob dies wirklich der Fall ist, es ist wahr, dass Dryaden an eine einzige, sehr große Eiche in ihrem Leben gebunden sind und aus keinem Grund mehr als 329,2 m von diesem Baum entfernt gehen können. Wenn eine Dryade weiter wegwandert, wird sie schwach und stirbt innerhalb von 6W6 Stunden, außer sie wird zu ihrem Heim zurückgebracht. Die Eichen der Dryaden strahlen keine Magie aus, aber jemand, der das Heim einer Dryade findet, hat große Macht über sie. Eine Dryade erleidet Schaden für jeden Schaden, der ihrem Heimatbaum zugefügt wird. Jeder Angriff auf den Baum einer Dryade wird natürlich eine rasende Verteidigung durch die Dryade zur Folge haben.'),
  ecology         = COALESCE(ecology, 'Dryaden sind standhafte Beschützerinnen der Wälder und Haine, in denen sie leben. Jede Handlung, die das Gebiet schädigt, und besonders sein Pflanzenleben, wird mit wenig Toleranz begegnet.'),
  no_appearing    = COALESCE(no_appearing, '1 or 1-6')
WHERE id = '92334491-6039-4655-a7e6-2b63cf58dccf' AND is_custom = FALSE;

-- Dwarf, Derro (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Derro sind eine degenerierte Rasse von zwergenhafter Statur. Sie haben seit Ewigkeiten in der Unterdunkelheit gehaust, wurden aber erst vor fünf Jahrhunderten von den Gedankenräubern entdeckt, und von den Drow nur kurz davor. Die Derro haben sich durch ihre ausgeprägte Grausamkeit einen Namen gemacht. Es heißt, dass ein Derro für zwei Dinge lebt: den langsamen und demütigenden Tod von Oberflächenhalbmenschen und besonders Menschen, und die Pervertierung von Wissen für ihre eigenen dunklen Zwecke.'),
  combat_tactics  = COALESCE(combat_tactics, 'Derro sind eine der geschicktesten humanoiden Rassen (im Durchschnitt 15-18) und ihre Rüstungsklasse muss entsprechend angepasst werden. Normalerweise ist eine Derro-Gruppe gut mit Waffen und Zaubern ausgerüstet. Alle Derro tragen kleine, ornamentale Klingen namens Secari, die als Dolche behandelt werden können, aber die meisten nutzen auch andere Waffen.'),
  habitat_society = COALESCE(habitat_society, 'Derro leben in großen unterirdischen Komplexen, näher an der Oberfläche als die Kuo-Toa und Drow, aber tiefer als Goblins und Trolle. Sie setzen sich niemals direktem Sonnenlicht aus, da es ihnen übel wird. Sonnenlicht würde einen Derro töten, sollte er ihm für einige Tage ausgesetzt sein. Dennoch besuchen Derro gelegentlich nachts die Oberflächenwelt, überfallen Menschen oder führen die Pläne eines Gelehrten aus.'),
  ecology         = COALESCE(ecology, 'Derro können von einer Diät aus unterirdischen Pilzen leben, aber sie finden das Zeug widerlich schmeckend, wenn es als mehr als nur Gewürze verwendet wird.'),
  no_appearing    = COALESCE(no_appearing, '3-30')
WHERE id = '57753c72-30f1-480c-9b4a-a9f12dbe368c' AND is_custom = FALSE;

-- Dwarf, Duergar (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Duergar oder Grauzwerge sind eine bösartige Rasse, die in den extremen Tiefen des Untergrunds lebt. Duergar können Kämpfer, Priester oder Diebe sein. Mehrkategorien-Duergar können Kämpfer/Priester, Kämpfer/Diebe oder Priester/Diebe sein. Dieb-Duergar sind im Umgang mit Gift bewandert.'),
  combat_tactics  = COALESCE(combat_tactics, 'Für jeden vier normalen 1-TW-Duergar, die außerhalb eines Baus angetroffen werden, gibt es einen mit 2+4 TW. Wenn eine Bande von neun Duergar außerhalb eines Baus angetroffen wird, führt immer ein zehnter Duergar mit 3+6 TW oder 4+8 TW die Gruppe an.'),
  habitat_society = COALESCE(habitat_society, 'Die Duergar sind anderen Zwergenkulturen ähnlich, obwohl das Leben viel härter ist aufgrund ihrer feindlichen Umgebung tief unter der Erde. Sie wagen sich nur nachts oder an den düstersten Tagen an die Oberfläche. Duergar leben länger als ihre oberflächenbewohnenden Verwandten. Die Lebensspanne kann 400 Jahre oder mehr erreichen.'),
  ecology         = COALESCE(ecology, 'Duergar verachten die anderen Zwergenrassen, die sie als verwöhnt, schwach und selbstsüchtig betrachten. Sie mögen sich mit bösen Zwergen verbünden und sogar Lebensraum teilen, aber die feindselige Natur der Duergar macht solche Allianzen extrem selten.'),
  no_appearing    = COALESCE(no_appearing, '2-9 or 201-300')
WHERE id = '3109c1b1-8242-4a1a-b533-e9bf12507de4' AND is_custom = FALSE;

-- Dwarf (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Zwerge sind ein edles Volk von Halbmenschen, die unter der Erde wohnen, große Städte errichten und gewaltige Kriege gegen die Mächte des Chaos und Bösen führen. Zwerge haben auch viel mit den Steinen und Edelsteinen gemein, mit denen sie gerne arbeiten, denn beide sind hart und unnachgiebig. Es wird oft gesagt, dass es einfacher ist, einen Stein zum Weinen zu bringen, als einen Zwerg umzustimmen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Zwerge sind mutige, hartnäckige Kämpfer, die Magie abgeneigt sind. Sie verwenden niemals magische Zauber oder bilden sich als Magier aus, obwohl sie Priester werden und die Zauber dieser Gruppe nutzen können. Aufgrund ihrer unmagischen Natur erhalten sie sogar einen speziellen Bonus auf alle Rettungswürfe gegen magische Stäbe, Zauberstäbe, Ruten und Zauber. Zwerge erhalten einen +1-Bonus auf Rettungswürfe gegen diese magischen Angriffe für jeweils 3,5 Punkte Konstitutionswert. Siehe Tabelle 9 im Spielerhandbuch für spezifische Boni.'),
  habitat_society = COALESCE(habitat_society, 'Gewöhnlich um profitable Minen herum errichtet, sind zwergische Städte weite, schöne Komplexe, die in massiven Stein gehauen sind. Zwergische Städte brauchen Hunderte von Jahren zur Fertigstellung, aber einmal vollendet stehen sie Jahrtausende ohne jede Art von Reparatur. Da Zwerge ihre Heime nicht oft verlassen und immer zu ihnen zurückkehren, erschaffen sie ihre Städte mit Dauerhaftigkeit im Sinn. Truppen bewachen zwergische Städte zu jeder Zeit, und manchmal (60% Chance) verwenden Zwerge auch Tiere als Wachen - entweder 2W4 Braunbären (75% Chance) oder 5W4 Wölfe (25% Chance).'),
  ecology         = COALESCE(ecology, 'Da ein Großteil ihrer Kultur darauf fokuss'),
  no_appearing    = COALESCE(no_appearing, '40-400')
WHERE id = '9aca76cc-31b5-411f-8262-4e52152968ad' AND is_custom = FALSE;

-- Dwarf, Gully (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rinnensalzwerge, auch als Aghar bekannt, sind dumm, schmutzig und widerwärtig.'),
  combat_tactics  = COALESCE(combat_tactics, 'Da sie Feigheit als Tugend betrachten, haben Rinnensalzwerge das Kriechen zur Kunstform erhoben. Werden sie von einem gefährlichen Gegner konfrontiert, aber nicht sofort angegriffen, werden Rinnensalzwerge entweder ohnmächtig, weinen, betteln um Gnade, ergießen Ströme von Informationen, laufen davon oder stehen da und zittern. Wenn sie angegriffen werden, verteidigen sich Rinnensalzwerge, aber manchmal kämpfen sie mit geschlossenen Augen. Rinnensalzwerge sind nicht zu schade zum Stehlen, Lügen oder Tyrannisieren, und schmutzige Tricks gehören zu ihren Lieblingstaktiken.'),
  habitat_society = COALESCE(habitat_society, 'Rinnensalzwerg-Gemeinschaften sind recht klein und überschreiten selten mehr als 2W10 Mitglieder. Ein typischer Clan von 11 Mitgliedern umfasst einen Häuptling (einen Kämpfer der Stufe 2-6), etwa vier Kämpfer der 1. Stufe (von denen einer als Schamane des Clans dient, obwohl er keine magischen Fähigkeiten hat), einen Kämpfer der Stufe 2-4 (oder einen Dieb derselben Stufenspanne); der Rest sind Weibchen und Kinder. Die meisten Clans leben in verlassenen Dörfern oder in der Wildnis in alten Minen und Höhlen. Andere leben in Slums, Müllhalden oder den Kanalisationssystemen großer Städte. Wenn mehrere Clans zusammenleben, wird der stärkste und klügste Häuptling zum örtlichen König, dessen Titel durch das Voranstellen des Präfixes "Hoch" vor seinen Clannamen entsteht. Jeder nachfolgende König nennt sich oft "der Erste", aufgrund der Unfähigkeit der Rinnensalzwerge zu zählen.'),
  ecology         = COALESCE(ecology, 'Andere Völker meiden Rinnensalzwerge, aber sie werden gelegentlich angeheuert, um niedere Arbeiten zu verrichten. Gnome heuern sie gelegentlich als Attentäter und Spione an, obwohl Rinnensalzwerge bei diesen Aufgaben nicht besonders geschickt sind. Rinnensalzwerge essen alles. Viele Rinnensalzwerge halten einen Topf mit Eintopf ständig kochend und werfen alles hinein, was tot oder fast tot ist.'),
  no_appearing    = COALESCE(no_appearing, '2-20')
WHERE id = '30a151b2-cc9e-4abe-b822-531559b1c28e' AND is_custom = FALSE;

-- Eagle (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Adler sind majestätische Raubvögel, die selten zur Jagd verwendet werden, aber oft wegen ihrer Schönheit und legendären Tapferkeit begehrt sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Adler nutzt seine Krallen und seinen Schnabel zum Kampf, von denen jeder 1-2 Schadenspunkte verursacht. Ein Adler greift normalerweise aus großer Höhe an, faltet seine Flügel zurück und lässt die Schwerkraft ihn auf seine Beute hinabstürzen. Wenn ein Adler über 30 m hinabstürzt, ist seine Sturzgeschwindigkeit doppelt so hoch wie seine normale Fluggeschwindigkeit und der Adler ist darauf beschränkt, nur mit seinen beiden Krallensätzen anzugreifen. Jedoch erhalten diese Hochgeschwindigkeitsangriffe einen +2-Bonus auf den Angriffswurf und verursachen doppelten Schaden.'),
  habitat_society = COALESCE(habitat_society, 'Hohe Felsklippen und große, breite Bäume sind die bevorzugten Nistplätze für Adler. Sobald ein Adler ein Nest baut, behält er dieses Heim und erweitert es mit jeder vorübergehenden Saison, bis das Nest zerstört wird oder der Adler stirbt. Es besteht immer eine 50%-Chance, dass 1W4 Eier in einem Nest vorhanden sind. Wenn keine Eier vorhanden sind, besteht eine 20%-Chance, dass stattdessen 1W4 junge Adler anwesend sind. Es besteht immer eine 10%-Chance, dass der Adler einige kleine, glänzende Gegenstände im Nest lagert (wie Goldmünzen oder Edelsteine).'),
  ecology         = COALESCE(ecology, 'Adler sind Fleischfresser und jagen im Allgemeinen Nagetiere, Fische und andere kleine Tiere. Adler ernähren sich bekanntermaßen auch vom Aas kürzlich getöteter Kreaturen. Außer bei außergewöhnlichem Hunger wird ein Adler niemals einen Menschen oder Halbmenschen angreifen, obwohl kleine Kreaturen wie Wichtel vor einem jagenden Adler auf der Hut sein müssen, der sie für Kaninchen halten könnte.'),
  no_appearing    = COALESCE(no_appearing, '1 or 2/5-12')
WHERE id = '1b8dcf1d-92af-4abc-aaec-21699fb284ba' AND is_custom = FALSE;

-- Eel (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Aale sind lange, schlangenartige Fische, die normalerweise nicht aggressiv sind. Dennoch hat die Natur die verschiedenen Aalarten mit interessanten - und gefährlichen - Verteidigungsmethoden ausgestattet.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein angreifender Aal, sei es zur Selbstverteidigung oder auf der Jagd nach Nahrung, entlädt einen Stromstoß. Diese Ladung hat eine Reichweite von 4,6 m Radius. Kreaturen, die weniger als 1,5 m vom Aal entfernt sind, erleiden 3W8 Schadenspunkte; Kreaturen in 1,5 bis 3 m Entfernung erhalten 2W8 Schadenspunkte; alle anderen Kreaturen in Reichweite erleiden 1W8 Schadenspunkte. Ein Aal muss sich eine Stunde lang (sechs Runden) zwischen Angriffen aufladen.'),
  habitat_society = COALESCE(habitat_society, 'Seichte, langsam fließende Süßwasserflüsse in wärmeren Klimazonen sind die Wohnorte des Zitteraals. Der Zitteraal ist kein geselliges Tier und lebt ein einsames Leben, außer während der Paarungszeit. Wenn jedoch ein Aal Elektrizität entlädt, besteht eine 80%ige Chance, dass sich 1-2 andere Aale in der Nähe nähern in der Hoffnung, etwas zu fressen zu bekommen.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = '9f917914-1b5c-4938-8a05-0780807e1d59' AND is_custom = FALSE;

-- Elemental (Athas), General Information (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Von Priestern in ganz Athas verehrt und respektiert, repräsentieren Elementare den Inbegriff der bekannten Elemente: Luft, Erde, Feuer und Wasser. Die vier Elementare stellen die Kräfte dar, die das Alltagsleben der Bewohner des belagerten Planeten formen. Luft repräsentiert den Akt des Lebens, da ein Kind sie beim ersten Betreten der Welt einatmet und ein Sterbender sie als seinen letzten Akt vor dem Tod ausatmet. Wasser ist das Leben selbst, immer benötigt und niemals als selbstverständlich betrachtet. Erde repräsentiert die Welt, immer im Wandel, immer hart, aber verlässlich immer da. Feuer repräsentiert die Hitze der Sonne, die brennende Wüste und alles was verloren war.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = 'cdc9840a-ddf1-45b8-b5fb-c87b8f0aa67c' AND is_custom = FALSE;

-- Elemental, Air Kin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sylphen sind wunderschöne, humanoide Frauen mit Flügeln wie Libellen. Ihre Flügel sind 1,2-1,5 m lang und durchscheinend, klar oder mit schillernden Farben gefleckt. Ihr langes, leuchtendes Haar kann jede "normale" Farbe haben oder blau, violett oder grün sein. Sie tragen fließende, durchsichtige Gewänder, die ihre Flügel oder ihr Haar betonen. Sylphen sind mit Luftelementaren und Nymphen verwandt, möglicherweise entstanden als Kreuzung zwischen Nymphen und Luftdienern. Sie sprechen die Gemeinsprache und ihre eigene melodische Sprache.'),
  combat_tactics  = COALESCE(combat_tactics, 'Sylphen greifen ihre Gegner nicht körperlich an. Stattdessen verwenden sie eine Vielzahl magischer Fähigkeiten.'),
  habitat_society = COALESCE(habitat_society, 'Sylphen berühren selten den Boden im Flachland. Sie reisen gerne, und es ist selten, eine in der Nähe ihres Zuhauses zu finden.'),
  ecology         = COALESCE(ecology, 'Sylphen halten normalerweise Abstand zu den gewöhnlicheren humanoiden Völkern, verkehren aber frei mit Nymphen und Dryaden. Flugmonster nähren sich gelegentlich von ihnen, aber sie sind in größerer Gefahr durch böse humanoide Männchen, die versuchen, sie für dunkle Zwecke zu fangen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '7d185771-221e-4269-8543-497e8737c3d2' AND is_custom = FALSE;

-- Elemental, Earth Kin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Pech sind Kreaturen der Ebene des elementaren Erds, obwohl einige ausgedehnte Minen in den tiefsten Regionen der Hauptmateriellen Ebene haben. Sie leben an dunklen Orten und bearbeiten Stein.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Pech verwenden Spitzhacken und Torfhämmer (behandle als Kriegshämmer) für Arbeit und Bewaffnung und sind gewöhnlich mit gleicher Anzahl von beiden ausgerüstet. Pech haben 18/50 Stärke.'),
  habitat_society = COALESCE(habitat_society, 'Pech sind grundsätzlich gute und friedliche Kreaturen, die in Ruhe gelassen werden wollen. Sie hassen helles Licht und offenen Himmel, und sie bitten andere schnell darum, Lichter zu löschen. Ihre Baue sind mit zahlreichen Engpässen konstruiert, sodass Steinwälle schnell Eindringlinge stoppen können. Ihr Bau beherbergt 10-40 Individuen, mit gleicher Anzahl von Weibchen und Männchen, und Junge entsprechend 20-50% der Weibchen.'),
  ecology         = COALESCE(ecology, 'Die Heimatebene der Pech ist feindlich, daher reisen viele zur Hauptmateriellen Ebene, um nach einem besseren Leben zu suchen. Sie haben dort wenige Feinde. Pech sparen keine großen Mengen Schätze; sie schürfen nach Dingen, die sie mit anderen gegen Nahrung oder Dienstleistungen tauschen können. Sie erschaffen manchmal einfache, unauffällige Ziergegenstände für den täglichen Gebrauch. Ein Pech-Bau kann 50-100 Handelsjuwelen plus 5-30 aus Stein und Rohmetall gearbeitete Geschirr und Utensilien enthalten. Diese Gegenstände sind nicht sehr wertvoll und kosten durchschnittlich 150 GM pro Stück.'),
  no_appearing    = COALESCE(no_appearing, '5-20')
WHERE id = '79d7f51a-5278-4a6b-8596-4dca881c76ba' AND is_custom = FALSE;

-- Elemental, Fire Kin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Salamander sind Eingeborene der Elementarebene des Feuers und gedeihen daher an heißen Orten. Diese grausamen, bösen Kreaturen kommen aus nur ihnen bekannten Gründen auf die Erste Materielle Ebene.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Salamander greift normalerweise mit seinem Metallspeer an, der 1W6 Schadenspunkte plus die gleiche Menge für die Hitze des Speers verursacht. Gleichzeitig kann er mit seinem schlangenartigen Schwanz ausschlagen und einen Gegner umschlingen, wobei er 2W6 Schadenspunkte durch Zusammenschnürung verursacht, plus zusätzliche 1W6 Schadenspunkte durch die Hitze seines Körpers. Während feuerresistente Kreaturen nicht unter dem Hitzeschaden des Salamanders leiden, sind sie dennoch dem Speer- und Zusammenschnürungsschaden unterworfen.'),
  habitat_society = COALESCE(habitat_society, 'Salamander sind Eingeborene der Elementarebene des Feuers. Sie kommen aus nur ihnen bekannten Gründen auf die Erste Materielle Ebene, obwohl es Gerüchte gibt, dass mächtige Magier und Priester bestimmter Religionen sie für kurze Zeit herbeirufen können. Salamander hassen Kälte und bevorzugen Temperaturen von 150 Grad oder mehr; sie können niedrigere Temperaturen nur für wenige Stunden ertragen. Ihre Baue sind normalerweise mindestens 260 Grad heiß. Alle dort gefundenen Schätze sind solche, die dieser Hitze standhalten können, wie Schwerter, Rüstungen, Stäbe, andere eisenhaltige Gegenstände und Juwelen. Brennbare Dinge wie Pergament und Holz, weiche Metalle wie Gold und Silber und Flüssigkeiten, die schnell verdampfen, werden niemals in Salamander-Bauen gefunden.'),
  ecology         = COALESCE(ecology, 'Das Blut dieser feurigen Kreaturen ist nützlich bei der Herstellung von Tränken der Feuerresistenz, und das Metall ihrer Speere kann zur Erschaffung von Ringen der Feuerresistenz verwendet werden.'),
  no_appearing    = COALESCE(no_appearing, '2-5')
WHERE id = '288432a5-3ef5-45bc-8819-40d253c17be7' AND is_custom = FALSE;

-- Elemental, Composite (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Sturm ist ein lebender Unwetter, der als dunkle Sturmwolke von vergleichsweise kleiner Größe erscheint. Menschliche oder tierische Züge sind oft in den brodelnden Dämpfen des Sturms zu erkennen. Silberne Adern erstrecken sich über die Kreatur und tragen die elektrischen Impulse, die die Energie des Sturms aufrechterhalten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Stürme sind territorial und betrachten jede Verletzung ihres Luftraums als direkte Herausforderung. Sie nähren sich von Feuchtigkeit aus Tieren und jagen oft in und um ihre Territorien. Sie haben eine Reihe angeborener Fähigkeiten, mit denen sie anderen Kreaturen das Leben schwer machen können. Sofern nicht anders angegeben, werden alle besonderen Fähigkeiten so eingesetzt, als wäre der Sturm ein Magier der 9. Stufe. Ein Sturm kann zwei Angriffe pro Runde ausführen, einen mit seinen Windkräften und einen mit seiner Blitzkraft.'),
  habitat_society = COALESCE(habitat_society, 'Es gibt viele Spekulationen über den Ursprung dieser Wesen, die offenbar mit Elementaren und Dschinn-Geschlecht verwandt sind. Stürme bestehen aus allen vier Grundelementen: Feuer, Erde, Luft und Wasser; Feuer in Form von Blitzen, Erde in ihrem silbernen "Kreislaufsystem", Luft in ihren Winden und Wasser in Form von Regen. Sie können versehentlich beschworen werden, wenn ein Zauberwirker versucht, einen Elementar zu beschwören, besonders einen der Luft oder des Wassers. Nach Ermessen des SL kann bei einer gestörten Beschwörung dem Zauberer eine 10%-50% Chance gewährt werden, einen Sturm zu beschwören. Diese Wesen können auch von einem Wetterbeschwörungszauber angezogen werden, mit einer 1% (nicht kumulativen) Chance zu erscheinen, jedes Mal wenn ein Zauber gewirkt wird.'),
  ecology         = COALESCE(ecology, 'Stürme nähren sich von der in Tierkörpern gefundenen Feuchtigkeit. Obwohl sie nicht imstande sind, lebenden Kreaturen durch Entzug ihrer Feuchtigkeit Schaden zuzufügen, schweben sie nach einem Kampf dicht über dem Boden, um das Wasser aus toten Gegnern sowie alles Wasser zu saugen, das sie während des Kampfes niedergeschlagen haben könnten. Sie werden manchmal beim Plündern nach großen Schlachten zwischen Menschen gefunden. Indem sie Wasser aus einem Leichnam entfernen, machen sie ihn ungeeignet für eine Rückkehr zum Leben durch einen Tote erwecken-Zauber, obwohl Auferstehung und andere Zauber normal wirken.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '5b7aa427-248b-4d9b-b5ee-814a03a36d21' AND is_custom = FALSE;

-- Elemental, General Information (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Elementare sind empfindungsfähige Wesen, die Körper aus einem der vier Grundelemente besitzen können, aus denen die Primärmaterielle Ebene besteht - Luft, Erde, Feuer oder Wasser. Normalerweise leben sie auf einer elementaren Inneren Ebene und werden nur auf der Primärmateriellen Ebene angetroffen, wenn sie durch magische Mittel herbeigerufen werden. (Siehe das Manual of the Planes für weitere Informationen über die Natur der verschiedenen Elementarebenen.) Jeder Elementar muss auf der Primärmateriellen Ebene eine Hülle aus dem Grundelement annehmen, das er repräsentiert, und sobald diese Hülle zerstört wird, kehrt der Elementar zu seiner heimatlichen Ebene zurück. Obwohl es viele mächtigere und intelligentere Bewohner der Elementarebenen gibt, ist der gewöhnliche Elementar am einfachsten zu kontaktieren und daher am häufigsten herbeigerufen.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = '66cc8a3b-f4fd-48ae-9652-56676bb18fe5' AND is_custom = FALSE;

-- Elf (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Obwohl ihre Leben mehrere Menschengenerationen überdauern, erscheinen Elfen auf den ersten Blick schwächlich im Vergleich zum Menschen. Jedoch besitzen Elfen eine Reihe besonderer Talente, die ihre etwas schwächere Konstitution mehr als ausgleichen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Elfen sind vorsichtige Kämpfer und nutzen immer ihre Stärken zu ihrem Vorteil, wenn möglich. Eine ihrer größten Stärken ist die Fähigkeit, sich lautlos und nahezu unsichtbar durch natürliche Umgebung, Wälder oder Forste zu bewegen. Indem sie sich leise bewegen und in der Vegetation Deckung suchen, können Elfen oft eine Person oder Gruppe überraschen (Gegner haben einen Überraschungsmodifikator von -4). Solange sie nicht angreifen, können die sich im Wald versteckenden Elfen nur von jemandem oder etwas entdeckt werden, das die Fähigkeit besitzt, unsichtbare Objekte zu sehen. Der militärische Wert dieser Fertigkeit ist immens, und elfische Armeen werden immer Späher aussenden, um den Feind auszuspionieren, da solche Spione selten gefangen - oder überhaupt gesehen - werden.'),
  habitat_society = COALESCE(habitat_society, 'Elfen schätzen ihre individuelle Freiheit sehr hoch, und ihre Gesellschaftsstruktur basiert auf unabhängigen Banden. Diese kleinen Gruppen, normalerweise bestehend aus nicht mehr als 200, erkennen die Autorität eines königlichen Oberherren an, der wiederum einem König oder einer Königin Treue schuldet. Jedoch sind die Gesetze und Beschränkungen, die der elfischen Gesellschaft auferlegt werden, sehr wenige im Vergleich zur menschlichen Gesellschaft und praktisch vernachlässigbar im Vergleich zur zwergischen Gesellschaft.'),
  ecology         = COALESCE(ecology, 'Elfen produzieren feine Kleidung, wunderschöne Musik und brillante Poesie. Für diese Dinge kennen andere Kulturen das Waldvolk am besten. In ihrer Welt innerhalb des Waldes jedoch halten Elfen die dunklen Kräfte des Bösen und die Kreaturen in Schach, die den Wald plündern und dann weiterziehen würden, um einen anderen zu plündern. Allein aus diesem Grund sind Elfen unersetzlich.'),
  no_appearing    = COALESCE(no_appearing, '20-200')
WHERE id = '0be7b709-3f81-4605-93c6-3100ade1c914' AND is_custom = FALSE;

-- Elf, Aquatic (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Unter den schäumenden Wogen wilder Küstenlinien lebt der Wasseself, der aquatische Verwandte der Waldelfen in Verhalten und Weltanschauung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wasserelfen sind eine friedliebende Kultur. Es ist ein seltener Anblick, einen Wasserelfen einen Angriff starten zu sehen, und noch seltener für eine ganze Bande, sich zum Krieg zu rüsten. Wasserelfen werden ihre Heimstätten nur verlassen, um in die Schlacht zu ziehen, wenn die gesamte Gemeinschaft in Gefahr ist oder gegen große Feinde. Wenn sie zum Krieg gezwungen werden, beeindrucken sie alle Gegner mit ihrer wilden Tapferkeit und ihrem Geschick.'),
  habitat_society = COALESCE(habitat_society, 'Kleine Gemeinschaften von 3W100+100 normalen Einwohnern sind die Regel des wasserelfischen Lebensstils. Diese Gemeinschaften finden sich oft in dichten Tangbetten in geschützten Gewässern, obwohl die Wasserelfen auch Heime in Höhlen am Boden von Lagunen und Korallenriffen errichten können. Wasserfelfengemeinschaften halten durch einen kunstvollen und ineffizienten Brauch wandernder Herold/Boten Kontakt zueinander, die von einer Bande zur anderen reisen, ähnlich wie Postboten, die mündliche Nachrichten übermitteln. In jeder Gemeinschaft gibt es mehrere Anführertypen, wie früher umrissen, regiert von einem Kämpfer der 10.-12. Stufe mit einer persönlichen Garde aus acht elfischen Kämpfern der 7. Stufe. Magische Waffen würden vom Anführer oder einem seiner Wachen getragen.'),
  ecology         = COALESCE(ecology, 'Jede Bande von Wasserelfen ist selbstgenügsam, baut ihren Tang an und jagt Fische, wenn nötig. Wasserelfen durchsuchen Wrackteile. Sie sind von der Vorstellung der Magie verzaubert, aber sie erkennen, dass Landelfen besser ausgerüstet sind, damit umzugehen. Sie handeln oft seltene oder dekorative Gegenstände, die sie gefunden haben, mit den Hochelfen gegen Metallwaffen und Werkzeuge, die sie nicht unter Wasser schmieden können.'),
  no_appearing    = COALESCE(no_appearing, '20-120')
WHERE id = '8f038a0e-b0d6-4214-bf31-5f2a25faa423' AND is_custom = FALSE;

-- Elf, Drow (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese gefürchteten, bösen Kreaturen waren einst Teil der Elfengemeinschaft, die noch immer durch die Wälder der Welt wandelt. Nun bewohnen diese Dunkelelfen schwarze Höhlen und gewundene Tunnel unter der Erde, wo sie düstere Pläne gegen die Völker schmieden, die noch unter der Sonne auf der Oberfläche der grünen Erde wandeln.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Welt der Drow ist eine, in der gewalttätige Konflikte Teil des Alltags sind. Es sollte daher nicht überraschen, dass die meisten angetroffenen Drow, ob allein oder in einer Gruppe, kampfbereit sind. Drow, die außerhalb einer Drow-Stadt angetroffen werden, sind mindestens Kämpfer der 2. Stufe.'),
  habitat_society = COALESCE(habitat_society, 'Vor langer Zeit waren Dunkelelfen Teil der Elfenrasse, die durch die Wälder der Welt wandelte. Nicht lange nach ihrer Erschaffung fanden sich die Elfen jedoch in rivalisierende Fraktionen gespalten - eine folgte den Grundsätzen des Bösen, die andere besaß die Ideale des Guten (oder zumindest der Neutralität). Ein großer Bürgerkrieg zwischen den Elfen folgte, und die selbstsüchtigen Elfen, die den Pfaden des Bösen und Chaos folgten, wurden in die Tiefen der Erde getrieben, in die düsteren, lichtlosen Höhlen und tiefen Tunnel der Unterwelt. Diese Dunkelelfen wurden zu den Drow.'),
  ecology         = COALESCE(ecology, 'Die Drow stellen ungewöhnliche Waffen und Kleidung mit quasi-magischen Eigenschaften her. Einige Schreiber und Forscher vermuten, dass es die seltsame Strahlung um Drow-Städte ist, die Drow-Handwerk besonders macht. Andere theoretisieren, dass feine Handwerkskunst ihren wunderbar starken Metallen und überlegenem Stoff seine einzigartigen Eigenschaften verleiht. Was auch immer der Grund ist, es ist klar, dass die Drow einen Weg entdeckt haben, ihre Kleidung und Waffen ohne den Einsatz von Magie herzustellen.'),
  no_appearing    = COALESCE(no_appearing, '5-50')
WHERE id = '43284770-cfb7-47dc-b83e-9762c1325745' AND is_custom = FALSE;

-- Ettercap (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ettercaps sind hässliche zweibeinige Kreaturen, die sehr gut mit allen Arten von Riesenspinnen auskommen. Diese Geschöpfe von geringer Intelligenz sind außerordentlich grausam, sehr verschlagen und geschickt im Aufstellen von Fallen - sehr tödlichen Fallen - ganz wie die Spinnen, die oft in ihrer Nähe leben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn ein Ettercap in einen Kampf verwickelt wird, schlägt er zuerst mit seinen Klauen zu und verursacht 1-3 Schadenspunkte mit jedem Satz. Die Kreatur versucht dann, ihren Gegner zu beißen und fügt mit ihren Zähnen und kräftigen Kiefern 1W8 Schadenspunkte zu. Ein erfolgreicher Bissangriff eines Ettercaps ermöglicht es dem Monster, seinem Opfer ein starkes Gift aus den Drüsen über den Fangzähnen des Ettercaps zu injizieren.'),
  habitat_society = COALESCE(habitat_society, 'Ettercaps ziehen es vor, im tiefsten Teil eines Waldes zu leben, nahe Pfaden, die häufig von Wild oder Reisenden frequentiert werden. Die Nester der Kreaturen bestehen aus einem Rahmen aus Strängen, gefüllt mit verrottenden Blättern und Moos. Die Baue befinden sich oft am Boden, können aber auch oben in großen, stabilen Bäumen gefunden werden. In Ettercap-Bauen ist kein Schatz zu finden, aber gelegentlich werden Gegenstände gefunden, die von Abenteurern fallen gelassen wurden, die in Ettercap-Fallen geraten sind.'),
  ecology         = COALESCE(ecology, 'Ein Ettercap frisst jedes Fleisch, unabhängig von der Art der Kreatur, von der es stammt. Nach dem Fangen eines Opfers vergiftet der Ettercap es, damit es nicht entkommen kann; sobald die Kreatur tot ist, verschlingt der Ettercap sofort so viel von dem Kadaver wie möglich. Typischerweise kann ein Ettercap einen ganzen Hirsch oder einen großen Humanoiden in einer einzigen Sitzung verzehren. Alles, was übrig bleibt, nachdem sich der Ettercap vollgefressen hat, wird den Aasfressern überlassen.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '51be6943-7459-44db-867e-b0b9675a5403' AND is_custom = FALSE;

-- Eyewing (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Augenflügel sind abscheuliche Bewohner des Abgrunds. Sie sind gehorsam, loyal und dumm - perfekte Diener für die dunklen Götter und ihre mächtigeren Schergen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Augenflügel hat zwei Hauptangriffsformen. Die häufigste Form ist der Einsatz seiner Klauen und seines Schwanzes, um seine Gegner zu treffen. Es kann entweder auf sie herabstoßen oder schweben und zuschlagen. Seine zweite Angriffsform besteht darin, seine Feinde mit einer großen Augenflügel-Träne zu bombardieren, die von dem lederartigen Augenlid aus dem großen Augapfel herausgepresst wird. Es hat erstaunliche Kontrolle über die Freisetzung der Träne - es hat die gleiche Trefferchance mit einer Träne wie mit seinen Nahkampfangriffen. Es setzt eine Träne frei, wenn es sich innerhalb von 30,5 m von seinem Ziel befindet. Es kann diesen Angriff sowohl beim Schweben als auch beim Sturzflug ausführen.'),
  habitat_society = COALESCE(habitat_society, 'Augenflügel sind übernatürliche Kreaturen, die nur existieren, um ihren dunklen Herren zu dienen. Wenn sie ohne Befehle gelassen werden, werden sie träge und lustlos. Das sollte nicht bedeuten, dass sie weniger gefährlich sind. Diese Lustlosigkeit ist ihr Ausdruck von Langeweile, aber nichts lindert die Langeweile eines Augenflügels so sehr wie das Zerreißen unschuldiger Kreaturen.'),
  ecology         = COALESCE(ecology, 'Augenflügel sind geschlechtslose Kreaturen, die nicht Teil der Natur sind. Sie töten sogar dann, wenn sie nicht dazu befohlen werden, nur zum Vergnügen. Augenflügel wurden auf dem Mond angetroffen, wo es keine Luft zum Atmen und kein Wasser zum Trinken gibt. Es wird angenommen, dass sie keine Luft oder Wasser benötigen. Sie wurden nie beim Essen gesehen; die meisten, die sie studiert haben, nehmen an, dass sie von Magie genährt werden. Die mächtigeren Kreaturen des Abgrunds haben keine Bedenken, einen Augenflügel als Snack zu verspeisen, sollte einer in der Nähe sein, aber sie sind nicht die natürliche Beute irgendeiner Kreatur.'),
  no_appearing    = COALESCE(no_appearing, '1-20')
WHERE id = '70c4cf01-cd0c-4076-8a18-a216af9ac4bd' AND is_custom = FALSE;

-- Feyr (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Feyrs (ausgesprochen wie „Fears") entstehen aus den Überresten gewöhnlicher Albträume, vermischt mit magischen Restenergien, und werden unbewusst durch die starken Emotionen großer Menschengruppen zum Leben erweckt. Sie sind am häufigsten in großen Städten anzutreffen, die eine beträchtliche Anzahl von Magiern, Priestern und anderen Zauberkundigen beherbergen. Gewöhnliche Feyrs durchstreifen nachts die Straßen und suchen nichts weiter, als Chaos zu stiften. Große Feyrs hingegen sind die Verbindung kleinerer Feyrs und können überall angetroffen werden, obwohl sie viel seltener sind als die gewöhnlichen Feyrs.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die horizontalen Kiefer des Feyrs, die unter seinem Bauch hängen, sind die hauptsächliche Angriffsform der Kreatur und verursachen 1W4 Schadenspunkte bei gewöhnlichen Feyrs und 2W6 Punkte bei großen Feyrs. Der Feyr nutzt seine Kiefer nicht zum Fressen, sondern um Terror in die Herzen derer zu schlagen, die seine wilden und blutigen Angriffe mitansehen. Wer den Angriff beider Feyr-Arten miterlebt, muss einen erfolgreichen Rettungswurf gegen Zauber schaffen oder wird von Furcht erfasst (wie der gleichnamige Zauber). Diese Furcht wirkt 1W4 Runden bei gewöhnlichen Feyrs und 2W6 Runden bei großen Feyrs. Diese Form der Furcht tritt nur ein, wenn die Kreatur angreift. Der bloße Anblick eines gewöhnlichen Feyrs löst keine Furcht aus.'),
  habitat_society = COALESCE(habitat_society, 'Einzelne gewöhnliche Feyrs werden vom Morgenlicht getötet. Gelegentlich verbinden sich mehrere gewöhnliche Feyrs zu einem großen Feyr, der zusätzlich zu seiner Immunität gegen die Auswirkungen der Sonne viel intelligenter ist. Der größere Feyr sucht noch stärkere Emotionen zu wecken, die er dann nutzen kann, um am Leben zu bleiben. Während gewöhnliche Feyrs nicht weit von ihrem Ursprungsort reisen, können große Feyrs lange Reisen unternehmen, angelockt von starken emotionalen Zuständen.'),
  ecology         = COALESCE(ecology, 'Gewöhnliche Feyrs werden durch die Emotionen großer Menschenmassen erschaffen und große Feyrs durch Zusammenschlüsse kleinerer Feyrs. Die Grundmaterialien für solche Kreaturen finden sich in jeder städtischen Siedlung, und wenn zusätzliche Spannungen in der Luft liegen, durchstreifen die Feyrs die Nacht. Belagerte Städte, von Rivalitäten oder Bürgerkriegen gespaltene Ortschaften, unterdrückte Völker und Siedlungen, die unter erbarmungsloser Sommerhitze schmoren, sind allesamt mögliche Brutstätten für Feyrs. Wach- und Patrouillentrupps reichen normalerweise aus, um mit gewöhnlichen Feyrs fertig zu werden, da diese alles angreifen, was sich bewegt. Aber die gefährlicheren großen Feyrs müssen von einem Magier oder ähnlich hochstufigen Individuum bekämpft werden, das sowohl dem Angriff des Feyrs standhalten als auch ihn vernichten kann.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'dda2f7a3-77c0-45e7-856b-9165893178eb' AND is_custom = FALSE;

-- Fish (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der erste Hinweis darauf, dass ein Barrakuda in der Nähe ist, könnte ein plötzlicher Schmerz im Fuß sein, wenn der Räuber vorbeischwimmt und ein paar zarte Zehen abbeißt. Sie sind in warmen Salzgewässern zu finden.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = 'd829514d-0a84-4903-9ad2-0ecd4aef6285' AND is_custom = FALSE;

-- Fish, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenfische sind eine vielfältige Gruppe von Kreaturen mit unterschiedlichen Angriffs- und Verteidigungsfähigkeiten. Während Fische grundsätzlich alle Wasserbewohner sind, haben einige die Fähigkeit, außerhalb des Wassers zu überleben und atmosphärischen Sauerstoff zu atmen.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '872e0310-4630-4724-97f8-f1950b05e145' AND is_custom = FALSE;

-- Fungus (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Pilze sind einfache Pflanzen, denen Chlorophyll, echte Stängel, Wurzeln und Blätter fehlen. Pilze sind nicht zur Photosynthese fähig und leben als Parasiten oder Saprophyten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gewöhnliche Pilze greifen weder an noch verteidigen sich selbst, aber sie sind fruchtbar und können sich dort ausbreiten, wo sie unerwünscht sind.'),
  habitat_society = COALESCE(habitat_society, 'Der Körper der meisten echten Pilze besteht aus schlanken, wattigen Fäden. Jeder, der dies selbst sehen möchte, braucht nur ein feuchtes Stück Brot für ein oder zwei Tage in einem Schrank zu lassen. Die Untersuchung des schwarzen Schimmels auf dem Brot mit einer Lupe zeigt nicht nur die Fäden, sondern auch die Sporenkörper an deren Spitzen. Die Sporen sind es, die dem Schimmel seine Farbe verleihen.'),
  ecology         = COALESCE(ecology, 'Pilze zersetzen organische Materie und spielen somit eine wichtige Rolle im Stickstoffkreislauf, indem sie tote Organismen zu Ammoniak abbauen. Ohne die Wirkung von Speisepilzen und Baumpilzen könnte die Bodenerneuerung nicht so leicht stattfinden, wie sie es tut.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'c49bcf19-54ca-4816-a3d1-7e5a39a6ae46' AND is_custom = FALSE;

-- Galeb Duhr (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Galeb Duhr ist ein merkwürdiges felsblockartiges Wesen mit Gliedmaßen, die als Hände und Füße fungieren. Diese intelligenten Kreaturen sind sehr groß und bewegen sich langsam. Sie leben in felsigen oder bergigen Gebieten, wo sie die Erdkraft spüren und die Felsen um sie herum kontrollieren können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Galeb Duhr sind ziemlich einzelgängerische Kreaturen, die es vorziehen, mit einigen ihrer eigenen Art zu leben, und mit keiner anderen Art, einschließlich Erdelementaren. Wenn sie genähert werden, neigen Galeb Duhr dazu, der Begegnung auszuweichen, indem sie in der Erde verschwinden. Wenn sie jedoch verfolgt oder anderweitig gereizt werden, zögern Galeb Duhr nicht, den Eindringling zu bekämpfen.'),
  habitat_society = COALESCE(habitat_society, 'Galeb Duhr, von denen angenommen wird, dass sie von der Elementarebene der Erde stammen, werden manchmal in kleinen Familiengruppen in bergigen Regionen der Hauptmateriellen Ebene angetroffen. Es ist nicht bekannt, wie (oder ob) sich Galeb Duhr fortpflanzen, aber "junge" Galeb Duhr wurden gelegentlich berichtet - diese angetroffenen Exemplare waren kleiner als normal.'),
  ecology         = COALESCE(ecology, 'Galeb Duhr haben keine natürlichen Feinde, außer denen, die nach den Edelsteinen gieren, die sie sammeln. Galeb Duhr fressen Gestein und bevorzugen Granit vor anderen Arten, während sie jede Sedimentart verschmähen. Die Felsen, die sie fressen, werden Teil der riesigen Kreaturen; eine solche Mahlzeit muss nur alle zwei oder drei Monate stattfinden.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'c57eda81-68da-4c6d-923e-086a0c7beffa' AND is_custom = FALSE;

-- Gargantua (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gargantua sind wahrhaft monströse Spezies, sowohl in ihrer Größe als auch Wildheit. Ob sie Rückfälle in ein anderes Zeitalter, Aberrationen natürlicher Prozesse oder Ergebnisse verrückter magischer Experimente sind, ist unbekannt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl er einen gewissen Grad von Intelligenz besitzt, sind die Handlungen des reptilienhaften Gargantua - zusammen mit den Handlungen der meisten Gargantua - die von geistlosen Rohlingen, die auf Zerstörung um der Zerstörung willen aus sind. Er greift mit schwingenden Hieben seiner Vorderklauen und vorstößenden Bissen seiner mächtigen Kiefer an. Wenn er sich aufrecht bewegt, kann er Opfer niedertrampeln und 10-100 (10W10) Schadenspunkte verursachen. Er fegt kontinuierlich den Boden mit seinem massiven Schwanz und schwingt ihn 27,4 m hinter sich und zu jeder Seite. Jede Kreatur in Reichweite des Schwanzes muss einen erfolgreichen Rettungswurf gegen Tod schaffen oder 8-80 (8W10) Schadenspunkte erleiden.'),
  habitat_society = COALESCE(habitat_society, 'Einige wenige reptilienhafte Gargantua machen ihr Zuhause auf den Böden subtropischer Ozeane. Die meisten jedoch leben auf entlegenen tropischen Inseln, weit entfernt von zivilisierten Ländern. Solche Inseln sind über die Ozeane von Kara-Tur verstreut, wobei die meisten von ihnen nicht kartographiert sind. Die bemerkenswerteste Ausnahme ist die Insel der Gargantua, eine der Äußeren Inseln vor der südwestlichen Spitze von Wa. Diese Insel wird vollständig von Gargantua verschiedener Arten bewohnt.'),
  ecology         = COALESCE(ecology, 'Der reptilienhafte Gargantua ist ein Allesfresser. Er frisst hauptsächlich Pflanzen und verschlingt ganze Bäume in einem einzigen Schluck. Aber er genießt auch lebende Beute aller Arten. Er kann sogar Mineralien, Edelsteine und andere anorganische Substanzen verzehren, wenn Vegetation und Wild knapp sind.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = 'b8373a3a-dca7-40f2-8bf5-84a8551a840d' AND is_custom = FALSE;

-- Gargoyle I (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese Monster sind grausame Raubtiere magischer Natur, die man gewöhnlich inmitten von Ruinen oder in unterirdischen Höhlen antrifft. Sie haben ihre eigene kehlige Sprache.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gargoyles greifen alles an, was sie entdecken, unabhängig davon, ob es gut oder böse ist, und zwar zu 90% der Zeit. Am liebsten foltern sie hilflose Beute zu Tode.'),
  habitat_society = COALESCE(habitat_society, 'Gargoyles leben in kleinen Gruppen mit anderen ihrer Art und sind an wenig mehr interessiert, als andere Kreaturen zu verletzen. Kleinere Tiere sind für diese abscheulichen Monster kaum der Mühe wert, die es vorziehen, Menschen oder andere intelligente Kreaturen anzugreifen.'),
  ecology         = COALESCE(ecology, 'Ursprünglich waren Gargoyles geschnitzte Dachrinnen, die groteske Menschen- und Tierfiguren darstellten. Sie wurden so gestaltet, dass das durch die Rinnen fließende Wasser von der Wand weggeschleudert wurde, um Flecken und Erosion zu verhindern. Später verwendete ein unbekannter Magier eine mächtige Verzauberung, um diese schrecklichen Skulpturen zum Leben zu erwecken. Die Rasse der Gargoyles hat geblüht und sich über die ganze Welt ausgebreitet.'),
  no_appearing    = COALESCE(no_appearing, '2-16')
WHERE id = 'bdf7ca38-69a5-4b80-979a-4b61b839fb18' AND is_custom = FALSE;

-- Genie (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dschinns stammen aus den Elementarebenen. Dort, unter ihresgleichen, haben sie ihre eigenen Gesellschaften. Dschinns werden manchmal auf der Primär-Materiellen Ebene angetroffen und oft gezielt beschworen, um irgendeinen Dienst für einen mächtigen Magier oder Priester zu erfüllen. Alle Dschinns können zu jeder der Elementarebenen reisen, ebenso zur Primär-Materiellen und zur Astralebene. Dschinns sprechen ihre eigene Sprache und die aller intelligenten Wesen, denen sie begegnen, durch eine begrenzte Form der Telepathie.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die magische Natur der Djinn ermöglicht es ihnen, einmal pro Tag folgende Fähigkeiten zu nutzen: nahrhafte Speisen für 2W6 Personen erschaffen und Wasser oder Wein für 2W6 Personen erschaffen; weiche Waren (bis zu 16 Kubikmeter) oder hölzerne Gegenstände (bis zu 9 Kubikmeter) von dauerhafter Natur erschaffen; Metall erschaffen, bis zu 45,4 kg Gewicht mit kurzer Lebensdauer (je härter das Metall, desto weniger Zeit hält es; Gold hat etwa eine 24-stündige Existenz, während Djinni-Stahl nur eine Stunde anhält); Illusion erschaffen wie ein Magier der 20. Stufe mit sowohl sichtbaren als auch hörbaren Komponenten, die ohne Konzentration anhalten, bis sie berührt oder magisch aufgelöst werden; Unsichtbarkeit, Gasgestalt oder Windwandeln nutzen.'),
  habitat_society = COALESCE(habitat_society, 'Das heimatliche Land der Djinn ist die Elementarebene der Luft, wo sie auf schwimmenden Inseln aus Erde und Stein leben, die zwischen 0,9 m und mehreren Kilometern Durchmesser haben. Sie sind vollgestopft mit Gebäuden, Höfen, Gärten, Springbrunnen und Skulpturen aus elementaren Flammen. In einem typischen Djinn-Landbesitz leben 3W10 Djinn verschiedener Altersstufen und Mächte, sowie 1W10 Jann und 1W10 Elementarkreaturen niedriger Intelligenz. Alle werden vom örtlichen Scheich regiert, einem Djinn mit maximalen Trefferpunkten.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '664cfdb5-1580-4994-94d9-9eca53301f60' AND is_custom = FALSE;

-- Ghost (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Geister sind die Seelen von Menschen, die entweder im Leben außerordentlich böse waren oder deren Tod so ungewöhnlich emotional war, dass sie mit der Gabe des Untotenstatus verflucht wurden. Daher wandeln sie nachts oder an dunklen Orten umher. Diese Geister hassen Güte und Leben und hungern danach, die Lebensessenz von den Lebenden zu ziehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Da Geister unkörperlich (ätherisch) sind, begegnet man ihnen gewöhnlich nur als Kreatur in einem ähnlichen Zustand, obwohl sie von nicht-ätherischen Kreaturen gesehen werden können. Die übernatürliche Macht eines Geistes ist jedoch derart, dass der bloße Anblick eines Geistes jedes humanoide Wesen 10 Jahre altern lässt und es für 2-12 (2W6) Runden panisch fliehen lässt, es sei denn, ein Rettungswurf gegen Zauber gelingt. Priester über der 6. Stufe sind gegen diesen Effekt immun, und alle anderen Humanoiden über der 8. Stufe dürfen +2 zu ihren Rettungswürfen addieren.'),
  habitat_society = COALESCE(habitat_society, 'In den meisten Fällen ist ein Geist auf ein kleines physisches Gebiet beschränkt, das der Geist heimsucht. Diejenigen, die Geschichten über ein verfluchtes Gebiet gehört haben, können daher versuchen, es zu ihrer eigenen Sicherheit zu meiden.'),
  ecology         = COALESCE(ecology, 'Die schreckliche Furcht, die der Geist verursacht und die ein Opfer 10 Jahre altern lässt, wird vom gewöhnlichen Menschen nicht gut verstanden, der sie oft der Tatsache zuschreibt, dass ein Geist "tot" ist. Wenn dies der Fall wäre, dann hätten sicherlich Skelette und Zombies denselben Effekt, was sie jedoch nicht haben.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'a4ccb67d-9f4f-4ab4-9ef6-26fdb76bcf20' AND is_custom = FALSE;

-- Ghoul (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ghule sind untote Kreaturen, einst Menschen, die sich nun vom Fleisch von Leichen nähren. Obwohl der Wandel vom Menschen zum Ghul ihren Verstand zerrüttet und zerstört hat, besitzen Ghule eine schreckliche Verschlagenheit, die es ihnen ermöglicht, ihre Beute höchst wirkungsvoll zu jagen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ghule greifen an, indem sie mit ihren schmutzigen Nägeln kratzen und mit ihren Reißzähnen beißen. Ihre Berührung bewirkt, dass Menschen (einschließlich Zwerge, Gnome, Halbelfen und Halblinge, aber ausgenommen Elfen) erstarren, es sei denn, ein Rettungswurf gegen Lähmung ist erfolgreich. Diese Lähmung dauert 3-8 (2+1W6) Runden oder bis sie von einem Priester aufgehoben wird.'),
  habitat_society = COALESCE(habitat_society, 'Ghule und Ghasts werden am häufigsten in der Nähe von Friedhöfen angetroffen, wo sie reichlich Leichen finden können, von denen sie sich nähren.'),
  ecology         = COALESCE(ecology, 'Ghule (und Ghasts, wie später beschrieben) erfreuen sich an widerlichen und abscheulichen Dingen - woraus wir unsere Adjektive "ghulisch" und "grässlich" ableiten.'),
  no_appearing    = COALESCE(no_appearing, '2-24 (2d12)')
WHERE id = '78386fa7-ba98-408c-90f5-f07fabbf6e56' AND is_custom = FALSE;

-- Giant, Cloud (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wolkenriesen betrachten sich selbst als über allen anderen Riesen stehend, außer den Sturmriesen, die sie als Gleichgestellte ansehen. Sie sind kreativ, schätzen schöne Dinge und sind Meisterstrategen im Kampf.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wolkenriesen kämpfen in gut organisierten Einheiten und verwenden sorgfältig entwickelte Schlachtpläne. Sie ziehen es vor, aus einer Position über ihren Gegnern zu kämpfen. Eine beliebte Taktik besteht darin, den Feind zu umkreisen und ihn mit Steinen zu bombardieren, während die Riesen mit magischen Fähigkeiten ihn mit Zaubersprüchen angreifen. Wolkenriesen können Steine bis zu einer maximalen Reichweite von 219,5 m schleudern und dabei 2-24 (2W12) Schadenspunkte verursachen. Ihre riesigen Morgensterne verursachen 6-24 (6W4) +11 Schadenspunkte, das Dreifache des normalen (menschengroßen) Schadens plus ihren Stärkebonus. Einer von 10 Wolkenriesen wird eine magische Waffe besitzen.'),
  habitat_society = COALESCE(habitat_society, 'Wolkenriesen leben in kleinen Sippen von höchstens sechs Riesen. Diese Sippen kennen jedoch die Lage von 1-8 anderen Sippen und werden sich mit einigen dieser Sippen für Feierlichkeiten, Schlachten oder zum Handel zusammenschließen. Diese vereinten Sippen werden einen von ihnen als ihren Anführer anerkennen - dies ist gewöhnlich ein älterer Wolkenriese, der magische Fähigkeiten besitzt. Einer von 10 Wolkenriesen wird Zaubersprüche haben, die einem Magier der 4. Stufe entsprechen, und einer von 20 Wolkenriesen wird einem Priester der 4. Stufe entsprechen. Ein Wolkenriese kann nicht sowohl Priester- als auch Magierfähigkeiten haben.'),
  ecology         = COALESCE(ecology, 'Wolkenriesen bevorzugen sorgfältig zubereitete Speisen mit Gewürzen und Saucen und schätzen erlesene, gereifte Weine.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = 'ee6abec1-6722-4373-9748-65992fc5de87' AND is_custom = FALSE;

-- Giant, Cyclops (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein zwergenhafter Verwandter der wahren Riesen, Zyklopsskin sind einäugige Riesen, die allein oder in kleinen Gruppen leben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Zyklopsskin sind entweder mit einer Keule oder einer Bardiche bewaffnet. Jeder trägt auch einen schweren Wurfspeer (1W6 Schaden) und eine Schleuder großer Größe (1W6 Schaden) bei sich. Sie tragen niemals Rüstung oder verwenden Schilde, da ihre zähe Haut ihnen ausreichend Schutz vor den meisten Angriffen gewährt.'),
  habitat_society = COALESCE(habitat_society, 'Die einäugigen Humanoiden meiden organisierte Siedlungen. Wenn sie in Ruhe gelassen werden, neigen sie dazu, bewaffnete Gruppen in Ruhe zu lassen, obwohl sie nicht davor zurückschrecken, eine viel schwächere Streitmacht anzugreifen, wenn sie auf eine solche stoßen. Zyklopsskin haben keinerlei Achtung vor irgendeiner anderen Lebensform als sich selbst. Gefangene werden entweder versklavt oder gefressen. Dies geschieht nicht sehr oft, da die Zyklopsskin dazu neigen, in abgelegenen felsigen Gegenden zu leben. Sie wandern selten mehr als 16,1 km von ihren Höhlen weg.'),
  ecology         = COALESCE(ecology, 'Zyklopsskin können von fast jeder tierischen oder pflanzlichen Nahrung überleben. Sie mögen Fleisch aller Art und schätzen es über pflanzliche Nahrung. Während sie vom Land leben, leben sie nicht mit ihm. Sie haben absolut keine sanitären Praktiken und kochen selten sogar ihre Mahlzeiten. Sie treffen keine Vorkehrungen, um ihre Umgebung beim Jagen zu erhalten, und gelten als eine der am leichtesten zu verfolgenden Kreaturen ihrer Größe.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = '5891f0b5-618e-4f6d-9fb6-df63b80d96cd' AND is_custom = FALSE;

-- Giant, Ettin (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ettins oder Zweiköpfige Riesen, wie sie oft genannt werden, sind bösartige und unberechenbare Jäger, die nachts auf die Pirsch gehen und jedes Fleisch fressen, das sie erbeuten können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Zwei Köpfe zu haben ist definitiv ein Vorteil für die Ettins, da einer immer wachsam ist und nach Gefahr und potentieller Nahrung Ausschau hält. Das bedeutet, dass ein Ettin nur bei einem Wurf von 1 auf 1W10 überrascht wird. Ein Ettin hat auch Infrasicht bis zu 27,4 m, was ihm ermöglicht, auch im Dunkeln effektiv zu jagen und zu kämpfen. Obwohl Ettins eine niedrige Intelligenz haben, sind sie gerissene Kämpfer. Sie ziehen es vor, ihre Opfer aus dem Hinterhalt anzugreifen, anstatt in einen direkten Kampf zu stürmen, aber sobald die Schlacht begonnen hat, kämpfen Ettins meist wütend, bis alle Feinde tot sind oder sich das Blatt gegen sie wendet. Ettins ziehen sich nicht leicht zurück und tun dies nur, wenn ein Sieg unmöglich ist.'),
  habitat_society = COALESCE(habitat_society, 'Ettins errichten gerne ihre Baue in abgelegenen, felsigen Gebieten. Sie bewohnen dunkle, unterirdische Höhlen, die nach verwesendem Futter und Abfall stinken. Ettins sind im Allgemeinen Einzelgänger, und Paarungspaare bleiben nur wenige Monate zusammen, nachdem ihnen ein junger Ettin geboren wurde. Junge Ettins reifen sehr schnell, und acht bis zehn Monate nach ihrer Geburt sind sie selbständig genug, um auf eigene Faust loszuziehen.'),
  ecology         = COALESCE(ecology, 'Da die Ettingesellschaft so primitiv ist, produzieren sie wenig von Wert für zivilisierte Kreaturen. Ettins dulden die Anwesenheit anderer Kreaturen wie Orks in der Nähe ihres Baus, wenn sie auf irgendeine Weise nützlich sein können. Ansonsten neigen Ettins dazu, gewalttätig isolationistisch zu sein und zermalmen Eindringlinge ohne zu zögern.'),
  no_appearing    = COALESCE(no_appearing, '1 or 1-4')
WHERE id = 'a1a67f73-128f-495a-ab63-bd08c77a7e5f' AND is_custom = FALSE;

-- Giant, Firbolg (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Von allen Riesenarten sind die Firbolg die mächtigsten, aufgrund ihrer natürlichen Intelligenz und beträchtlichen magischen Kraft.'),
  combat_tactics  = COALESCE(combat_tactics, 'Firbolg können alle großen Waffen verwenden; sie verschmähen den Gebrauch von Rüstung oder Schilden. Von menschengemachten Waffen bevorzugen sie zweihändige Schwerter und Hellebarden, die sie beide ohne Abzug einhändig führen können. Waffen ihrer eigenen Herstellung sind doppelt so große Entsprechungen menschlicher Waffen, für die sie einen Stärkebonus erhalten (19 Stärke, +7 Schaden). Wenn sie diese riesigen Waffen jedoch mit beiden Händen führen, verursachen sie den doppelten normalen Schaden plus den Stärkebonus.'),
  habitat_society = COALESCE(habitat_society, 'Firbolg leben in abgelegenen Wäldern und Hügeln. Diese Riesenart misstraut den meisten anderen zivilisierten Völkern und hält sich von ihnen fern. Sie halten sich mit Druiden und Feenwesen einschließlich Elfen auf gutem Fuß, bitten weder um viel noch geben sie viel, vermeiden aber Beleidigungen oder Verletzungen. Fremden begegnen sie mit Vorsicht, häufig in illusionärer Verkleidung als Angehörige ihres eigenen Volkes. Sie greifen nicht ohne Grund an oder töten, erfreuen sich aber an Streichen, besonders solchen, die Fremde um ihre Schätze erleichtern.'),
  ecology         = COALESCE(ecology, 'Firbolg leben vom Land und mit ihm. Ihre Häuser werden aus Bäumen gebaut, die um das Haus herum gerodet werden. Der Clan hält ein Feld für die Ernte, aber nur genug, um seine Ernährung zu ergänzen. Sie tauschen Arbeiten, die große Stärke erfordern, gegen Nahrung, normalerweise mit anderen friedlichen Völkern in den Wäldern oder Hügeln. Der Rest ihrer Nahrung wird durch Sammeln und Jagen in einem Gebiet von bis zu 32,2 km um ihr Gehöft erhalten. Fleisch wird in kleinen Mengen für die meisten Mahlzeiten verwendet, obwohl große Feiern immer einen großen Braten beinhalten.'),
  no_appearing    = COALESCE(no_appearing, '1-4 or 4-16')
WHERE id = 'dfc4ee67-3f41-49b3-bd24-c2b5b3293fa1' AND is_custom = FALSE;

-- Giant, Fire (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Feuerriesen sind brutal, rücksichtslos und militaristisch.'),
  combat_tactics  = COALESCE(combat_tactics, 'Feuerriesen sind immun gegen nichtmagisches Feuer und Hitze sowie gegen den Atem Roter Drachen. Sie sind resistent gegen alle Arten von magischem Feuer; solche Angriffe verursachen -1 Trefferpunkt pro Schadenswürfel. Erwachsene Feuerriesen können Steine für 2-20 (2W10) Schadenspunkte schleudern. Ihre Mindestreichweite beträgt 2,7 m, während ihre Maximalreichweite 182,9 m ist. Sie können ähnlich große Geschosse zu 50% der Zeit abfangen. Sie kämpfen üblicherweise in disziplinierten Gruppen und werfen Steine, bis ihnen die Munition ausgeht oder der Gegner in den Nahkampf kommt. Feuerriesen warten oft in Hinterhalten an Lavaseen oder heißen Quellen und schleudern erhitzte Steine auf Opfer für zusätzliche 1-6 Schadenspunkte.'),
  habitat_society = COALESCE(habitat_society, 'Feuerriesen leben in gut organisierten militärischen Gruppen und bewohnen große Burgen oder Höhlen. Wenn sie in ihrem Bau angetroffen werden, sind dort 13-20 (1W8+12) Riesen, von denen die Hälfte unreife Riesen sind. Um die Reife eines Riesen zu bestimmen, würfle 1W4. Ein Wurf von 4 zeigt ein Kleinkind ohne Kampffähigkeit und mit den Trefferpunkten eines Ogres an, während Würfe von 1-3 ältere Nachkommen mit um 1, 2 bzw. 3 reduzierten Trefferwürfeln, Schaden und Angriffswürfen anzeigen.'),
  ecology         = COALESCE(ecology, 'Feuerriesen leben überall dort, wo es viel Hitze gibt. Sie bevorzugen vulkanische Gebiete oder Bereiche mit heißen Quellen. Häufig teilen sie ihre Baue mit anderen feuerbewohnenden Kreaturen wie Salamandern oder Feuerelementaren.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = 'a41b6f32-3409-4a2d-97e8-5c1e4a715f6c' AND is_custom = FALSE;

-- Giant, Fog (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Verwandt mit den Wolkenriesen, sind diese großen Felswurfspezialisten intelligenter und heimtückischer als in Geschichten oder Liedern dargestellt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Nebelriesen jagen normalerweise in Gruppen von 2-5 Männchen, obwohl sie sich manchmal mit ein oder zwei Wolkenriesen zusammentun, um eine Jagdgruppe von 3-7 zu bilden. Sie bevorzugen Angriffe aus der Deckung (Nebel wird am meisten bevorzugt). Nach einigem Fernkampf mit Felswurf, um ihre Gegner zu zerstreuen, stürmen sie in den Nahkampf mit fliegenden Fäusten und Schwertern. Erwachsene Nebelriesen können Felsen bis zu 82-219,5 m weit schleudern und dabei 2-20 Schadenspunkte bei jedem Getroffenen verursachen. Sie haben auch eine 45% Chance, geworfene Waffen ähnlicher Größe zu fangen, können aber keine abgeschossenen Geschosse wie Pfeile, Bolzen und Schleudersteine fangen. Im Nahkampf kämpfen sie normalerweise mit Keulen und Fäusten, obwohl Geschichten über schwertbewaffnete Nebelriesen häufig sind.'),
  habitat_society = COALESCE(habitat_society, 'Nebelriesen sind stolz auf ihre Stärke und Kampffähigkeiten und spielen oft Spiele während Jagdausflügen, um zu versuchen, einander zu übertreffen. Ihr liebstes solches Spiel heißt "Copsi" und besteht darin, dass sich die Riesen paarweise zusammentun, um immer größere Felsbrocken zu ihren Partnern zu werfen, bis eines der Paare seinen Wurf verfehlt.'),
  ecology         = COALESCE(ecology, 'Aufgrund ihrer Größe verbrauchen Nebelriesen große Mengen an Nahrung und benötigen ein beträchtliches Territorium pro Jagdgruppe, um sich zu ernähren. Die Riesen errichten oft territoriale Markierungen aus Felsbrocken und Baumstämmen, um die Grenzen zwischen ihren Jagdgebieten zu definieren. Sie sehen es nicht gern, wenn jemand diese Markierungen niederreißt oder bewegt. Ihre regulären Pfade sind schwer zu verbergen und werden stattdessen mit Steinschlägen und Baumstämmen eingefallen, um Eindringlinge abzuschrecken.'),
  no_appearing    = COALESCE(no_appearing, '1-4 (rarely 1-6)')
WHERE id = '9e945f11-45e1-4496-b610-a5ec09dc4434' AND is_custom = FALSE;

-- Giant, Fomorian (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Fomorianer sind die abscheulichsten, entstelltesten und bösartigsten aller Riesenverwandten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Fomorianer verwenden alle Arten von Keulen und anderen stumpfen Instrumenten. Unabhängig von der Waffe verursacht sie doppelten Schaden plus 8 Punkte für Stärke, während ihre Fäuste allein 2W4+8 Schadenspunkte verursachen. Ihre Entstellungen hindern sie daran, Felsbrocken zu schleudern wie echte Riesen. Sie arbeiten alle Metallstücke, die sie finden und sammeln können, in ihre Kleidung ein, um ihre Rüstungsklasse zu verbessern. Der typische Fomorianer hat RK 3, während ein besonders gut gepanzerter oder einer mit einem Schild eine RK von 1 erreichen könnte, aber nicht besser.'),
  habitat_society = COALESCE(habitat_society, 'Fomorianer leben in Berghöhlen, verlassenen Minen oder anderen unterirdischen Bereichen. Sie verändern ihre Behausungen selten, sondern passen sich an das an, was bereits vorhanden ist. Diese entstellten Riesen wandern durch den gesamten unterirdischen Komplex, über nahezu jede Entfernung, nur aufgehalten von Gefahren, denen sie sich nicht stellen wollen. Ein fomorianischer Clan wählt eine kleine, für sie verteidigbare Nische als Bau. Ihre Territorien sind manchmal durch die Körper ihrer Feinde markiert. Ihr Schatz besteht nur aus gestohlenen Gegenständen von Feinden. Rüstungsteile werden zu ihrem eigenen zusammengestückelten Schutz hinzugefügt. Da sie sich nicht darum kümmern, verschlechtert sich diese Rüstung schnell und wird wertlos.'),
  ecology         = COALESCE(ecology, 'Diese verdrehten Riesen können wochenlang mit wenig oder gar keiner Nahrung überleben. Das ist gut, da ihre unterirdischen Behausungen keine Fülle davon bieten. Sie können fast jedes organische Material fressen, einschließlich Pilzen, Flechten, Pflanzen aller Art, Fledermäusen, Mäusen und Fischen. Sie schätzen besonders den Geschmack großer Säugetiere, vor allem solcher, die darum betteln, nicht gefressen zu werden. Die Zubereitung einer Mahlzeit beinhaltet gewöhnlich eher Folter als irgendwelche Bemühungen, den Geschmack zu verbessern.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'f49d24dc-2ed9-4af4-aa5d-e30252ac58b1' AND is_custom = FALSE;

-- Giant, Frost (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wie alle bösen Riesen haben Frostriesen einen Ruf für Rohheit und Dummheit. Dieser Ruf ist berechtigt, aber Frostriesen sind verschlagene Kämpfer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Frostriesen sind immun gegen Kälte. Erwachsene Frostriesen können Steine für 2-20 (2W10) Schadenspunkte schleudern. Ihre Mindestreichweite beträgt 2,7 m, während ihre Maximalreichweite 182,9 m beträgt. Sie können ähnliche große Geschosse zu 40% der Zeit abfangen. Normalerweise beginnen sie den Kampf aus der Distanz und werfen Steine, bis ihnen die Munition ausgeht oder der Gegner näher kommt. Eine ihrer bevorzugten Strategien ist es, Opfer zu überfallen, indem sie sich im Schnee an der Spitze eines eisigen oder schneereichen Hangs vergraben, wo Gegner Schwierigkeiten haben werden, sie zu erreichen.'),
  habitat_society = COALESCE(habitat_society, 'Frostriesen leben in kleinen Banden, die aus einem Anführer, seinen Handlangern und ihren Mitläufern bestehen. Eine Bande besetzt normalerweise eine primitive Burg oder eisige Höhle. Wenn sie in ihrem Bau angetroffen werden, sind 9-16 (1W8+8) Riesen anwesend; die Hälfte davon ist unreif. Um die Reife eines Riesen zu bestimmen, wirf 1W4. Ein Wurf von 4 zeigt einen Säugling ohne Kampffähigkeiten und mit den Trefferpunkten eines Oggers an; Würfe von 1-3 zeigen ältere Nachkommen mit Trefferwürfeln, Schaden und Angriffswürfen eines Steinriesen an.'),
  ecology         = COALESCE(ecology, 'Frostriesen leben in eiskalten, arktischen Ländern mit Gletschern und starkem Schneefall. Frostriesen essen hauptsächlich Fleisch, das sie selbst jagen und töten können. Sie überfallen menschliche und Halbmenschen-Siedlungen wegen Nahrungsmitteln und anderer Beute.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = 'a822e9d0-3341-437d-b493-bdc155be2a0a' AND is_custom = FALSE;

-- Giant, Hill (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hügelriesen sind selbstsüchtige, gerissene Bestien, die durch Jagd und durch Terrorisierung und Plünderung nahegelegener Gemeinden überleben. Trotz ihrer niedrigen Intelligenz sind sie fähige Kämpfer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hügelriesen ziehen es vor, ihre Gegner von hohen Felsklippen aus zu bekämpfen, wo sie ihre Ziele mit Steinen und Felsbrocken bombardieren können, während sie die Risiken für sich selbst begrenzen.'),
  habitat_society = COALESCE(habitat_society, 'Ein Hügelriesenbau wird 9-16 (1d8+8) Riesen haben; gewöhnlich eine Großfamilie. Manchmal nehmen diese Familien einzelne Hügelriesen in ihre Reihen auf. Wenn sechs oder mehr Riesen in einem Bau angetroffen werden, ist die Hälfte von ihnen männlich, ein Viertel weiblich und der Rest sind unreife Riesen. Um die Reife eines Riesen zu bestimmen, würfle 1d4. Ein Wurf von 4 zeigt einen Säugling ohne Kampffähigkeit und mit Trefferpunkten eines Gnolls an; Würfe von 1-3 zeigen ältere Nachkommen mit Trefferwürfeln, Schaden und Angriffswürfen gleich denen eines Ogers.'),
  ecology         = COALESCE(ecology, 'Die Hauptnahrung der Hügelriesen besteht aus Fleisch, das sie durch Jagd erlangen. Das Fleisch junger Grüner Drachen gilt als Delikatesse, und häufig organisieren Riesen, die auf bewaldeten Hügeln und Bergen leben, Jagdgruppen auf der Suche nach Grünen Drachen-Horten. Im Gegenzug ist bekannt, dass Grüne Drachen Hügelriesen jagen.'),
  no_appearing    = COALESCE(no_appearing, '1-12')
WHERE id = '17692fd9-dd69-4f43-b41b-aaa638cd195e' AND is_custom = FALSE;

-- Giant, Mountain (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Bergriesen sind riesige Humanoide, die in abgelegenen Berghöhlen leben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Bergriesen greifen immer auf direkte Art an, nicht aus dem Hinterhalt oder mit Täuschung. Sie lieben es, eine hohe, uneinnehmbare Position mit vielen Felsbrocken zu erreichen. In solch einer Position suchen Bergriesen selten Deckung, sondern stehen offen da, um ihre Geschosse zu schleudern. Sie können Felsbrocken auf ihre Gegner hinabschleudern und dabei jeweils 2W10 Schadenspunkte verursachen. Sie können ähnliche Geschosse zu 30% der Zeit abfangen.'),
  habitat_society = COALESCE(habitat_society, 'Das Heim einer Familie von Bergriesen befindet sich oft in einer großen Felshöhle in einem Berg. Häufig gibt es unerforschte Gänge, die aus dem Heim der Riesen herausführen. Sie haben selten Interesse an irgendetwas jenseits ihrer Höhle. Es besteht eine 75%ige Chance, dass herbeigerufene Kreaturen als Wachen und Untergebene in der Höhle fungieren.'),
  ecology         = COALESCE(ecology, 'Bergriesen sind Sammler und Jäger. Ihr Lieblingsfutter sind Bergschafe. Sie essen auch Nüsse, Knollen und andere essbare Bergpflanzen. Nichts jagt Bergriesen, aber manchmal wählen sie die falsche Höhle, um sich häuslich niederzulassen. Da sie dazu neigen, nicht alle hinteren Tunnel vollständig zu erkunden, ist es vorgekommen, dass böse Dinge aus dem Untergrund schlafende Riesen angegriffen und verschlungen haben.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'aa067245-6c28-4b81-93c7-6b0e655dbef1' AND is_custom = FALSE;

-- Giant, Stone (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Steinriesen sind schlank, aber muskulös. Ihr hartes, haarloses Fleisch ist glatt und grau, wodurch sie leicht mit ihrer bergigen Umgebung verschmelzen können. Ihre hageren Gesichtszüge und tiefen, eingesunkenen schwarzen Augen lassen sie stets grimmig erscheinen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn möglich, kämpfen Steinriesen aus der Entfernung. Sie können Steine über eine Mindestentfernung von 2,7 m bis zu einer Maximalentfernung von 274,3 m schleudern und verursachen mit jedem Stein 3-30 (3W10) Schadenspunkte. Diese Riesen können Steine und ähnliche Wurfgeschosse zu 90% der Zeit abfangen. Eine beliebte Taktik der Steinriesen ist es, nahezu bewegungslos vor Felsen zu stehen, mit dem Hintergrund zu verschmelzen, dann hervorzutreten und Steine zu werfen, um ihre Feinde zu überraschen. Viele Riesen errichten Steinhaufen in der Nähe ihrer Baue, die wie eine Lawine ausgelöst werden können, wenn Eindringlinge zu nahe kommen.'),
  habitat_society = COALESCE(habitat_society, 'Steinriesen bevorzugen es, in tiefen Höhlen hoch auf felsigen, sturmgepeitschten Bergen zu wohnen. Normalerweise leben sie in Gesellschaft ihrer Verwandten, obwohl solche Sippen gewöhnlich nicht mehr als 10 Riesen umfassen. Riesensippen errichten ihre Baue jedoch nahe beieinander, um Gemeinschaftsgefühl und Schutz zu haben. Ein Gebirgszug beherbergt üblicherweise 2-8 Sippen.'),
  ecology         = COALESCE(ecology, 'Steinriesen sind Allesfresser, aber sie essen nur frische Nahrung. Sie kochen und essen ihr Fleisch schnell, nachdem es getötet wurde. Sie verwenden die Häute der Tiere als Decken und tauschen, was sie nicht brauchen, mit nahegelegenen menschlichen Gemeinschaften gegen Stoffballen oder Herdentiere ein, die sie als Nahrung verwenden. Viele Steinriesengruppen halten Riesenziegen in und nahe ihren Bauen, damit sie eine kontinuierliche Versorgung mit Milch, Käse und Butter haben.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = '1a4628fd-cde4-4067-904a-89584c34647d' AND is_custom = FALSE;

-- Giant, Storm (matched by token_sort)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sturmriesen sind sanftmütig und zurückgezogen lebend. Sie sind normalerweise tolerant gegenüber anderen, können aber sehr gefährlich werden, wenn sie wütend sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle Sturmriesen sind immun gegen Elektrizität und Blitze. Sie verwenden Waffen und besondere Fähigkeiten anstatt Steine zu schleudern, können aber große Geschosse zu 65% der Zeit abfangen.'),
  habitat_society = COALESCE(habitat_society, 'Sturmriesen sind zurückgezogen und einzelgängerisch, aber nicht schüchtern. Sie leben in Burgen, die auf Wolkeninseln (60%), Berggipfeln (20%) oder unter Wasser (10%) erbaut sind. Sie führen ein ruhiges, nachdenkliches Leben und verbringen ihre Zeit damit, über die Welt zu sinnieren, Musik zu komponieren und zu spielen sowie ihr Land zu bestellen oder Nahrung zu sammeln. Land- und luftbewohnende Sturmriesen stehen gewöhnlich auf gutem Fuß mit benachbarten Silberdrachen und guten Wolkenriesen und arbeiten mit ihnen zur gemeinsamen Verteidigung zusammen. Wasserlebende Sturmriesen haben ähnliche Beziehungen zu Meermenschen und Bronzedrachen.'),
  ecology         = COALESCE(ecology, 'Sturmriesen leben vom Land in der unmittelbaren Umgebung ihrer Bauten. Wenn die natürliche Ernte nicht ausreicht, um sie zu versorgen, schaffen und bestellen sie sorgfältig große Gebiete von Gärten, Feldern und Weinbergen. Sie halten keine Tiere als Nahrung, sondern ziehen es vor zu jagen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-4)')
WHERE id = 'f97dd1c6-b4d2-498b-8a7e-2d7ffb424e11' AND is_custom = FALSE;

-- Giant, Verbeeg (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese als "menschliche Kolosse" bekannten Menschenriesen bewohnen Gebiete, die von Hügelriesen und Ogern befallen sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Verbeeg sind klug genug, andere zuerst den Feind schwächen zu lassen. Das bedeutet nicht, dass sie Feiglinge sind, nur egoistisch und praktisch veranlagt. Da sie gewöhnlich mit Hügelriesen und Ogern angetroffen werden, treiben Verbeeg in den ersten Kampfrunden ihre weniger intelligenten Gefährten vor sich in die Schlacht. Dies wird von vielen Flüchen, Schwüren und höchst anschaulichen Schilderungen der Abstammung der Riesen und Oger begleitet.'),
  habitat_society = COALESCE(habitat_society, 'Verbeeg findet man in denselben Klimazonen wie Oger und Hügelriesen. Diese menschlichen Kolosse werden niemals allein wandernd angetroffen. 30% der wandernden Verbeeg-Begegnungen treffen auf 1W6 dieser Riesenverwandten mit 1W4 Hügelriesen oder Ogern (gleiche Chance), die auch ihren Bau teilen; 50% der Zeit sind 1W6 Verbeeg mit 1W6 Wölfen oder Worgs zusammen (in polaren Klimazonen Winterwölfe oder Eisbären); den Rest der Zeit (20%) werden 1-2 von ihnen mit einer normal großen Gruppe wandernder Monster angetroffen, die in diesem Gebiet gefunden werden (der SL muss in diesem Fall vernünftige Beurteilung walten lassen).'),
  ecology         = COALESCE(ecology, 'Verbeeg essen fast alles, aber sie lieben Fleisch aller Art. Sie unterhalten eine für beide Seiten vorteilhafte Beziehung zu den Riesen und Ogern, die ihren Bau teilen. Die Verbeeg stellen die Intelligenz und Führung bereit, die diesen Riesenarten fehlt, und die Riesen bieten durch ihre größere Kampfkraft Schutz. Eine Gruppe in Aktion zu beobachten kann urkomisch sein, solange man nicht ihr beabsichtigtes Opfer ist. Hügelriesen und Oger sind zu dumm, um viel selbst zu denken. Sie neigen dazu, Anweisungen zu wörtlich zu befolgen. Das bringt die Verbeeg gewöhnlich zur Weißglut. Sie hüpfen von einem Fuß auf den anderen und schreien Beleidigungen zu den verwirrten Riesen, die sie an Größe und Masse überragen, während selbst die einfachsten Anweisungen von diesen begriffsstutzigen Humanoiden falsch interpretiert werden.'),
  no_appearing    = COALESCE(no_appearing, '1-6 or 5-30')
WHERE id = '386bf9f3-1d18-4d00-b37b-8ccbedbba5d1' AND is_custom = FALSE;

-- Giant, Wood (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Waldriesen (auch als Voadkyn bekannt) gehören zu den kleinsten der niederen Riesenrassen und sehen aus wie riesengroße Waldelfen. Sie sind launisch, leichtsinnig und gute Freunde der Waldelfen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Voadkyn kämpfen nicht, es sei denn, sie sind gezwungen, sich selbst oder Verbündete zu verteidigen. Ihre Lieblingswaffe ist ihr riesiger, nicht-magischer Langbogen. Sie erhalten einen +1 Bonus auf Angriffswürfe und 50% bessere Reichweite aufgrund seiner ungewöhnlichen Größe. Die passenden Pfeile sind über 1,2 m lang und verursachen 1W8 Schadenspunkte. Waldriesen schleudern keine Steine oder Felsbrocken. Werden sie zum Nahkampf gedrängt, führen sie ihre zweihändigen Schwerter mit einer Hand.'),
  habitat_society = COALESCE(habitat_society, 'Waldriesen bewohnen dieselben Wälder wie Waldelfen. Sie haben keine Baue und ziehen es vor, unter den Sternen zu leben oder zeitweise bei den Waldelfen zu bleiben. Waldriesen, die im Wald angetroffen werden, sind größtenteils männlich (90%). Weibliche Waldriesen bleiben gewöhnlich in einem provisorischen Lager oder bei den Waldelfen in deren Bau. Nachkommen sind selten, da jedes Weibchen nur 1W4 Kinder in seinem Leben gebiert. Die Jungen werden tief in den Wäldern unter den Waldelfen geboren und aufgezogen, fern von neugierigen Blicken.'),
  ecology         = COALESCE(ecology, 'Der Kiefer der Voadkyn ist groß wegen der übergroßen Mahlzähne darin. Diese Zähne sind völlig ungeeignet für das Fressen von Fleisch, aber sie sind perfekt für Gemüse und andere Pflanzen. Waldriesen können die Blätter und Wurzeln vieler Pflanzen essen, die für Menschen ungenießbar sind. Sie genießen besonders Nüsse und Samen.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'dfe9fa7a-1380-4c0a-9fe5-96c9bca305f3' AND is_custom = FALSE;

-- Gibberling (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sie kommen schreiend, brabbelnd und heulend aus der Nacht. Dutzende, vielleicht Hunderte bucklige, nackte Humanoide schwärmen unaufhörlich vorwärts und schwingen Kurzschwerte. Sie denken weder an Sicherheit, noch an Finesse oder Strategie, und lassen anderen keine Hoffnung, ihren Massenangriff zu stoppen. Und dann, nachdem sie gekommen und getötet haben, ziehen die Gibberlinge wahllos wieder zurück in die Nacht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gibberlinge greifen in großer Zahl an und stoßen grauenhafte Heuler, Klicklaute, Schreie und wahnsinniges Geschwätz aus, das selbst die mutigsten Söldlinge dazu bringt, jede Runde eine Moralprobe zu machen. Spielercharaktere müssen nur eine Moralprobe ablegen, wenn es für ihren Charakter angemessen ist. Die schreiende Horde ist völlig unorganisiert in ihrer Form und zufällig in ihrer Richtung.'),
  habitat_society = COALESCE(habitat_society, 'Es ist schwierig, sich eine soziale Struktur der Gibberlinge vorzustellen. Sie kann grob mit der sozialen Struktur von Lemmingen verglichen werden, die sich ins Meer stürzen, oder mit einem Piranhaschwarm in einem Fressrausch. Es gibt keinen Sinn, keine Organisation und keine Individualität. Obwohl sie eindeutig ein primitives Mittel haben, untereinander zu kommunizieren, besitzen sie keine erkennbare Sprache.'),
  ecology         = COALESCE(ecology, 'Versuche, die Baue der Gibberlinge zu finden, haben unvermeidlich zu unterirdischen Gängen geführt, wo sich die Spur schließlich in den tiefsten steinbödigen Vertiefungen der Höhlen verliert.'),
  no_appearing    = COALESCE(no_appearing, '40-400')
WHERE id = 'e6adf19c-eed7-4bf9-b221-92b1657d24b5' AND is_custom = FALSE;

-- Gith (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: Turm des eisernen Willens, Kraft projizieren; Devotionen: Ich-Einflüsterung, Geistesstoß, Kontakt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn möglich, greifen die Gith in der Masse an, meist beginnend mit einem psionischen Angriff durch einen ihrer Anführer. Dann stürmt die gesamte Gruppe schnell in den Nahkampf. Ihr Hauptangriff wird oft durch einen Sprung von bis zu 6,1 m in einem einzigen gewaltigen Satz ausgeführt, um ihre Feinde zu erreichen. Wenn sie diesen Sprung einsetzen, verleiht er ihnen einen +2 Angriffsbonus in der ersten Kampfrunde.'),
  habitat_society = COALESCE(habitat_society, 'Die Gith leben in Stammesorganisationen. Das Individuum mit den mächtigsten psionischen Kräften fungiert generell als Anführer. Alle anderen sozialen Positionen werden nach seinem Belieben verteilt.'),
  ecology         = COALESCE(ecology, 'Gebirgs-Gith leben in unterirdischen Bauen und beanspruchen eine bestimmte Schlucht oder ein Tal als ihr Territorium. Gith, die das Tafelland bewohnen, organisieren ihre Gesellschaft eher nach Art eines nomadischen Jagdclans und gehen dorthin, wo das Wild sie hinführt. Sie zögern nicht, Menschen- oder Halbmenschengruppen anzugreifen, da sie Menschen und Halbmenschen als erlesene Nahrungsquelle betrachten und diese anderem Fleisch vorziehen. Sie greifen sogar Thri-Kreen an, wenn sie hungrig genug sind, aber die Insektoiden schmecken schlecht und entkommen den Gith-Räubern gewöhnlich.'),
  no_appearing    = COALESCE(no_appearing, '10-100')
WHERE id = '51870ccb-89bd-414e-8ad5-2b829cf2e872' AND is_custom = FALSE;

-- Gith, Pirate of (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Als die Githyanki unter ihrer Befreierin Gith sich vom Joch der Illithiden-Sklaverei befreiten, floh dieser Zweig der Rasse nicht in die Astralebene, sondern in den arkanen Raum.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Piraten von Gith können als Kämpfer, Magier oder Kämpfer/Magier agieren, mit einer Begrenzung auf Stufe 11 in jeder Klasse. Typischerweise führt der höchststufige Kämpfer das Schiff. Dies befreit alle Magier (einfach- und mehrklassige) für Spelljamming- oder Kampfaufgaben.'),
  habitat_society = COALESCE(habitat_society, 'Die Piratenphilosophie überträgt sich auf alle Lebensaspekte. Die Stärksten nehmen sich, was sie wollen. Jedes Schiff ist für seine Besatzung sehr wichtig, da es der primäre Faktor bei der Bestimmung der Hackordnung in einer Siedlung ist. Dies erklärt die ständige Suche der Piraten nach besseren Schiffen. Jede Siedlung wird gewaltsam von ihrem besten Schiff oder einer Koalition der besten Schiffe regiert.'),
  ecology         = COALESCE(ecology, 'Die Gith-Piraten sind Fleischfresser, rein und einfach. Es ist ihnen egal, in welchem Zustand sich das Fleisch befindet, außer wenn es verwest ist. Einige der Piratenbanden betreiben auch Kannibalismus.'),
  no_appearing    = COALESCE(no_appearing, '20-40/As ship crew')
WHERE id = 'ba97ad80-f3c1-4783-a7b5-46551208c7e9' AND is_custom = FALSE;

-- Githyanki (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Githyanki sind eine uralte Rasse, die von Menschen abstammt. Sie bewohnen die Astralebene, verlassen diese Ebene aber oft, um anderen Rassen den Krieg zu erklären. Sie sind in einen langwierigen Krieg mit den Githzerai verwickelt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Githyanki hatten lange Jahre Zeit, die Kriegskunst zu perfektionieren. Ihre bloße Existenz zeugt von ihrer Kampftüchtigkeit. Jeder einzelne Githyanki hat eine Charakterklasse und Stufe, von denen Dinge wie ETW0, Rüstungsklasse, Zaubergebrauch usw. abgeleitet werden.'),
  habitat_society = COALESCE(habitat_society, 'Die Geschichte liefert einige Informationen über die Githyanki - ihre Rasse ist sowohl uralt als auch zurückgezogen lebend. Gelehrte glauben, dass sie einst Menschen waren, die von Gedankenschindern gefangen genommen wurden, um als Sklaven und Vieh zu dienen. Die Gedankenschinder behandelten ihre menschlichen Sklaven grausam und das Volk hegte einen tiefen Groll gegen die Illithiden. Jahrhundertelang steigerten diese Menschen ihren Hass, konnten aber nicht die notwendige Kraft aufbringen, um sich zu befreien. So warteten sie viele Jahre, entwickelten heimlich ihre Macht und warteten auf eine Gelegenheit, gegen ihre Herren zu schlagen. Schließlich trat eine mächtige Frau unter ihnen hervor, eine Befreierin namens Gith. Sie überzeugte das Volk, sich gegen ihre grausamen Herren zu erheben. Der Kampf war lang und bösartig, aber schließlich befreiten sich die Menschen. Sie hatten ihre Freiheit verdient und wurden zu den Githyanki (was in ihrer Sprache Söhne von Gith bedeutet).'),
  ecology         = COALESCE(ecology, 'Githyanki haben eine ähnliche Ökologie wie die der Menschen. Jedoch bietet die Astralebene nicht dieselben Arten von Umgebungen wie die Primäre Materialebene, daher sind ihre kulturellen Gruppen sehr anders. In einer Gesellschaft, wo Bauern und Handwerker unnötig sind, haben sich einzigartigere, spezialisierte Gruppen entwickelt.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (away from lair)')
WHERE id = '5802a342-dcf4-43d4-aae3-fd2ada78867a' AND is_custom = FALSE;

-- Githzerai (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Githzerai sind die klösterlichen, chaotisch neutralen Gegenstücke zu den Githyanki. Die beiden Völker teilen einen Abschnitt ihrer Geschichte; die Githzerai sind der geringere und stärker unterdrückte Ableger des ursprünglichen Volkes, dem die Kriegerin Gith vor Jahrtausenden zur Flucht aus der Sklaverei unter den Gedankendieben verhalf.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Githzerai sind schmucklos und rücksichtslos geradlinig in ihrem Kampf und ihrer Magie. Ihre starke Magieresistenz scheint ihre allgemein schlechtere Kampffähigkeit auszugleichen.'),
  habitat_society = COALESCE(habitat_society, 'Die Githzerai waren ursprünglich Nachkommen einer Menschenrasse, die von der Sklaverei unter Gedankendieben durch eine große weibliche Kriegerin namens Gith befreit wurden. Diese Männer und Frauen entschieden sich jedoch nicht, Giths Wegen zu folgen, nachdem sie gegen ihre Sklavenhalter revoltierten. Stattdessen fielen sie den Lehren eines mächtigen Magiers anheim, der sich zum König - und später zum Gott - des Volkes erklärte. Die Githzerai trennten sich dann von den Githyanki und begannen einen großen Rassenkrieg, der die langen Jahrtausende ohne Nachlassen überdauert hat.'),
  ecology         = COALESCE(ecology, 'Solange Menschen von der Fähigkeit wissen, durch die Ebenen zu reisen, haben sie sich über die natürliche Macht der Githzerai gewundert, nach Belieben von Ebene zu Ebene zu wandern. Obwohl Mensch und Githzerai keine natürlichen Feinde sind, werden häufig Schlachten zwischen den beiden Völkern geführt, teilweise aufgrund des Verlangens einiger Menschen, einen lebenden Githzerai zum Studium zu fangen. Bis heute wurde kein solches Wesen gesichert.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (away from lair)')
WHERE id = 'efaefbf8-50ba-45f3-8658-dd7cfba2ec40' AND is_custom = FALSE;

-- Gloomwing (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Kreatur, die gemeinhin Düsterflügel genannt wird, ist das erwachsene Stadium des düsteren Wurms (siehe unten). Diese riesigen Motten sind auf der Halbebene der Schatten heimisch. Ihre Körper und Flügel sind mit schimmernden, geometrischen Mustern aus Schwarz und Silber bedeckt. Sie haben große, farnartige schwarze Fühler mit weißen Spitzen und acht Beine, die jeweils in einer perlmuttfarbenen Klaue enden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die schimmernden Zeichnungen eines Düsterflügels machen ihn zu einem schwierigen Ziel. Jede Kreatur, die die Motte direkt von oben oder unten betrachtet, muss erfolgreich gegen Zauber würfeln oder wird für 5-8 (1W4+4) Runden verwirrt, wie durch den Magierzauber 4. Grades. Die Zeichnungen bieten auch ausgezeichnete Tarnung, und die Motte ist zu 50% unentdeckbar in Dunkelheit, Zwielicht oder Mondlicht. Erfolgreich getarnte Düsterflügel können keine Verwirrung verursachen.'),
  habitat_society = COALESCE(habitat_society, 'Düsterflügel-Motten sind kurzlebige, einzelgängerische Jäger. Sie verwenden verschiedene Pheromone, um Rivalen abzuwehren und Partner zu finden. Sie bilden Gruppen, aber nur um große Beute anzugreifen, und dann nur, wenn sie durch das Kampfpheromon angelockt werden. Wenn sich zwei Düsterflügel des gleichen Geschlechts treffen, fliehen sie, es sei denn, Kampfpheromon liegt in der Luft.'),
  ecology         = COALESCE(ecology, 'Düsterflügel-Motten leben nur 4-9 (1W6+3) Wochen. Während dieser Zeit suchen sie nach Partnern und fressen gefräßig. Eiertragende Weibchen (½ Chance) nutzen Leichen von kleinen oder größeren Kreaturen als Brutkästen für ihre Eier. Die Eier schlüpfen nach 12 Tagen und bringen 1W6+4 kleine düstere Würmer hervor. Die Leiche kann nicht wiederbelebt werden, es sei denn, der Befall wird zuerst mit einem Krankheit heilen-Zauber entfernt. Wenn sie nicht getötet werden, verschlingen die jungen Würmer den Körper vollständig, wenn sie schlüpfen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '3908b906-ddfa-4a95-b8c6-e06e0be7d47c' AND is_custom = FALSE;

-- Gnoll (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gnolls sind große, böse, hyänenartige Humanoide, die in locker organisierten Banden umherziehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gnolls versuchen ihre Gegner durch schiere Überzahl zu überwältigen und nutzen Hordentaktiken. Wenn sie unter der Führung von Flinds oder einem starken Anführer stehen, können sie dazu gebracht werden, die Reihen zu halten und als Einheit zu kämpfen. Obwohl sie nicht oft Fallen legen, werden sie Hinterhalte legen oder versuchen, von einer Flanke oder Rückenposition aus anzugreifen. Gnolls bevorzugen Schwerter (15%), Stangenwaffen (35%) und Streitäxte (20%) im Kampf, verwenden aber auch Bögen (15%) und Morgensterne (15%).'),
  habitat_society = COALESCE(habitat_society, 'Gnolls werden am häufigsten unterirdisch oder in verlassenen Ruinen angetroffen. Wenn sie sich oberirdisch aufhalten, operieren sie hauptsächlich nachts. Die Gnoll-Gesellschaft wird vom Stärksten regiert, der Furcht und Einschüchterung einsetzt. Wenn sie unterirdisch gefunden werden, haben sie (30% Wahrscheinlichkeit) 1-3 Trolle als Wachen und Diener. Oberirdisch halten sie Haustiere (65% der Zeit) wie 4-16 Hyänen (80%) oder 2-12 Hyänodons (20%), die als Wachen fungieren können.'),
  ecology         = COALESCE(ecology, 'Gnolls fressen alles Warmblütige und bevorzugen intelligente Kreaturen gegenüber Tieren, weil sie besser schreien. Sie werden ein Gebiet vollständig abgejagt haben, bevor sie weiterziehen. Es kann mehrere Jahre dauern, bis das Wild zurückkehrt. Wenn man sie am natürlichen Altern sterben lässt, wird der typische Gnoll etwa 35 Jahre alt.'),
  no_appearing    = COALESCE(no_appearing, '2-12 (2d6)')
WHERE id = '527af4eb-4f96-4231-88ac-8fac550ab748' AND is_custom = FALSE;

-- Gnome (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kleine Vettern der Zwerge, Gnome sind freundlich aber zurückhaltend, schnell dabei, ihren Freunden zu helfen, aber von anderen Völkern selten gesehen, außer sie wollen es. Sie neigen dazu, unterirdisch in hügeligen, bewaldeten Gebieten zu leben, wo sie ihren Interessen in Frieden nachgehen können. Gnome können Kämpfer oder Priester sein, aber die meisten ziehen es vor, stattdessen Diebe oder Illusionisten zu werden. Mehrkassencharaktere sind unter den Gnomen häufiger als bei jedem anderen Halbmenschenvolk.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gnome bevorzugen den Einsatz von Strategie gegenüber roher Gewalt im Kampf und verwenden oft Illusionen auf fantasievolle Weise, um "die Chancen auszugleichen". Ihr großer Hass auf Kobolde und Goblins, ihre traditionellen Feinde, gibt ihnen einen +1 auf ihre Angriffswürfe beim Kampf gegen diese Wesen. Sie sind geschickt darin, den Angriffen großer Gegner auszuweichen und zwingen alle Kreaturen der Riesenklasse (Gnolle, Großgoblins, Oger, Trolle, Riesen usw.) dazu, 4 von ihren Angriffswürfen abzuziehen, wenn sie gegen Gnome kämpfen.'),
  habitat_society = COALESCE(habitat_society, 'Gnome leben in unterirdischen Bauten in abgelegenen hügeligen, bewaldeten Gebieten. Sie sind sippenorientiert, mit freundschaftlichen Rivalitäten zwischen benachbarten Sippen. Sie verbringen ihr Leben mit dem Abbau von Erzen, der Herstellung feinen Schmucks und dem Genuss der Früchte ihrer Arbeit. Gnome arbeiten hart, und sie spielen hart. Sie begehen viele Feste und Feiertage, die normalerweise Spiele, Nasenmess-Wettbewerbe und das Austauschen großartiger Geschichten beinhalten. Ihre Gesellschaft ist gut organisiert, mit vielen Verantwortungsebenen, die in einem einzigen Häuptling gipfeln, der von Priestern in Angelegenheiten beraten wird, die direkt mit ihrer Berufung zusammenhängen.'),
  ecology         = COALESCE(ecology, 'Gnome sind sehr viel ein magischer Teil der Natur, existieren in Harmonie mit dem Land, das sie bewohnen. Sie wählen, unterirdisch zu leben, aber bleiben nahe der Oberfläche, um ihre Schönheit zu genießen.'),
  no_appearing    = COALESCE(no_appearing, '4-12 (4d3)')
WHERE id = '95ce237f-ce73-47f3-a7a1-b2707c1ffbb3' AND is_custom = FALSE;

-- Gnome, Spriggan (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese hässlichen, mürrischen Vettern der Gnome können nach Belieben riesenhaft werden. In beiden Größen sehen Spriggans grundsätzlich gleich aus. Sie sind hässliche, dickleibige Humanoide mit blasser oder matt gelber Haut, braunem oder schwarzem Haar und roten Augen. In seltenen Fällen kann ein Spriggan rotes Haar haben, was sie für ein Symbol des Glücks halten. Ihre Nasen sind groß und knollig, aber nicht jenseits der menschlichen Norm. Sie sind sehr angetan von Schnurrbärten und buschigen Koteletten, aber sie säubern oder kämmen sie nie. Diese Politik der Unsauberkeit erstreckt sich auf ihre Körper und alle anderen Besitztümer. Spriggans riechen nach feuchter Erde, abgestandenem Schweiß und Schmutz.'),
  combat_tactics  = COALESCE(combat_tactics, 'Spriggans sind tückisch und zäh im Kampf. Sie haben eine große Vielfalt an Kampfoptionen. Ihre Hauptfähigkeit ist es, nach Belieben von kleiner zu riesiger Größe zu wechseln. Waffen, Rüstung und andere unbelebte Gegenstände an ihrer Person schrumpfen und wachsen mit ihnen. Diese Handlung dauert die gesamte Runde, während der sie sich bis zu 9,1 m bewegen, aber nicht kämpfen können. Wenn sie klein sind, können Spriggans die folgenden zauberähnlichen Effekte anwenden: gewöhnliche Feuer beeinflussen, zerbrechen und erschrecken (mit einer Strafe von -2 auf den Rettungswurf aufgrund ihrer Hässlichkeit). Sie können eine dieser Fähigkeiten statt des Kampfes einsetzen, einmal in jeder Runde, so oft sie wollen. Wenn sie riesenhaft sind, können Spriggans keine Magie anwenden, außer wieder zu schrumpfen. In dieser Form sind sie so stark wie Hügelriesen (19).'),
  habitat_society = COALESCE(habitat_society, 'Spriggans reisen gewöhnlich in Rudeln, alle männlich. Die Weibchen halten sich in düsteren Bauen oder geheimen Verstecken in vergessenen Ruinen auf und wagen sich selten weiter hinaus als nötig, um Nahrung zu sammeln. Ein Weibchen hat dieselben Kampffähigkeiten wie ein Männchen, außer dass sie nur 7+4 Trefferwürfel in Riesenform haben.'),
  ecology         = COALESCE(ecology, 'Die umherstreifenden Rudel der Männchen neigen dazu, Fleischfresser zu sein und ziehen es vor, ihre Nahrung zu jagen oder zu stehlen. Als solche müssen sie in Bewegung bleiben und weite Kontrollgebiete etablieren. Die Weibchen neigen dazu, Früchte und Getreide zu essen, die leicht in der Nähe ihrer Baue gesammelt werden können. Sie essen nur Fleisch, wenn es von einem Männchen als Teil des Paarungsrituals angeboten wird.'),
  no_appearing    = COALESCE(no_appearing, '3-12')
WHERE id = '28fcf700-2373-4ee5-b0a8-7ea3286e37e0' AND is_custom = FALSE;

-- Goblin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese kleinen, bösen Humanoiden wären nur lästige Schädlinge, wären da nicht ihre großen Zahlen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Goblins hassen helles Sonnenlicht und kämpfen mit -1 auf ihre Angriffswürfe, wenn sie ihm ausgesetzt sind. Diese ungewöhnliche Lichtempfindlichkeit dient den Goblins jedoch unter der Erde gut und verleiht ihnen Infrasicht bis zu 18,3 m.'),
  habitat_society = COALESCE(habitat_society, 'Menschen würden die Höhlen und unterirdischen Behausungen der Goblins als feucht und düster betrachten. Jene wenigen Stämme, die oberirdisch leben, finden sich in Ruinen und sind nur nachts oder an sehr dunklen, bewölkten Tagen aktiv. Sie verwenden keinerlei sanitäre Einrichtungen, und ihre Baue haben einen üblen Gestank. Goblins scheinen einigermaßen widerstandsfähig gegen die Krankheiten zu sein, die in solchem Schmutz gedeihen.'),
  ecology         = COALESCE(ecology, 'Goblins werden nur etwa 50 Jahre alt. Sie müssen nicht viel essen, töten aber allein aus Vergnügen. Sie fressen jede Kreatur von Ratten und Schlangen bis zu Menschen. In mageren Zeiten fressen sie Aas.'),
  no_appearing    = COALESCE(no_appearing, '4-24 (4d6)')
WHERE id = '3331794c-ecfc-4d56-9e23-1f211a9120c3' AND is_custom = FALSE;

-- Golem, General Information (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Golems sind magisch erschaffene Automaten von großer Macht. Ihre Erschaffung erfordert mächtige Magie und elementare Kräfte.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle Golems teilen mehrere gemeinsame Eigenschaften. Sie sind alle immun gegen alle Formen von Gift und können nicht von Lähmung, Bezauberung, Furcht oder anderen geistbasierten Zaubern betroffen werden, da sie keinen eigenen Verstand haben. Bestimmte Zauber können Golems schaden; diese werden unten erwähnt.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = '75d5b7b9-5814-4c37-b64c-d8942b88877d' AND is_custom = FALSE;

-- Golem I (Greater Golem) (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein größerer Golem ist ein künstlicher humanoider Körper, der von einem Elementargeist beseelt wurde, aber unter der vollständigen Kontrolle seines Erschafers bleibt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Größere Golems sind im Kampf geistlos und folgen nur den einfachen Taktiken ihrer Meister. Sie sind völlig emotionslos und können in keiner Weise von ihren Anweisungen abgebracht werden. Sie werden keine Waffen aufheben und im Kampf verwenden, selbst wenn es ihnen befohlen wird, und bevorzugen immer ihre Fäuste. Steingolems haben eine Stärke von 22 zum Zweck des Zerbrechens oder Werfens von Gegenständen.'),
  habitat_society = COALESCE(habitat_society, 'Golems sind Automaten, künstlich erschaffen und unter der direkten Kontrolle ihres Erschafers. Sie haben keine Gesellschaft und sind mit keinem bestimmten Lebensraum verbunden. Sie werden häufig verwendet, um wertvolle Gegenstände oder Orte zu bewachen. Anders als die geringeren Golems stehen die größeren Golems immer unter der vollständigen Kontrolle ihres Meisters. Ein größerer Golem kann einfache Anweisungen mit direkten Handlungen und einfachen Bedingungsphrasen befolgen. Obwohl dies besser ist, als ein geringerer Golem befolgen kann, sind sie dennoch schlechte Diener. Jede gegebene Aufgabe könnte mehrere separate Befehle erfordern, um den Golem zu ihrer Vollendung zu führen.'),
  ecology         = COALESCE(ecology, 'Golems sind keine natürlichen Kreaturen und spielen keine Rolle in der Ökologie der Welt. Sie essen nicht, schlafen nicht und "leben", bis sie zerstört werden, normalerweise im Kampf. Bestimmte Zauber (siehe oben) können verwendet werden, um jeden Schaden zu heilen oder zu reparieren, der ihnen im Kampf zugefügt wurde. Dies wird normalerweise von ihren Erschaffern getan, um langen und wertvollen Dienst zu gewährleisten.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '223ed488-80f7-4abc-9796-1ce28d369f32' AND is_custom = FALSE;

-- Golem II (Lesser Golem) (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein Golem ist ein künstlicher humanoider Körper, der von einem Elementargeist belebt wird und unter der Kontrolle seines Erschafers steht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die niederen Golems sind im Kampf geistlos. Sie befolgen die Befehle ihres Meisters ausdrücklich und sind zu keinerlei Strategie oder Taktik fähig. Sie sind emotionslos im Kampf und können nicht leicht provoziert werden (es sei denn, sie haben die Kontrolle verloren und sind rasend geworden). Sie werden keine Waffen im Kampf verwenden, selbst wenn sie dazu befohlen werden, und schlagen immer lieber mit ihren Fäusten zu. Fleischgolems haben eine Stärke von 19 zum Zweck des Hebens, Werfens oder Einschlagens von Türen.'),
  habitat_society = COALESCE(habitat_society, 'Golems sind Automaten, künstlich erschaffen und unter der direkten Kontrolle ihres Erschaffers. Sie haben keine Gesellschaft und sind mit keinem bestimmten Lebensraum verbunden. Sie werden häufig verwendet, um wertvolle Gegenstände oder Orte zu bewachen. Ein niederer Golem kann einfachen Anweisungen folgen, die eine einzelne, direkte Handlung betreffen. Sie sind schlechte Diener, weil jede Einzelheit einer Aufgabe als separater Befehl gegeben werden muss.'),
  ecology         = COALESCE(ecology, 'Golems sind keine natürlichen Kreaturen und spielen keine Rolle in der Ökologie der Welt. Sie essen und schlafen nicht und leben, bis ihre Körper zerstört werden, gewöhnlich im Kampf.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'dc4584ce-d41b-466d-8d20-9cfb90d8af88' AND is_custom = FALSE;

-- Golem III (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Knochengolem wird aus den ehemals belebten Knochen von skelettartigen Untoten gebaut. Diese Schrecken stehen etwa 1,8 m hoch und wiegen zwischen 50 und 27,2 kg. Sie sind selten gepanzert und können leicht für Untote gehalten werden, sehr zum Leidwesen derjenigen, die diesen Fehler machen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Knochengolems sind nicht intelligenter als andere Golemformen, daher setzen sie im Kampf keine cleveren Taktiken oder Strategien ein. Ihre große Macht jedoch macht sie weitaus tödlicher, als sie anfangs erscheinen. Es besteht eine 95%ige Chance, dass diejenigen, die mit der wahren Natur ihres Gegners nicht vertraut sind, sie für einfache Untote halten.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '0da7d70f-5e93-4e0e-8e85-df01120b159a' AND is_custom = FALSE;

-- Golem V (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Necrophidius und die Vogelscheuche sind Konstrukte wie alle anderen Golems, aber sie sind weniger mächtig aufgrund der magischen Abkürzungen, die bei ihrer Erschaffung verwendet wurden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Necrophidius zieht es vor, Gegner zu überraschen, und seine Lautlosigkeit verhängt einen Malus von -2 auf ihre Überraschungswürfe. Wenn der Necrophidius nicht überrascht wird, führt er ein makabres Manöver namens Tanz des Todes durch, ein hypnotisches Schwanken, unterstützt von geringfügiger Magie. Der Tanz fesselt die Aufmerksamkeit aller, die ihn beobachten, es sei denn, ein erfolgreicher Rettungswurf gegen Zauber wird gewürfelt. Intelligente Opfer werden bewegungsunfähig gemacht, wie durch den Hypnose-Zauber. Dies erlaubt es dem Necrophidius, ohne Widerstand anzugreifen.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '5bab3209-9271-4d95-a8c0-db18699c57d0' AND is_custom = FALSE;

-- Gorgon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gorgonen sind wilde, stierartige Bestien, die ihre Baue in trostlosen Höhlen oder in der Wildnis errichten. Sie sind von Natur aus aggressiv und greifen normalerweise jede Kreatur oder Person an, der sie begegnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Viermal täglich können Gorgonen eine Atemwaffenangriff ausführen (ihre bevorzugte Angriffsart). Ihr Atem schießt in einem abgeschnittenen Kegel hervor, der an der Basis 1,5 m breit ist und an seinem Ende 6,1 m breit wird, mit einer maximalen Reichweite von 18,3 m. Jede Kreatur, die in diesem Kegel gefangen wird, muss einen Rettungswurf gegen Versteinerung würfeln. Diejenigen, die versagen, werden sofort zu Stein verwandelt! Das Bewusstsein der Gorgonen erstreckt sich auf die Astral- und Ätherische Ebene, ebenso wie die Auswirkungen ihrer Atemwaffe.'),
  habitat_society = COALESCE(habitat_society, 'Es wird vermutet, dass Gorgonen tatsächlich die lebenden Statuen verschlingen können, die sie mit ihrer Atemwaffe erschaffen. Ob ihre flachen Eisenzähne den Stein zerbrechen und zermahlen oder ihr Speichel das Opfer während des Fressens wieder zu Fleisch verwandelt, bleibt eine Vermutung.'),
  ecology         = COALESCE(ecology, 'Gorgonen haben keine natürlichen Feinde außer sich selbst. Gorgonenstiere werden oft dazu aufgerufen, ihre Positionen gegen abtrünnige Gorgonen zu verteidigen. Diese Kämpfe sind normalerweise nicht tödlich, aber selbst eine Gorgone kann durch einen gut gezielten Hornhieb gefällt werden. Die einzige andere Kreatur, die bekanntermaßen diese wilden Raubtiere jagt, ist der Mensch.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '2e255988-c85e-4ede-b97b-23e41d78f3fe' AND is_custom = FALSE;

-- Gremlin, Jermlaine (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Jermlaine sind eine winzige humanoide Rasse, die in Tunneln lebt und unglückliche Abenteurer aus dem Hinterhalt überfällt. Sie sind unter verschiedenen Namen bekannt, wie Unglücksbringer oder Fluch-Mücken.'),
  combat_tactics  = COALESCE(combat_tactics, 'Jermlaine sind Feiglinge, die den Hinterhalt zur Kunst erhoben haben. Sie greifen nur an, wenn sie das Gefühl haben, dass es keinen ernsthaften Widerstand gibt. Sie bevorzugen es, verletzte, kranke oder schlafende Opfer anzugreifen. Sie vermeiden es, starken, wachsamen Gruppen direkt gegenüberzutreten, obwohl sie aus reiner Bosheit versuchen könnten, sie zu verletzen.'),
  habitat_society = COALESCE(habitat_society, 'Jermlaine sind extrem entfernte Verwandte der Gnome. Ihr tief verwurzeltes Minderwertigkeitsgefühl wegen ihrer eigenen winzigen Größe ist zu einem bösartigen Bedürfnis geworden, normalgroße Humanoide zu demütigen. Sie verdienen sich ihren Lebensunterhalt gut damit, unglückliche Abenteurer zu berauben, die Reichtümer, sadistische Unterhaltung und gelegentlich eine Mahlzeit bieten. Jermlaine erwerben eine große Vielfalt an Schätzen, obwohl solche Gegenstände meist kleine Objekte sind.'),
  ecology         = COALESCE(ecology, 'Jermlaine sind opportunistische Räuber, die unvorsichtige Reisende in den unterirdischen Regionen jagen. Sie sind sich aller solcher Reisenden bewusst, einschließlich der Größe, Zusammensetzung und allgemeinen Verfassung einer Gruppe. Jermlaine können gegen eine angemessene Gebühr dazu überredet werden, solches Wissen mit Abenteurern zu teilen. Jermlaine können mit "Riesen" (jede Rasse größer als sie selbst) Geschäfte machen, wenn sie bestochen werden oder Zugang zu einem reichlichen Strom von Opfern oder Reichtümern erhalten. Sie verbünden sich niemals mit wahrhaft gut gesinnten Abenteurern, obwohl sie in einem Moment der Verschlagenheit vorgeben können, ein solches Bündnis einzugehen. Ungeachtet ihrer gesprochenen Absichten lügen oder wenden sich 75% der Jermlaine schließlich gegen ihre größeren "Verbündeten". Sie können ihre Baue in der Nähe der etablierten Territorien solcher Rassen wie Drow, Trolle oder Troglodyten errichten. Obwohl sie vorsichtig sind, direkten Konflikt mit solchen bösen Wesen zu vermeiden, jagen die Jermlaine fröhlich die Opfer ihrer Nachbarn und plündern die Schauplätze der Schlachten ihrer Nachbarn. Jermlaine können als Wächter für ihre Nachbarn fungieren, vorausgesetzt, geeignete Bedingungen können vereinbart werden.'),
  no_appearing    = COALESCE(no_appearing, '12-48')
WHERE id = '0a9191ff-a23c-4df9-a26f-81ae33a1d7d1' AND is_custom = FALSE;

-- Gremlin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gremlins werden oft mit Wichten verwechselt, sind aber kleine, geflügelte Goblinoide. Es gibt viele Arten von Gremlins, und die meisten sind chaotisch und boshaft. Ihre Hautfarbe reicht von braun über schwarz bis grau, häufig in einer gesprenkelten Mischung. Ihre Ohren sind sehr groß und spitz, was ihnen eine 65%ige Chance verleiht, Geräusche zu hören. Ein Paar fledermausartiger Flügel ermöglicht es ihnen zu fliegen oder zu gleiten. Gremlins tragen niemals Kleidung oder Schmuck.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gremlins sind in echten Kämpfen wertlos; bei jeder Gelegenheit fliehen sie, anstatt von Angesicht zu Angesicht zu kämpfen. Was Gremlins am liebsten tun, ist Ärger zu bereiten. Je wütender ihre Opfer sind, desto glücklicher sind die Gremlins. Ihre bevorzugte Taktik ist es, eine Falle aufzustellen, um Gegner zu demütigen und sie vielleicht sogar dazu zu bringen, einen wertvollen Besitz zu beschädigen oder einen geliebten Menschen zu verletzen. Wenn der Gegner dabei auch noch verletzt wird, ist das nur recht. Zum Beispiel könnte der Gremlin einen Stolperdraht über eine Türöffnung spannen, der eine zerbrechliche Vase auf den Kopf des Opfers herabzieht. Ein Gebäude, das von einem Gremlin-Rudel befallen ist, kann in einer einzigen Nacht zu Trümmern reduziert werden.'),
  habitat_society = COALESCE(habitat_society, 'Gremlins sind magische Kreaturen, die aus einer unbekannten Existenzebene stammen. Sie sind hochgradig anfällig für Mutationen und können sich mit jeder Goblinoiden-Art paaren. Dies hat zu mehreren verschiedenen Gremlin-Rassen geführt, jede mit leicht unterschiedlichen Fähigkeiten und Naturen.'),
  ecology         = COALESCE(ecology, 'Gremlins sind kein natürlicher Teil der Ökologie. Ihre Immunität gegen normale Waffen schützt sie vor normalen Raubtieren. Unbehelligt leben sie jahrhundertelang.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = 'e6bc3b3f-a714-42cf-9c79-ccb843055818' AND is_custom = FALSE;

-- Griffon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Halb Löwe, halb Adler, sind Greifen wilde gefiederte Fleischfresser, die Pferde und ihre Verwandten (Hippogreifen, Pegasi und Einhörner) jagen. Dieser Hunger nach Pferdefleisch bringt Greifen oft in direkten Konflikt mit Menschen und Halbmenschen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Greifen jagen in Gruppen von höchstens 12 und durchsuchen die Ebenen und Wälder in der Nähe (innerhalb von 32,2 km) ihres Baus nach Pferden und Herdentieren. Mit ihrer überlegenen Sicht und ihrem Geruchssinn können Greifen Beute bis zu zwei Meilen Entfernung entdecken. Wenn die Beute ein Pferd oder ein Pferderverwandter ist, greifen Greifen zu 90% an, auch wenn die Pferde Reiter haben. Greifen jagen nur nach Nahrung, daher kann ein Reiter, der ein oder zwei Pferde freigibt, meist unverletzt entkommen (obwohl sein Pferd höchstwahrscheinlich nicht überlebt). Jeder Versuch, ein Pferd zu schützen, zieht die volle Wut der angreifenden Greifen auf den Beschützer.'),
  habitat_society = COALESCE(habitat_society, 'Greifen bevorzugen felsige Lebensräume in der Nähe offener Ebenen. Sobald Greifen ihr Territorium etabliert haben, bleiben sie dort, bis die Nahrungsversorgung erschöpft ist.'),
  ecology         = COALESCE(ecology, 'Wenn sie von sehr frühem Alter an (drei Jahre oder weniger) trainiert werden, dienen Greifen als Reittiere. Das Training ist jedoch sowohl zeitaufwändig als auch teuer und erfordert die Fachkenntnis eines Tierbändigers für zwei Jahre. Einmal ausgebildet sind Greifen jedoch wilde und treue Reittiere, die sich ein Leben lang an einen Meister binden und ihn sogar bis in den Tod beschützen. Ein Greifenreittier kennt keine Furcht im Kampf, greift aber Pferde oder Pferderverwandte anderen Gegnern vor.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '98979f50-f737-4a52-8b7c-eb86dd4603e3' AND is_custom = FALSE;

-- Grimlock (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kräftig gebaute Humanoide, die nur in dunkle, schmutzige Lumpen gekleidet sind. Diese kriegerischen unterirdischen Kreaturen verlassen nachts ihre tiefen Höhlen, um nach unglücklichen Menschen zu suchen, die sie ihren Speisekammern hinzufügen können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Grimlocks sind immun gegen die Effekte von Zaubern, die das Sehvermögen beeinflussen. Dazu gehören Phantomkraft, Dunkelheit, Unsichtbarkeit, Spiegelbild und viele andere. Jedoch werden Zauber wie Hörbare Illusion oder jeder laute, andauernde Lärm sie teilweise "blenden". Dies reduziert ihre Fähigkeit, Gegner wahrzunehmen, auf eine Reichweite von 3 m und verschlechtert ihre Angriffswürfe um -2. Substanzen wie Schnupftabak oder starke Parfüms haben den gleichen Effekt, wenn sie von einem Grimlock eingeatmet oder ihm ins Gesicht geworfen werden.'),
  habitat_society = COALESCE(habitat_society, 'Grimlocks nisten in riesigen Höhlenkomplexen in gebirgigen Gebieten. Sie sind gut an diese Umgebung angepasst. In jedem felsigen Gelände verschmelzen sie so gut, dass sie, während sie bewegungslos sind, völlig unentdeckbar sind - es sei denn, man stößt tatsächlich mit ihnen zusammen. In jedem Grimlock-Bau wird es fast so viele Weibchen (1 Trefferwürfel und RK 6) wie Männchen geben, und mindestens so viele Junge (1 Trefferpunkt, RK 6 und Nichtkämpfer). Grimlock-Anführer und Champions üben tatsächlich eine gewisse Kontrolle über diese Gemeinschaften aus.'),
  ecology         = COALESCE(ecology, 'Grimlocks fressen nur das rohe Fleisch humanoider Kreaturen und bevorzugen dabei das von Menschen bei weitem vor allen anderen. Beutezüge überfallen oft die Behausungen anderer unterirdischer Rassen, besonders jene, die große Sklavenpopulationen halten (wie die Drow). Sie stehen oft auf gutem Fuß mit Gedankenschindern, da Illithiden eine große Versorgung mit humanoiden Körpern haben, die weggeworfen werden, nachdem sie die Gehirne verschlungen haben. Grimlocks werden besonders von Githyanki aus diesem Grund gehasst. Da das Sklavenfleisch, das die Grimlocks oft (roh) konsumieren, häufig ungesund ist, werden ganze Gemeinschaften oft durch Krankheiten dezimiert.'),
  no_appearing    = COALESCE(no_appearing, '20-200')
WHERE id = '1acc33a7-e5f9-4474-a55c-d679d3f2c5e8' AND is_custom = FALSE;

-- Grippli (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Grippli ähneln kleinen, intelligenten, humanoiden Baumfröschen. Sie haben eine primitive Kultur und sind nicht aggressiv.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wegen der Färbung der Grippli erleiden Gegner einen Malus von -3 auf ihre Überraschungswürfe. Grippli verteidigen sich mit Schlingen, Netzen, vergifteten Pfeilen und gelegentlich Schwertern oder Dolchen. Alle Metallwaffen müssen anderswo für die Grippli hergestellt werden, daher sind Schwerter selten. Sie können sich an die Verwendung aller Waffen anpassen, und sie sind dafür bekannt, bei seltenen Gelegenheiten Speere und Blasrohre zu verwenden. Sie tragen niemals Rüstung. Allgemein gesprochen bevorzugen die Grippli kleine Waffen, die beim Klettern nicht im Weg sind.'),
  habitat_society = COALESCE(habitat_society, 'Ein Grippli-Stammdorf besteht aus kleinen Hütten aus Holz und Lehm, die am Boden im tiefen Schatten großer Bäume errichtet werden. Bei seltenen Gelegenheiten findet man ein Grippli-Dorf in den starken Ästen der Bäume. Jedes Dorf wird von einer Stammmutter angeführt (RK 7, TW 3, 1W6+1 Schadenspunkte mit einer Waffe). Einmal pro Tag kann die Stammmutter eine Moschuswolke ausstoßen, die wie ein Stinkende Wolke-Zauber behandelt wird. Sie sieht aus wie jeder andere Grippli, außer dass sie fast 1,2 m groß ist. Sie hat 1W3 Gefährten von übernormal großer Statur (RK 8, TW 2, 1W4+1 Schadenspunkte mit vergifteten Waffen), die 0,9 bis 1 m groß sind. Die Stammmutter soll einen Hauch des Blutes ihres Gottes in sich haben.'),
  ecology         = COALESCE(ecology, 'Grippli essen Früchte und Insekten. Sie fangen kleine Insekten in großen Mengen und jagen die Riesenvarianten wie Menschen Hirsche jagen. Sie werden ihrerseits von den meisten großen, boden- und baumbasierten Raubtieren gejagt. Riesenschlangen und Spinnen insbesondere mögen Grippli als Mahlzeiten.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = '2b59e04c-fc17-4ad7-abb0-954d91c3616e' AND is_custom = FALSE;

-- Guardian Daemon (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese Dämonen werden von bösen Magiern oder Priestern beschworen, um etwas von Wichtigkeit zu bewachen. Wächterdämonen verteidigen ihren Auftrag stets mit großer Wildheit.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wächterdämonen können dreimal täglich Feuer atmen in einem Kegel von 9,1 m Länge mit 3 m Basisdurchmesser. Der Schaden hängt von der Art des atmenden Dämons ab. Niedrigste und geringere Dämonen verursachen 3W6 bzw. 5W6 Schadenspunkte, während größere Dämonen 7W6 Punkte pro Atemattacke zufügen. Ein erfolgreicher Rettungswurf gegen Atemwaffe halbiert den Schaden. Wächterdämonen verwenden niemals ihren Feueratem, wenn das Feuer das beschädigen könnte, was sie zu beschützen beauftragt sind.'),
  habitat_society = COALESCE(habitat_society, 'Wächterdämonen müssen jederzeit innerhalb von 82,3 m des Objekts bleiben, das sie zu beschützen beschworen wurden. Innerhalb dieses 82,3-Meter-Radius ziehen es Wächterdämonen vor, auf Distanz zu bleiben und im Kampf ihre Atemwaffe zu maximalem Vorteil einzusetzen.'),
  ecology         = COALESCE(ecology, 'Die Beschwörung eines Wächterdämons ist eine gefährliche Angelegenheit. Es gibt eine 10% Chance für jede Stufe, die der Beschwörer über der 7. Stufe ist, dass sein Antrag auf einen Wächterdämon gewährt wird (maximale Chance 90%). Umgekehrt, falls die Beschwörung fehlschlägt, gibt es eine 30% Chance (-2% pro Stufe des Beschwörers über der 10.), dass der Dämon Anstoß nimmt und sich einpfortet, um den Zauberkundigen zu erschlagen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '97310ab2-9c76-4fa8-a60b-86beca0d92df' AND is_custom = FALSE;

-- Hag (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hexen sind hexenähnliche Wesen, die Verwüstung und Zerstörung verbreiten, ihre Magie wirken und alle erschlagen, denen sie begegnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Kampffähigkeiten von Hexen variieren je nach Art siehe unten für Details, aber alle Hexen besitzen folgendes: Stärke von 18/00 oder höher, eine gewisse Magieresistenz und die zauberähnliche Fähigkeit, sich nach Belieben zu verwandeln. Hexen nutzen diese letzte Fähigkeit, um Opfer anzulocken, indem sie sich häufig als junge Menschen- oder Halbmenschenfrauen, hilflose alte Frauen oder gelegentlich als Orks oder Hobgoblins ausgeben. Eine verkleidete Hexe enthüllt ihre wahre Gestalt und springt zum Angriff über, wenn schwache Gegner in die Nähe kommen. Gegen gut bewaffnete und gerüstete Gruppen behalten Hexen ihre Verkleidung bei und wenden weitere Tricks an, die darauf ausgelegt sind, das beabsichtigte Opfer in eine verwundbarere Position zu bringen. Diese Tricks können verschiedene Formen annehmen, einschließlich verbaler Überredung, das Opfer in eine vorbereitete Falle zu locken und so weiter.'),
  habitat_society = COALESCE(habitat_society, 'Hexen leben allein oder in Zirkeln von drei. Sie wählen immer trostlose, abgelegene Orte als Wohnstätte. Sie koexistieren manchmal mit Ogern oder bösen Riesen. Erstere fungieren als Diener oder Wachen für Hexen, aber Riesen werden mit Respekt behandelt aus offensichtlichen Gründen und kooperieren oft mit Hexen, um Taten großen Übels gegen die Außenwelt zu vollbringen.'),
  ecology         = COALESCE(ecology, 'Hexen haben einen unersättlichen Appetit und können menschengroße Kreaturen in nur 10 Runden verschlingen. Sie bevorzugen Menschenfleisch, begnügen sich aber bei Bedarf mit Ork oder Halbmensch. Diese mutwillige Zerstörung hat den Hexen einige mächtige Feinde eingebracht. Neben der Menschheit im Allgemeinen jagen sowohl gute Riesen als auch gute Drachen Hexen und erschlagen sie, wann immer möglich. Dennoch vermehren sich Hexen schnell, indem sie ihre Fähigkeit zur Selbstverwandlung nutzen, um allein angetroffenen Männern als schöne Jungfrauen zu erscheinen. Hexennachkommen sind immer weiblich. Legenden besagen, dass Hexen ihr ungeborenes Kind gegen das einer menschlichen Frau austauschen können, während sie schläft. Sie besagen weiter, dass jede Mutter, die ein solches Kind austrägt, dann von dem Hexenkind getötet wird, das sie trägt. Glücklicherweise wurden solche grauenhaften Geschichten nie bewiesen.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = '853ab9d5-6888-4c95-aae3-b5d17e68e100' AND is_custom = FALSE;

-- Halfling (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Halblinge sind ein arbeitsames Volk friedlicher Bürger. Ihre Gemeinden ähneln denen der Menschen, obwohl sie gewöhnlich viele Erdhöhlen zusätzlich zu oberirdischen Häuschen enthalten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Halblinge kämpfen mit großer Erbitterung zur Verteidigung des Guten oder ihrer Heime. Sie sind sehr geschickt sowohl mit der Schleuder als auch dem Bogen (sie erhalten einen +3 Bonus auf alle Angriffswürfe) und nutzen diese Waffen zu großem Vorteil im Kampf. Ihre Taktiken umfassen oft Finten, um ihre Angreifer ins Freie zu locken, wo sie einem Hagel von Geschossen aus der Deckung unterworfen werden können.'),
  habitat_society = COALESCE(habitat_society, 'Halblingdörfer haben gewöhnlich zwischen 30 und 300 (30W10) Einwohner. Für je 30 Halblinge in einer bestimmten Gemeinde gibt es zwei Kämpfer der 2. Stufe und einen Priester der 3. Stufe. Werden mehr als 90 Halblinge angetroffen, gibt es einen zusätzlichen Anführer mit Kampffähigkeiten der 3. Stufe. Werden mehr als 150 angetroffen, gibt es auch die folgenden zusätzlichen Halblingkrieger in der Gruppe: einen Kämpfer der 9. Stufe, zwei Kämpfer der 4. Stufe und drei Kämpfer der 3. Stufe. Ferner hat eine Gemeinde von 150 Halblingen einen Priester der 5. Stufe.'),
  ecology         = COALESCE(ecology, 'Halblinge jagen gelegentlich, bevorzugen aber Brot, Gemüse und Früchte mit gelegentlich einem Fasan dazu. Sie haben eine durchschnittliche Lebenserwartung von 100 Jahren.'),
  no_appearing    = COALESCE(no_appearing, '2-12 (2d6)')
WHERE id = '6b11453a-a838-4916-a71c-99deaed270a8' AND is_custom = FALSE;

-- Harpy (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Harpyien sind böse Vogel-Bestien, die fast alle Kreaturen jagen, aber das Fleisch von Menschen und Halbmenschen bevorzugen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Gesang der Harpyien hat die Fähigkeit, alle Menschen und Halbmenschen zu bezaubern, die ihn hören (Elfen sind resistent gegen den Zauber). Diejenigen, die ihren Rettungswurf gegen Zauber verfehlen, werden mit aller möglichen Geschwindigkeit zur Harpyie gehen, nur um verzaubert dazustehen, während die Harpyie sie in aller Ruhe tötet. Dieser Zauber hält so lange an, wie die Harpyie weiter singt. Harpyien können sogar während eines Nahkampfes singen.'),
  habitat_society = COALESCE(habitat_society, 'Harpyien machen ihre Heimat an Küstenlinien in Regionen nahe Schifffahrtsrouten und an viel bereisten Pfaden. Dort nutzen sie ihren Gesang, um Reisende in ihr Verderben zu locken.'),
  ecology         = COALESCE(ecology, 'Harpyien jagen alle Arten von Bestien und bleiben in einem Gebiet, solange die Nahrungsversorgung anhält. Sie werden von allen Kreaturen, die schwächer sind als sie selbst, verachtet und sehr gefürchtet.'),
  no_appearing    = COALESCE(no_appearing, '2-12 (2d6)')
WHERE id = '76d914ca-b4b2-49f8-b2f0-b48aa9ee08e9' AND is_custom = FALSE;

-- Hatori (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hatori, manchmal als "Krokodile der Wüste" bezeichnet, sind riesige Reptilien, die in sandigen Wüstenöden leben. Die harte, knorrige Haut der Hatori reicht farblich von grau-weiß bis rot-braun und ist praktisch nicht von Stein zu unterscheiden. Hatori nutzen diese Ähnlichkeit zu ihrem großen Vorteil, indem sie sich vom Wind teilweise unter dem Sand begraben lassen, sodass ein flüchtiger Beobachter glauben könnte, er blicke auf Felsbrocken anstatt auf Ungeheuer der Wüste.'),
  combat_tactics  = COALESCE(combat_tactics, 'Das Einzige, was Hatori in den Kampf treiben kann, ist Hunger. Unglücklicherweise haben Hatori unersättlichen Appetit und Nahrung ist in ihrer Heimatumgebung selten, daher lassen sie niemals eine Gelegenheit aus, aus einem vorbeiziehenden Reisenden - oder sogar einer ganzen Karawane - eine Mahlzeit zu machen. Die bevorzugte Jagdmethode der Hatori ist es, sich entlang eines vielgenutzten Wanderpfads oder einer Karawanenroute zu positionieren. Wenn eine potenzielle Mahlzeit nahe vorbeigeht und die Hatori für nichts weiter als einen Felsvorsprung hält, schlagen die Hatori zu.'),
  habitat_society = COALESCE(habitat_society, 'Hatori leben in den sandigen Regionen großer Wüsten. Da sie jedoch ständig nach Nahrung suchen, werden sie tendenziell in der Nähe von Wanderpfaden oder entlang belebter Karawanenrouten angetroffen. Sie bleiben in einem ertragreichen Gebiet, bis Nahrung knapp wird.'),
  ecology         = COALESCE(ecology, 'Hatori fressen alles, obwohl sie Edelsteine oder magische Rüstungen und Waffen nicht verdauen können. Diese Gegenstände neigen dazu, sich über ihre langen Lebenszeiten in ihren Mägen anzusammeln. Hatori haben keine natürlichen Feinde (außer einander zur Paarungszeit), obwohl es Gerüchte gibt, dass bestimmte Arten von Drachen bekanntermaßen kleinere Hatori in Zeiten des Hungers angegriffen haben. Legenden sprechen von einem verborgenen Hatori-Friedhof, wo uralte Hatori hingehen, um zu sterben. Falls ein solcher Friedhof existiert, ist er sicherlich voller Edelsteine und magischer Rüstungen.'),
  no_appearing    = COALESCE(no_appearing, '1 or 2-5')
WHERE id = '8e0c139a-d8fa-4403-934d-c74d236e0b9e' AND is_custom = FALSE;

-- Haunt (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, '(Anmerkung: Bei durch Schrägstrich getrennten Statistiken beziehen sich die linken Werte auf den natürlichen Zustand, die rechten auf ein besessenes Opfer.)'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Haunt muss innerhalb von 54,9 m von seinem Todesort bleiben, es sei denn, er übernimmt die Kontrolle über den Körper eines Opfers. Dieser 54,9-Meter-Radius wird die Domäne des Haunts genannt.'),
  habitat_society = COALESCE(habitat_society, 'Die genaue zu vollendende Aufgabe variiert, aber die Beweggründe sind immer mächtig - Rache, Gier, Liebe, Hass. Oft müssen große Entfernungen zurückgelegt werden, bevor eine Aufgabe vollendet werden kann, und Haunts werden ihre Wirte gnadenlos zum Ziel treiben und dabei das Bedürfnis nach Nahrung oder Schlaf ignorieren.'),
  ecology         = COALESCE(ecology, 'Haunts klammern sich allein durch Willenskraft an diese Welt. Sie haben keinen eigenen Schatz, es sei denn, er steht im Zusammenhang mit ihrer Suche. Sie jagen nur Menschen und Halbmenschen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '46e6cc10-b345-4b1d-9b02-1e245f79172b' AND is_custom = FALSE;

-- Hawk (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Habichte sind auf der ganzen Welt verbreitet, von tropischen bis zu subarktischen Gebieten. Sie leben hauptsächlich von Ungeziefer und Nagetieren und werden daher in vielen Gegenden geschätzt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Habichte greifen über sturzflugartige Sturzflüge an, normalerweise aus einer Höhe von 30,5 m oder mehr. Dieser Sturzflug verleiht ihnen einen +2 Bonus auf ihren Angriffswurf und ihr Schwung ermöglicht es ihren Krallen, doppelten normalen Schaden zu verursachen. Habichte können nicht mit ihren Schnäbeln angreifen in der Runde, in der sie einen Sturzangriff ausführen.'),
  habitat_society = COALESCE(habitat_society, 'Habichte bauen ihre Nester in hohen Bäumen oder versteckt zwischen felsigen Hängen. Dort legt das Weibchen im frühen Frühling ein bis drei Eier. Die Eier schlüpfen zum Sommerende und danach arbeiten sowohl Männchen als auch Weibchen daran, die Nestlinge zu füttern und sie vor Wintereinbruch zu stärken.'),
  ecology         = COALESCE(ecology, 'Wenn sie jung gefangen und von einem Experten trainiert werden, können Habichte zur Jagd ausgebildet werden. Deswegen zahlen viele Tierdresseure gut für gesunde Nestlinge. Der Preis für einen Nestling beträgt etwa 500 Goldstücke auf dem freien Markt. Trainierte Habichte verkaufen sich für bis zu 1.200 Goldstücke das Stück.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = 'e914aa5a-d127-4ad0-b403-5aa9b8de2fc2' AND is_custom = FALSE;

-- Hell Hound (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Höllenhunde sind feuerspeiende Hundeartige von einer anderen Existenzebene, die hierher im Dienste böser Wesen gebracht wurden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Höllenhunde sind clevere Jäger, die in Rudeln operieren. Sie bellen nicht wie normale Hunde während der Jagd. Sie bewegen sich mit großer Heimlichkeit und verhängen eine -5 Strafe auf die Überraschungswürfe ihrer Gegner. Ein oder zwei aus dem Rudel schleichen sich an die Beute heran, während die anderen einen Ring um sie bilden. Der erste Höllenhund springt dann aus dem Hinterhalt hervor, greift das nächste Opfer an und versucht die anderen zum Rest des Rudels zu treiben. Wenn die Beute nicht wegläuft, rückt der Rest des Rudels innerhalb von 1W4+2 Runden näher heran. Wenn Höllenhunde fliehende Beute verfolgen, könnten sie bellen.'),
  habitat_society = COALESCE(habitat_society, 'Höllenhunde sind heimisch in jenen außerdimensionalen Ebenen, die für ihre heißen, feurigen Landschaften bekannt sind. Dort streifen sie in Rudeln von 2W20 Tieren umher. Die Höllenhunde auf der Materiellen Hauptebene werden dorthin beschworen, um den Bedürfnissen böser Kreaturen zu dienen. Die meisten von ihnen entkommen später in die Wildnis.'),
  ecology         = COALESCE(ecology, 'Höllenhunde haben wenig Platz in der Ökologie der normalen Welt. Sie sind gefährliche Plagen, die dazu neigen, Brände zu verursachen, wo immer sie jagen. Höllenhunde verursachen mehr Waldbrände als jede andere Kreatur außer Humanoiden. Höllenhunde haben jedoch ihre Verwendung. Wegen ihrer Fähigkeit, verborgene oder unsichtbare Kreaturen leicht zu entdecken, geben Höllenhunde ausgezeichnete Wachhunde ab, besonders für intelligente Monster wie Feuerriesen.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '61a6774c-176d-46fa-abf1-5d02391b27cf' AND is_custom = FALSE;

-- Hippogriff (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hippogreife sind fliegende Monster, die mit gleicher Wahrscheinlichkeit Räuber, Beute oder Reittier sein können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Hippogreif greift mit seinen adlerartigen Klauen und seinem Schnabel an. Jede Klaue kann 1W6 Schadenspunkte verursachen, während der scherenähnliche Schnabel 1W10 Schadenspunkte zufügt.'),
  habitat_society = COALESCE(habitat_society, 'Hippogreife bevorzugen die verlassenen Gebiete gemäßigter und tropischer Regionen, besonders hügelige Landschaften, die es ihnen ermöglichen, schnell in die Luft zu kommen.'),
  ecology         = COALESCE(ecology, 'Hippogreife sind eng mit Greifen verwandt. Genau wie Greife das Ergebnis einer Kreuzung zwischen einem Adler und einem Löwen sind, entstanden Hippogreife aus der Kreuzung eines Adlers mit einem Pferd. Hippogreife könnten als natürliche Beute für die Greife erschaffen worden sein. Glücklicherweise für den Hippogreif geben ihm seine eigenen beeindruckenden Waffen eine Kampfchance. Um die Überlegenheit des Greifen auszugleichen, sammeln sich Hippogreife in größeren Gruppen.'),
  no_appearing    = COALESCE(no_appearing, '2-16')
WHERE id = 'd8173f2f-7342-4382-9229-e89c6231e78a' AND is_custom = FALSE;

-- Hobgoblin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hobgoblins sind eine wilde humanoide Rasse, die einen ewigen Krieg gegen die anderen humanoiden Rassen führt. Sie sind intelligent, organisiert und aggressiv.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hobgoblins einer typischen Truppe sind mit Stangenwaffen (30%), Morgensterne (20%), Schwertern und Bögen (20%), Speeren (10%), Schwertern und Speeren (10%), Schwertern und Morgensternen (5%) oder Schwertern und Peitschen (5%) ausgerüstet.'),
  habitat_society = COALESCE(habitat_society, 'Hobgoblins sind albtraumhafte Zerrbilder der humanoiden Rassen, die eine militärische Gesellschaft haben, die in Stammesgruppen organisiert ist. Jeder Stamm ist intensiv eifersüchtig auf seinen Status. Zufällige Begegnungen mit anderen Stämmen führen zu verbalen Beleidigungen (85%) oder offenen Kämpfen (15%). Hobgoblin-Stämme findet man in fast jedem Klima oder unterirdischen Reich.'),
  ecology         = COALESCE(ecology, 'Hobgoblins fühlen sich Goblins oder Orks überlegen und können als deren Anführer agieren. In solchen Fällen werden die "niederen Rassen" als Kanonenfutter verwendet. Hobgoblin-Söldner können für mächtige oder reiche böse Humanoide arbeiten.'),
  no_appearing    = COALESCE(no_appearing, '2-20 (2d10)')
WHERE id = 'f29578b2-fc23-4336-8582-8b55afe0fe0a' AND is_custom = FALSE;

-- Homunculus (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Homunkulusse sind kleine mystische Wesen, die von Magiern zum Spionieren und für andere besondere Aufgaben erschaffen werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Homunkulus ist ein schneller und gewandter Flieger, der diese Fähigkeit im Kampf zu seinem großen Vorteil nutzt. Er kann so schnell hin und her huschen, dass jeder Versuch ihn zu fangen, außer mit einem Netz oder Netz-Zauber, nahezu unmöglich ist.'),
  habitat_society = COALESCE(habitat_society, 'Homunkulusse sind künstliche Kreaturen, die von Magiern als lebende Werkzeuge erschaffen werden. Der Prozess ihrer Erschaffung ist lang, kompliziert und teuer. Jeder Magier, der einen Homunkulus als Diener wünscht, muss zuerst einen Alchemisten ausfindig machen und anheuern. Der Magier muss einen halben Liter seines eigenen Blutes und 500-2.000 (1W4×500) Goldstücke bereitstellen. Das Blut wird zur Grundlage für den Körper der Kreatur, während das Geld für verschiedene andere Vorräte und die Zeit des Alchemisten aufkommt. Der Alchemist benötigt 1-4 Wochen, um das Blut in die notwendige magische Grundsubstanz zu verwandeln. Dann wird der Magier gerufen und muss Reparieren-, Spiegelbild- und Magierauge-Zauber auf die Flüssigkeiten wirken. Sobald der letzte dieser Zauber gewirkt wird, gerinnen die Flüssigkeiten spontan und bilden den Körper des Homunkulus.'),
  ecology         = COALESCE(ecology, 'Homunkulusse sind nichts weiter als Werkzeuge. Sie haben keinen Platz in der natürlichen Welt und sind nicht Teil irgendeines ökologischen Systems. Sie bieten dem Magier, der sie erschaffen hat, verschiedene nützliche Dienste. Gewöhnlich wird ein Homunkulus dazu berufen, als Spion, Späher, Bote oder Gesandter zu fungieren. Wegen des potentiellen Schadens, den der Tod eines Homunkulus seinem Meister zufügt, werden sie selten als Leibwächter oder lebende Waffen eingesetzt.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '72939647-f425-4685-b2fc-a40507cfea74' AND is_custom = FALSE;

-- Hook Horror (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Hakenschrecken ist ein zweibeiniges, unterirdisch lebendes Monster, das wie eine Kreuzung zwischen einem Geier und einem Menschen mit Haken anstelle von Händen aussieht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hakenschrecken haben scharfes Gehör und werden nur bei einem Wurf von 1 überrascht. Sie kennen immer ihr Territorium und versuchen ahnungslose Reisende oder Höhlenbewohner zu überfallen. Jede Runde schlagen sie mit beiden Haken zu. Wenn in einer Runde beide treffen, trifft ihr Schnabel in derselben Runde automatisch. Sie fügen automatisch 2W6 Schadenspunkte jede Runde mit dem Schnabel zu, bis mindestens einer der Haken gelöst wird.'),
  habitat_society = COALESCE(habitat_society, 'Der offensichtliche Nachteil, Haken anstelle von Händen zu haben, ist, dass Hakenschrecken keine Waffen oder Werkzeuge verwenden können. Sie können Gegenstände nur mit ihren Schnäbeln aufheben. Dies schränkt ihre Fähigkeit, große Schätze anzuhäufen, stark ein.'),
  ecology         = COALESCE(ecology, 'Obwohl Hakenschrecken grundsätzlich Allesfresser sind, bevorzugen sie Fleisch. Sie können fast jeden höhlenbewohnenden Pilz, Pflanzen, Flechten oder Tiere fressen. Hakenschrecken sind gut an das Höhlenleben angepasst. Sie haben wenige natürliche Feinde, obwohl alles, was es schafft, einen zu fangen, versuchen würde, ihn zu fressen. Das Exoskelett des Hakenschreckens trocknet aus und wird nach etwa einem Monat zu spröde für die Verwendung.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '07f3428c-6230-4949-bbab-202102c4e26d' AND is_custom = FALSE;

-- Hornet, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenhornissen sind nichts weiter als fantastisch vergrößerte Versionen normaler Insekten. Im Gegensatz zu ihren gewöhnlicheren Verwandten sind sie oft feindselig und aggressiv.'),
  combat_tactics  = COALESCE(combat_tactics, 'Riesenhornissen sind Einzelgänger, die bei Sichtkontakt angreifen. Sie stürzen sich auf ihre Beute herab und halten sie mit ihren Beinen fest, während ihr Stachel in den Körper des Opfers sticht. Zusätzlich zu 1-4 Schadenspunkten injiziert der Stachel auch ein starkes Gift. Wird ein Rettungswurf gegen Gift nicht geschafft, verursacht das Gift 5-30 Schadenspunkte und lähmt das Opfer für 2-12 (2W6) Stunden.'),
  habitat_society = COALESCE(habitat_society, 'Riesenhornissen sollen das Ergebnis fehlgeschlagener magischer Experimente sein. Abgesehen von der Tatsache, dass sie viel aggressiver als gewöhnliche Hornissen sind, hat ihre gigantische Größe ihr instinktives Verhalten nicht verändert.'),
  ecology         = COALESCE(ecology, 'Die Riesenhornissen sind das Ergebnis absichtlicher Manipulation der Natur. Sie durchstreifen die Welt gedankenlos und folgen ihrem ursprünglichen Instinkt zur Fortpflanzung.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '3c4c8347-ec9d-44b8-bdc6-4a884f0e86cb' AND is_custom = FALSE;

-- Human (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese primitiven Menschen werden in ansonsten unbewohnten Gebieten gefunden. Für alle 10 Ureinwohner gibt es einen Kämpfer der 3. Stufe. Ureinwohnerstämme werden immer von einem Häuptling (ein Kämpfer der 5. Stufe) und 1-4 Unterhäuptlingen (Kämpfer der 4. Stufe) angeführt. Für alle 10 angetroffenen Ureinwohner besteht eine 10%ige Chance, dass sie einen Schamanen (Priester der 3. Stufe) bei sich haben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dies sind NSC-Gegenstücke zur SC-Gruppe, Gruppen von Kämpfern, Dieben, Priestern und Magiern, die sich zusammenschließen auf der Suche nach Ruhm, Reichtum und Macht. Typische Abenteuergruppen bestehen aus zwei bis acht Mitgliedern. Einzelne Abenteurer könnten von ihrer Gruppe getrennt, verloren, fortgeschrittene Späher oder alleinige Überlebende dezimierter Gruppen sein.'),
  habitat_society = COALESCE(habitat_society, 'Banditen sind ländliche Diebe, die offen Reisende und abgelegene Behausungen ausrauben. Sie reisen in Gruppen von 20-200, normalerweise angeführt von hochstufigen Kämpfern, Schurken, Magiern und Priestern. Für alle 20 angetroffenen Banditen gibt es einen zusätzlichen Kämpfer der 3. Stufe. Wenn 100+ angetroffen werden, ist der Anführer mindestens 8. Stufe.'),
  ecology         = COALESCE(ecology, 'Barbaren gehören zu primitiven Kulturen, die rudimentäre Fertigkeiten wie Tierhaltung und einfache Herstellung (Weben, Schnitzen) besitzen. Sie können in Dörfern mit einfachen Gebäuden leben oder in tragbaren Strukturen wie Zelten, Tipis, Jurten oder Wagen. In aquatischen Gebieten können sie auf Wasserfahrzeugen wie Kanus oder Flößen leben.'),
  no_appearing    = COALESCE(no_appearing, '1-100')
WHERE id = 'efe6a1ed-df7f-4671-a647-f69604e4b6f8' AND is_custom = FALSE;

-- Hydra (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hydras sind gewaltige reptilische Monster mit mehreren Köpfen. Für jeden Trefferwürfel, den die Hydra hat, besitzt sie einen Kopf. Die obige Tabelle listet den ETW0-Wert für Hydras, die Anzahl der Köpfe und den Schaden auf, den sie bei jedem Biss verursachen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hydras haben immer 8 Punkte auf jedem ihrer Trefferwürfel und alle Köpfe müssen abgetrennt werden, bevor die Hydra stirbt. Eine Hydra kann bis zu vier Köpfe gegen einen einzelnen Gegner einsetzen und mit jedem einmal beißen.'),
  habitat_society = COALESCE(habitat_society, 'Hydras sind Einzelgänger, die düstere Umgebungen bevorzugen. Sie versammeln sich nur zur Paarung.'),
  ecology         = COALESCE(ecology, 'Trotz der Größe der Hydra und ihrer mehrfachen Angriffe werden sie oft von Drachen gejagt. Sie sind unmöglich zu trainieren.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '443985dd-a475-4883-ab46-eeb64cd4d0ef' AND is_custom = FALSE;

-- Hyena (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hyänen sind Hundeartige, die in warmen Grasländern und Ebenen umherstreifen. Sie sind in erster Linie Aasfresser, jagen aber gelegentlich auch kleineres Wild. Ihre kräftigen Kiefer verleihen ihnen einen gefährlichen Biss.'),
  combat_tactics  = COALESCE(combat_tactics, 'Hyänen sind Feiglinge. Sie greifen nicht an, außer ihr Opfer ist hilflos, in der Unterzahl oder bereits tot.'),
  habitat_society = COALESCE(habitat_society, 'Hyänen durchstreifen die offenen Ebenen warmer, grasiger Regionen. Sie werden normalerweise in Sichtweite einer Herde von Tieren wie Zebras und Antilopen gefunden. Gewöhnlich gibt es 1 Hyäne für jeweils 10 Herdentiere, denen sie folgt. Ein typisches Hyänenrudel kann mit einem menschengroßen Tier alle drei Tage überleben. Wenn sie ein Tier angreifen und töten, werden sie es in kürzester Zeit bis auf die Knochen abfressen. Jedes Aas, das sie antreffen, wird ebenfalls verzehrt.'),
  ecology         = COALESCE(ecology, 'Hyänen sind aktive Aasfresser, die sich von den Kadavern ernähren, die von anderen, größeren Raubtieren zurückgelassen werden. Sie sind auch in der Lage, lebende Beute zu reißen, obwohl sie ihre Jagd normalerweise auf kleine, junge, alte oder kranke Tiere beschränken. Sie haben eine starke Konstitution und einen Verdauungstrakt, der es ihnen ermöglicht, sogar krankes Fleisch sicher zu verdauen.'),
  no_appearing    = COALESCE(no_appearing, '2-12 (2d6)')
WHERE id = 'b87766b4-aef2-4007-8958-2279565d10d0' AND is_custom = FALSE;

-- Imp (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kobolde sind winzige Kreaturen böser Natur, die durch die Welt wandern und als Vertraute für rechtschaffen böse Magier und Priester dienen.'),
  combat_tactics  = COALESCE(combat_tactics, 'In seiner natürlichen Form greift der Kobold mit dem bösartigen Stachel an seinem Schwanz an. Zusätzlich zu 1-4 Schadenspunkten injiziert dieser Stachel ein mächtiges Gift, das so tödlich ist, dass diejenigen, die ihren Rettungswurf gegen Gift verfehlen, sofort daran sterben. Wenn er verwandelt ist, greift der Kobold mit den natürlichen Waffen seiner angenommenen Form an, obwohl die Ziegen- und Rabenform keine schadenverursachenden Angriffe besitzen.'),
  habitat_society = COALESCE(habitat_society, 'Kobolde sind Wesen sehr böser Natur, die aus den dunkelsten bösen Ebenen stammen. Ihr Hauptzweck auf der Materiellen Hauptebene ist es, das Böse zu verbreiten, indem sie rechtschaffen bösen Magiern und Priestern helfen. Wenn eine solche Person des Dienstes eines Kobolds für würdig befunden wird, kommt der Kobold als Antwort auf einen Vertrauten finden-Zauber.'),
  ecology         = COALESCE(ecology, 'Kobolde sind die Laufburschen der mächtigen bösen Wesen, die über die dunkelsten Ebenen herrschen. Sie handeln oft als Abgesandte und Agenten, aber ihre Hauptaufgabe ist es, die Ausbreitung des Bösen in unserer Welt zu verstärken.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'c10da93a-c336-4e25-b3a9-03f84d2c9bb8' AND is_custom = FALSE;

-- Insect, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Insekten sind die widerstandsfähigsten und zahlreichsten aller Kreaturen. Normale Insekten findet man fast überall. Die riesigen Varianten, von denen viele hier aufgeführt sind, verfügen über zusätzliche Kraft und Macht und stellen zähe Gegner dar.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = '5a53d6fb-33d4-4dde-9c69-9478374e9a4f' AND is_custom = FALSE;

-- Insect Swarm (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Als Einzeltiere sind Samtameisen, Grashüpfer und Heuschrecken relativ harmlos. Aber in Schwärmen können diese Insekten immense Schäden an Feldern und Wäldern verursachen und das Leben aller Kreaturen in ihrem Weg bedrohen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Samtameisenschwarm frisst alles in seinem Weg, sowohl tierische Materie als auch Vegetation. Um die Größe eines Schwarms zu bestimmen, würfle 1W100 und multipliziere das Ergebnis mit 1.000. Es gibt etwa 100 Ameisen pro 0,09 m²; daher bildet ein Schwarm von 10.000 Ameisen einen Block von etwa 3 m je Seite. Wenn ein Schwarm mit einem Hindernis in Kontakt kommt, wendet er sich um 90° und setzt seinen Weg fort. Ein Opfer, das mit einem Schwarm in Kontakt steht, hat eine 80%ige Chance pro Runde, gebissen zu werden und 1W4 Schadenspunkte zu erleiden. Das Opfer muss einen erfolgreichen Rettungswurf gegen Gift würfeln oder intensive Schmerzen für die nächsten 2W4 Runden erleiden, wodurch alle Angriffs- und Schadenswürfe während dieser Zeit mit einem Malus von -2 belegt werden.'),
  habitat_society = COALESCE(habitat_society, 'Insektenschwärme sind wandernd und schlafen nachts, wo immer sie sich gerade befinden. Weibchen legen jedes Jahr bis zu 100 Eier. Diese Insekten haben keine Anführer oder spezialisierte Arbeiter. Sie sammeln keine Schätze.'),
  ecology         = COALESCE(ecology, 'Samtameisen fressen Samen, Gräser und Fleisch und bevorzugen besonders Aas. Das Gift der Samtameisen macht sie für Fleischfresser ungenießbar.'),
  no_appearing    = COALESCE(no_appearing, 'See below')
WHERE id = '8ed09db5-33ee-40c4-83a4-f5ab5d80793d' AND is_custom = FALSE;

-- Intellect Devourer (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaft: ektoplasmatische Form; Hingabe: Körpergleichgewicht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Ustilagor greift an, indem er mit seinem flexiblen Fühler zuschlägt. Der Fühler sondert eine alkalische Substanz ab, die bei einem erfolgreichen Treffer 1W4+1 Schaden verursacht sowie weitere 1W4+1 Schaden in der folgenden Runde, es sei denn, das Opfer besteht einen erfolgreichen Rettungswurf gegen Gift. Die Kreatur ist ziemlich beweglich und kann schnell springen und huschen.'),
  habitat_society = COALESCE(habitat_society, 'Intellektverschlinger leben unter der Erde oder in trostlosen Wildnisgebieten. Ihre Fortpflanzungsmethode ist unbekannt. Der Intellektverschlinger schützt selten seine Jungen und kann sie sogar verschlingen. Ustilagor entwickeln eine symbiotische Beziehung mit einem bizarren Pilz, der sich von residualen Gedankenausstrahlungen der Opfer des Ustilagor nährt. Ein Ustilagor wird erwachsen, indem er das Gehirn einer psionischen Kreatur verschlingt.'),
  ecology         = COALESCE(ecology, 'Gedankenschinder züchten Intellektverschlinger, behandeln die Ustilagor als kulinarische Leckerbissen und verwenden Erwachsene als Wachhunde. Beide Formen der Kreatur können als Komponenten in Gegenständen und Tränken verwendet werden, die mit ASW und Geisteskontrolle in Verbindung stehen.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '3d99e134-3e9a-4b92-8169-3e43f3c3e8db' AND is_custom = FALSE;

-- Invisible Stalker (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Unsichtbare Pirscher ist ein Wesen von der Elementarebene der Luft. Jene, die auf der Primär-Materiellen Ebene angetroffen werden, sind fast immer von Magiern beschworen worden, um eine spezielle Aufgabe zu erfüllen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Unsichtbare Pirscher greifen an, indem sie die Luft selbst als Waffe nutzen. Sie sind imstande, einen plötzlichen, intensiven Wirbel zu erschaffen, der ein Opfer mit 4-16 (4W4) Schadenspunkten traktiert. Solche Angriffe betreffen ein einzelnes Opfer auf derselben Ebene wie der Unsichtbare Pirscher.'),
  habitat_society = COALESCE(habitat_society, 'Wenig ist über das Leben dieser Kreaturen auf ihrer Heimatebene bekannt. Es wird angenommen, dass sie normalen Luftelementaren ähneln, wenn sie dort angetroffen werden.'),
  ecology         = COALESCE(ecology, 'Unsichtbare Pirscher sind eine Spezies, die unfreiwillig auf die Primär-Materielle Ebene verpflanzt wurde. Sie sind Sklaven, deren Dienstbedingungen ihre kurzen Aufenthalte beherrschen. Jene, die großen Härten unterworfen waren, sehr schwierige Aufgaben zugewiesen bekamen oder dem Tod durch die Hände von Humanoiden ins Auge blickten, neigen dazu, ein Misstrauen oder offenen Hass gegen sie zu bewahren. Jene, die während vergangener Dienstperioden eine leichte Zeit hatten oder zum ersten Mal auf der Primär-Materiellen Ebene eintreffen, mögen einfacher zu behandeln sein. Solche Gefühle mögen sich übertragen und Begegnungen mit Humanoiden beeinflussen, die durch die Luftebene reisen. Jeder, der in der Vergangenheit einen Unsichtbaren Pirscher zum Freund gewonnen hat, wird feststellen, dass Reisen durch die Elementarebene der Luft weit weniger gefährlich sind, als sie andernfalls gewesen wären.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'a46a7077-56d6-44d5-9ed7-5015cb864eb7' AND is_custom = FALSE;

-- Ixitxachitl (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ixitxachitl sind eine Rasse intelligenter, aquatischer Wesen, die kleinen Mantarochen mit Stachelschwänzen ähneln. Sie haben eine böse Veranlagung und verehren böse Mächte; sie lieben es, maritime Humanoide zu jagen und ihre Beute dann zu opfern oder zu verschlingen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Eine bevorzugte Taktik der Ixitxachitl ist es, sich im Sand des Meeresbodens zu verstecken, zu warten bis Beute vorbeikommt, dann hervorzuspringen und sie zu beißen. Die Kreaturen sind nicht sehr heimlich, und diese Taktik gibt ihnen normale Chancen, ihre Beute zu überraschen.'),
  habitat_society = COALESCE(habitat_society, 'Obwohl sie gelegentlich in Flüssen angetroffen werden, leben Ixitxachitl in seichten Meerestiefen. Sie haben gewöhnlich eine Gemeinschaft von 10-100 Individuen, die in einem Labyrinth von Korridoren innerhalb eines Korallenriffs lebt. Eine Gemeinschaft hat gewöhnlich 20-200 humanoide Sklaven, die schwere Arbeit für sie verrichten, wie das Graben von Korridoren. Der Eingang der Gemeinschaft ist versteckt.'),
  ecology         = COALESCE(ecology, 'Ixitxachitl haben keine natürlichen Feinde, obwohl sie viele Gegner haben, von Sahuagin bis hin zu Menschen. Sie sind bösartige Räuber, die fast jede lebende Kreatur jagen; sie überjagen oft eine Region und eliminieren alle Lebensformen, was die Ixitxachitl zwingt, neue Jagdgründe zu finden.'),
  no_appearing    = COALESCE(no_appearing, '5-12 (1d8+4)')
WHERE id = '071a2ca0-612a-43a4-9562-020d61b35f1e' AND is_custom = FALSE;

-- Jackal (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schakale sind kleine, hundeartige Aasfresser, die durch die warmen Grasländer der Welt streifen. Sie sind weder wild noch mutig, aber durchaus häufig anzutreffen. Es gibt drei bekannte Schakalarten in der Welt: Asiatische, Schabrackenschakale und Streifenschakale. Abgesehen von ihren Markierungen sind diese Tiere sehr ähnlich.'),
  combat_tactics  = COALESCE(combat_tactics, 'In der Regel wird jeder Schakal fliehen, wenn er von einem anderen Raubtier angegriffen oder bedroht wird. Tatsächlich werden sie sogar ihre Jagdbemühungen aufgeben, wenn sich herausstellt, dass ihre Beute mehr Leben in sich hat, als sie erwartet hatten.'),
  habitat_society = COALESCE(habitat_society, 'Schakale bewohnen Ebenen, Wüsten und Grasländer in den wärmeren Regionen der Welt. Während des Tages, wenn die Sonne zu heiß für ihren Geschmack ist, bleiben sie in Löchern, die sie in den Boden gegraben haben.'),
  ecology         = COALESCE(ecology, 'Schakale sind zurückhaltende Raubtiere und ihre Position in der Nahrungskette ist die eines Aasfressers statt eines Jägers. Indem sie kranke oder schwache Tiere jagen und töten, spielen sie eine wichtige Rolle im Prozess der natürlichen Selektion. Zusätzlich würde das Aas, das sie verzehren, andernfalls verrotten und zu einem potentiellen Gesundheitsrisiko und Nährboden für Krankheiten werden.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = 'f01bb5fd-1b88-4a4e-bb44-6ca0d8975b78' AND is_custom = FALSE;

-- Kelpie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Kelpie ist eine Form intelligenten, aquatischen Pflanzenlebens, das seine Gestalt verändern und einen Charme-Zauber wirken kann. Sein Zweck ist es, Toren zu ertränken.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Kelpie verfügt nicht über echte Offensivfähigkeiten. Wenn sich ein humanoider Mann nähert, formt sich der Kelpie in die Gestalt einer Frau oder eines Reittiers um. Obwohl das Ergebnis eine groteske Nachäffung ist, die bei Tageslicht zu 95% als abstoßend erkennbar ist, kann der Kelpie seine Täuschung durch Magie verstärken.'),
  habitat_society = COALESCE(habitat_society, 'Eine Legende erzählt, dass der Kelpie von einem rachsüchtigen Meeresgott geschaffen wurde, um Männer zu bestrafen, die unbesonnen genug waren, die Meere zu befahren, ohne dem Meeresgott seine rechtmäßige Ehrerbietung zu erweisen. Da zu jener Zeit wenige Frauen Seefahrerinnen waren, blieben sie vom Fluch des Kelpie verschont. Eine weniger weit verbreitete Legende berichtet, wie Kelpies von Olhydra, der Elementarprinzessin der bösen Wasserkreaturen, erschaffen wurden. Aus Respekt vor ihrem eigenen Geschlecht machte Olhydra alle Frauen immun gegen die Charme ihrer Schöpfungen.'),
  ecology         = COALESCE(ecology, 'Kelpie-Sprösslinge sind 500 GM wert. Die Sprösslinge sind anfangs zu klein, um Magie zu nutzen, können aber in einem Monat zu ausgewachsenen Kelpies heranwachsen, wenn sie ausreichende Pflege erhalten. Kelpies können sich mit mächtigen Kreaturen verbünden und bewachen gelegentlich versunkene Schätze.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '6e47f344-ad5e-4e20-956c-3a5f5d299059' AND is_custom = FALSE;

-- Kenku (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kenku sind zweibeinige, humanoide Vögel, die ihre Kräfte nutzen, um Menschen und Halbmenschen zu belästigen und ihnen Unannehmlichkeiten zu bereiten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle Kenku verfügen über die Fertigkeiten eines Diebes der 4. Stufe. Sie sind erfahrene Kämpfer und greifen gewöhnlich mit einem Krummsäbel oder Kampfstab an. Sind sie unbewaffnet, attackieren sie entweder mit beiden Klauenpaaren (zwei Angriffe für je 1W4 Schadenspunkte) und ihrem Schnabel (1W6 Schadenspunkte). Sind sie zu Fuß unterwegs, nutzen sie die Handklauen. Im Flug werden die Fußklauen eingesetzt. Normalerweise töten sie nicht, es sei denn, ihr eigenes Leben wird durch das Überleben ihres Feindes bedroht. Alle Kenku verfügen über gut entwickelte Verkleidungsfertigkeiten. Sie haben eine 50%ige Chance, für Menschen gehalten zu werden, obwohl ihre Verkleidungen oft verräterisch große Nasen aufweisen.'),
  habitat_society = COALESCE(habitat_society, 'Kenku sind eine geheimnisvolle Rasse, die unter Menschen und Halbmenschen lebt, ohne dass der Großteil der Bevölkerung jemals ihre Anwesenheit bemerkt.'),
  ecology         = COALESCE(ecology, 'Häuslich aufgezogene Kenku werden als Diener geschätzt. Kenku-Eier werden gewöhnlich für 250 GM verkauft, Jungtiere für 300-500 GM. Dies ist jedoch eine Form des Sklavenhandels mit allen damit verbundenen Komplikationen. Entdeckt ein Kenku gefangene Kenku, wird er versuchen, den Gefangenen heimlich zu befreien und, wenn möglich, den Sklavenhändler oder Besitzer zu entführen. Sie werden getötete Kenku rächen.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '3cf86867-c308-4769-9ced-993f1fb4e5d9' AND is_custom = FALSE;

-- Killmoulis (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Killmoulis sind winzige Wesen, die gerne nützliche Dienste verrichten, aber auch Schabernack treiben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Killmoulis sind grundsätzlich harmlose Wesen. Ihnen fehlt jede echte Fähigkeit, Menschen oder Halbmenschen anzugreifen. Sie mögen Nadeln benutzen, um Ratten zu stechen; solche Angriffe verursachen 1 Schadenspunkt.'),
  habitat_society = COALESCE(habitat_society, 'Killmoulis leben immer an Orten, wo Menschen oder Halbmenschen irgendeiner Form von Gewerbe nachgehen, vorzugsweise dort, wo Nahrungsmittel verarbeitet werden. Sie machen ihre Heime unter Böden, in Wänden oder auf dunklen Dachsparren. Sie kommen nur heraus, wenn die Arbeiter fort sind. Wie ihre entfernten Verwandten, die Brownies, sind die Killmoulis zwischen der wohlwollenden Verrichtung nützlicher Pflichten und einem schelmischen Hang zu harmlosen Streichen zerrissen. Killmoulis sind unermüdliche Arbeiter, die geschickt einfache Aufgaben verrichten.'),
  ecology         = COALESCE(ecology, 'Killmoulis sind eine Rasse, die sich an eine symbiotische Lebensweise angepasst hat. Weise Menschen und Halbmenschen heißen diese geheimnisvollen Assistenten willkommen: trotz des Killmoulis-Appetits ist ihre Arbeit meist wertvoller als die Nahrung, die sie verzehren. Killmoulis fungieren auch als Wächter gegen gemeinsame Bedrohungen wie Ungeziefer und Feuer.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = '127bfa87-62e6-4544-ac4a-7608af82d4e3' AND is_custom = FALSE;

-- Ki-rin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kontrolle über das Leblose, Reisen, Gedankenlesen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Ki-rin kann körperlich mit seinen mächtigen Hufen angreifen (jeweils 2W4 Schadenspunkte) oder einem einhornartigen Horn, das einen +3-Bonus auf seinen Angriffswurf erhält und 3W6 Schadenspunkte verursacht.'),
  habitat_society = COALESCE(habitat_society, 'Die Ki-rin sind eine Rasse von Luftwesen, die selten ihre Hufe auf festen Boden setzen. Nur die Männchen nähern sich jemals dem Boden. Noch nie wurde eine Begegnung mit einem weiblichen Ki-rin verzeichnet, obwohl sicher ist, dass solche Wesen existieren. Ebenso wurde noch nie ein junger Ki-rin angetroffen, daher sind Details über ihre Fortpflanzung unbekannt. Ki-rin sind zurückhaltend bei diesen Themen.'),
  ecology         = COALESCE(ecology, 'Ki-rin verbringen die meiste Zeit damit, ihre eigenen Angelegenheiten zu verfolgen. Sie überwachen oft die Aktivitäten mächtiger böser Kreaturen und Wesen. Wenn solche Wesen zu bösartig werden, handeln die Ki-rin gegen sie.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '23dcb49f-e7c6-43e0-a0ac-0b0e54210cf7' AND is_custom = FALSE;

-- Kobold (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kobolde sind eine feige, sadistische Rasse kleiner Humanoider, die heftig mit Menschen und Halbmenschen um Lebensraum und Nahrung kämpfen. Sie mögen Gnome besonders nicht und greifen sie auf Sicht an.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Kampfansatz der Kobolde nutzt erdrückende Übermacht oder Tricks. Kobolde greifen Gnome auf Sicht an, aber werden zweimal überlegen, bevor sie Menschen, Elfen oder Zwerge angreifen, es sei denn, die Kobolde sind mindestens zwei zu eins in der Überzahl. Sie schleudern oft Speere und Wurfspieße und ziehen es vor, nicht näher zu kommen, bis sie sehen, dass ihre Feinde geschwächt wurden.'),
  habitat_society = COALESCE(habitat_society, 'Kobolde leben an dunklen, feuchten Orten unter der Erde und in überwucherten Wäldern. Sie können in fast jedem Klima gefunden werden. Da Kobolde gute Bergleute sind, ist jedes Gebiet mit Bergbaupotenzial ein möglicher Ort für eine Ansiedlung.'),
  ecology         = COALESCE(ecology, 'Vielleicht sind Kobolde so grausam, weil sie leichte Beute für größere Humanoide und hungrige Monster sind. Sie haben viele Feinde, und sogar die Zwerge mussten zugeben, dass die zahlreichen Kobold-Goblin-Kriege die Anzahl der Goblins auf einem sicheren Niveau gehalten haben.'),
  no_appearing    = COALESCE(no_appearing, '5-20 (5d4)')
WHERE id = '7445eca8-e871-4986-93b4-e33bbab980d9' AND is_custom = FALSE;

-- Korred (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wenn Reisende durch die waldreichen Wälder der Welt wandern, sollten sie sich vor Musik und Gelächter hüten, die aus einer Lichtung kommen. Höchstwahrscheinlich ist die Ursache der tanzliebende Korred, eine Rasse, die der Natur nahesteht und ihre Lebensweise eifersüchtig beschützt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Korred haben große Stärke (durchschnittlich 18/76) und nutzen sie, um Felsbrocken bis zu 30 m zu schleudern (Schaden 2W8). Sie verwenden auch Knüppel (Schaden 1W6+4) oder Scheren, die sich in ihren Beuteln befinden (Schaden 1W4+4). Ohne Waffe kann der Korred für 1 oder 2 Schadenspunkte zuschlagen, wobei seine große Stärke +4 zu dieser Summe hinzufügt.'),
  habitat_society = COALESCE(habitat_society, 'Bewaldete Hügel und waldreiche Umgebungen werden von den Korred bevorzugt, die normalerweise in Höhlen oder Bauen hausen. Die Korred sind sippenorientiert und verwenden das Wort "Sippe" als Titel (zum Beispiel Sippe Korefyr). Im Einklang mit ihrer chaotischen Natur haben sie keine strukturierten Gemeinschaften. Typischerweise gibt es 1-4 Erwachsene und 2-8 (2W4) Kinder pro Familie, wobei 2-8 (2W4) Familien zu jeder einzelnen Sippe gehören. Diese Familien sind über ein Gebiet von etwa acht Kilometern verstreut.'),
  ecology         = COALESCE(ecology, 'Diese magische Rasse wird für die Erschaffung verschiedener magischer Gegenstände gesucht. Ihr Haar ist eine Schlüsselzutat für Verstrickungsseile und Fangnetze. Die fermentierten Fruchtgetränke, die die Korred konsumieren, können auch als Komponente für Liebestränke und Tränke der Menschenbeherrschung verwendet werden.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'e1ca3530-c619-4dfb-90f8-aa51ae8a98e4' AND is_custom = FALSE;

-- Kuo-Toa (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Kuo-Toa sind eine uralte Rasse von Fischmenschen, die unterirdisch lebt und einen tiefen Hass auf Oberflächenbewohner und Sonnenlicht hegt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Diese Kreaturen reisen normalerweise in gut bewaffneten Banden. Wenn mehr als 20 Kuo-Toa angetroffen werden, besteht eine 50%ige Wahrscheinlichkeit, dass sie sich innerhalb von 1W10×1 km von ihrem Bau befinden. Für jeden vier normalen Krieger, die angetroffen werden, gibt es einen zusätzlichen Kämpfer der 3. oder 4. Stufe. Für jeden acht normalen Kämpfer gibt es einen zusätzlichen Kämpfer der 5. oder 6. Stufe. Für jeden 12 normalen Kuo-Toa in der Gruppe gibt es einen Priester/Dieb von jeweils 1W4+3 Stufen. Wenn mehr als 20 normale Kämpfer angetroffen werden, handelt es sich bei der Gruppe um eine Kriegsschar bestehend aus Folgendem:'),
  habitat_society = COALESCE(habitat_society, 'Kuo-Toa laichen wie Fische, und Schlüpflinge oder Jungfische, wie sie ihre Jungen nennen, werden in Becken aufgezogen, bis ihre amphibischen Eigenschaften sich entwickeln, etwa ein Jahr nach dem Schlüpfen. Die Jungen, nun etwa 30 cm groß, sind dann in der Lage, Luft zu atmen und werden in Gehegen nach ihrem Geschlecht und ihrer Tauglichkeit aufgezogen. Es gibt keine Familien, wie wir sie kennen, in der Kuo-Toa-Gesellschaft.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '2-24')
WHERE id = 'cf1aebfd-e503-407f-8ba3-2154fc04c521' AND is_custom = FALSE;

-- Lamprey (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Neunaugen sind blutegelähnliche Aale, die in tiefen Süß- und Salzgewässern leben. Sie ernähren sich, indem sie ihre Opfer beißen, sich mit ihren Zähnen festhalten und das Blut ihrer Beute aussaugen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Sie ernähren sich, indem sie ihre Opfer beißen und sich mit ihren sphinkterartigen Mäulern festhalten. Sobald sie angeheftet sind und der anfängliche Schaden dem Opfer zugefügt wurde, beginnt das Neunauge in der nächsten und den folgenden Runden Blut zu entziehen. Die Rate des Blutentzugs entspricht 2 Trefferpunkten pro Trefferwürfel des Neunauges. Somit entzieht ein normales Neunauge pro Runde Blut für 2 Schadenspunkte.'),
  habitat_society = COALESCE(habitat_society, 'Neunaugen bewohnen Tiefwassergebiete und hausen in natürlichen Höhlen oder Korallenformationen. Neunaugen haben einen unfehlbaren Heimfindungsinstinkt, der es ihnen ermöglicht, bis zu 3,2 km von ihrem Bau entfernt umherzustreifen.'),
  ecology         = COALESCE(ecology, 'In Salzwasserumgebungen fressen Haie gerne Riesenneunaugen. Man könnte argumentieren, dass die Anwesenheit dieser Meerneunaugen die Anzahl der Haiangriffe auf Küstengemeinden niedrig hält.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '657d9001-e77e-4c03-860a-d2c439f58e99' AND is_custom = FALSE;

-- Lich (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Lich ist vielleicht die mächtigste Form von Untoten, die bekanntermaßen existiert. Sie streben danach, ihre eigene Macht um jeden Preis zu mehren und haben wenig oder gar kein Interesse an den Angelegenheiten der Lebenden, außer wenn diese Angelegenheiten ihre eigenen beeinträchtigen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl sich ein Lich selten in tatsächlichen Nahkampf mit denen begibt, die er als Feinde betrachtet, ist er mehr als imstande, sich zu behaupten, wenn er zum Kampf gedrängt wird.'),
  habitat_society = COALESCE(habitat_society, 'Lichs sind üblicherweise Einzelgänger. Sie haben ihren Platz als lebende Wesen aus freier Entscheidung abgelegt und wollen nun so wenig wie möglich mit der Welt der Menschen zu tun haben. Von Zeit zu Zeit jedoch mag das Interesse eines Lich an der Welt im Allgemeinen durch irgendein großes Ereignis von persönlicher Wichtigkeit wiedererweckt werden.'),
  ecology         = COALESCE(ecology, 'Der Lich ist nicht ein Ding dieser Welt. Obwohl er einst eine lebende Kreatur war, ist er in eine unnatürliche Existenz eingetreten.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'dbf8cc6c-e44f-4274-8036-ebb45f0bbfb0' AND is_custom = FALSE;

-- Living Wall (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Lebende Wände erscheinen als normale Wände aus Stein oder Ziegeln, obwohl sie sowohl Böses als auch Magie ausstrahlen, falls dies entdeckt wird. Infrasicht erkennt keine besonderen Muster. Ein Charakter, der jedoch einen Zauber der wahren Sicht wirkt oder durch einen Edelstein des Sehens blickt, sieht durch die Illusion hindurch: Die Wand besteht tatsächlich aus grauem und sehnigem Fleisch - aus Gesichtern, Händen, gebrochenen Knochen, Füßen und Zehen, die aus der Oberfläche hervorragen. Charaktere in 4,6 m Entfernung zur Wand können leise Stöhnen des Grauens, Schmerzes und der Trauer von ihr ausgehen hören. Selbst wenn ein Zauber der Stille gewirkt wird, steigen die Klagen weiter auf.'),
  combat_tactics  = COALESCE(combat_tactics, 'Eine lebende Wand beginnt niemals einen Kampf, außer gegen ihren Erschaffer, den sie verabscheut. Wenn eine solche Wand angegriffen wird, führt jede Kreatur, die Teil der Wand ist, einen Gegenangriff pro Schlag gegen die Wand aus. Wenn eine Wand aus 12 Kreaturen besteht und eine Kreatur einen Treffer gegen die Wand landet, ist der Angreifer einem Dutzend Gegenangriffen der Wand ausgesetzt.'),
  habitat_society = COALESCE(habitat_society, 'Lebende Wände pflanzen sich niemals fort und bleiben immer aktiv, bis sie getötet werden. Lebende Wände, die in den Bauten bösartiger Kreaturen angetroffen werden, dienen oft als Teil einer Folterkammer oder um die wahren Öffnungen zu geheimen Durchgängen oder Korridoren zu verdecken.'),
  ecology         = COALESCE(ecology, 'Chaotisch böse Magier erschaffen gelegentlich diese Monolithen. Die genaue Methode ist unbekannt, aber mehrere Jahre der Vorbereitung und des Zauberwirkens sind erforderlich. Mindestens drei Leichen sind für die Zauber notwendig.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'ad5dbd43-f8e5-4319-b3ff-907c6aa28536' AND is_custom = FALSE;

-- Lizard (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Feuerechsen ähneln flügellosen roten Drachen und werden manchmal "falsche Drachen" genannt. Sie sind grau gefärbt mit gesprenkeltem rot-braunem Rücken und rötlicher Unterseite. Jungtiere sind hellgrau gefärbt und dunkeln mit dem Alter nach.'),
  combat_tactics  = COALESCE(combat_tactics, 'Feuerechsen greifen mit einer Kombination aus kratzenden Klauen und Biss an. Sie können gleichzeitig einen feurigen Kegel atmen, der am Maul 1,5 m breit, am Ende 3 m breit und 4,6 m lang ist und 2-12 Punkte feuerbasierten Schaden verursacht (die Hälfte bei erfolgreichem Rettungswurf gegen Atemwaffe). Feuerechsen sind immun gegen feuerbasierte Angriffe.'),
  habitat_society = COALESCE(habitat_society, 'Feuerechsen bevorzugen unterirdische Baue, kommen aber alle vierzehn Tage heraus, um frische Beute zu jagen. Die Beute wird zurück zum Bau geschleppt für eine gemütliche Mahlzeit; die Überreste bilden den Schatzhort. Feuerechsen bewegen sich langsam und schlafen 50% der Zeit. Ihre Baue können 1-4 Eier enthalten (10% Chance, Marktwert 5.000 GM je Ei). Jungtiere verlassen sofort den Bau, um allein zu jagen. Glänzende Gegenstände locken Feuerechsen an; Edelsteine und Metalle bilden den Großteil der in ihren Höhlen gefundenen Schätze.'),
  ecology         = COALESCE(ecology, 'Feuerechsen sind vielleicht ein ursprünglicher Drachentyp oder Ableger eines gemeinsamen Vorfahren. Echte Drachen meiden diese "falschen Drachen", die 50-100 Jahre alt werden. Feuerechseneier sind 5.000 GM wert, Jungtiere 7.500 GM.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '7534ad53-1864-44fc-ab70-ad1025a0ce19' AND is_custom = FALSE;

-- Lizard Man (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Echsenmenschen sind wilde, halbaquatische, reptilienhafte Humanoide, die durch Plündern, Raubzüge und in weniger feindseligen Gebieten durch Fischfang und Sammeln überleben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Im Kampf kämpfen Echsenmenschen als unorganisierte Einzelwesen. Haben sie Gleichstand oder einen Vorteil gegenüber ihren Gegnern, neigen sie zu Frontalangriffen und Massenattacken. Wenn sie jedoch in der Unterzahl, unterlegen oder auf ihrem Heimatgebiet sind, werden sie zu listigen und grimmigen Gegnern. Fallen, plötzliche Hinterhalte und Störangriffe sind in diesen Situationen bevorzugte Taktiken. Obwohl sie im Nahkampf einzeln wild sind, neigen Echsenmenschen dazu, sich von Nahrung (wie erschlagenen Gegnern) und einfachen Schätzen ablenken zu lassen, was einigen ihrer Beute die Flucht ermöglichen kann. Gelegentlich nehmen sie Gefangene als Sklaven, als Nahrung oder um sie in obskuren Stammesriten zu opfern.'),
  habitat_society = COALESCE(habitat_society, 'Echsenmenschen findet man typischerweise in Sümpfen, Marschen und ähnlichen Orten, oft (35%) leben sie völlig unter Wasser in luftgefüllten Höhlen. Ein Stamm zählt selten mehr als 150 Individuen, einschließlich Weibchen und Schlüpflinge. Es ist nicht ungewöhnlich, dass mehrere Stämme in einem Gebiet eine informelle Allianz gegen Außenseiter schmieden, einschließlich anderer Echsenmenschenstämme.'),
  ecology         = COALESCE(ecology, 'Echsenmenschen haben wenige natürliche Feinde. Sie machen Jagd auf menschliche, halbmenschliche oder humanoide Siedlungen, falls diese in der Nähe sind. Echsenmenscheneier sind bitter und ungenießbar, ebenso wie ihr Fleisch, aber ihre Haut wird manchmal als Schuppenrüstung verarbeitet (Rüstungsklasse 6). Echsenmenschen schaffen keine Kunst, Artefakte oder Handelswaren.'),
  no_appearing    = COALESCE(no_appearing, '8-15 (1d8+7)')
WHERE id = '9abd6089-51f3-4cc7-aebd-2027a1928d14' AND is_custom = FALSE;

-- Lurker (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Lauerer ist ein fleischfressender Aasfresser, der nur in unterirdischen Umgebungen anzutreffen ist. Er ähnelt einem großen Manta-Rochen; sein gräulicher Bauch hat eine steinähnliche Struktur. Der Lauerer heftet sich typischerweise an eine Decke, wo er sehr schwer zu entdecken ist (nur 10% Chance), es sei denn, er wird tatsächlich angestoßen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Lauerer sind langsam bewegende Kreaturen, die warten müssen, bis ihre Beute in Reichweite kommt. Lauerer warten an der Decke, dann lassen sie sich fallen und umhüllen ihre Beute. Lauerer verursachen eine -4 Strafe auf die Überraschungswürfe der Gegner. Die Umklammerung verursacht 1W6 Schadenspunkte pro Runde und Erstickung innerhalb von 1W4+1 Runden, unabhängig vom erlittenen Schaden des Opfers. Dieser Schaden tritt automatisch jede Runde ein, es sei denn, das Opfer befreit sich oder der Lauerer stirbt. Lauerer hören nicht auf anzugreifen, bis sie tot sind. Die Beute kann nur mit kurzen Waffen kämpfen, die in der Hand waren, als der Lauerer angriff.'),
  habitat_society = COALESCE(habitat_society, 'Lauerer sind Einzelgänger. Die Weibchen legen Eier in einen klebrigen Haufen nahe der Decke. Die Schlüpflinge fallen zu Boden und ernähren sich von Ungeziefer, bis sie groß genug sind zu fliegen. Junge ähneln rechteckigen Moosflächen.'),
  ecology         = COALESCE(ecology, 'Lauerer sind opportunistische Fresser, die mit allem vorlieb nehmen, was vorbeikommt. Der Lauerer fliegt mittels Gasen, die in Säcken erzeugt werden. Diese Gase können bei der Herstellung eines Tranks des Schwebens verwendet werden. Lauerer-Eier oder Schlüpflinge können als lebende Verteidigung an diejenigen verkauft werden, die sie wollen. Lauerer-, Fallensteller- und Minen-Eier können alle für 900 GM verkauft werden, Schlüpflinge für 1.100 GM.'),
  no_appearing    = COALESCE(no_appearing, '1 (1-4)')
WHERE id = 'f3850df3-16fe-4eb6-9c1b-f001cdc180d7' AND is_custom = FALSE;

-- Lycanthrope, Wererat (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Werratten, auch Rattenmenschen genannt, sind Menschen, die sich in drei Formen verwandeln können - menschlich, menschengroßer Rattenmensch und Riesenratte. Sie sind verschlagen und böse und bewohnen üblicherweise Tunnelkomplexe unter Städten.'),
  combat_tactics  = COALESCE(combat_tactics, 'In allen drei Formen verlassen sich Werratten auf Waffen für ihre Angriffe und bevorzugen Kurzschwerter und Dolche. Jeder, der von einer echten Werratte verletzt wird, hat eine 1%ige Chance pro Schadenspunkt, selbst zu einer Werratte zu werden. In ihren Rattenmenschen- und Riesenrattenformen können Werratten nur durch Silber oder magische Waffen verletzt werden.'),
  habitat_society = COALESCE(habitat_society, 'Werratten leben in Rudeln, unabhängig von ihrer Form, und sind niemals allein, wenn sie es vermeiden können. Einzelgängerische Werratten sind entweder Alleinsüberlebende oder mit Unfug beschäftigt. Sie bilden keine zwischenmenschlichen Bindungen wie Liebe oder Ehe. Tatsächlich paaren sich Werratten selten mit ihresgleichen. Nachkommen einer Werratte und einer menschlichen Frau sind Menschen, obwohl sie klein sind wie ihre Väter. Nachkommen einer weiblichen Werratte ähneln Riesenratten mit menschenähnlichen Pfoten. Diese Rattenjungen wachsen in zwei Jahren zur Reife heran und erlangen die Fähigkeit, sich in menschliche Kinder zu verwandeln mit einem scheinbaren Alter von etwa dem Dreifachen des tatsächlichen Alters des Rattenjungen.'),
  ecology         = COALESCE(ecology, 'Werratten sind Parasiten. Sie erkennen, dass sie körperlich schwächer sind als die meisten Arten, die die Oberfläche beherrschen. Sie haben die eine Nische gefunden und ausgebeutet, wo sie eine Chance haben zu dominieren: die Welt unter den Städten. Sie ernähren sich von Menschen und stehlen deren Reichtümer. Menschen schützen unwissentlich die Werratten sowohl vor oberflächenbewohnenden Kreaturen als auch vor jenen, die von weit unten heraufgraben könnten. Außerdem bezahlen die Menschen für die Instandhaltung des Kanalisationsreichs der Werratten.'),
  no_appearing    = COALESCE(no_appearing, '4-24 (4d6)')
WHERE id = '97bd3238-3bb4-4cec-92bb-fc39e6552d19' AND is_custom = FALSE;

-- Mammal (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Säugetiere sind die häufigsten Wirbeltiere. Sie werden im Allgemeinen lebend geboren und besitzen Haare.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, NULL)
WHERE id = 'ef1ef330-5238-4d06-826f-c5ae56fc8fb5' AND is_custom = FALSE;

-- Mammal, Herd I (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Herdentiere leben in allen Klimazonen und Geländearten, von eisiger Tundra (Trampeltier) über gemäßigte Hügel (Wildrind) bis hin zu tropischen Ebenen (Antilope). Obwohl normalerweise friedlich, können Herdentiere gefährlich werden, wenn sie verärgert oder erschreckt sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die meisten Herdentiere greifen durch Beißen an. Büffel verteidigen sich mit ihren Hörnern und greifen normalerweise an, wenn man ihnen zu nahe kommt (1,8 m oder weniger); wenn sie aus einer Entfernung von mindestens 12 m anstürmen, verursacht ein Büffel 3-18 TP Spießschaden plus 1-4 TP Trampelschaden. Bösartige Kamele haben eine 50%ige Chance, Personen anzuspucken, die versuchen, auf ihnen zu reiten oder sie als Lasttiere zu benutzen; das Opfer eines Spuckangriffs hat eine 25%ige Chance, für 1-3 Runden geblendet zu werden. Rinder, Antilopen und Schafe fliehen normalerweise vor Gefahr, greifen aber an, wenn sie in die Enge getrieben oder bedroht werden. Ein männliches Antilopen- oder Schafsmännchen, das seine Herde verteidigt, wird anstürmen und 1-4 TP Rammschaden verursachen, wenn es aus mindestens 12 m Entfernung angreift. Männliche Rinder greifen zu 75% an, wenn Eindringlinge sich nähern, bevor die Herde eine Chance zur Flucht hatte.'),
  habitat_society = COALESCE(habitat_society, 'Herdentiere weiden auf offenem Gelände und wandern in ein neues Territorium, wenn die Nahrungsversorgung des alten erschöpft ist. Die Herdengröße variiert von einer Familie mit vier Büffeln bis zu einer kommerziellen Schafherde mit 1.000 Tieren. Das größte und älteste Männchen dient normalerweise als Anführer, lenkt die Bewegung seiner Herde und hält nach Raubtieren Ausschau. Herdentiere sammeln keine Schätze.'),
  ecology         = COALESCE(ecology, 'Herdentiere fressen Gras, Getreide und Sträucher. Sie sind die bevorzugte Beute von Fleischfressern, einschließlich Löwen, Tigern und Drachen. Menschen domestizieren Herdentiere oft wegen ihres Fleisches, ihrer Milch, ihres Fells (Decken und Kleidung) und ihrer Haut (Schuhe und Zelte). Getrockneter Dung von Herdentieren kann als Brennstoff verbrannt werden.'),
  no_appearing    = COALESCE(no_appearing, '1-12')
WHERE id = '1bf776a5-bf94-4496-9b54-1a7071c0fe7b' AND is_custom = FALSE;

-- Mammal, Minimal (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Minimale sind halbgroße Züchtungen ansonsten normaler Tiere. Sie haben die gleichen körperlichen und Verhaltensmerkmale wie ihre normalgroßen Verwandten, obwohl die meisten nicht so gefährlich sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Minimale kämpfen auf die gleiche Weise wie die normalen Züchtungen. Einige der Fleischfresser sind sogar noch aggressiver.'),
  habitat_society = COALESCE(habitat_society, 'Minimale (die populäre Kurzform für "kleine Tiere") wurden mittels Zaubersprüchen erschaffen, die ähnlich denen sind, die zur Erschaffung von Riesenreptilien, Insekten und dergleichen verwendet werden. Minimale sind meist nur in isolierten oder abgeschlossenen Gebieten zu finden. Dort sind sie zu 80% die einzigen Säugetierarten in der Umgebung. Sie existieren selten in Gebieten mit großen Fleischfressern, da sie schnell ausgerottet würden.'),
  ecology         = COALESCE(ecology, 'Minimale sind das Ergebnis absichtlicher Manipulation der Natur durch magische Mittel. Abgesehen von ihrer geringeren Größe haben sie die gleichen Eigenschaften und Bedürfnisse wie ihre normalgroßen Verwandten. Anders als die meisten vergrößerten Monster haben die winzigen Minimalen erhöhte Nützlichkeit und Überlebensfähigkeit, da sie weniger Nahrung und Territorium benötigen. Minimale Häute und Felle sind ⅔ des Wertes der normalgroßen Arten wert.'),
  no_appearing    = COALESCE(no_appearing, 'As full size but 50% likely for twice the number rolled')
WHERE id = 'd81a2905-b469-40a3-8b54-0a20484149a4' AND is_custom = FALSE;

-- Manticore (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Mantikor ist ein wahres Monster mit dem Rumpf und den Beinen eines Löwen, fledermausartigen Flügeln, dem Kopf eines Mannes, einem mit Eisenstacheln besetzten Schwanz und einem Appetit auf Menschenfleisch.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Mantikor feuert zuerst eine Salve von 1-6 Schwanzstacheln ab (164,6 m Reichweite wie eine leichte Armbrust). Jeder Stachel verursacht 1-6 Schadenspunkte. Der Mantikor kann vier solcher Salven pro Tag abfeuern (die Stacheln wachsen schnell nach). Anschließend nähert sich der Mantikor seiner Beute und greift mit seinen Vorderklauen und scharfen Zähnen an. In einer Außenumgebung versucht der Mantikor in der Luft zu bleiben, um seine Chance, angegriffen zu werden, zu minimieren. Er ist jedoch ein ungeschickter Flieger und kann seine Zähne in der Luft nicht einsetzen.'),
  habitat_society = COALESCE(habitat_society, 'Mantikore finden sich in jedem Klima, bevorzugen aber warme Länder gegenüber kühlen. Dies spiegelt die weite Klimaspanne ihrer Lieblingsspeise, der Menschen, wider. Das Territorium eines Mantikors kann 20 oder mehr Quadratkilometer umfassen und schließt mindestens eine menschliche Siedlung ein. Solche Territorien überschneiden sich gewöhnlich mit denen anderer Mantikore und anderer menschenfressender Räuber wie Drachen.'),
  ecology         = COALESCE(ecology, 'Mantikore sind weit umherstreifende Fleischfresser, die erfolgreich in jeder von Menschen bewohnten Region überlebt haben, sei es in der Wildnis oder im Untergrund. Sie sind alptraumhafte Gegner, aber unschätzbare Verbündete, wenn die Bedingungen stimmen. Das Fell eines Mantikors ist ein Zeichen der mächtigsten Jäger und Krieger. Eine intakte, gegerbte Mantikor-Haut komplett mit Flügeln ist 10.000 GM wert.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'df608b4d-2538-4122-b02d-a137c1c1ded0' AND is_custom = FALSE;

-- Medusa, Maedar (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, '(1,5-2,1 m)'),
  combat_tactics  = COALESCE(combat_tactics, 'Maedar greifen mit mächtigen Fäusten an, die jeweils 2W4 Schadenspunkte verursachen. Alle drei Runden kann der Maedar Stein zu Fleisch durch Berührung verwandeln. Maedar können mit ihrer normalen Bewegungsrate durch Stein hindurchgehen. Sie benötigen eine Runde der Konzentration davor; in dieser Runde kann keine andere Aktivität unternommen werden. Maedar, die von einem Phasentür-Zauber getroffen werden, während sie durch Stein gehen, werden sofort getötet.'),
  habitat_society = COALESCE(habitat_society, 'Maedar sind die wenig bekannte männliche Version der Medusen. Sie sind jedoch extrem selten (weitaus seltener als die Häufigkeitsangabe andeuten würde), und nur wenige Medusen finden jemals einen Maedar als Partner.'),
  ecology         = COALESCE(ecology, 'Maedar können mit rechtschaffen bösen Kreaturen wie Kobolden und Orks zusammenarbeiten, im Austausch für Sicherheit oder Belohnung. Wenn sie gezwungen werden, einer anderen Kreatur zu helfen, suchen Maedar bei der ersten Gelegenheit Rache.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '2c900f84-b14e-4c8b-b628-399129f16581' AND is_custom = FALSE;

-- Medusa (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Medusen sind weibliche Humanoide mit Haar aus wimmelnden Schlangen. Sie sind hasserfüllte Kreaturen, die jedes Wesen versteinern können, das ihrem Blick begegnet.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Medusa versucht, sich einem Opfer zu nähern, bevor sie ihre wahre Natur offenbart. Sie wird ihren attraktiven Körper nutzen, um Männer näher zu locken, während sie im Schatten bleibt. Sobald die Medusa innerhalb von 9,1 m ist, schlägt sie zu und versucht, ihr Opfer dazu zu bringen, in ihre Augen zu blicken. Jede Kreatur innerhalb von 9,1 m muss einen Rettungswurf gegen Versteinerung machen oder sich augenblicklich in leblosen Stein verwandeln. Wenn ein Gegner seine Augen abwendet, stürmt die Medusa heran, damit ihre schlangenartigen Auswüchse angreifen können. Die Reichweite solcher Angriffe beträgt nur 0,3 m, aber das Opfer muss gegen Gift retten oder sterben.'),
  habitat_society = COALESCE(habitat_society, 'Medusen leben in dunklen Höhlen oder den unteren Bereichen großer verlassener Gebäude. Sie arrangieren die Beleuchtung so, dass ihre Heime von flackernden Schatten erfüllt sind.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = '915a0183-2b17-48d0-ae5f-f8608aa57c30' AND is_custom = FALSE;

-- Merman (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Meermänner sind meeresbewohnende, amphibische Humanoide mit dem Oberkörper eines Menschen und dem Unterkörper eines Fisches.'),
  combat_tactics  = COALESCE(combat_tactics, 'Meermanngemeinschaften sind gut bewaffnet. Die von Meermännern verwendeten Waffen sind folgende:'),
  habitat_society = COALESCE(habitat_society, 'Für jeden 20 angetroffenen Meermänner gibt es einen Patrouillenfüherer (2-3 TW) und 1-3 Barrakudas (RK 6; Bewegung 30; TW 3; #AT 1; Schaden 2W4). Für jeden 40 Meermänner gibt es einen Anführer (4 TW). Für jeden 120 angetroffenen Meermänner gibt es einen Häuptling (6 TW) und zwei Wachen (4 TW). Für jeden zehn Meermänner besteht eine 10%ige Chance auf einen Schamanen (3 TW, mit den Zaubern eines Priesters 3. Stufe).'),
  ecology         = COALESCE(ecology, 'Meermänner sind Allesfresser, aber sie bevorzugen eine Diät aus Fischen, Hummern, Krabben und Schalentieren. Sie kochen diese Kreaturen nicht, müssen sie aber vor dem Verzehr filetieren. Sie können eine Stunde außerhalb des Wassers überleben, bevor sie zu dehydrieren beginnen. Wenn dehydriert, verlieren sie 2 Trefferpunkte pro Stunde und sterben, wenn sie null erreichen; das Eintauchen in Süß- oder Salzwasser stellt diese verlorenen Trefferpunkte sofort wieder her.'),
  no_appearing    = COALESCE(no_appearing, '20-200')
WHERE id = 'e4165830-24a6-4ca3-80ba-12e83b14e569' AND is_custom = FALSE;

-- Mimic (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Mimics sind magisch erschaffene Kreaturen mit einer harten, steinähnlichen äußeren Schale, die ihre weichen inneren Organe schützt. Mimics können ihre Form und ihre Pigmentierung verändern; sie nutzen diese Begabung, um Opfer in Nahkampfreichweite zu locken, wo sie versuchen, sich von ihnen zu ernähren. Gewöhnlich erscheinen sie in Form von Schatztruhen. Es gibt zwei Varianten, den kleineren, intelligenteren gewöhnlichen Mimic und den größeren, weniger intelligenten Killer-Mimic.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Mimic kann seine Opfer leicht überraschen (-4 Malus auf die Überraschungswürfe der Opfer). Wenn eine Kreatur einen Mimic berührt, schlägt er mit einem Pseudopod zu, das 3W4 Schadenspunkte verursacht. Außerdem bedeckt sich der Mimic mit einer klebstoffähnlichen Substanz. Jede Kreatur oder jeder Gegenstand, die einen Mimic berühren, werden festgehalten. Alkohol schwächt den Klebstoff in drei Runden, wodurch der Charakter sich befreien kann, oder der Charakter kann versuchen, einen Türen-öffnen-Wurf zu machen, um sich zu befreien. Pro Charakter darf nur ein Versuch unternommen werden, und keine andere Aktion, weder offensiv noch defensiv, darf während der Runde ausgeführt werden, in der der Versuch unternommen wird. Ein Mimic kann seinen Klebstoff jederzeit neutralisieren, wenn er es wünscht; der Klebstoff löst sich fünf Runden nach dem Tod des Mimics auf. Der Mimic ist immun gegen Säureangriffe und wird von Schimmelpilzen, grünem Schleim und verschiedenen Puddings nicht beeinträchtigt.'),
  habitat_society = COALESCE(habitat_society, 'Mimics leben unterirdisch, wo sie Sonnenlicht meiden können. Sie sind Einzelgänger; dies stellt sicher, dass jeder Mimic ein großes Weidegebiet hat. Sie haben keine Kultur; ihre Hauptsorgen sind Überleben und Nahrung. Gewöhnliche Mimics sind recht intelligent und werden gerne Informationen im Austausch für Nahrung anbieten. Killer-Mimics greifen ungeachtet der Kommunikationsversuche an. Mimics haben keinen Moralkodex und kein Interesse an Kultur oder Religion. Magier, die sie als Wächter einsetzen, haben manchmal festgestellt, dass sie weniger als begeistert dabei sind, ihren Befehlen zu gehorchen.'),
  ecology         = COALESCE(ecology, 'Mimics wurden ursprünglich von Magiern erschaffen, um sich vor Schatzsuchern zu schützen. Eine gute Mahlzeit (ein oder zwei Menschen) kann sie wochenlang am Leben erhalten. Sie vermehren sich durch Teilung und wachsen in mehreren Jahren zur vollen Größe heran. Mimics geben sich als Steinwerk, Türen, Statuen, Treppen, Truhen oder andere gewöhnliche Gegenstände aus Stein, Holz und Metall aus. Ihre Haut ist mit optischen Sensoren bedeckt, die empfindlich auf Hitze und Licht in einem Radius von 27,4 Metern reagieren, selbst in völliger Dunkelheit. Jede starke Lichtquelle kann sie leicht blenden, einschließlich direktes Sonnenlicht. Zusätzlich zum Klebstoff können sie eine Flüssigkeit ausscheiden, die nach verrottendem Fleisch riecht; dies lockt kleinere, gewöhnlichere Beute an (normalerweise Ratten). Mimic-Blut ist nützlich bei der Herstellung von Verwandlung-Selbst-Tränken, und ihre Klebstoff- und Lösungsmittelsäcke können an Alchemisten verkauft werden. Andere innere Organe sind nützlich bei der Herstellung von Parfums. Die inneren Organe des Mimics gelten in manchen Kulturen als schmackhafte Delikatessen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'd607af96-a6fe-4bca-a8a1-5c1d5d402e09' AND is_custom = FALSE;

-- Mind Flayer (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Illithide oder Gedankenschinder ist ein böses und gefürchtetes Geschöpf der Unterwelt; seine Kräfte sind beeindruckend und er nährt sich von den Gehirnen aller Kreaturen, denen er begegnet. Mit arkanen Kräften versklavt oder vernichtet er seine Feinde, zu denen so mächtige Kreaturen wie Drow und Kuo-Toa gehören.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die bevorzugte Angriffsmethode eines Gedankenschinders ist der Gedankenblitz, der in einem Kegel von 18,3 m Länge projiziert wird, 1,5 m breit am Gedankenschinder und 6,1 m breit am gegenüberliegenden Ende. Alle innerhalb des Kegels müssen einen Rettungswurf gegen Stäbe machen oder werden betäubt und können 3W4 Runden lang nicht handeln. Der Illithide versucht ein oder zwei betäubte Opfer zu packen (normale Angriffswürfe sind erforderlich, falls andere dies zu verhindern suchen) und mit ihnen zu entkommen.'),
  habitat_society = COALESCE(habitat_society, 'Gedankenschinder hassen Sonnenlicht und meiden es wenn möglich. Sie leben in unterirdischen Städten von 200 bis 2.000 Illithiden, plus mindestens zwei Sklaven pro Illithide. Alle Sklaven stehen unter den Effekten von Person bezaubern oder Monster bezaubern und gehorchen ihren Illithiden-Herren ohne zu fragen.'),
  ecology         = COALESCE(ecology, 'Gedankenschinder leben etwa 125 Jahre. Sie sind warmblütige Amphibien und verbringen die ersten 10 Lebensjahre als Kaulquappen, schwimmend im Ältestengehirn-Becken, bis sie entweder sterben (was die meisten tun) oder zu erwachsenen Illithiden heranwachsen. In unregelmäßigen Abständen füttern erwachsene Illithiden die Kaulquappen mit Gehirnen, die das Ältestengehirn nicht belästigen. Illithiden sind zwittrig; jeder kann zweimal in seinem Leben eine Kaulquappe hervorbringen.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '5e78ea65-6cf1-4b05-a8f3-a1915215fe8c' AND is_custom = FALSE;

-- Minotaur (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Minotauren sind entweder verfluchte Menschen oder die Nachkommen von Minotauren und Menschen. Sie leben gewöhnlich in unterirdischen Labyrinthen, da sie in diesen Orten nicht die Orientierung verlieren, was ihnen einen Vorteil gegenüber ihrer Beute verschafft.'),
  combat_tactics  = COALESCE(combat_tactics, 'Minotauren sind sehr stark (entspricht einer menschlichen Stärke von 18). Gegen menschengroße Gegner (mindestens 1,8 m groß) können sie mit dem Kopf stoßen und dabei 2-8 Schadenspunkte verursachen. Gegen kleinere Gegner beißen sie und verursachen 1-4 Schadenspunkte. Wenn ein Minotaurus 9,1 m oder mehr von seinem Gegner entfernt ist, kann er den Kopf senken und gegen jede Kreatur anstürmen, die mindestens 1,8 m groß ist. Bei Erfolg verursacht der Sturmangriff doppelten Kopfstoßschaden. Zusätzlich zu diesen Angriffen tragen die meisten Minotauren auch Waffen - eine riesige Axt (behandle sie wie eine Hellebarde) oder einen Flegel, mit dem sie normalen Schaden +2 verursachen.'),
  habitat_society = COALESCE(habitat_society, 'Minotauren leben in Gemeinschaften von bis zu acht Mitgliedern. Wenn die Gemeinschaft mehr als sechs Minotauren umfasst, wird einer ein älterer Minotaurus mit 18/50 Stärke und 8+4 Trefferwürfeln sein. Der Minotaurus-Älteste ist der Clanführer; er bleibt im Zentrum des Labyrinths und zieht junge Minotauren auf, während andere jagen. Er wird immer im Zentrum eines Labyrinths angetroffen.'),
  ecology         = COALESCE(ecology, 'Der Fluch, der Minotauren erschafft, ist unbekannt, aber Gelehrte vermuten, dass er "Verbrechen gegen die natürliche Ordnung" beinhaltet. Minotauren sind immer männlich. Es wird auch gesagt, dass der erste Minotaurus ursprünglich ein großer und jähzorniger menschlicher Kämpfer war; er wollte so stark wie ein Stier sein und sein Wunsch wurde auf die abscheulichste erdenkliche Weise erfüllt. Minotauren paaren sich mit menschlichen Weibchen, um Nachkommen zu zeugen, die männliche Minotauren sind. Minotauren haben eine Lebensspanne von 200 Jahren. Sie können jahrelang ohne Nahrung leben, sind aber immer hungrig, es sei denn, sie werden regelmäßig gefüttert. Sie sind Fleischfresser, aber ihr Fluch veranlasst sie, eine Diät aus Menschenfleisch zu bevorzugen. Diejenigen, die durch Flüche in Minotauren verwandelt wurden, können durch einen Wunsch in menschliche Gestalt zurückverwandelt werden, aber diejenigen, die als Minotauren geboren wurden, können nicht zu Menschen gemacht werden. Gnolle sind ihre natürlichen Feinde; sie töten sich gegenseitig auf den ersten Blick.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = '5f3bfd3b-12e5-4bc5-add0-56587f706d78' AND is_custom = FALSE;

-- Mist, Crimson Death (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der karmesinrote Tod ist eine bösartige, dampfförmige Kreatur, die sich von den Körperflüssigkeiten ihrer Opfer nährt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Das Monster greift nur an, um sich zu nähren oder sich zu verteidigen. Es umgibt sein Opfer mit dampfförmigen Tentakeln. Wann immer es trifft, entziehen die Tentakel Körperflüssigkeiten und verursachen 3W10 Schadenspunkte.'),
  habitat_society = COALESCE(habitat_society, 'Der karmesinrote Tod wohnt in den Sümpfen und Mooren, wo Kälte und Feuchtigkeit vorherrschen. Die Kreatur ist in ihrem natürlichen Lebensraum nahezu unsichtbar.'),
  ecology         = COALESCE(ecology, 'Der karmesinrote Tod ist ein gefährlicher Jäger, der die Sümpfe wie ein lebender Geist durchstreift. Ein karmesinroter Tod kann gesammelt und in einem luftdichten Behälter eingesperrt werden. Dies schadet ihm nicht. Ein karmesinroter Tod in einem solchen Behälter kann für einen eingesperrten Dschinn oder magischen Dampf gehalten oder falsch etikettiert werden. Wenn jemand den karmesinroten Tod freilässt, greift die hungernde Kreatur sofort ihren unwissenden Retter an.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'b0bae14d-a12f-46cd-af1b-a717aee34ffe' AND is_custom = FALSE;

-- Mist, Vampiric (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese gasförmigen Monster jagen alle lebenden Kreaturen, umhüllen sie mit ihren gasförmigen Ranken und entziehen ihnen dann das Blut als Nahrung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Vampirische Nebel spüren automatisch die Anwesenheit jeder warmblütigen Kreatur in 15,2 m Entfernung. Hungrige Nebel nehmen den kürzesten Weg zum Opfer, navigieren durch Berührung und fließen mühelos über Wasser oder durch schmale Risse. Ihr Pfad kann durch nicht-poröse Hindernisse blockiert werden, aber vampirische Nebel sind intelligent und falls ein vernünftiger Weg existiert, werden sie ihn finden.'),
  habitat_society = COALESCE(habitat_society, 'Diese schrecklichen Monster bewohnen sowohl Sümpfe, wo sie sich kriechend mit Morgen- und Nachtnebel vermischen, als auch unterirdische Höhlen, wo sie Beute in absoluter Dunkelheit jagen. Vampirische Nebel greifen nachts oder früh morgens an und fließen über den Boden auf der Suche nach warmblütigen Opfern. Sie bevorzugen einzelne Opfer, aber hungrige Nebel überfallen manchmal nachts Städte, töten Vieh und entziehen schlafenden Opfern Blut, bevor sie bei Tagesanbruch davonschlüpfen.'),
  ecology         = COALESCE(ecology, 'Zunächst für unreife Formen des Purpurnen Todes gehalten, ist nun bekannt, dass diese Scheusale absichtlich von einem mächtigen Vampir-Magier erschaffen wurden.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = 'cd27ae6d-223e-49b8-a044-5c4781994dcd' AND is_custom = FALSE;

-- Mold I (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schimmel sind eine Vielfalt sporenbildender Pilze, die in verrottendem Essen oder an warmen, feuchten Orten entstehen. Diese Pilze haben normalerweise eine wollige oder pelzige Textur. Während die meisten Schimmel harmlos sind, gibt es (mindestens) drei Arten von monströsen Schimmeln, die eine tödliche Bedrohung für Abenteurer darstellen: brauner, rostroter und gelber Schimmel.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1 patch')
WHERE id = '8720e5c9-dfce-4b3b-aecd-dc834ae1daba' AND is_custom = FALSE;

-- Moldman (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schimmelmänner, manchmal abwertend als Vegepygmäen oder sogar Schimmlinge bezeichnet, sind kleine, zweibeinige Pilzkreaturen. Sie haben scharfe, dornenartige Klauen, und blattartige Ranken bilden einen Saum an ihren Schultern, Bäuchen und Gliedmaßen. Ein Haarschopf aus diesen Ranken sitzt am höchsten Punkt des Kopfes eines Vegepygmäen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gruppen von Schimmelmännern jagen nahe ihrer Baue. In ihrem Heimatterritorium verschmelzen Schimmelmänner mit ihrer Umgebung, sodass Gegner einen Malus von -2 auf Überraschungswürfe erhalten.'),
  habitat_society = COALESCE(habitat_society, 'Schimmelmänner bilden primitive, sesshafte Stämme. Ihre Baue finden sich normalerweise in warmen unterirdischen Gebieten, obwohl manche Stämme Baue im Unterholz tiefer, dunkler Wälder und Dschungel haben. Stämme sind sehr territorial.'),
  ecology         = COALESCE(ecology, 'Schimmelmänner leben durch Aasfraß und Jagd. Sie fressen Fleisch in jedem Zustand, von frisch bis verwest. In Zeiten großer Not fressen sie bekanntermaßen andere Schimmelmänner oder sogar Myconiden, obwohl sie selten Mitglieder ihres eigenen oder eines verbündeten Stammes angreifen.'),
  no_appearing    = COALESCE(no_appearing, '6-24 or 30-300')
WHERE id = '8dd92dea-5bf3-4c57-99d0-171bcdde1949' AND is_custom = FALSE;

-- Mongrelman (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Mongrelmen sind eine Mischung aus dem Blut vieler Spezies: Menschen, Orks, Gnolls, Oger, Zwerge, Hobgoblins, Elfen, Bugbears, Bullywugs und viele andere. Ihr Aussehen variiert stark und kombiniert die schlechtesten Eigenschaften ihrer Elternstämme. Sie sind meist in schmutzige Lumpen gekleidet; sie schämen sich ihres Aussehens und versuchen ihre Körper zu verbergen, besonders unter Fremden. Sie haben keine eigene Sprache, sondern sprechen ein entartetes Gemeinsprech, vermischt mit Grunzen, Pfeifen, Knurren und Gesten. Ihre Namen ahmen oft Tiergeräusche nach.'),
  combat_tactics  = COALESCE(combat_tactics, 'Mongrelmen haben drei besondere Fähigkeiten, die ihnen beim Überleben helfen: Nachahmung, Taschendiebstahl und Tarnung.'),
  habitat_society = COALESCE(habitat_society, 'Für jeden 10 angetroffenen Mongrelmen gibt es mindestens einen mit 2 Trefferwürfeln; für jeden 30 gibt es einen mit 3 Trefferwürfeln; und für jeden 40 gibt es einen mit 4 Trefferwürfeln. In einer Gemeinschaft, wo sie nicht als Sklaven gehalten werden, gibt es normalerweise einen Anführer (RK 4, Bewegung 12, TW 5, Schaden 1W12, +1 Bonus auf Angriffswurf) und fünf Leibwächter (TW 4).'),
  ecology         = COALESCE(ecology, 'Mongrelmen sind Allesfresser, aber ihre Zähne sind am effizientesten beim Fleischverzehr. Die Lebensspanne eines freien Mongrelman liegt zwischen 25 und 35 Jahren; der durchschnittliche Sklave lebt nur 15 bis 20 Jahre. Ihre Säuglingssterblichkeitsrate ist sehr hoch. Ihre Hauptfeinde sind Stämme wandernder Humanoider, die sie zum Sport jagen.'),
  no_appearing    = COALESCE(no_appearing, '1-100')
WHERE id = '310a4ca0-de1b-44db-961c-bbdb5f678bf4' AND is_custom = FALSE;

-- Mummy (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Mumien sind Leichname, die in trockenen Wüstengebieten beheimatet sind, wo die Toten durch ein als Mumifizierung bekanntes Verfahren beigesetzt werden. Wenn ihre Gräber gestört werden, erwachen die Leichname zu einem seltsamen untoten Zustand, dessen unheiliger Hass auf das Leben sie dazu bringt, Lebewesen ohne Gnade anzugreifen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Mumien sind furchtbare Gegner. Ein einziger Schlag ihres Arms verursacht 1-12 Schadenspunkte, und schlimmer noch, ihre schorfige Berührung infiziert das Opfer mit einer fäulniserregenden Krankheit, die in 1-6 Monaten tödlich ist. Für jeden Monat, in dem die Fäulnis fortschreitet, verliert das Opfer dauerhaft 2 Punkte Charisma. Die Krankheit kann nur mit einem Krankheit heilen Zauber geheilt werden. Wunden heilen Zauber haben keine Wirkung auf eine von Mumienfäule befallene Person und ihre Wunden heilen mit 10% der normalen Geschwindigkeit. Ein Regeneration Zauber wird den Schaden wiederherstellen, beeinflusst aber den Verlauf der Krankheit nicht anderweitig.'),
  habitat_society = COALESCE(habitat_society, 'Mumien sind das Produkt eines Einbalsamierungsverfahrens, das bei reichen und wichtigen Persönlichkeiten angewandt wird. Die meisten Mumien sind Leichname ohne magische Eigenschaften. Gelegentlich, vielleicht aufgrund mächtiger böser Magie oder vielleicht weil das Individuum im Leben so gierig war, dass es sich weigert, seinen Schatz aufzugeben, stirbt der Geist der mumifizierten Person nicht, sondern zapft Energie aus der Positiven Materialebene an und wird in einen untoten Schrecken verwandelt. Die meisten Mumien bleiben ruhend, bis ihr Schatz genommen wird, aber dann werden sie erregt und töten ohne Gnade.'),
  ecology         = COALESCE(ecology, 'Um eine Mumie zu erschaffen, sollte ein Leichnam mehrere Wochen lang in einer konservierenden Lösung (typischerweise Natriumkarbonat) eingeweicht und mit Gewürzen und Harzen bedeckt werden. Körperorgane wie Herz, Gehirn und Leber werden typischerweise entfernt und in Krügen versiegelt. Manchmal werden Edelsteine in das Tuch eingewickelt (wenn die Schatzauflistung für die Mumie anzeigt, dass sie Edelsteine besitzt, können einige in die Umhüllungen gelegt werden). Mumien sind nicht Teil des natürlichen Ökosystems und haben keine natürlichen Feinde.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (2d4)')
WHERE id = 'ec9c9ae1-74f8-45a6-a12b-1958059dabe0' AND is_custom = FALSE;

-- Naga, Dark (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Dunkle Naga sind Feenwesen mit menschenähnlichen Gesichtern (mit Reißzähnen) auf lederartigen, schlangenähnlichen Körpern. Sie arbeiten gewöhnlich mit anderen bösen Wesen zum gegenseitigen Vorteil oder Überleben zusammen. Dunkle Naga sind meist schwarz, violett-schwarz oder sehr dunkelblau gefärbt, und ihre gehäubten Köpfe und glatten, nahezu unsichtbaren Schuppen lassen sie eher wie riesige Aale als wie Schlangen aussehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Dunkle Naga besitzen natürliche Gedankenlese-Kräfte (24 m Reichweite) und setzen diese Fähigkeit ständig ein.'),
  habitat_society = COALESCE(habitat_society, 'Dunkle Naga nisten in felsigen Orten wie Höhlen oder Ruinen; sie mögen ein Zuhause, wo sie Dinge verstecken können (wie Schätze und Zauberbücher), das mehr als einen Ein- oder Ausgang hat und mindestens einen Ort, der schmal genug ist, dass sie ihn mit ihrem Körper blockieren und im Alleingang Eindringlinge abwehren können. Dunkle Naga lieben Fallen und werden diese entwickeln (oder andere Kreaturen damit beauftragen, sie zu installieren), wann immer möglich.'),
  ecology         = COALESCE(ecology, 'Dunkle Naga fressen nicht freiwillig andere dunkle Naga, aber sie fressen fast alles andere, sowohl lebend als auch tot. Sie fressen einige Flechten und gelegentlich grüne Pflanzen, aber ihre Hauptnahrung ist Fleisch. Sie schätzen besonders heißes, noch frisches Blut.'),
  no_appearing    = COALESCE(no_appearing, '1-3 (usually 1)')
WHERE id = '79c3e85b-c6f7-434a-a0f0-a138ff2263ea' AND is_custom = FALSE;

-- Neogi (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Neogi erscheinen als Kreuzung zwischen einer Wolfspinne und einer Muräne. Der kurze, pelzige, achtgliedrige Körper wird von einem geschmeidigen, nackten, fleischigen Hals mit einem schlangenartigen Kopf gekrönt, dessen Maul voller nadelspitzer Zähne ist. Die Enden ihrer Gliedmaßen sind mit kleinen Klauen bewehrt. Das Fell der Neogi ist hellbraun, wird aber in verschiedenen Farben gefärbt, um Macht, Rang, Errungenschaften und Warnungen an andere Neogi zu kennzeichnen. Je älter ein Neogi wird, desto farbenprächtiger wird sein Fell.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Neogi verfügen über mehrere Verteidigungsmittel. Das erste und offensichtlichste ist die Versklavung von Umber Hulks. Jeder Neogi hat einen persönlichen Umber Hulk-Sklaven, der gleichzeitig Leibwächter, Diener und nützliche Hilfskraft ist. Zweitens ist der Biss des Neogi giftig. Wer gebissen wird und einen Rettungswurf gegen Gift nicht schafft, ist für 1W8 Runden wie von einem Langsam-Zauber betroffen. Mehrfache Bisse verlängern diese Zeit um zusätzliche 1W8 Runden pro Biss. Schließlich hat 1 von 10 Neogi magische Fähigkeiten, die menschlichem Zauberwirken der Stufen 1-8 entsprechen.'),
  habitat_society = COALESCE(habitat_society, 'Die verhassten Neogi sind nur an sehr abgelegenen Orten zu finden, tief unter der Erde oder unter den entferntesten Sternen. Ihr Leben dreht sich um ihre Gemeinschaften und ihre Sklaven. Neogi sind eine versklavende Rasse mit einem angeborenen Besitzgefühl: alles ist entweder Besitz oder Besitzer, Sklave oder Neogi. Sogar Neogi sind Sklaven anderer Neogi, aber Sklaven-Neogi können ihre eigenen Sklaven haben. Die Neogi tätowieren ihre Nicht-Neogi-Sklaven mit Besitzsymbolen, üblicherweise auf der linken Schulter vorne und hinten.'),
  ecology         = COALESCE(ecology, 'Wenn ein Neogi älter wird und sein Verstand nachlässt, werden seine Befehle verworren und seine Sklaven ungehorsam. Seine Neogi-Artgenossen können sich dazu entscheiden, den älteren sofort zu vergiften. Die verschiedenen Gifte, die durch seinen Körper fließen, überlasten das System des alten Neogi, und er beginnt seine Verwandlung in einen Großen Alten Meister.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = '1b0e4129-c7db-4ed0-96c6-5b7ad4bf2120' AND is_custom = FALSE;

-- Nightmare (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Alpträume, die bösen Streitrosse der Unteren Ebenen, dienen als Reittiere für Baatezu, Tanar''ri, Nachthexen und mächtige Untotenfürsten. Sie sehen aus wie große, kräftige Pferde mit pechschwarzem Fell. Alpträume haben glühend rote Augen, flammend orangefarbene Nüstern und Hufe, die wie Glut brennen. Ihre langen Mähnen und Schweife sind zerzaust und wild. Sie verstehen Befehle böser Reiter und verständigen sich untereinander durch Empathie.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alpträume hassen alles Leben. Sie greifen oft jede Kreatur an, die nicht von den Unteren Ebenen stammt (und manchmal auch Wesen der Unteren Ebenen). Ihre Reißzähne verursachen 2W4 Schadenspunkte, ihre beiden brennenden Vorderhufe verursachen je 1W6+4 Schadenspunkte und entzünden brennbare Materialien.'),
  habitat_society = COALESCE(habitat_society, 'Alpträume dienen vielen Kreaturen der Unteren Ebenen. Sie sind intelligent und können nicht so beiläufig behandelt werden wie ein Pferd. Sie dienen bereitwillig als Reittier für jede Mission, die Böses beinhaltet. Jedoch können sich für den unvorsichtigen Reiter die eigenen Ambitionen eines Alptraums als unüberwindlich erweisen. Diese hasserfüllten Streitrosse tun oft, was sie wollen, anstatt den Wünschen ihres "Meisters" zu folgen. Ein Alptraum bereitet dieselben Probleme wie magische Waffen mit großem Ego.'),
  ecology         = COALESCE(ecology, 'Alpträume haben keine biologische Verbindung zu echten Pferden. Ein Alptraum ist ein Diener des Bösen, ohne Bedürfnis nach Nahrung oder Luft. Alpträume werden als Fleischfresser aufgeführt, weil sie gefallene Feinde fressen. Jedoch deutet nichts darauf hin, dass die Alpträume daraus Nahrung ziehen; wahrscheinlicher ist, dass sie ihre Kraft durch den Dienst am Bösen gewinnen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'c3153758-ed0c-40c6-b8ce-9be7d6f0a6a4' AND is_custom = FALSE;

-- Nixie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Nixen sind Wasserfeen, die in Süßwasserseen leben, und obwohl sie keinen Groll gegen die Menschheit hegen, erfreuen sie sich daran, Männer als ihre Lasttiere zu versklaven.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn sich ein oder mehrere Männer bis auf 9 m einer Gruppe von Nixen nähern, bündeln die Kreaturen ihre Magie, um einen mächtigen Bezauberungszauber zu erschaffen - einen solchen Zauber für je 10 Nixen -, der vom Opfer einen Rettungswurf gegen Zauber mit -2 auf den Würfelwurf verlangt. Sobald eine Person bezaubert ist, aber bevor sie ins Wasser geht, besteht eine 75%ige Chance, dass ein Magie bannen-Zauber die Bezauberung bricht. Sobald sie im Wasser ist, sinkt die Chance, die Magie zu bannen, auf 10%. Nixen behalten ihre bezauberten Sklaven ein ganzes Jahr lang, zwingen sie, all ihre schwere Arbeit zu verrichten, aber danach lässt die Bezauberung nach und das Opfer wird freigelassen. Während dieser Versklavung halten die Nixen einen Wasseratmung-Zauber auf dem menschlichen Gefangenen aufrecht, denn Nixen können diesen Zauber einmal täglich auf jede Kreatur wirken oder bannen (Dauer ist ein Tag).'),
  habitat_society = COALESCE(habitat_society, 'Nixenbauten sind aus lebenden Seetangen gewoben und es ist nur zu 5% wahrscheinlich, dass ihr Bau in einer Entfernung unter 6 m bemerkt wird (aus mehr als 6 m Entfernung ist er unmöglich zu entdecken). Nixen halten Riesenfische als Wächter, entweder 1-2 Knochenhechte (20%) oder 2-5 Hechte (80%), und diese werden gelehrt, einfachen Befehlen zu gehorchen. Kleine Zierfische oder regenbogenfarbene Fische werden als Haustiere gehalten und darauf trainiert, kunstvolle Tricks auszuführen. Forellen, Barsche und Welse werden als Nahrung gehütet. Nixen können auch 10-100 kleine Fische herbeirufen (dies dauert 1-3 Runden).'),
  ecology         = COALESCE(ecology, 'Seen mit Nixenstämmen werden sauber und gut bestückt gehalten, und oft werden die menschlichen Sklaven dazu eingesetzt, die Umwelt durch das Entfernen von Müll und Hindernissen zu verbessern. Nixenkunstgegenstände umfassen Schmuck aus Muscheln, Perlen und Opalen, Seide von Wasserspinnen und Tränke der Wasseratmung.'),
  no_appearing    = COALESCE(no_appearing, '20-80 (2d4×10)')
WHERE id = '61bdf113-1e71-4ac6-99a1-1a637746fb23' AND is_custom = FALSE;

-- Obliviax (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Obliviax ist ein schwarzes Moos mit bösartiger Natur und der magischen Fähigkeit, Erinnerungen von intelligenten Kreaturen zu stehlen. Es wird "Erinnerungsmoos" genannt und ist der Fluch aller Magier.'),
  combat_tactics  = COALESCE(combat_tactics, 'Erinnerungsmoos kann die Annäherung fühlender Wesen spüren; sobald sie sich innerhalb von 18,3 m befinden, kann das Moos versuchen, ihre Erinnerungen zu stehlen. Es ist wählerisch und versucht zuerst, die Erinnerungen von Magiern zu stehlen, dann die von Priestern, dann die anderer Zauberwirker, dann die aller anderen Charaktere. Wenn eine intelligente Kreatur in den Einflussbereich des Obliviax eintritt und angegriffen wird, muss sie einen erfolgreichen Rettungswurf gegen Zauber würfeln oder alle Erinnerungen der letzten 24 Stunden verlieren, einschließlich aller eingeprägten Zauber. Das Moos versucht jede Runde von einer Kreatur zu stehlen, bis es erfolgreich ist, dann greift es 24 Stunden lang nicht wieder an. Diese gestohlenen Erinnerungen verleihen der Pflanze Vitalität und Nahrung. Jede Kreatur, die Erinnerungen verloren hat, wirkt verwirrt und desorientiert, vergisst oft wichtige Ereignisse und Wissen und hat nichts als eine Lücke in ihren Erinnerungen seit dem Vortag.'),
  habitat_society = COALESCE(habitat_society, 'Obliviax wächst in tropischen bis gemäßigten Klimazonen, kann aber nicht zu viel Wasser oder Kälte ertragen. Es wächst nicht in Wüstenterrain. Es ist nicht ungewöhnlich, Flecken auf Baumstämmen, umgefallenen Stämmen oder sprießend auf verrottenden Blättern zu finden. Obwohl es Intelligenz besitzt und sich anderer Moose in der Nähe bewusst ist, handelt es nicht gemeinsam mit seinen Artgenossen, sondern zieht es vor, nach den bestmöglichen Erinnerungen zu greifen. Kleine Kolonien dieses Mooses findet man manchmal in Tunneln oder Höhlen, entweder gewachsen aus Mooszweigen, die von einer unwissenden Kreatur hineingetragen wurden, oder gekeimt aus Sporen, die vom Wind hineingeweht wurden.'),
  ecology         = COALESCE(ecology, 'Es ist möglich, die Erinnerungen anderer zu erlangen, indem man das Moos isst. Jeder, der Zauber durch das Essen des Obliviax erhält, kann sie wirken, aber die Erinnerungen verblassen nach 24 Stunden. Böse Kreaturen verpflanzen manchmal Obliviax in die Nähe ihrer Baue, damit es als Wächter fungiert.'),
  no_appearing    = COALESCE(no_appearing, '2-12')
WHERE id = '36adf1b8-8897-410c-9237-6a6678f6b4ce' AND is_custom = FALSE;

-- Ogre (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Oger sind große, hässliche, gierige Humanoide, die von Hinterhalten, Raubzügen und Diebstahl leben. Schlecht gelaunt und bösartig werden diese Monster oft als Söldner in den Reihen von Orkstämmen, bösen Priestern oder Gnolls angetroffen. Sie verkehren frei mit Riesen und Trollen.'),
  combat_tactics  = COALESCE(combat_tactics, 'In kleinen Gruppen kämpfen Oger als unorganisierte Einzelwesen, aber Gruppen von 11 oder mehr haben einen Anführer, und Gruppen von 16 oder mehr schließen üblicherweise zwei Anführer und einen Häuptling ein. Oger mit Waffen erhalten einen Stärkebonus von +2 auf ihre Angriffe; Anführer haben +3, Häuptlinge haben +4. Weibchen kämpfen wie Männchen, verursachen aber nur 2-8 Schadenspunkte und haben maximal nur 6 Trefferpunkte pro Würfel. Junge Oger kämpfen wie Goblins.'),
  habitat_society = COALESCE(habitat_society, 'Ogerstämme sind überall zu finden, von tiefen Höhlen bis zu Berggipfeln. Stämme haben 16-20 Männchen, 2-12 Weibchen und 2-8 Junge. Schamanen, falls vorhanden, sind 3. Stufe und haben Zugang zu den Sphären Kampf, Wahrsagerei, Heilung, Schutz und Sonne (nur Dunkelheit). Oger leben von Raubzügen und Plünderung und fressen alles. Ihre Vorliebe für Elfen-, Zwergen- und Halblingsfleisch bedeutet, dass nur eine 10%ige Chance besteht, diese als Sklaven oder Gefangene anzutreffen. Es besteht eine 30%ige Chance, dass ein Ogerbau 2-8 Sklaven einschließt. Gefangene Gefangene werden immer als Sklaven (25%) oder Nahrung (75%) gehalten. Extrem habgierig streiten sich Oger um Schätze und können nicht vertraut werden, nicht einmal von ihresgleichen.'),
  ecology         = COALESCE(ecology, 'Oger plagen die Menschheit beständig, gieren nach Gold, Edelsteinen und Schmuck sowie nach Menschenfleisch. Sie sind bösartige Kreaturen, die sich mit anderen Monstern zusammenschließen, um die Schwachen zu jagen, und bevorzugen überwältigende Chancen vor einem fairen Kampf. Oger fertigen keine Handwerkserzeugnisse und verrichten keine Arbeit.'),
  no_appearing    = COALESCE(no_appearing, '2-20 (2d10)')
WHERE id = '0182e5f5-2ac2-4e76-af23-3ce23ecb7167' AND is_custom = FALSE;

-- Ogre, Half- (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wenn Abenteuergruppen in die Wildnis ziehen, begegnen sie oft Ogern; große, hässliche Humanoide. Gelegentlich enthält eine Ogergruppe ein oder zwei Individuen, die etwas kleiner, aber deutlich intelligenter sind und eine Waffe mit mehr Geschick führen, als man erwartet hätte. Sie verstehen ihre Gegner besser und grunzen Befehle, die den Zügen der Abenteurer zuvorkommen. Auf diese Weise erwerben sich Mischlinge, die Nachkommen von Ogern und Menschen, den Respekt ihrer Art.'),
  combat_tactics  = COALESCE(combat_tactics, 'Halbogre jeder Art erleiden Abzüge von -2 auf ihre Angriffswürfe gegen Zwerge und -4 gegen Gnome, da diese kleineren Völker so geschickt im Kampf gegen größere Gegner sind.'),
  habitat_society = COALESCE(habitat_society, 'Halbogre haben keine eigene Gesellschaft. Leben sie mit Ogern, sind sie die schnell denkenden Mitglieder des Stammes, stets auf den Zehen, um sich als würdig zu erweisen. Wird ein Halbogre in einer menschlichen Gemeinschaft aufgezogen, lernt er, mit Misstrauen und Furcht zu leben, und wendet sich oft einem militärischen oder einsamen Beruf zu.'),
  ecology         = COALESCE(ecology, 'Weise haben über die Jahre viel Sorge geäußert und sich gefragt, warum Oger sich mit Menschen, aber nicht mit Elfen oder Halblingen paaren können. Als die tatsächliche Antwort entdeckt wurde, erwiesen sich die Sorgen der Weisen als unbegründet. Die Erklärung hatte nichts mit einem angenommenen gemeinsamen Ursprung von Menschen und Ogern zu tun, sondern vielmehr mit einer ungewöhnlichen Eigenschaft, die Oger mit Orcs teilen: rasch anpassungsfähige Biologie. So wie sich Orcs und Oger schnell an jedes Gelände anpassen können, von Wäldern bis zu den höchsten Bergen, erlaubt ihnen ihre genetische Struktur, sich mit jeder humanoiden Rasse zu paaren.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '3446c322-236f-4b43-bc0e-36bd8cc92072' AND is_custom = FALSE;

-- Ooze/Slime/Jelly I (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Es gibt viele verschiedene Arten von Schleim, Glibber und Gallert. Ständig werden neue entdeckt, da pervertierte Magier versuchen, Leben zu erschaffen oder effiziente Kerkeraasfresser zu gestalten. Das vereinende Merkmal dieser Kreaturen ist eine auflösende Berührung, die Fleisch ebenso wie Waffen und Rüstungen zerfrißt.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'c60f9fb8-7e16-4420-9e79-daeab2297f22' AND is_custom = FALSE;

-- Ooze/Slime/Jelly, Slithering Tracker (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gleitende Verfolger sind transparente, Plasma entziehende Gallertmassen, die in vielen Verliesen und anderen dunklen Orten zu finden sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die einzigartige Natur der gleitenden Verfolger verleiht ihnen den deutlichen Vorteil, durch Risse und Löcher schlüpfen zu können, die so klein wie ein Rattenloch sind. Sie bewegen sich völlig lautlos über alle Oberflächen und sickern einfach langsam über alle Unebenheiten und Windungen. Sie greifen bevorzugt schlafende, einsame oder bewusstlose Kreaturen an, da ihre Hauptschwäche in der langen Dauer ihrer Angriffsform liegt. Sie sondern eine lähmende Substanz ab, die das Opfer bei Kontakt für 12 Stunden bewegungsunfähig macht, falls ein Rettungswurf gegen Lähmung misslingt. Der gleitende Verfolger bedeckt dann den gesamten Körper seines Opfers und entzieht der Kreatur langsam das gesamte Plasma (wodurch das Opfer natürlich getötet wird). Er kann eine menschengroße Kreatur in einer Stunde aussaugen.'),
  habitat_society = COALESCE(habitat_society, 'Gleitende Verfolger sind Einzelgänger. Da sie über keine Angriffsform verfügen, die anderen Verfolgern schaden könnte, ist die Territorialität eine Frage des Erstgekommenen. Als intelligenteste aller Schleime und Gallertmassen wäre es natürlich, dass sich gleitende Verfolger als Anführer der anderen etablierten. Aber Gallertmassen und Schleimen fehlen sowohl die Kommunikationsmittel als auch die Intelligenz, sich zusammenzuschließen. Sie bleiben am unteren Ende der Nahrungskette der Monster und dienen als Aasfresser, die die Schwachen und Dummen töten und die größeren Kreaturen den Hauptraubtieren in den Verliesen überlassen, die sie bewohnen.'),
  ecology         = COALESCE(ecology, 'Es gibt zwei Theorien über den Ursprung der gleitenden Verfolger. Die erste und wahrscheinlichste ist, dass gleitende Verfolger nur fortgeschrittene Formen der anderen Gallertmassen sind, die das Glück hatten, einen transparenten Plasmakörper und ein wenig Intelligenz zu entwickeln. Wie die meisten Gallertmassen vermehren sie sich geschlechtslos, wenn Zeit und Nahrungsmengen es erlauben.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '222207ee-419f-4fd7-b20a-c91e0af24cb6' AND is_custom = FALSE;

-- Orc (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Orks sind eine Art aggressiver fleischfressender Säugetiere, die sich in Stämmen zusammenschließen und durch Jagd und Raubzüge überleben. Orks glauben, dass sie ihr Territorium erweitern müssen, um zu überleben, und so sind sie ständig in Kriege gegen viele Feinde verwickelt: Menschen, Elfen, Zwerge, Goblins und andere Orkstämme.'),
  combat_tactics  = COALESCE(combat_tactics, 'Orks befinden sich ständig im Kampf. Sie verwenden die folgenden Waffen.'),
  habitat_society = COALESCE(habitat_society, 'Für jeden drei angetroffenen Orks wird es einen Anführer und drei Assistenten geben. Diese Orks haben jeweils 8 Trefferpunkte, da sie die gemeinsten und stärksten der Gruppe sind. Werden 150 oder mehr Orks angetroffen, werden folgende zusätzliche Gestalten bei der Gruppe sein: ein Unteranführer und 3-18 Wachen, jede mit Rüstungsklasse 4, 11 Trefferpunkten und +1 Schaden aufgrund von Stärke bei allen Angriffen. Sie kämpfen als Monster mit 2 Trefferwürfeln (ETW0 19). Für jeden 100 angetroffenen Orks wird es entweder einen Schamanen (maximal 5. Stufe Priester) oder einen Hexendoktor (maximal 4. Stufe Magier) geben. Schamanen und Hexendoktoren erhalten zusätzliche 1W4 Trefferpunkte für jede Stufe über der 1. und kämpfen als Monster mit 1 Trefferwürfel für jeweils zwei Stufen (Bruchteile aufrunden) ihrer Zauberfähigkeit (z.B. hat ein 5. Stufe Schamane W8+4W4 Trefferpunkte und kämpft als Monster mit 3 Trefferwürfeln).'),
  ecology         = COALESCE(ecology, 'Orks haben eine durchschnittliche Lebenserwartung von 40 Jahren. Sie haben eine Tragzeit von 10 Monaten und bringen zwei bis drei Nachkommen pro Geburt zur Welt. Die Säuglingssterblichkeit ist hoch. Orks sind Fleischfresser, bevorzugen aber Wildfleisch oder Vieh gegenüber Halbmenschen und Humanoiden.'),
  no_appearing    = COALESCE(no_appearing, '30-300 (3d10×10)')
WHERE id = '20e1e3a2-52c3-4815-bbf3-131513a1e063' AND is_custom = FALSE;

-- Otyugh (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Otyughs (Aw-tee-ug), auch bekannt als Gulguthra, sind furchterregende Kreaturen, die in Haufen aus Dung und Verwesung lauern und darauf warten, dass etwas sie stört. Es gibt zwei Arten: den gewöhnlichen Otyugh und seinen größeren, intelligenteren Ableger, den Neo-Otyugh. Sie ernähren sich von Dung und Abfällen anderer Kerkerkreaturen (Gulguthra bedeutet "Dungfresser"), genießen aber auch gelegentlich einen Snack aus frischem Fleisch.'),
  combat_tactics  = COALESCE(combat_tactics, 'Otyughs lauern unter Haufen von Abfall mit nur ihren Augen sichtbar. Sie greifen normalerweise an, wenn sie sich bedroht fühlen oder wenn sie hungrig sind und frisches Fleisch in der Nähe ist. Sie greifen mit ihren zwei gerippten Tentakeln an, die einen Gegner entweder zermalmen oder packen. Gepackte Gegner erleiden 2-4 Schadenspunkte pro Runde. Otyughs'' Bissangriffe erhalten einen +2 Bonus auf den Angriffswurf, wenn sie gepackte Gegner beißen. Otyughs werfen gepackte Gegner zu Boden, während die intelligenteren Neo-Otyughs ihre Opfer als Schilde verwenden und ihre Rüstungsklasse um 1 verbessern. Neo-Otyughs können auch Angreifer zwingen, den gepackten Charakter mit einem erfolgreichen eigenen Angriffswurf zu treffen (gegen die RK des gepackten Charakters); um dies zu tun, verzichtet der Neo-Otyugh auf seinen Quetschungsangriff. Charaktere mit einer Stärke von mindestens 18 können eine Runde lang kämpfen und sich automatisch befreien; andere müssen einen erfolgreichen Türen-öffnen-Wurf schaffen, um zu entkommen.'),
  habitat_society = COALESCE(habitat_society, 'Alle Gulguthra haben begrenzte telepathische Fähigkeiten. Ein Otyugh kann mit Kreaturen bis zu 12,2 m Entfernung kommunizieren, während ein Neo-Otyugh mit Kreaturen bis zu 18,3 m Entfernung kommunizieren kann. Die Kommunikation ist normalerweise auf einfache Gefühle und Emotionen beschränkt wie Hunger, Temperaturbedingungen und damit verbundene Beschwerden, seine Abneigung gegen helle Lichter und den bevorstehenden Tod für seine Beute. Gulguthra haben auch Infrasicht mit einer Reichweite von 27,4 m.'),
  ecology         = COALESCE(ecology, 'Otyughs und Neo-Otyughs leben unterirdisch in Haufen aus Abfall und Müll. Sie hassen helles Sonnenlicht und bevorzugen die behagliche Dunkelheit von Kerkern. Sie paaren sich jedes Jahr für einen Monat, wobei ein Nachkomme hervorgebracht wird. Es dauert vier Monate, bis das Neugeborene heranreift (unreife Gulguthra haben 3-5 TW, Schaden 1-6/1-6/1-2, und eine Stärke von 16 ist erforderlich, um sich aus ihrem Griff zu befreien). Otyughs sind so widerlich, dass kein Alchimist oder Magier ihre Bestandteile anfassen möchte, daher haben die Leichen der Gulguthra keinen bekannten Nutzen oder Wert.'),
  no_appearing    = COALESCE(no_appearing, '1 (2)')
WHERE id = '50c08313-c43f-4768-b787-9a6c4ffc7c57' AND is_custom = FALSE;

-- Owl (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Eulen sind eine Familie nachtaktiver Greifvögel. Es gibt viele verschiedene Arten und Varietäten sind in jedem Klima zu finden, aber Eulen sind am häufigsten in gemäßigten und subarktischen Klimazonen. Eulen sind Raubtiere, die Nagetiere, kleine Echsen und Insekten jagen und Menschen nur angreifen, wenn sie erschreckt werden (oder magisch dazu befohlen). Einige Kulturen sehen Eulen als Symbole der Weisheit; andere als Symbole bevorstehenden Todes.'),
  combat_tactics  = COALESCE(combat_tactics, 'Eulen haben doppelte normale Ultrasicht, vierfaches normales Gehör und fliegen in völliger Stille, so dass sie ihre Beute häufiger überraschen werden; andere haben -6 auf ihren Überraschungswurf. Eulen können während der Stunden der Dämmerung und Dunkelheit (Sonnenuntergang bis Sonnenaufgang) nicht überrascht werden. Während der Tagesstunden ist ihr Sehvermögen schlechter als das eines Menschen, so dass Eulen leichter überrascht werden können; sie haben -3 auf ihren Überraschungswurf, wenn sie an ihrem Tagesruheplatz entdeckt werden. Eulen greifen mit ihren scharfen Krallen und ihrem gebogenen Schnabel an. Wenn sie aus einer Höhe von 15,2 m oder höher herabstoßen, hat jeder Angriff +2 und verursacht doppelten Schaden, aber kein Schnabelangriff ist möglich.'),
  habitat_society = COALESCE(habitat_society, 'Eulen leben in praktisch jedem Teil der Welt. Die meisten Eulen leben in Baumhöhlen, aber die Kaninchenule lebt in Löchern, die von Präriehunden gemacht wurden. Eulen versuchen die Baue anderer Vögel zu finden und sie zu vertreiben. Einige Tagvögel (Krähen, Raben), die von Eulen gejagt werden, scharen sich zusammen, um sie während des Tages anzugreifen; deswegen verwenden Jäger manchmal Eulen als Lockvögel. Eulen leben entweder in Einsamkeit oder in Paaren. Sie können einigermaßen domestiziert werden, wenn sie jung genommen werden, aber können nicht zur Jagd abgerichtet werden.'),
  ecology         = COALESCE(ecology, 'Eulen jagen Nagetiere, Kröten, Frösche, Insekten und Tagvögel. Keine Kreaturen sind dafür bekannt, Eulen zu jagen, außer Monstern wie Wyvern, die die meisten fliegenden Kreaturen angreifen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2)')
WHERE id = 'e4d42824-ea4c-486c-a641-06a10370167d' AND is_custom = FALSE;

-- Owlbear I (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Eulenbären sind wahrscheinlich die gekreuzte Schöpfung eines wahnsinnigen Magiers; angesichts der Tödlichkeit dieser Kreatur ist es sehr wahrscheinlich, dass der Magier, der sie erschuf, nicht mehr am Leben ist. Eulenbären sind bösartig, gefräßig, aggressiv und zu jeder Zeit schlecht gelaunt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Eulenbär greift Beute beim ersten Anblick an und kämpft immer bis zum Tod (ignoriere die Moralwertung bei der Bestimmung eines Rückzugs). Er greift mit seinen Klauen und seinem schnappenden Schnabel an. Wenn ein Eulenbär einen Klauenhieb mit einem Wurf von 18 oder höher erzielt, zerrt er sein Opfer in eine Umarmung und quetscht seinen Gegner anschließend für 2-16 Schadenspunkte pro Runde, bis entweder das Opfer oder der Eulenbär getötet wird. Der Eulenbär kann auch seinen Schnabelangriff gegen in seinem Griff gefangene Opfer einsetzen, kann aber seine Klauen nicht verwenden. Ein einzelner Versuch eines Stangen biegen/Tore heben-Wurfs kann unternommen werden, um sich aus dem Griff eines Eulenbären zu befreien. Beachte, dass wenn die Rüstungsklasse eines Opfers hoch genug ist, dass 18 nicht ausreicht um zu treffen, die Umarmung nicht wirksam ist und kein Schaden genommen wird.'),
  habitat_society = COALESCE(habitat_society, 'Eulenbären bewohnen die Tiefen verworrener Wälder in gemäßigten Klimazonen sowie unterirdische Labyrinthe und leben in Höhlen oder hohlen Baumstümpfen.'),
  ecology         = COALESCE(ecology, 'Eulenbären haben eine Lebensspanne von 20 Jahren. Sie sind warmblütige Säugetiere, legen aber Eier. Sie jagen alles, von Kaninchen über Bären bis zu Trollen, Schlangen und Reptilien. Eulenbären bevorzugen gemäßigte Klimazonen, aber einige gedeihen auch in subarktischen Umgebungen. Als Hybride zweier Tiere, eines tagaktiven und eines nachtaktiven, haben sie eine ungewöhnliche Aktivitätszeit: Sie erwachen mittags, jagen tagsüber aktive Tiere und jagen dann nachtaktive Kreaturen, bevor sie um Mitternacht schlafen gehen. Eulenbären sind in den Sommermonaten aktiv und halten während der kalten Jahreszeit Winterschlaf. Es gibt Gerüchte über weiße arktische Eulenbären, eine Kreuzung zwischen arktischen Eulen und Eisbären, aber es wurden niemals Exemplare gefangen.'),
  no_appearing    = COALESCE(no_appearing, '1 (2-8)')
WHERE id = 'd5362fc5-8ae7-4672-a570-35d59d1d49f5' AND is_custom = FALSE;

-- Pegasus (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Pegasi sind prachtvolle geflügelte Schlachtrösser, die oft der Sache des Guten dienen. Diese intelligenten Kreaturen sind sehr scheu und wild, nicht leicht zu zähmen. Sie dienen nur guten Charakteren, und wenn sie es tun, werden sie ihrem Herren mit absoluter Treue für den Rest seines Lebens dienen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Pegasus greift mit seinen Hufen und Zähnen an. Er kann einen Gegner, der hinter ihm steht, mit seinen Hinterhufen angreifen und dabei 2-12 Schadenspunkte verursachen, aber er kann in dieser Runde keine seiner anderen Attacken einsetzen. Ein Pegasus kann auch aus Höhen von 15,2 m oder höher auf einen Gegner herabstoßen und seine Hufangriffe verwenden; jeder Angriffswurf erhält +2 und verursacht doppelten Schaden.'),
  habitat_society = COALESCE(habitat_society, 'Pegasi sind eierlegende Säugetiere. Falls sie in ihrem Bau angetroffen werden, gibt es ein Nest für jedes Pegasus-Paar. Pro Nest besteht eine 20%ige Chance, dass 1-2 Eier (30% Chance) oder Junge (70%) mit 20-50% Reife vorhanden sind. Jedes Ei ist 3.000 Silberstücke wert, während die Jungen auf dem freien Markt 5.000 Silberstücke pro Kopf wert sind.'),
  ecology         = COALESCE(ecology, 'Pegasi ernähren sich von Gras, Früchten und anderen Pflanzen. Greifen und Hippogreifen sind die natürlichen Feinde eines Pegasus. Pegasi haben eine Lebensspanne von etwa 40 Jahren.'),
  no_appearing    = COALESCE(no_appearing, '1-10')
WHERE id = 'caf01f44-8452-45b0-9ec8-0a4e1f0ffc31' AND is_custom = FALSE;

-- Peryton (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Hoch über den Bergen und felsigen Hügeln der meisten Länder fliegt ein scharfäugiges Monster, das als Peryton bekannt ist. Intelligent, geduldig und böswillig beobachtet und wartet es auf Beute - um ihr das Herz herauszureißen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Peryton hat nur zweitrangiges Interesse an seiner Beute als Nahrung. Sein Hauptinteresse an Menschen und Humanoiden gilt dem Herzen seiner Beute. Er ist unnatürlich treffsicher im Kampf. Spieltechnisch erhält ein Peryton einen +2 Bonus auf seinen Angriffswurf.'),
  habitat_society = COALESCE(habitat_society, 'Perytons nisten in Höhlen hoch oben auf Klippen oder Berggipfeln. Sie siedeln sich in Nestern von 2W4 Kreaturen an, wobei jedes Nest unabhängig von anderen ist und sich keine zwei Nester innerhalb mehrerer Kilometer voneinander befinden, außer unter ungewöhnlichen Umständen - wie einer Zwergengemeinschaft in den Bergen, die ihnen reichlich Beute bietet.'),
  ecology         = COALESCE(ecology, 'Der Peryton ist ein Raubtier ohne natürliche Feinde (nur wenige könnten seine magisch resistente Haut durchdringen). Humanoide und besonders Menschen sind seine bevorzugte Beute. Ein weiblicher Peryton benötigt ein frisches, schlagendes Herz zur Fortpflanzung, und Menschenherzen sind die bevorzugte Sorte. Sobald ein Peryton ein Herz gefressen hat, verändert sich sein Schatten zu dem seiner normalen Gestalt und die Kreatur wird für 3W6 Stunden fruchtbar. Unausgebrütete Peryton-Eier können für 10W12 GM pro Stück verkauft werden.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '33b48c1d-3cb2-4fa1-a18b-9f87aed3c4a7' AND is_custom = FALSE;

-- Phantom (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Phantome sind Bilder, die von besonders starken Todestraumata zurückgelassen werden. Ein Phantom ist wie ein dreidimensionales Filmbild, das zum Zeitpunkt des Todes an dem Ort aufgenommen wurde, wo es starb.'),
  combat_tactics  = COALESCE(combat_tactics, 'Es ist schwierig, Phantome zu bekämpfen, da sie lediglich Bilder sind und keine Macht haben, direkten Schaden zu verursachen. Sie können selbst nicht verletzt werden. Das Schwingen von Waffen oder das Wirken von Zaubern in den Bereich des Bildes stört die Projektion nicht, und man kann nicht mit ihnen verhandeln. Ein Phantom ist nicht intelligent und existiert aus keinem wirklichen Grund; seinen Mörder aufzuspüren oder seine Mission zu vollenden wird ein Phantom nicht loswerden.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '97ca7303-1022-4666-8864-07761bf15c63' AND is_custom = FALSE;

-- Piercer (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Piercers ähneln Stalaktiten, die von Höhlendächern hängen. Sie sind tatsächlich eine Art Gastropoden, die ohne ihre Schalen Schnecken mit langen Schwänzen ähneln. Ein Piercer klettert an die Decke einer Höhle und wartet geduldig; wenn er Beute unter sich entdeckt, lässt er sich von der Decke fallen und durchbohrt das Opfer mit dem spitzen Ende seines Panzers.'),
  combat_tactics  = COALESCE(combat_tactics, 'Piercers haben nur eine Chance zu treffen; wenn ein Angriff keinen tödlichen Treffer erzielt, kann der Piercer nicht erneut angreifen, bis er langsam eine Wand erklettert, um seine Position wieder einzunehmen. Piercers können Geräusche hören und Wärmequellen in einem Radius von 110 m entdecken; diese Wärmequellen schließen Menschen ein. Wenn das Geräusch und Licht über viele Minuten hinweg stationär bleiben, bewegen sich Piercers langsam in Angriffsposition über die Quelle des Reizes. Piercers sind praktisch nicht von natürlichen Phänomenen zu unterscheiden. Eine Gruppe von Charakteren hat einen -7 Modifikator auf ihren Überraschungswurf gegen einen Piercer (dies garantiert, dass die Gruppe überrascht wird, es sei denn, sie hat positive Modifikatoren).'),
  habitat_society = COALESCE(habitat_society, 'Obwohl Piercers nicht intelligent sind, sind die Piercers in einer Kolonie sich ihrer gegenseitigen Anwesenheit bewusst. Sie fallen oft gleichzeitig, um sich von denen zu nähren, die von anderen Piercers getötet wurden (was das Gebiet plötzlich sehr gefährlich macht).'),
  ecology         = COALESCE(ecology, 'Der Piercer ist ein Weichtier, das aus einem hühnereigroßen Ei schlüpft, welches das Elterntier in Gelegen von sechs bis acht Eiern in abgelegenen Bereichen der Höhle legt. Wenn sie schlüpfen, erscheinen die Jungen als Schnecken, die sich von Pilzen ernähren. Nach mehreren Monaten klettern sie die Höhlenwände hoch, scheiden eine Chemikalie aus, die zu der vertrauten Stalaktitform aushärtet, und warten dann auf Beute.'),
  no_appearing    = COALESCE(no_appearing, '3-18 (3d6)')
WHERE id = '3d6cb45e-a471-4265-975d-ec5e7c3c0808' AND is_custom = FALSE;

-- Piranha (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Mit Ausnahme des Hais gibt es keinen gefürchteteren Fisch als den Piranha, den Schrecken tropischer Flüsse. In schieren Gefräßigkeit hat der Piranha keine Rivalen. Es gibt viele Geschichten von Rindern, die das Pech hatten, von Piranhas verseuchte Gewässer zu betreten und von diesen Kreaturen innerhalb weniger Minuten bis auf die Knochen abgenagt wurden. Piranhas greifen alles an, einschließlich Menschen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Piranhas greifen mit ihren scharfen Zähnen an. Ein einzelner Biss ist zwar schmerzhaft, aber normalerweise nicht tödlich. Piranhas reisen in Gruppen (Schwärme genannt) von 5-50 Tieren. Es besteht eine 75%ige Chance, dass mindestens einer von ihnen jede Kreatur angreift, die in der Nähe des Schwarms schwimmt oder watet. Wenn sie angreifen und einer von ihnen mit einem Treffer Blut zieht, gerät der gesamte Schwarm in Raserei und jeder Piranha greift zweimal pro Kampfrunde an (doppelt so oft wie normal). Bis zu 20 Piranhas können gleichzeitig ein menschengroßes Individuum angreifen.'),
  habitat_society = COALESCE(habitat_society, 'Piranhas leben in tropischen Umgebungen. Sie sind in großen Flusssystemen häufiger anzutreffen. Sie sind gnadenlose Raubtiere und aggressiv sogar außerhalb des Wassers (obwohl sie wie die meisten Fische innerhalb weniger Minuten ohne Wasser ersticken). Wie Haie werden Piranhas vom Geruch des Blutes angezogen, und Blut im Wasser versetzt sie schnell in einen Fressrausch.'),
  ecology         = COALESCE(ecology, 'Piranhas sind Fleischfresser; ihre übliche Nahrung besteht aus Fischen, aber sie fressen jedes Tier, das ihr Territorium betritt. Sie haben keine natürlichen Feinde. Ihre schneidenden Zähne reißen wie die von Haien das Fleisch von ihren Opfern, während sie angreifen. Sie sind nach nur wenigen Lebensmonaten fortpflanzungsfähig (was ganzjährig erfolgt), und ihre Lebensspanne beträgt etwa vier Jahre.'),
  no_appearing    = COALESCE(no_appearing, '5-50')
WHERE id = '20997bc2-6426-477c-b8bc-c823df0b2115' AND is_custom = FALSE;

-- Pixie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Von allen magischen Feenvölkern (Brownies, Sprites, Nixen, Kobolde und Pixies) sind Pixies vielleicht die intelligentesten und verschlagensten. Diese von Natur aus unsichtbaren Kreaturen leben in idyllischen Waldländern und haben besonderen Gefallen daran, Reisende mit ihren Streichen zu plagen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Pixies tragen winzige Schwerter und Bögen. Ihre Schwerter entsprechen Dolchen. Ihre Bögen haben die halbe Reichweite eines Kurzbogens. Sie verwenden drei Arten von Pfeilen, von denen jeder einen +4 Bonus auf den Angriffswurf hat (ETW0 16). Der erste Pfeil ist ihr Kriegspfeil, der 1W4 +1 Schadenspunkte verursacht. Die zweite Art verursacht Schlaf in einem komatösen Zustand für 1W6 Stunden bei jeder Kreatur, die ihren Rettungswurf gegen Zauber verfehlt, wenn sie getroffen wird. Der dritte Angriff schadet dem Ziel nicht körperlich, aber das Ziel muss einen Rettungswurf gegen Zauber würfeln. Ein Fehlschlag zeigt an, dass das Opfer einen vollständigen Gedächtnisverlust erlitten hat, der nur durch einen priesterlichen Heilzauber oder einen begrenzten Wunsch wiederhergestellt werden kann.'),
  habitat_society = COALESCE(habitat_society, 'Pixies leben in tiefen Waldhöhlen und tanzen in mondscheinbeschienenen Lichtungen zur Musik von Grillen und Fröschen. Sie ziehen es vor, fern von Menschen zu leben, aber nahe genug, um sie zu belästigen. Pixies sind Schelme, die es besonders lieben, Reisende in die Irre zu führen. Sie nutzen ihre Illusionskräfte, um dies zu bewerkstelligen, daher der Ausdruck „von Pixies geführt" für jemanden, der sich verirrt hat. Sie erschrecken gerne junge Mädchen, klopfen an Wände, blasen Kerzen aus und treiben ihr Spiel auf dem Wasser.'),
  ecology         = COALESCE(ecology, 'Pixies sind, wie alle Feenvölker, Kreaturen der Magie. Pixies essen Früchte und Nektar und halten Scheingelage und Feste ab, während sie feiern. Das berühmteste Nebenprodukt von Pixies ist Pixiestaub, auch bekannt als Staub des Verschwindens. Pixies haben eine natürliche Verschwinde-Fähigkeit, aber durch das Zermahlen von 50 Pixieflügeln zu einem feinen Pulver ist es größeren Kreaturen möglich, diese Fähigkeit nachzuahmen (solange der Staub anhält). Fünfzig Pixieflügel reichen für eine Dosis des Pulvers.'),
  no_appearing    = COALESCE(no_appearing, '5-20')
WHERE id = '10805627-1e77-4329-9eb7-18ace29f696c' AND is_custom = FALSE;

-- Poltergeist (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Poltergeister sind die Geister ruheloser Toter. Sie ähneln Gespenstern, sind aber bösartiger. Sie hassen lebende Wesen und quälen sie ständig, indem sie Möbel zerbrechen, schwere Gegenstände werfen und beunruhigende Geräusche machen. Oft, aber nicht immer, sind sie an einen bestimmten Ort gebunden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Poltergeist greift an, indem er einen schweren Gegenstand wirft - jeder nahe Gegenstand, den ein starker Mensch werfen kann, genügt. Er hat dieselbe Trefferchance wie ein Monster mit 5 TW (daher sein angepasster ETW0 in den oben angegebenen Werten). Wenn das Opfer getroffen wird, erleidet es keinen Schaden (behandle den Einsatz tödlicher Waffen wie Messer und Schwerter als furchterregende Beinahe-Treffer), aber es muss einen erfolgreichen Rettungswurf gegen Zauber würfeln oder 2W12 Runden lang vor Schreck in eine zufällige Richtung fliehen (wähle verfügbare Ausgänge weg vom Poltergeist und bestimme zufällig), bevor es sich erholt. Es besteht eine 50%ige Chance, dass das Opfer fallen lässt, was es gerade hält (es lässt es zu Beginn seiner Flucht fallen). Sobald eine Person einen erfolgreichen Rettungswurf würfelt, ist sie gegen weitere Furchtversuche des Poltergeists in diesem Gebiet immun.'),
  habitat_society = COALESCE(habitat_society, 'Manche sagen, dass Poltergeister die Geister jener sind, die abscheuliche Verbrechen begingen, die zu Lebzeiten unbestraft blieben. Was auch immer ihr Ursprung ist, Poltergeister sind bösartige Geister, deren Aktivitäten von lästig bis tödlich reichen können. Ihr Daseinszweck ist es, jene zu verfolgen und zu stören, die noch leben.'),
  ecology         = COALESCE(ecology, 'Diese Geister, die zugleich furchterregend und bemitleidenswert sind, verzehren keine Nahrung und sammeln keine Schätze. Poltergeister lösen sich auf, wenn sie getötet oder zur Ruhe gebracht werden.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = 'ddbd68cf-54e4-4da6-bf06-12c2d44a5d1f' AND is_custom = FALSE;

-- Porcupine (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Stachelschweine sind große Nagetiere, die in gemäßigten Waldgebieten beheimatet sind. Es gibt viele Stachelschweinarten, die sich nur in geringfügigen Details unterscheiden. Stachelschweine sind scheue, zu Panik neigende Kreaturen mit einem sehr unangenehmen Abwehrmechanismus - steife, scharfe Haare, die als Stacheln bekannt sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Entgegen manchen volkstümlichen Legenden wirft ein gewöhnliches (schwarzes oder braunes) Stachelschwein seine Stacheln nicht, aber es kann sie leicht ablösen, wenn sie einen Feind treffen. Diese Pflanzenfresser greifen nicht an, es sei denn, sie fühlen sich bedroht, und selbst dann nur, wenn sie nicht sicher davonlaufen können. Stachelschweine schlagen einen Angreifer mit ihren Schwänzen und lösen dabei Stacheln ab. Schwarze Stachelschweine fügen 1-3 Schadenspunkte mit ihren Widerhakenstacheln zu, während die längeren Stacheln der braunen Stachelschweine 1W4 Schadenspunkte verursachen. Kreaturen, die versuchen, ein Stachelschwein zu berühren, erleiden automatisch Schaden durch dessen Stacheln. Aufgrund ihrer überlappenden Widerhaken sind Stachelschweinstacheln extrem schwer zu entfernen und verursachen schmerzhafte Schwellungen.'),
  habitat_society = COALESCE(habitat_society, 'Stachelschweine leben in dicht bewaldeten Gebieten. Sie sind ausgezeichnete Baumkletterer. Sie sind nicht ungesellige Kreaturen, scheinen aber einen Partner und Junge als einzige Gesellschaft zu bevorzugen.'),
  ecology         = COALESCE(ecology, 'Stachelschweine ernähren sich von der Rinde und den Blättern der Bäume; ihr Appetit hat manchmal die Bäume getötet, von denen sie sich ernähren. Sie fressen auch Früchte und mögen besonders gern Salz. Wenige Kreaturen greifen das Stachelschwein an. Es sind keine Tränke oder Zauber bekannt, die Stachelschweinbestandteile verwenden.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '91aa50d8-e8eb-4c78-b515-73e85057afc1' AND is_custom = FALSE;

-- Quaggoth (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaft: Telekinese; Andachten: Flammen kontrollieren, molekulare Erregung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Quaggoth-Stämme beanspruchen ein bestimmtes Territorium für sich und patrouillieren es auf der Jagd nach Nahrung. Alle entdeckten Tiere oder Kreaturen (wie eine Abenteurergruppe) ziehen sicherlich einen Angriff nach sich.'),
  habitat_society = COALESCE(habitat_society, 'Quaggoths sind nomadische Jäger. Sie wechseln regelmäßig ihre Territorien. In jedem neuen Territorium beanspruchen sie eine zentrale Höhle als Bau und hinterlassen Schätze bei einigen wenigen Wachen. Der Rest des Stammes jagt und kehrt regelmäßig zurück, um zu rasten und die Wachen zu wechseln.'),
  ecology         = COALESCE(ecology, 'Quaggoths stellen einige wenige Artefakte her, meist grob geschnitzte Steingegenstände. Einige scheinen talentiert darin zu sein, Halsketten mit hölzernen, knöchernen oder steinernen Perlen zu fertigen.'),
  no_appearing    = COALESCE(no_appearing, '2-24')
WHERE id = 'd4855af1-2a9e-487a-b706-5d567d596b47' AND is_custom = FALSE;

-- Rakshasa (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rakshasas sind eine Rasse bösartiger Geister, die in Fleisch gehüllt sind und die Menschheit jagen und quälen. Niemand weiß, woher diese Kreaturen stammen; manche sagen, sie seien die Verkörperung von Alpträumen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Rakshasas genießen frisches Menschenfleisch und nutzen Illusionen, um es zu bekommen. Sie haben eine begrenzte Form von Gedankenlesen, die es ihnen erlaubt, sich als jemand zu tarnen, dem das Opfer vertraut; der Rakshasa nutzt diese Illusion als Köder und schlägt zu, wenn das Opfer am wenigsten vorbereitet ist. Der Rakshasa muss die Illusion fallen lassen, wenn er angreift. Normalerweise können Rakshasas magische Fähigkeiten haben, bis zu folgenden Grenzen: vier Magierkauber der 1. Stufe, drei Magierkauber der 2. Stufe, zwei Magierkauber der 3. Stufe und drei Priesterzauber der 1. Stufe. Diese werden mit der Fähigkeit der 7. Stufe gewirkt. Rakshasas sind immun gegen alle Zauber unter der 8. Stufe. Ein Angreifer benötigt mindestens eine +1 magische Waffe, um einen Rakshasa zu verletzen; jede Waffe unter +3 verursacht nur halben Schaden. Ein Treffer mit einem gesegneten Armbrustbolzen tötet einen Rakshasa jedoch sofort.'),
  habitat_society = COALESCE(habitat_society, 'Die Rakshasa-Gesellschaft ist durch starre Kasten gebunden. Jeder Rakshasa wird in eine bestimmte Rolle im Leben hineingeboren und kann nicht aufsteigen. Weibchen (bekannt als Rakshasi) sind dazu bestimmt, Gefährtinnen zu sein, nur durch ihre Treue und die Kampffähigkeit ihrer Kinder geehrt. Es gibt 1-3 Weibchen pro Männchen.'),
  ecology         = COALESCE(ecology, 'Als Geister sind Rakshasas praktisch unsterblich. Sie bringen jedes Jahrhundert eine neue Generation hervor, um die Rakshasas zu ersetzen, die in der Schlacht getötet wurden. Keine Kreaturen machen Jagd auf Rakshasas, außer denen, die ihre Opfer rächen würden. Rakshasa-Essenz kann eine Zutat in einem Trank der Täuschung sein.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '49f4f643-48da-4287-9b53-fe9d7e8d7a15' AND is_custom = FALSE;

-- Ray (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rochen, auch Seefledermäuse genannt, stammen aus warmen tropischen Flachwassern. Sie sind breite, flache Kreaturen mit Augen auf der oberen, dunkelfarbigen Oberfläche ihres Körpers und Maul und Kiemen auf der helleren Unterseite. Ihre Brustflossen sind riesig, was ihnen ein fledermausähnliches Aussehen verleiht, und sie nutzen ihren kurzen Schwanz als Ruder. Sie ernähren sich von Weichtieren und Krustentieren und greifen nur selten Menschen an, mit Ausnahme der bösartigen Ixitxachitl. Diese langen, flachen Kreaturen vergraben sich im Schlick und Sand des Meeresbodens, um ihre Beute zu überraschen.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = 'e6794ddb-bb26-40e4-ba55-eac0bfbd7011' AND is_custom = FALSE;

-- Revenant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Revenants sind rachsüchtige Geister, die aus dem Grab erstanden sind, um ihre Mörder zu vernichten. Der Revenant erscheint als gespenstische, verweste Version seines Aussehens zum Zeitpunkt seines Todes. Seine fahle Haut ist straff über die Knochen gespannt. Das Fleisch ist kalt und feucht. Die eingefallenen Augen sind stumpf und schwer umlidert, doch wenn der Revenant seinem beabsichtigten Opfer gegenübersteht, lodern die Augen mit unnatürlicher Intensität. Der Revenant trägt eine Aura der Trauer, des Zorns und der Entschlossenheit.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Revenant greift an, indem er seine klauenartigen Hände um die Kehle seines Opfers schlingt. Diese Strangulation verursacht 2W8 Schadenspunkte pro Runde. Er löst seinen Griff nicht, bis entweder der Revenant zerstört wird oder sein Opfer tot ist. Er verwendet niemals Waffen.'),
  habitat_society = COALESCE(habitat_society, 'Unter außergewöhnlichen Umständen kann ein Charakter, der eines gewaltsamen Todes gestorben ist, als Revenant aus dem Grab auferstehen, um Rache an seinem Mörder zu nehmen. Um diesen Übergang zu vollziehen, müssen zwei Voraussetzungen erfüllt sein. Die Konstitution des toten Charakters muss 18 betragen und entweder seine Weisheit oder Intelligenz muss größer als 16 sein. Außerdem muss die Summe seiner sechs Eigenschaftswerte 90 oder mehr betragen. Selbst wenn diese Bedingungen erfüllt sind, besteht nur eine 5%ige Chance, dass der tote Charakter zu einem Revenant wird. Wenn sowohl Intelligenz als auch Weisheit über 16 liegen, steigt die Chance auf 10%. Wenn Intelligenz, Weisheit und Konstitution alle 18 betragen, kann die Kreatur nach Belieben in jeden frisch getöteten Humanoiden wechseln, falls der Revenant einen erfolgreichen Rettungswurf gegen Tod würfelt.'),
  ecology         = COALESCE(ecology, 'Revenants geben Mordopfern eine Chance, ihre eigenen Morde zu rächen. Sie verfolgen ihre Ziele allein ohne Verlangen oder Bedürfnis nach Verbündeten. Jedoch, wenn der Revenant einem mächtigen Feind gegenübersteht, der imstande ist, die neue Form des Revenant zu zerstören, kann der Revenant entscheiden, Abenteurer als Schachfiguren in seinem Rachefeldzug zu benutzen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '013447d5-3ec4-4cb0-9b29-62831c6ed203' AND is_custom = FALSE;

-- Roc (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rochs sehen fast zu groß aus, um real zu sein. Es sind riesige Raubvögel, die in warmen Bergregionen leben und dafür bekannt sind, große Tiere (Rinder, Pferde, Elefanten) als Nahrung zu verschleppen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Roch stößt auf seine Beute herab, packt sie mit mächtigen Klauen und trägt sie in den Bau des Rochs, um sie in Ruhe zu verschlingen. Der daraus resultierende Schaden beträgt 3W6 pro Klaue. Meistens (95%) trägt ein Roch seine Beute nur weg, wenn beide Klauen treffen. Wenn die Beute nur von einer Klaue getroffen wurde, lässt der Roch normalerweise los, wendet sich um und versucht einen weiteren Griff. Sobald die Beute gesichert ist, fliegt der Roch zurück zu seinem Nest. Wenn sich die Kreatur wehrt, schlägt der Roch mit seinem Schnabel zu und verursacht 4W6 Schadenspunkte pro Treffer.'),
  habitat_society = COALESCE(habitat_society, 'Roch-Baue sind riesige Nester aus Bäumen, Ästen und ähnlichem. Sie bewohnen die höchsten Berge in warmen Regionen. Rochs neigen nicht dazu, nah beieinander zu nisten, wobei ein Nest selten innerhalb von 32,2 km eines anderen Nestes zu finden ist. Es besteht eine 15%ige Chance, 1W4+1 Eier in einem Roch-Nest zu finden. Diese Eier werden für 2W6×100 GM an Händler verkauft, die auf exotische Gegenstände spezialisiert sind. Wie zu erwarten ist, kämpfen Rochs bis zum Tod, um diese Nester und deren Inhalt zu schützen, und erhalten einen Bonus von +1 auf ihren Angriffswurf.'),
  ecology         = COALESCE(ecology, 'Rochs werden gelegentlich gezähmt und von Wolken- oder Sturmriesen verwendet. Gut gesinnte Riesen erlauben ihren Rochs nicht, zivilisierte Gebiete und die dort lebenden Tiere anzugreifen.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = 'bff35554-eb5b-4836-996b-e6c609f790fa' AND is_custom = FALSE;

-- Roper (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein Roper gleicht einem felsigen Vorsprung. Die Haut der Kreatur ist gelblichgrau und rau, und ihr Körper sehr formbar. Sie sind normalerweise säulenförmig gestaltet, 2,7 m groß, etwa 0,9 m im Durchmesser an der Basis und etwa 0,3 m im Durchmesser an der Spitze. Der Roper hat ein einzelnes gelbes Auge und einen von scharfen Zähnen umringten Schlund.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Roper kann aufrecht stehen, um einem Stalagmiten zu gleichen, am Boden liegen, um einen Felsbrocken zu imitieren, oder sich sogar abflachen, um wie ein Klumpen auf einem Höhlenboden auszusehen. Sie können ihre Farbe etwas ändern, genug um mit felsigen Hintergründen zu verschmelzen. Gegner erleiden einen Malus von -2 auf Überraschungswürfe, wenn sie einem Roper gegenüberstehen.'),
  habitat_society = COALESCE(habitat_society, 'Roper sind nicht sozial und kooperieren selten miteinander, obwohl eine Gruppe von ihnen an einem guten Jagdplatz gefunden werden kann. Eine Gruppe von Ropern wurde von Gelehrten, die nichts Besseres zu tun haben, als "Cluster" bezeichnet.'),
  ecology         = COALESCE(ecology, 'Roper fressen jedes Fleisch, bevorzugen aber Halbmenschen und Menschen. Gnome, Zwerge und andere bergbautreibende Völker dienen oft als Beute für Roper.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = '659cc4e0-203f-481b-9c85-0d5ffdf311ab' AND is_custom = FALSE;

-- Rot Grub (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Fäulniswürmer sind widerliche kleine Kreaturen, die Maden ähneln. Sie wären als unbedeutend zu betrachten, wenn nicht ihre entsetzliche Angriffsform wäre.'),
  combat_tactics  = COALESCE(combat_tactics, 'Diese kleinen Kreaturen graben sich bösartig in jedes lebende Fleisch, das sie berührt, da sie solche Kost sehr gerne verspeisen. Der Angriff ist automatisch erfolgreich - kein Angriffswurf ist notwendig, sofern sie von bloßer Haut berührt wurden. Falls fraglich ist, ob bloße Haut einem Fäulniswurm ausgesetzt war, multipliziere die Rüstungsklasse des potentiellen Opfers mit 10, ohne Schilde zu berücksichtigen. Dies ist die Chance, gewürfelt mit Prozentwürfeln, dass die Fäulniswürmer bloße Haut berühren.'),
  habitat_society = COALESCE(habitat_society, 'Fäulniswurmschwärme werden gelegentlich in Haufen von Abfall oder Dung gefunden. Sie werden selten in Decken, Böden oder Wänden gefunden, aber es ist möglich. Manchmal tragen Untote wie Ghule, Ghäste, Zombies oder Wichte Fäulniswürmer mit sich, obwohl die kleinen Bestien keine Wirkung auf diese untoten Wirte haben. In Dschungel- und Sumpfgebieten können Fäulniswürmer in Haufen verrottender Pflanzen gefunden werden. Jeder, der so töricht ist, barfuß in solchen Gebieten zu laufen, bekommt was er verdient!'),
  ecology         = COALESCE(ecology, 'Fäulniswürmer werden oft von Attentätern gesucht. Einen oder zwei davon auf ein schlafendes Opfer zu platzieren gewährleistet normalerweise einen schnellen, stillen Tod. Außerdem kann, falls ein Arzt nicht weiß wonach er suchen soll, die Todesursache nicht bestimmt werden.'),
  no_appearing    = COALESCE(no_appearing, '5-20')
WHERE id = '36d4666c-06c9-4d02-8e77-29e1c2fbdb79' AND is_custom = FALSE;

-- Rust Monster (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Rostmonster sind unterirdische Kreaturen mit einem Appetit auf alle Arten von Metall. Diese einzigartigen Geschöpfe sind zwar im Allgemeinen harmlos, aber sie sind der Fluch aller Kämpfer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Rostmonster sind von Natur aus friedlich, aber wenn sie in Riechweite von Metall gelangen, werden sie aufgeregt und stürzen sich sofort auf die Quelle zu. Rostmonster können Metall bis zu einer Entfernung von 27,4 m riechen. Wenn die Antennen des Rostmonsters Metall berühren (bestimmt durch einen erfolgreichen Angriffswurf), rostet das Metall. Magische Gegenstände haben eine Chance von 10% pro Plus, nicht betroffen zu werden (eine +2 Waffe oder Rüstung hat eine 20%ige Chance, nicht betroffen zu werden). Jedes betroffene Metall rostet oder korrodiert und zerfällt sofort in Stücke, die von der Kreatur leicht gefressen und verdaut werden. Metallwaffen, die ein Rostmonster treffen, sind genauso betroffen, als hätten die Antennen der Kreatur sie berührt. Sollte ein nicht-waffenartiger metallischer magischer Gegenstand zufällig mit einem Rostmonster in Kontakt kommen, behandle ihn wie eine +2 magische Waffe zur Bestimmung, ob er zerbricht oder nicht.'),
  habitat_society = COALESCE(habitat_society, 'Rostmonster leben nur an dunklen, unterirdischen Orten wie Höhlen und unterirdischen Strukturen. Sie neigen nicht zu Gruppenbildung; oft besteht ein Bau aus ein oder zwei Rostmonstern, mit einer 5%igen Chance, auf einen einzelnen Nachkommen zu treffen, der als halbstarkes Rostmonster mit vollstarkem Appetit agiert. Es ist bekannt, dass diese Kreaturen die gesamte Länge und Breite eines unterirdischen Komplexes durchstreifen, um nach Metallvorräten zu suchen. Obwohl es rohes Erz frisst, bevorzugt ein Rostmonster immer raffiniertes, geschmiedetes Metall (genauso wie ein Mensch frisches, gefiltertes Wasser gegenüber Sumpfwasser bevorzugen würde).'),
  ecology         = COALESCE(ecology, 'Rostmonster helfen dabei, metallischen Schrott und Unrat aus unterirdischen Festungen zu entfernen. Tatsächlich ist es nicht ungewöhnlich, ein Rostmonster und einen Aasfresser in einer symbiotischen Beziehung zu finden, wobei letzterer den organischen Abfall frisst und ersteres die metallischen Abfälle konsumiert.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = 'aae31dbb-2905-4bf4-bd7d-b99381458264' AND is_custom = FALSE;

-- Sahuagin (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sahuagin sind eine bösartige, räuberische Rasse von Fischmenschen, die in warmen Küstengewässern leben. Sie sind hoch organisiert und erfreuen sich sehr daran, Küstengemeinden zu überfallen, um Nahrung und Sport zu erhalten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl sie keine Rüstung tragen, sind ihre Schuppen zäh und entsprechen RK 5. Sahuagin tragen ein Geschirr, um ihre persönliche Ausrüstung und Waffen zu tragen. Eine Gruppe dieser Kreaturen ist typischerweise wie folgt bewaffnet:'),
  habitat_society = COALESCE(habitat_society, 'Die Sahuagin werden manchmal als "Seeteufel" oder "Teufelsmenschen der Tiefe" bezeichnet. Sie leben in warmem Salzwasser in Tiefen von 100 bis 0,3 m. Sahuagin sind extrem räuberisch, und sie stellen eine Bedrohung für alle Lebewesen dar, weil sie aus Sport und Vergnügen sowie für Nahrung töten. Sie verabscheuen Süßwasser. Sie mögen kein Licht, und helles Licht wie das eines Dauerlicht-Zaubers ist schädlich für ihre Augen.'),
  ecology         = COALESCE(ecology, 'Sahuagin wagen sich in dunklen, mondlosen Nächten an Land, um menschliche Küstenstädte'),
  no_appearing    = COALESCE(no_appearing, '20-80')
WHERE id = 'e1998d5d-40f4-4fc9-88f7-02a251f5ee9f' AND is_custom = FALSE;

-- Satyr (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Satyre, auch Faune genannt, sind eine vergnügungsliebende Rasse von halb-menschlichen, halb-ziegenartigen Kreaturen. Sie verkörpern die sorglosen Wege der Natur.'),
  combat_tactics  = COALESCE(combat_tactics, 'Satyre haben scharfe Sinne, daher erhalten sie einen +2 Bonus auf Überraschungswürfe. Sie können nahezu lautlos sein und sich mit Blätterwerk vermischen, sodass sie zu 90% nicht entdeckbar sind; dies verleiht Gegnern eine -2 Strafe auf Überraschungswürfe. Satyre haben Infrasicht bis zu einer Entfernung von 18,3 m.'),
  habitat_society = COALESCE(habitat_society, 'Satyre interessieren sich nur für Vergnügungen: Herumtollen, Pfeifen, Waldnymphen jagen und andere Freuden. Sie ärgern sich über Störungen und vertreiben jede Kreatur, die sie beleidigt. Ein glücklicher Wanderer mag auf eine Waldfeier stoßen, die eine gleiche Anzahl von Dryaden und Faunen plus 3W8 andere Waldkreaturen und eine 25%ige Chance auf 2W6 Zentauren enthält. Fremde sind nur willkommen, wenn sie gute Speisen und Getränke mitbringen, besonders erlesene (10+ GM pro Flasche) Weine. Solcher Wein kann auch verwendet werden, um Satyre zu locken oder zu bestechen. Wenn eine Gruppe Elfen einschließt, haben sie eine bessere Chance, willkommen geheißen zu werden.'),
  ecology         = COALESCE(ecology, 'Satyre in Waldländern halten die Wildtierpopulationen auf normalem Niveau; sie jagen niemals übermäßig oder verwüsten Pflanzen.'),
  no_appearing    = COALESCE(no_appearing, '2-8 (2d4)')
WHERE id = 'd9f7bc04-9065-4481-a7e7-c29afe2243e6' AND is_custom = FALSE;

-- Scorpion (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenskorpione sind bösartige Raubtiere, die fast überall leben, einschließlich relativ kalter Orte wie Verliese, obwohl sie Wüsten und warme Länder bevorzugen. Diese Kreaturen sind Riesenversionen der normalen 10 cm langen Skorpione, die man in Wüstengebieten findet.'),
  combat_tactics  = COALESCE(combat_tactics, 'Der Riesenskorpion wird mit 95%iger Wahrscheinlichkeit jede Kreatur angreifen, die sich nähert. Die Kreatur hat einen harten, chitinösen Panzer, der ihr Rüstungsklasse 3 verleiht. Dieses Monster greift an, indem es Beute mit seinen beiden riesigen Scheren packt und dabei jeweils 1-10 Schadenspunkte zufügt, während es mit seinem Schwanz nach vorn peitscht, um zu stechen. Somit kann es drei Gegner gleichzeitig bekämpfen. Wenn ein Riesenskorpion es schafft, ein Opfer in einer Schere zu packen, fügt er automatisch jede Runde 1-10 Schadenspunkte zu, bis er das Opfer loslässt. Das Opfer hat nur eine Chance zu entkommen. Wenn es seinen Wurf für Eisenstangen biegen/Tore heben schafft, wird es der Klaue entkommen. Dies kann jedoch die einzige Handlung des Charakters in dieser Runde sein und nur einmal pro Kampf versucht werden. Wird der Stich gegen ein nicht gefangenes Opfer eingesetzt, ist ein Angriffswurf für einen erfolgreichen Angriff erforderlich, aber ein gefangener Charakter wird automatisch von jedem gegen ihn gerichteten Stichangriff getroffen, ohne dass ein Angriffswurf nötig ist.'),
  habitat_society = COALESCE(habitat_society, 'Riesenskorpione leben in unterirdischen Bauten oder Verliesen. Jeder Bau kann (20%) 5W4 Skorpioneier enthalten. Diese Bestien fressen jede lebende Kreatur, die das Pech hat, zu nah an ihren Bau zu geraten. Alle gefundenen Schätze stammen von den Körpern menschlicher oder halbmenschlicher Opfer, die hierher geschleppt wurden, um verzehrt zu werden. Rüstungen findet man selten intakt, da der Skorpion sicherlich seine Scheren benutzt hat, um seine Beute zu zerstückeln.'),
  ecology         = COALESCE(ecology, 'Diese bizarren Insekten tragen zum Ökosystem bei, indem sie sich von anderen Riesenversionen von Insekten wie Spinnen und Ameisen ernähren. Sie selbst sind Beute für Purpurwürmer und andere riesige, unterirdische Kreaturen. Alchemisten und Meuchelmörder schätzen das Gift des Skorpions wegen seiner Wirksamkeit.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = 'c2bce4f0-c553-4420-9358-5c2d724dee0d' AND is_custom = FALSE;

-- Sea Horse, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenseepferdchen sind einfach eine riesige Spezies der gewöhnlicheren Seepferdchen. Sie haben die charakteristischen pferdeartigen Köpfe und sich verjüngenden Schwänze aller Seepferdchen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ein Seepferdchen kann normalerweise nur mit einem Kopfstoß angreifen, aber ein Seepferdchen, das von Locathah oder Wasserelfen als Reittier ausgebildet wurde, kann auch seinen langen, sich windenden Schwanz einsetzen, um Feinde einzuschnüren und festzuhalten. Das Seepferdchen muss geritten werden, um den Befehl zur Einschnürung ordnungsgemäß zu befolgen und muss dann einen erfolgreichen Angriffswurf schaffen. Ein gefangener Gegner kann sich mit einem erfolgreichen Türen-öffnen-Wurf mit -1 Malus befreien. Der Schwanz eines Riesenseepferdchens ist so lang, dass er denselben Gegner angreifen kann, den der Kopf stößt, oder denjenigen, den sein Reiter angreift, ohne Malus. Die Länge des Schwanzes schnürt auch den gesamten Körper jeder menschengroßen oder kleineren Kreatur ein, wodurch Zauberwirken oder Nahkampf für eingeschnürte Kreaturen unmöglich wird. Die Einschnürung verursacht keinen Schaden, aber das Seepferdchen kann sich dennoch entscheiden, das hilflose Opfer zu stoßen, falls gewünscht.'),
  habitat_society = COALESCE(habitat_society, 'In ihrer natürlichen Umgebung versammeln sich Seepferdchen in Schwärmen und ernähren sich von kleinem Plankton und Seetang. Sie haben Schwarmführer und folgen den vorherrschenden Strömungen. Sie sind allgemein scheu und meiden Kontakt außer mit anderen Seepferdchen.'),
  ecology         = COALESCE(ecology, 'Seepferdchen werden von der üblichen Auswahl ozeanischer Räuber gejagt, nämlich Haien, Riesenkalmaren und einem Kraken oder zwei. Sie haben nur einen besonderen Feind, die bösartigen Sahuagin. Unglücklicherweise für Seepferdchen fressen Sahuagin alles mindestens einmal und sie fanden heraus, dass Riesenseepferdchen tatsächlich eine große Delikatesse waren. Ein kleines und profitables Gewerbe in jeder Sahuagin-Stadt ist die Marktgilde, und die wertvollste Ware ist Seepferdchenfleisch. Viele Adelshäuser spezialisieren sich darauf, diese friedlichen Kreaturen zu jagen und zusammenzutreiben. Sahuagin entscheiden sich dagegen, Seepferdchen zu züchten, da sie glauben, dass der offene Ozean die Pferde zäher und schmackhafter macht.'),
  no_appearing    = COALESCE(no_appearing, '1-20')
WHERE id = 'ae05aae5-11bd-4c87-ae96-3540c4928e35' AND is_custom = FALSE;

-- Shadow (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Schatten sind schattenhafte, untote Kreaturen, die mit ihrer eiskalten Berührung die Stärke ihrer Opfer entziehen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Da Schatten hauptsächlich auf der Negativen Materialebene existieren, haben sie die Fähigkeit, die Lebenskraft ihrer Opfer zu entziehen. Die eiskalte Berührung eines Schattens fügt seinem Opfer 2-5 Schadenspunkte zu und entzieht zusätzlich einen Punkt Stärke. Verlorene Stärkepunkte kehren 2-8 Runden nach der Berührung zurück. Wenn ein menschlicher oder halbmenschlicher Gegner durch einen Schatten auf null Stärke oder null Trefferpunkte reduziert wird, hat der Schatten die Lebenskraft entzogen und der Gegner wird ebenfalls zu einem Schatten. Der neu entstandene Schatten ist dann gezwungen, sich der umherziehenden Bande anzuschließen und ein Leben des Bösen zu führen. Andere Lebewesen brechen einfach vor Erschöpfung zusammen (wenn sie auf null Stärke gebracht werden) oder fallen bewusstlos (wenn sie auf null Trefferpunkte gebracht werden), wo sie dem Tod überlassen werden oder beim Erwachen erneut gejagt werden.'),
  habitat_society = COALESCE(habitat_society, 'Schatten reisen in lose organisierten Rudeln, die frei durch uralte Ruinen, Friedhöfe und Verliese streifen. Sie spezialisieren sich darauf, ihre Opfer zu terrorisieren.'),
  ecology         = COALESCE(ecology, 'Den meisten sachkundigen Gelehrten zufolge scheinen Schatten magisch erschaffen worden zu sein, vielleicht als Teil eines uralten Fluchs, der über irgendeinen längst toten Feind verhängt wurde. Der Fluch betrifft nur Menschen und Halbmenschen, so dass es scheint, dass er die Seele oder den Geist betrifft. Wenn die Opfer nicht länger widerstehen können, sei es durch Bewusstseinsverlust (Trefferpunkte) oder körperliche Kraft (Stärkepunkte), wird der Fluch aktiviert und der Großteil der Essenz des Charakters wird auf die Negative Materialebene verschoben. Nur ein Schatten ihres früheren Selbst verbleibt auf der Primären Materialebene, und die Verwandlung macht das Opfer immer sowohl furchtbar wahnsinnig als auch unbestreitbar böse.'),
  no_appearing    = COALESCE(no_appearing, '2-20 (2d10)')
WHERE id = 'f57edf57-0c0c-4a16-accf-fc1e70a08fb7' AND is_custom = FALSE;

-- Shambling Mound (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wankende Hügel oder "Wanker" erscheinen als Haufen verfaulender Vegetation. Sie sind tatsächlich eine intelligente Form pflanzlichen Lebens, grob humanoider Gestalt, mit einer Höhe von 1,8 bis 2,7 m und einem Umfang von etwa 1,8 m an ihrer Basis (Beine bis Taille) und 0,6 m an ihrem Gipfel (dem "Kopf").'),
  combat_tactics  = COALESCE(combat_tactics, 'Wankende Hügel sind furchtlose Angreifer und sind vielleicht die tödlichste bekannte Form pflanzlichen Lebens. Ihre gewaltigen armähnlichen Fortsätze verursachen bei jedem Treffer 2-16 Punkte Quetschschaden, und ein unglückliches Opfer, das von beiden Armen in derselben Runde getroffen wird, verfängt sich in den schleimigen Ranken und der verfaulenden Pflanzenmaterie der Kreatur. Verfangene Kreaturen ersticken im Schleim in 2W4 Runden, es sei denn, der Wanker wird getötet oder das Opfer befreit sich (bei erfolgreichem Wurf für Stäbe biegen/Tore heben).'),
  habitat_society = COALESCE(habitat_society, 'Wankende Hügel findet man nur in Gebieten mit starkem Niederschlag und dichter Vegetation. Düstere Sümpfe, Marschland und Regenwälder sind ihre bevorzugten Klimazonen, aber auch einige feuchte unterirdische Orte dienen als Baue der Wanker. Sie sind Einzelgänger und leben nur selten im selben Gebiet wie andere Wanker - normalerweise nur in Gebieten, wo die Nahrungsquelle konstant ist (z.B. in der Nähe berühmter Ruinen oder verlassener Goldminen usw.).'),
  ecology         = COALESCE(ecology, 'Der wankende Hügel ist ein belebter Klumpen Vegetation mit einem kleinen gehirnähnlichen Kontrollzentrum, das tief in der "Brust"-Höhle liegt. Einen wankenden Hügel zu enthaupten schadet ihm daher nicht im Geringsten. Da die "Gliedmaßen" eines wankenden Hügels lediglich zusammengeballte Klumpen aus Ranken und Moos sind, behindert auch die Entfernung einer oder mehrerer von ihnen die Kreatur nicht. Verbleibende Ranken entlang des Rumpfes verbinden sich bis zur nächsten Runde zu einem neuen Glied. Erst wenn genug vom wankenden Hügel weggehackt wurde, stirbt die Kreatur.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = 'e9036941-45b8-4944-baff-a2b51627cb04' AND is_custom = FALSE;

-- Shark (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Haie sind große, mit Flossen ausgestattete, gefräßige Fleischfresser, die alle bekannten Ozeane und Meere bewohnen. Sie sind vielleicht die aggressivsten Fressmaschinen, die in den düsteren Tiefen zu finden sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Haie spüren Druckveränderungen unter Wasser, die meist durch Geräusche anderer Kreaturen verursacht werden. Umherplätschern im Wasser zieht immer Haie an, da sich normalerweise nur verletzte Fische so verhalten. Haie können diese Bewegungen aus einer Entfernung von bis zu 1,6 km wahrnehmen, und sobald ein Hai Beute entdeckt, folgen bald weitere. Haie greifen auch gnadenlos beim Geruch von Blut an, den sie ebenfalls aus Entfernungen von 1,6 km oder mehr wahrnehmen können.'),
  habitat_society = COALESCE(habitat_society, 'Haie sind reine Fress- und Tötungsmaschinen, die sich ganz natürlich zu überlegenen Raubtieren entwickelt haben und dann Millionen von Jahren unverändert blieben. Sie sind hauptsächlich Aasfresser, die Kranke und Verwundete jagen, greifen aber frisches Fleisch an, wenn sie dazu verlockt werden. Sie sind sehr territorial und einzelgängerisch.'),
  ecology         = COALESCE(ecology, 'Haie haben nur zwei natürliche Schwächen. Die erste ist, dass ihre inneren Organe nur schlecht durch eine dicke, flexible Knorpelschicht anstatt eines harten Skeletts geschützt sind. Einige Kreaturen, wie Delfine, nutzen dies aus, indem sie Haie von der Seite rammen. Aufgrund ihrer hochintelligenten Natur sind Delfine die einzigen wahren Feinde der Haie. Sie sind die einzige bekannte Spezies, die diese ansonsten sehr gefürchteten und respektierten Monster aktiv jagt und tötet.'),
  no_appearing    = COALESCE(no_appearing, '3-12')
WHERE id = '1bfc2446-0de9-4f08-91a6-8d9515fa9361' AND is_custom = FALSE;

-- Shedu (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Shedu sind in heißen, trockenen Klimazonen beheimatet. Sie haben kraftvolle, stämmige Pferdekörper mit kurzen, starken gefiederten Flügeln. Ihre Köpfe sind groß und menschenähnlich und wirken eher zwergenhaft. Sie haben immer Bärte und Schnurrbärte. Das Haar der Shedu ist sehr borstig und kräuselt sich zu engen Wellen oder Bändern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle Shedu greifen mit kraftvollen Vorderhufen an. Beide Formen der Shedu ziehen es jedoch vor, ihre psionischen Kräfte zu verwenden, wann immer möglich.'),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '2d4')
WHERE id = '23b428fe-d7b2-47fe-835c-cf8730808a8c' AND is_custom = FALSE;

-- Sirine (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Sirinen sind wunderschöne, menschenähnliche Weibchen, die sich in jeder Wasserumgebung wohlfühlen. Sie haben menschliche Hauttöne, die bis zu einem hellen Gelbgrün reichen, und ihr Haar kann fast jede Farbe haben, obwohl Silber und Dunkelgrün am häufigsten sind. Sirinen haben schöne Figuren und tragen bestenfalls spärliche Kleidung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Eine einsame Sirine wird immer 6 oder 7 TW haben; jedes Mitglied einer Gruppe hat die gleiche Chance auf 4, 5 oder 6 TW. Alle Mitglieder einer Gruppe haben dieselbe Grundgesinnung (alle böse, alle gut oder alle neutral in Bezug auf gut und böse). Alle Sirinen können ihre Einsamkeit mit einigem Geschick verteidigen.'),
  habitat_society = COALESCE(habitat_society, 'Sirinen werden nur an einsamen Orten angetroffen, die ansonsten unbewohnt sind. Die meisten leben in der Nähe von felsigen Vorsprüngen oder kleinen Inseln im Meer. Einige entscheiden sich dafür, in Süßwasser zu leben, meiden diese Gebiete aber tendenziell, weil sie normalerweise bevölkert und manchmal schwer zu erreichen sind.'),
  ecology         = COALESCE(ecology, 'Sirinen schaden ihrer Umgebung in keiner Weise. Sie töten nur genug, um zu essen, und nehmen niemals zu viel aus dem Meer. Sie haben wenige natürliche Feinde und sind mehr als fähig, für sich selbst zu sorgen. Obwohl sie wunderschöne Gewänder aus Muscheln, Fischhaut und Seetang herstellen, gewinnen sie andere Besitztümer und Schätze durch das Plündern von Schiffswracks.'),
  no_appearing    = COALESCE(no_appearing, '1 (2d4)')
WHERE id = '82e23566-b4fa-45e6-9dc1-ec5235e39e0e' AND is_custom = FALSE;

-- Skeleton (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Alle Skelette sind magisch belebte untote Monster, die von mächtigen bösen Magiern und Priestern als Wächter oder Krieger erschaffen werden.'),
  combat_tactics  = COALESCE(combat_tactics, 'Menschengroße humanoide Skelette kämpfen immer mit Waffen, gewöhnlich einem rostigen Schwert oder Speer. Aufgrund ihrer magischen Natur kämpfen sie nicht so gut wie lebende Wesen und verursachen nur 1-6 Schadenspunkte bei einem Treffer. Tierskelette beißen fast immer für 1-4 Schadenspunkte, außer sie würden offensichtlich weniger verursachen (d.h. Rattenskelette sollten nur 1-2 Punkte verursachen, usw.). Monsterskelette, die immer aus humanoiden Kreaturen konstruiert werden, verwenden riesengroße Waffen, die den gleichen Schaden wie ihre lebenden Gegenstücke verursachen, aber ohne Stärkeboni.'),
  habitat_society = COALESCE(habitat_society, 'Skelette haben kein soziales Leben oder interessante Gewohnheiten. Sie können überall gefunden werden, wo es einen Magier oder Priester gibt, der mächtig genug ist, sie zu erschaffen. Zu beachten ist, dass einige neutrale Priester von Gottheiten der Toten oder Sterbenden oft ganze Armeen belebter Anhänger in Zeiten der Not auferstehen lassen. Gute Priester können Skelette nur erschaffen, wenn das tote Wesen die Erlaubnis erteilt hat (entweder vor oder nach dem Tod) und wenn die Gottheit des Priesters ausdrückliche Erlaubnis dazu gegeben hat. Andernfalls ist die Verletzung der ewigen Ruhe jedes Wesens oder Tieres etwas, was die meisten guten Gottheiten höchst missbilligen.'),
  ecology         = COALESCE(ecology, 'Sofern die Überreste des Skeletts nicht zerstört oder weit voneinander verstreut werden, kann das Skelett durch die Anwendung eines weiteren Zaubers der Totenerweckung neu erschaffen werden. Gerüchte über hochstufige Zauber der Totenerweckung, die Skelette erschaffen, die sich selbst reformieren können, um nach ihrer Zerstörung weiterzukämpfen, wurden nicht zuverlässig bestätigt.'),
  no_appearing    = COALESCE(no_appearing, '3-30 (3d10)')
WHERE id = '50f2e1ae-27d8-4f61-866a-15dac799536f' AND is_custom = FALSE;

-- Skeleton, Warrior (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ehemals mächtige Kämpfer sind Skelettkrieger untote Fürsten, die von mächtigen Magiern oder bösen Halbgöttern in ihren alptraumhaften Zustand gezwungen wurden, welche ihre Seelen in goldenen Reifen gefangen hielten. Der einzige Grund, warum Skelettkrieger auf der Ersten Materiellen Ebene verweilen, ist die Suche nach den Reifen, die ihre Seelen enthalten, um diese zurückzuerlangen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Jeder, der den Reifen eines Skelettkriegers besitzt, kann dessen Handlungen kontrollieren, solange der Kontrolleur innerhalb von 73,2 m vom Krieger entfernt bleibt. Der Kontrolleur befindet sich entweder in aktiver Kontrolle über den Krieger oder im passiven Modus. Bei aktiver Kontrolle kann der Kontrolleur alles sehen, was das Skelett sieht, und er kann es mental befehligen zu kämpfen, nach Schätzen zu suchen oder andere Handlungen zu unternehmen; jedoch ist der Kontrolleur selbst unfähig, Zauber zu wirken, sich zu bewegen oder andere Handlungen zu unternehmen, während er in aktiver Kontrolle ist. Im passiven Modus kann der Kontrolleur normale Handlungen ausführen, aber er kann nicht durch die Augen des Kriegers sehen; der Skelettkrieger bleibt träge, während der Kontrolleur im passiven Modus ist. Der Kontrolleur kann nach Belieben zwischen dem passiven Modus und der aktiven Kontrolle wechseln.'),
  habitat_society = COALESCE(habitat_society, 'Skelettkrieger werden gewöhnlich in der Nähe der Gebiete gefunden, wo sie in ihrem früheren Leben starben oder wo sie begraben wurden. Ein Skelettkrieger besitzt normalerweise eine beträchtliche Schatzmenge, die Überreste eines Lebens voller Abenteuer. Da ein Skelettkrieger damit beschäftigt ist, seinen Reif zurückzuerlangen, hat der Schutz seines Schatzes keine Priorität.'),
  ecology         = COALESCE(ecology, 'Skelettkrieger werden von ihren Kontrolleuren als Leibwächter, Diener oder Arbeiter eingesetzt. Da Skelettkrieger von ihren Reifen besessen und daher unzuverlässig sind, verkehren böse Kreaturen und andere Untote selten mit ihnen. Skelettkrieger essen nicht, schlafen nicht und führen keine anderen physiologischen Funktionen aus.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '88ea38ea-669a-494d-9683-c040edc7cc2a' AND is_custom = FALSE;

-- Skunk (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Stinktiere sind waldbewohnende Allesfresser, die in den meisten gemäßigten und subtropischen Regionen zu finden sind. Sie sind leicht an dem langen weißen Streifen zu erkennen, der von ihren Gesichtern über ihre schwarzfelligen Rücken bis zu den Spitzen ihrer Schwänze verläuft.'),
  combat_tactics  = COALESCE(combat_tactics, 'Stinktiere reagieren auf jede ernsthafte Bedrohung, indem sie rückwärts auf den Gegner zugehen. Wenn sich die andere Kreatur nicht schnell außer Reichweite begibt, stößt das Stinktier eine übelriechende Wolke aus stinkendem Moschus auf sie aus.'),
  habitat_society = COALESCE(habitat_society, 'Stinktiere sind wandernde Aasfresser und haben keine Sozialstruktur. Sie bevorzugen es, die Überreste größerer Raubtiere zu fressen und leben immer tief im Wald.'),
  ecology         = COALESCE(ecology, 'Wie oben erwähnt, fressen Stinktiere fast alles, normalerweise die Überreste anderer Beutetiere. Ihr Moschus wird aus einem kleinen hinteren Sack abgesondert, der stark bemuskelt ist, um das Ausstoßen der Flüssigkeit zu ermöglichen. Die Flüssigkeit bildet einen schweren Nebel, der je nach vorherrschenden Winden und gefülltem Bereich bis zu einer Woche oder länger in einem Gebiet verweilt. Wenn das Stinktier überrascht und schnell getötet wird, besteht eine 50%ige Chance, dass der Moschus geborgen werden kann. Ein auf diese Weise getötetes Riesenstinktier kann ein Preis von fast 200 GM für einen Gelehrten oder Alchemisten sein, da der Moschus ein geschätzter alchemistischer Bestandteil ist (für Stinkwolken-Spruchtinten, Rauchbomben usw.).'),
  no_appearing    = COALESCE(no_appearing, '1 or 1-6')
WHERE id = '4681e2e6-0678-4c64-80bd-35cbe20d5c9c' AND is_custom = FALSE;

-- Slaad (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Slaadi sind zweibeinige froschartige Wesen, die auf der Äußeren Ebene des Limbus leben. Sie plündern Schlachtfelder des Blutkrieges, ernähren sich von den Toten und nutzen die Verwundeten als Instrumente in ihrem Fortpflanzungszyklus. Slaadi streben danach, die bestehende Ordnung auf allen Ebenen zu ändern, um sich selbst Macht zu verschaffen, aber ihnen fehlt der Wille, Armeen zu mobilisieren oder sich in die Intrigen anderer Teufel zu verwickeln. Daher verfolgen die mächtigen Arten von Slaad ihre eigenen Ziele und nutzen weniger mächtige Arten als ihre Schläger und Agenten.'),
  combat_tactics  = COALESCE(combat_tactics, 'Rote Slaadi greifen mit zwei Klauen an (je 1W4 Schaden) und beißen (2W8 Schaden). Sie wählen vorhersehbare, einfallslose Taktiken und sind nicht besonders intelligent.'),
  habitat_society = COALESCE(habitat_society, 'Slaadi beachten eine informelle und pragmatische Hierarchie, nicht weil sie Regulierung respektieren, sondern weil starke Herrscher ungehorsame Untergebene vernichten.'),
  ecology         = COALESCE(ecology, 'Obwohl die Slaadi die Äußeren Ebenen bewohnen und durch die Unteren Ebenen reisen, kämpfen sie normalerweise nicht im Blutkrieg zwischen Baatezu und Tanar''ri. (Einige graue Slaadi haben Informationen an beide Seiten verkauft im Austausch gegen mächtige magische Gegenstände.) Jedoch plündern Slaadi die Schlachtfelder der Gefallenen, ernähren sich von Aas und bringen verwundete Opfer in ihre alptraumhaften temporären Gefangenenlager. Nach der Nutzung der Opfer zur Ausbrütung einer neuen Generation trennen sich die Slaadi, die das Lager organisierten, und ziehen weiter, indem sie Gerüchten über neue Schlachten folgen.'),
  no_appearing    = COALESCE(no_appearing, '3-18')
WHERE id = '1f58357b-6f50-4e81-927f-bb5313b9cc1e' AND is_custom = FALSE;

-- Slug, Giant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Riesenschnecken sind gewaltige, allesfressende Mutationen der kleinen und harmlosen Gartenschnecken. Ihre hochentwickelten Mäuler können sowohl Fleisch als auch Pflanzen zerkauen, und sie spucken eine hochätzende Säure auf ihre Nahrung. Die meisten Riesenschnecken sind blassgrau mit totenweißen Bäuchen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Riesenschnecken können für 1W12 Schadenspunkte beißen, aber ihre Hauptangriffsform ist ihr ätzender Säurespeichel. Die Säure wird auf ein einzelnes Ziel gespuckt und zerfrisst jedes organische Gewebe (Pflanzen oder Tiere). Sie zerstört auch Ausrüstung (Rettungswurf gegen Säure). Die Säure verursacht 4W8 Schadenspunkte (erfolgreicher Rettungswurf gegen Atemwaffe für halben Schaden). Riesenschnecken können diese Atemwaffe jede Runde einsetzen (ihre Säurevorräte sind niemals aufgebraucht). Schnecken sind mit diesem Angriff nicht sehr treffsicher; der erste Schuss hat nur eine 10%ige Trefferchance. Der Erfolg nachfolgender Schüsse hängt von der Entfernung zum Ziel ab - die Grundchance zu treffen beträgt 90% auf eine Entfernung von neun Metern, mit einem Malus von -10% pro weitere neun Meter. Wenn die Schnecke verfehlt, trifft die Säure 3 m vom gewünschten Ziel entfernt (bestimme zufällig die Richtung). Beachte, dass Riesenschnecken gegen diese Säurespucke immun sind.'),
  habitat_society = COALESCE(habitat_society, 'Riesenschnecken können in jeder feuchten und dunklen Umgebung gefunden werden, einschließlich verlassener Verliese, Sümpfe und Regenwälder. Riesenschnecken sind Einzelgänger und sprechen keine Sprache. Sie sind kaum empfindungsfähig und zeigen nur rudimentäre instinktive Reaktionen, wenn sie konfrontiert werden.'),
  ecology         = COALESCE(ecology, 'Niemand hat jemals eine gute Verwendung für Riesenschnecken gefunden, außer vielleicht als riesige Müllschlucker. Sie haben keine bekannten Fressfeinde. Sie fressen alles - Pflanzen, Aas, Müll - bevorzugen aber warmes, lebendes Fleisch, wenn sie es fangen können. Da Riesenschnecken solch riesigen Appetit haben, greifen sie selten kleinere Kreaturen wie Eichhörnchen und Affen an, die sie ohnehin schlecht sehen können. Selbst an einem guten Tag müssen sie ihre Mahlzeiten normalerweise mit etwas Vegetation ergänzen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '0d00215c-706f-4507-bcd3-ba88ff7ff2df' AND is_custom = FALSE;

-- Snake, Winged (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Geflügelte Schlangen, manchmal auch Funken-Schlangen genannt, sind farbenfrohe Reptilien, die in Zakharas Wäldern und Dschungeln leben. Geflügelte Schlangen kommen in vielen Farben vor, von himmelblau und smaragdgrün bis himbeerrot. Sie werden von unsichtbar schnellen, hauchzarten Flügeln getragen, was sie wie reptilische Kolibris aussehen lässt. Wenn ihre zarten Flügel nach hinten gefaltet sind, können geflügelte Schlangen nach Belieben wie Spinnen klettern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Geflügelte Schlangen bewegen sich mit fließender Anmut und verheerender Geschwindigkeit. Sie erhalten immer einen -3 Bonus auf die Initiative.'),
  habitat_society = COALESCE(habitat_society, 'Geflügelte Schlangen müssen ständig fressen, um zu überleben. Sie flattern in kleinen Schwärmen durch den Dschungel und suchen nach tropischen Früchten, aus denen sie ihre Nahrung ziehen. Eine geflügelte Schlange fliegt zu einer Frucht und injiziert sie mit ätzendem Gift. Das Gift zersetzt die Frucht zu einer weichen, saftigen Mischung und verdaut sie teilweise, während sie noch in ihrer Schale bleibt. Die Schlange saugt dann das fruchtige Fruchtfleisch durch die von ihren Reißzähnen gemachten Einschnitte aus. Eine typische geflügelte Schlange frisst täglich etwa das 10-fache ihres Gewichts an Früchten, nur um am Leben zu bleiben.'),
  ecology         = COALESCE(ecology, 'Geflügelte Schlangen spielen eine wichtige Rolle in der Dschungelökologie. Wie Riesenbienen transportieren sie Pollen von Obstbaum zu Obstbaum und helfen bei der Verteilung von Samen im ganzen Dschungel. Als Erwachsene haben sie keine natürlichen Feinde.'),
  no_appearing    = COALESCE(no_appearing, '2-8')
WHERE id = '6b705f5a-e11e-42af-9cd9-5ccde3b1ad9c' AND is_custom = FALSE;

-- Spectre (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Spekter sind mächtige Untote, die in den trostlosesten und verlassensten Orten umgehen. Sie hassen alles Leben und alles Licht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Spekter existieren hauptsächlich auf der Negativen Materialebene und können daher von Wesen auf der Primären Materialebene nur mit magischen Waffen angegriffen werden. Tageslicht macht Spekter kraftlos, indem es ihre Verbindungen zur Negativen Materialebene schwächt.'),
  habitat_society = COALESCE(habitat_society, 'Die meisten Spekter sind Einzelgänger, aber einige Enklaven existieren, wo ein besonders mächtiger oder glücklicher Spekter es geschafft hat, Sterblichen das Leben zu entziehen. Dieser führende Spekter ist als Meister-Spekter bekannt (immer mit maximalen Trefferpunkten pro Würfel), während die anderen kollektiv als Gefolgsleute bekannt sind. In dieser Anordnung greift der Meister-Spekter fast niemals persönlich Feinde an, sondern schickt stattdessen seine Untergebenen zum Töten. Sterbliche, die von Gefolgsleute-Spektern das Leben entzogen bekommen, sind dem Meister-Spekter untertan, nicht den Gefolgsleuten. Beachte, dass wenn der Meister-Spekter getötet wird, alle Gefolgsleute unabhängig werden und überall hinreisen können, wo sie wollen, in der Hoffnung, selbst Meister-Spekter zu werden. Sobald ein Charakter ein Spekter wird, ist Heilung nahezu unmöglich und erfordert eine besondere Aufgabe.'),
  ecology         = COALESCE(ecology, 'Niemand weiß, wer der erste Spekter war oder wie er entstanden ist; die wenigen oben detaillierten Fakten sind alles, was mit irgendeinem Grad an Sicherheit bekannt ist.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '16969cc4-b8d6-4409-be18-e68ebbd2fab4' AND is_custom = FALSE;

-- Spider (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Spinnen sind aggressive Raubtiere, die sowohl ober- als auch unterirdisch leben. Die meisten hier aufgelisteten sind giftig und beißen ihre Beute zuerst, da bewusstlose Opfer leichter in den Bau zu tragen sind.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1-20')
WHERE id = '684332a6-a387-4a09-b6ae-d0fcc638d6a9' AND is_custom = FALSE;

-- Sprite (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kobolde sind scheue und zurückgezogene Feenwesen, verwandt mit anderen Feenvölkern wie Brownies und Leprechauns. Es gibt mehrere Arten, einschließlich Pixies und Nixies. Die meisten haben kleine, halb durchsichtige Flügel und elfische Züge. Gewöhnliche Kobolde haben ausgeprägt elfische Züge und leben auf Wiesen und bewaldeten Lichtungen. Die flügellosen Seekobolde machen ihre Heime auf farbenprächtigen Korallenriffen, leben in Harmonie mit den Meereskreaturen, beschützen die empfindliche Umwelt der Riffe und tollen in den Wellen herum. Die natürlich unsichtbaren Pixies sind vielleicht die intelligentesten und schelmischsten der Feen; sie bewohnen idyllische Waldgebiete und erfreuen sich daran, Reisende mit ihren Streichen zu belästigen. Nixies sind Wasserkobolde, die in Süßwasserseen leben und, obwohl sie keinen Groll gegen die Menschheit hegen, sich daran erfreuen, Männer als ihre Lasttiere zu versklaven. Andere Waldkreaturen, die mit Kobolden verwandt sind, schließen die flinken Atomies und die schelmischen Grigs ein, beides Waldbewohner.'),
  combat_tactics  = COALESCE(combat_tactics, 'Kobolde hassen das Böse und Hässlichkeit und sind zu entschlossenem Kampfgeist fähig, falls ihre abgeschiedenen Heime von Orks oder Schlimmerem heimgesucht werden. Sie kämpfen mit langen, schmalen Schwertern, die Schaden wie ein menschengroßer Dolch verursachen, oder ihren eigenen speziellen Bögen. Bögen haben eine Reichweite von der Hälfte eines menschlichen Kurzbogens und verursachen nur halb so viel Schaden (1-3 Punkte). Die Spitzen ihrer Pfeile sind mit einer speziellen Salbe bestrichen, die von den Kobolden gebraut wird. Jede Kreatur, die von den betäubten Pfeilen getroffen wird, muss unabhängig von Stufe, Rasse oder Magieresistenz einen Rettungswurf gegen Gift schaffen oder in einen tiefen Schlaf fallen, der 1W6 Stunden anhält. Normalerweise tun Kobolde nicht mehr, als ihre Opfer an einen sicheren Ort sehr weit weg zu bringen (oft beschlagnahmen sie dabei ihre Waffen), obwohl böse Kreaturen getötet werden können.'),
  habitat_society = COALESCE(habitat_society, 'Kobolde ziehen es vor, andere intelligente Wesen zu meiden und leben an Orten, wo sie viele Feiern, Feste und Zusammenkünfte haben können. Sie versammeln sich in den meisten mondhellen Nächten zum Singen und Tanzen, Landkobolde in den Lichtungen und Wasserkobolde in der Brandung. Landkobolde leben in sylvanischen Waldgebieten, sie überwachen und beschützen Wälder und abgeschiedene Lichtungen. Wasserkobolde beschützen ihre wässrigen Territorien ebenso gut.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '10-100')
WHERE id = 'fc8b7620-e1f6-473a-81de-948e694844fb' AND is_custom = FALSE;

-- Stirge (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Stirges sind vogelähnliche Kreaturen, die das Blut ihrer Opfer zur Nahrung trinken. Sie haben vier kleine, zangenähnliche Beine, mit denen sie sich an den Hälsen ihrer Opfer festklammern. Sie sind rostrot bis rötlichbraun gefärbt, und ihre Augen und Füße sind gelblich. Die herabhängenden Rüssel der Stirges sind an der Spitze rosa und verblassen zur Basis hin (nahe ihren Köpfen) zu grau.'),
  combat_tactics  = COALESCE(combat_tactics, 'Aufgrund einer instinktiven Fähigkeit, Schwachstellen zu finden und anzugreifen, greifen Stirges wie Kreaturen mit 4 Trefferwürfeln an, anstatt wie 1+1. Ihr langer Rüssel verursacht 1-3 Schadenspunkte beim Treffer und entzieht danach jede Runde 1W4 Blutpunkte. Wenn eine Stirge insgesamt 12 Blutpunkte von einem Opfer entzogen hat, wird sie aufgebläht und fliegt davon, um ihre proteinreiche Mahlzeit zu verdauen.'),
  habitat_society = COALESCE(habitat_society, 'Stirges bilden nestartige Kolonien in Dachböden, Verliesen und Baumgruppen. Obwohl sie Vögeln ähneln, hängen sie beim Schlafen kopfüber, was darauf hindeutet, dass Stirges eng mit Vampirfledermäusen verwandt sein könnten.'),
  ecology         = COALESCE(ecology, 'Stirges haben einen ausgeprägten Geruchssinn, können im Dunkeln sehen und Wärmequellen innerhalb von 61 m wahrnehmen. Diese Sinne halten Stirges darüber informiert, wenn Lebewesen ihr Habitat betreten. Kreaturen mit einer natürlichen RK von 3 oder besser sind normalerweise immun gegen den Blutentziehungsangriff einer Stirge, da ihre Haut zu dick zum Durchdringen ist. Infolgedessen leben riesige Stirgenester symbiotisch mit manchen bösen Drachen.'),
  no_appearing    = COALESCE(no_appearing, '3-30')
WHERE id = 'b20033a0-52a5-4cd2-8934-98a638648176' AND is_custom = FALSE;

-- Su-Monster (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wissenschaften: keine; Hingabe: Verstärkung.'),
  combat_tactics  = COALESCE(combat_tactics, 'Su-Monster greifen wenn möglich mit allen vier Gliedmaßen an und reißen mit ihren extrem scharfen Nägeln über ihr Opfer. Sie können auch einen kräftigen Biss mit ihrem hundeähnlichen Maul ausführen. Diese Kreaturen jagen gerne in kleinen Rudeln (1W12 Mitglieder). Ihre bevorzugten Jagdgründe sind vielbenutzte Pfade durch den Dschungel oder Wald. Sie suchen einen stabilen Ast, der über einen Pfad hängt, und hocken in den Bäumen und warten geduldig. Wenn ein Opfer unter ihnen vorbeigeht, können sie sich herabschwingen und dabei ihre Schwänze als Anker benutzen. Auf diese Weise können sie mit allen vier Klauen plus dem Biss angreifen. Opfer dieser Art von Hinterhalt erleiden eine -4 Strafe auf ihre Überraschungswürfe.'),
  habitat_society = COALESCE(habitat_society, 'Eine Su-Monster-Familie besteht aus zwei Eltern (erwachsenes Männchen und Weibchen) und zwei Jungen. Wenn zwei oder mehr Familien zusammenleben, bilden sie einen Clan. Su-Monster sind sehr territorial und hegen einen besonderen Hass gegen psionisch Begabte.'),
  ecology         = COALESCE(ecology, 'Su-Monster verstecken ihre Wertsachen gut verborgen in den hohen Stämmen der Bäume in ihrem Territorium. Sie haben keinen Nährwert, da ihr Fleisch schwach giftig ist. Charaktere, die Su-Monster-Fleisch essen, müssen einen Rettungswurf gegen Gift bestehen oder werden krank, und natürliche Heilung ist 1 Woche lang nicht möglich.'),
  no_appearing    = COALESCE(no_appearing, '1d12')
WHERE id = '69663411-d345-4695-9085-2bc3b52cbe01' AND is_custom = FALSE;

-- Tako (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Tako sind eine Rasse intelligenter Oktopusse, die sich an Land bewegen und Waffen sowie andere Werkzeuge verwenden können.'),
  combat_tactics  = COALESCE(combat_tactics, 'Obwohl normalerweise friedlich, greifen Tako jede Kreatur an, die in ihr Territorium eindringt. Außerdem haben sie einen starken Ehrsinn und werden Angriffe rächen und sich mit Mitgliedern anderer Rassen verbünden, die ihnen helfen. Sie sind listige Gegner. Tako können ihre Farbe und ihr Muster in einer einzigen Runde an jedes natürliche Gelände anpassen. Diese Tarnung macht sie zu 90% unentdeckbar und verändert die Überraschungswürfe der Gegner um -3.'),
  habitat_society = COALESCE(habitat_society, 'Ein Tako-Stamm besteht aus 3-12 (3W4) Männchen, halb so vielen Jungen und 1-2 Weibchen. Die Weibchen treffen alle Entscheidungen für den Stamm, während die Männchen als Verteidiger und Jäger fungieren. Die Kreaturen errichten ihre Baue in küstennahen Unterwasserhöhlen und unternehmen gelegentliche Raubzüge an Land nach Nahrung, Waffen und Schatzgegenständen. In einigen Gebieten koexistieren Tako mit Menschen und arbeiten zusammen, um Seeungeheuer anzugreifen und Fischern zu helfen, aber solche Fälle sind extrem selten.'),
  ecology         = COALESCE(ecology, 'Tako fressen Austern, Krebse, Hummer und andere Schalentiere, die sie mit ihren kräftigen Kiefern aufknacken. Sie können kleine Wolken reichhaltiger blauer Tinte ausstoßen, aber die Wolken sind zu begrenzt, um als Verteidigung zu dienen. Menschen schätzen die Tinte jedoch sehr und verwenden sie für Kalligraphie.'),
  no_appearing    = COALESCE(no_appearing, '3-12')
WHERE id = '78562a18-29b3-49d2-8a52-6195965e6197' AND is_custom = FALSE;

-- Tanar'ri, True, Balor (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die größten und schrecklichsten der wahren Tanar''ri, die Balors sind die unbestrittenen Schrecken des Abgrunds. Sie treiben die Beteiligung der Tanar''ri am Blutkrieg voran und schöpfen immenses Vergnügen aus dem Leiden anderer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Balors können nicht überrascht werden. Sie sind immun gegen alle nichtmagischen Angriffe einschließlich Feuer, Gas, Gift und Waffen, sowie alle Angriffe mit magischen Waffen mit weniger als +3 Verzauberung.'),
  habitat_society = COALESCE(habitat_society, 'Mindestens vierundzwanzig Balors sind bekanntermaßen existent. Sie wandern durch den Abgrund, bilden Armeen und kommandieren sie im Kampf gegen die Baatezu.'),
  ecology         = COALESCE(ecology, 'Nichts ist im Abgrund wichtiger als der Blutkrieg. Die Balors sind in gewissem Sinne der Blutkrieg aus der Perspektive der Tanar''ri. In diesem Sinne sind sie die Ökologie des Abgrunds, treiben die Erschaffung neuer Wesen voran und bestimmen ihr Überleben.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '23ed9564-b7ff-461e-bb28-bbc5955c3bc0' AND is_custom = FALSE;

-- Tanar'ri, True, Marilith (matched by override)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Kühn und gerissen sind Mariliths die Generäle und Taktiker für den Blutkrieg. Während Balors der Einfluss und die Energie hinter den Kriegsanstrengungen sind, sind Mariliths das Hirn und die Taktik.'),
  combat_tactics  = COALESCE(combat_tactics, 'Mariliths sind niemals überrascht. Obwohl sie Strategen und Taktiker sind, lieben Mariliths den körperlichen Kampf, wenn sich die Gelegenheit bietet. Sie schätzen jeden Kampf ab, bevor sie sich einmischen, und nutzen Gelände, Hindernisse und die Nachteile des Gegners voll aus. Sie können mit jedem ihrer sechs Arme angreifen und ein Opfer zusätzlich mit ihren schlangenartigen Schwänzen umschnüren.'),
  habitat_society = COALESCE(habitat_society, 'Wie erwähnt, sind Mariliths die Strategen des Blutkriegs. Sie entwickeln Schlachttaktiken und koordinieren die wahren Tanar''ri (außer den Balors, natürlich). Aufgrund der chaotischen Natur der anderen Tanar''ri ist die Koordination ihrer Aktivitäten nahezu unmöglich.'),
  ecology         = COALESCE(ecology, 'Mariliths fühlen insgeheim, dass sie die wahre Kraft hinter dem Blutkrieg sind, dass die Balors ihren Platz nur wegen ihrer großen Macht haben und ansonsten unnötig sind. Sie könnten recht haben, aber die Macht der Balors bleibt unangefochten.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '8c580c75-b04c-4006-b323-92ab09c8479e' AND is_custom = FALSE;

-- Thought Eater (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Gedankenfresser sind Bewohner des Grenzätherischen, und sie können nur in ätherischer Form überleben. Sie erscheinen als kränklich graue Skelettleiber mit übergroßen Schnabeltierköpfen. Sie haben schwimmhäutige Skeletttatzen, die zum Schwimmen durch den Äther geeignet sind.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gedankenfresser sind einzigartig. Sie haben keine Kampffähigkeiten außer ihren angeborenen psionischen Talenten, selbst im Grenzätherischen, daher können sie leicht getötet werden, wenn man ihnen dort begegnet.'),
  habitat_society = COALESCE(habitat_society, 'Wenig ist über Gedankenfresser bekannt, außer dass sie ausschließlich in der Ätherischen Ebene existieren und sehr einzelgängerische Wesen sind. Magische Forschung hat gezeigt, dass sie nicht bösartig sind; ihre Angriffe dienen allein dem Zweck am Leben zu bleiben, genau wie bei jedem humanoiden Jäger. Einige Gelehrte glauben, dass Gedankenfresser das endgültige Schicksal von Psionikern sind, nachdem sie gestorben sind.'),
  ecology         = COALESCE(ecology, 'Gedankenfresser tragen keine Schätze. Wenn einer stirbt, fällt er automatisch aus dem Äther heraus und materialisiert sich auf der Materiellen Hauptebene. Natürlich werden sie gewöhnlich als Schnabeltiere abgetan, die an Verhungerung gestorben sind.'),
  no_appearing    = COALESCE(no_appearing, '1-3')
WHERE id = '5306a302-6296-44eb-8513-38230d49d99f' AND is_custom = FALSE;

-- Thri-kreen (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die oben angegebenen Werte gelten für geschlechtsreife erwachsene Thri-kreen. Andere haben die folgenden Fähigkeiten, basierend auf ihrem Alter (sie altern eine Alterskategorie pro Jahr, bis sie geschlechtsreife Erwachsene erreichen):'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Mehrzahl der Thri-kreen sind Jäger, die sich hauptsächlich darum sorgen, genügend Beute zu finden, um das Rudel zu versorgen. Thri-kreen-Jäger greifen selten andere empfindungsfähige Wesen als Nahrung an, aber sie werden sich verteidigen, wenn sie angegriffen werden. Einige Thri-kreen sind vom Jagen abgewichen und haben mit dem Plündern begonnen, diese Thri-kreen sind die Geißel aller anderen Kreaturen. Thri-kreen greifen in einer gut koordinierten Gruppe an, schwächen ihre Feinde generell mit Psionik und Fernkampfwaffen, bevor sie sich im Nahkampf engagieren. Sie pirschen auch Beute an und sind unerbittlich in ihrer Verfolgung. Da Thri-kreen nicht schlafen, ist ihre Fähigkeit im Belagerungskampf überlegen. Eine Plündertruppe kann einen Angriff lange fortsetzen, nachdem ihre Gegner ermüdet sind. Obwohl Thri-kreen die meisten Schlachten durch Gewalt gewinnen können, gewinnen sie manche durch Zermürbung und Ausdauer.'),
  habitat_society = COALESCE(habitat_society, 'Thri-kreen schlüpfen aus Eiern. Die, die aus derselben Gruppe von Eiern schlüpfen, werden als ein Gelege betrachtet. Die Bindung eines Gelegegenossen geht über Familie oder Freundschaft hinaus. Wenn Thri-kreen in die humanoide Gesellschaft eintreten, fühlen sie sich immer noch verpflichtet, zu einem Gelege zu gehören und akzeptieren oft Humanoide als Gelegegenossen.'),
  ecology         = COALESCE(ecology, 'Thri-kreen sind Fleischfresser. Sie jagen selten andere intelligente Kreaturen als Nahrung, aber werden dies in Zeiten der Not tun. Mantis-Krieger haben einen bekannten Geschmack für Elfen, was beide Rassen bestenfalls in einem unruhigen Frieden hält. Wenn sie plündern statt einfach zu jagen, sind Thri-kreen selten an Gegenständen mit monetärem Wert interessiert, konzentrieren sich gewöhnlich auf die Dinge, die sie essen können. Thri-kreen-Rudel tragen wenig bei sich, was als Schatz betrachtet werden könnte, obwohl ihre Waffen und Werkzeuge von einigen als wertvoll betrachtet werden. Thri-kreen-Chitin kann auch für Rüstung von Humanoiden verwendet werden, wenn Sorgfalt angewendet wird.'),
  no_appearing    = COALESCE(no_appearing, '2d12')
WHERE id = 'a4a44e6f-b8ae-4d82-9dd2-62a1da4e63ec' AND is_custom = FALSE;

-- Treant (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Baumhirten sind auf seltsame Weise sowohl mit Menschen als auch mit Bäumen verwandt und vereinen Merkmale beider Arten. Von Natur aus friedlich, können Baumhirten großen Schaden anrichten, wenn sie zum Zorn gereizt werden. Sie hassen böse Dinge und den ungezügelten Gebrauch von Feuer.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Kampffähigkeit von Baumhirten variiert mit ihrer Größe. Junge Baumhirten (4,0 m) haben 7 oder 8 Trefferwürfel und fügen 2-16 Schadenspunkte pro Angriff zu. Baumhirten mittleren Alters (4,6 m) haben entsprechend 9 oder 10 Trefferwürfel und fügen 3-18 Schadenspunkte pro Angriff zu. Ältere Baumhirten (5,2 m) haben 11 oder 12 Trefferwürfel und fügen 4-24 Schadenspunkte pro Angriff zu.'),
  habitat_society = COALESCE(habitat_society, 'Baumhirten leben in kleinen Gemeinschaften, meist inmitten alter Laubwälder (Eiche, Ahorn, Mahagoni usw.). Im Wald zeigen sich Baumhirten selten, da sie es vorziehen, nicht mit vergänglicheren Lebensformen zu interagieren (allem mit einer Lebensspanne von 500 Jahren oder weniger). Menschen und Halbmenschen haben nur eine geringe Chance, einen Baumhirten zu entdecken, der versucht, mit den Bäumen zu verschmelzen. Waldläufer haben eine faire Chance, einen Baumhirten zu entdecken (10% pro Stufe).'),
  ecology         = COALESCE(ecology, 'Baumhirten gewinnen wie alle Bäume ihre Nahrung durch Photosynthese. Baumhirten schlafen oft für lange Zeiträume (von einigen Tagen bis zu mehreren Jahren), während derer kurze Wurzeln in den Boden unter ihnen wachsen und Wasser und Mineralien aus dem Erdreich sammeln. Die Fortpflanzung erfolgt über Ableger-Stängel, die die weiblichen Baumhirten dann schützen und pflegen, bis die Stängel ausgewachsen sind.'),
  no_appearing    = COALESCE(no_appearing, '1-20')
WHERE id = 'bdb902ce-c5b7-4211-b5ae-729a9692224f' AND is_custom = FALSE;

-- Troglodyte (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Troglodyten sind eine kriegerische Rasse fleischfressender reptilienartiger Humanoider, die in natürlichen unterirdischen Höhlen und in den Rissen und Spalten von Bergen leben. Sie hassen Menschen über alle anderen Kreaturen und führen oft blutige Raubzüge gegen menschliche Gemeinden durch, auf der Suche nach Nahrung und Stahl.'),
  combat_tactics  = COALESCE(combat_tactics, 'Fünfzig Prozent einer Troglodyten-Streitmacht verwenden ihre Zähne und Klauen. Die verbleibenden 50% verwenden Waffen: Schwerter (5%), steinerne Streitäxte (10%), steinerne Morgensterne (10%), oder zwei Troglodyten-Speere (25%). Von besonderer Bedeutung ist der Troglodyten-Speer. Diese großen Wurfpfeile gewähren einen +3 Bonus auf den Angriffswurf, wenn sie von einem Troglodyten geworfen werden; sie verursachen 2W4 Schadenspunkte. Dieser Bonus spiegelt die große Geschicklichkeit der Troglodyten mit diesen Wurfpfeilen wider. Etwa 25% der Troglodyten tragen je zwei solcher Wurfpfeile.'),
  habitat_society = COALESCE(habitat_society, 'Die Troglodyten-Gesellschaft ist in Clans organisiert, wobei jeder Clan von einem Häuptling geführt wird (gewöhnlich der größte und furchteinflößendste Troglodyt). Eine Anzahl von Unterhäuptlingen ist ebenfalls vorhanden, ausgewählt aus jenen Troglodyten, die sich im Kampf am meisten ausgezeichnet haben. Der Rang ist locker und interne Streitigkeiten häufig. Die meisten Häuptlinge führen nur solange, wie der Clan satt bleibt (und keine Mahlzeit länger).'),
  ecology         = COALESCE(ecology, 'Als strikte Fleischfresser bevorzugen Troglodyten Menschenfleisch über alle anderen, aber sie zögern nicht, praktisch alles zu verschlingen, was sie fangen können, einschließlich Mitgliedern anderer Troglodyten-Clans. Wenige Kreaturen jagen Troglodyten, denn ihr Geschmack soll noch widerlicher sein als ihr Geruch.'),
  no_appearing    = COALESCE(no_appearing, '10-100')
WHERE id = '270b4417-aacd-43a8-bfd4-5b9b42bf1f45' AND is_custom = FALSE;

-- Troll (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Trolle sind scheußliche Fleischfresser, die in allen Klimazonen zu finden sind, von arktischen Ödlanden bis zu tropischen Dschungeln. Die meisten Kreaturen meiden diese Bestien, da Trolle keine Furcht kennen und ununterbrochen angreifen, wenn sie hungrig sind. Ihr Körperbau wirkt dünn und zerbrechlich, aber Trolle besitzen überraschende Stärke. Ihre Arme und Beine sind lang und ungeschickt. Die Beine enden in großen dreizehigen Füßen, die Arme in breiten, kraftvollen Händen mit geschärften Klauen. Die gummiartige Haut der Trolle ist moosgrün, grün-grau gesprenkelt oder faulig grau gefärbt. Eine sich windende haarähnliche Masse wächst aus ihren Schädeln und ist meist grünlich-schwarz oder eisengrau. Ihre stumpfen, eingesunkenen schwarzen Augen besitzen 27,4 m Infrasicht. Weibchen sind leicht von den Männchen zu unterscheiden; sie sind sowohl größer als auch kraftvoller als ihre männlichen Artgenossen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Trolle greifen mit zwei bekrallten Händen und ihrem Biss an und können mehrere Gegner gleichzeitig attackieren. In dem seltenen Fall, dass ein Troll eine Waffe führt, greift er mit einem Schadensbonus von +8 an. Trolle regenerieren mit erstaunlicher Geschwindigkeit. Beginnend drei Runden nach dem ersten Blutvergießen, erholt sich die Kreatur um 3 Trefferpunkte pro Runde, bis sie geheilt ist. Trolle, die auf 0 oder weniger Trefferpunkte reduziert werden, fallen zu Boden, kampfunfähig aber nicht getötet. Kampfunfähige Trolle regenerieren weiter und stehen wieder auf zum Kampf, sobald sie eine positive Anzahl von Trefferpunkten haben.'),
  habitat_society = COALESCE(habitat_society, 'Trolle können in allen Klimazonen überleben, bevorzugen aber dichte Wälder und unterirdische Orte, da helles Sonnenlicht ihre Augen schmerzt; Trolle erleiden deswegen keine Kampfnachteile. Sie errichten ihre Baue normalerweise in Höhlen und verwenden große Felsbrocken, um die Eingänge zu blockieren. Innerhalb einer Trollhöhle befinden sich mehrere grobe Nester aus Stroh und Gras sowie verstreute Knochen und Schätze von Opfern. Wenn es in einem Gebiet keine Höhlen gibt, graben sich Trolle ein Trollloch und bedecken dessen Öffnung mit Zweigen und Blättern. Trolllöcher werden normalerweise in der Nähe von Bäumen gebaut und sind zu 90% nicht entdeckbar. Jeder, der auf ein Trollloch tritt, fällt zu 75% durch die belaubte Tür und stürzt in die darunter liegende Höhle.'),
  ecology         = COALESCE(ecology, 'Trolle jagen alle Kreaturen außer den mächtigsten. Sie respektieren und fürchten Drachen, aber sie hassen Riesen guter Gesinnung und führen häufig Krieg gegen sie. Das grüne Blut der Trolle wird zur Herstellung sowohl von Giftgegenmitteln als auch von Heiltrünken verwendet. Das Blut von einem Troll im Wert von 400 GM kann drei solche Tränke herstellen.'),
  no_appearing    = COALESCE(no_appearing, '1-12')
WHERE id = '1b08f873-2cee-422d-8f1c-17099381f8a9' AND is_custom = FALSE;

-- Umber Hulk (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Braunschatten sind mächtige unterirdische Räuber, deren eisenharte Klauen es ihnen ermöglichen, sich auf der Suche nach Beute durch festen Stein zu graben.'),
  combat_tactics  = COALESCE(combat_tactics, 'Trotz all ihrer monströsen Eigenschaften sind Braunschatten intelligente Gegner. Gewöhnlich graben sie sich zu einem Punkt neben einem Hauptkorridor, warten dann und spähen durch einen Riss, den sie gemacht haben, bis wahrscheinliche Beute vorbeigeht. Der Braunschatten springt dann auf sein erschrecktes Opfer heraus. Bei Anwendung dieser Technik haben Gegner einen Modifikator von -5 auf ihre Überraschungswürfe. Andere Taktiken umfassen geplante Höhleneinstürze und Sackgassentunnel, wo ein Braunschatten warten kann, bis Opfer zu ihm kommen. Ihre Grabgeschwindigkeit variiert von 3 m pro Runde in festem Stein bis zu 18,3 m pro Runde in weicher Erde.'),
  habitat_society = COALESCE(habitat_society, 'Braunschatten leben in den Tiefen der Erde. Sie überfallen Verliese auf Nahrungssuche, ähnlich wie Ameisenbären Ameisenkolonien überfallen, fressen sich satt und ziehen dann weiter, um die "Kolonie" sich erholen zu lassen.'),
  ecology         = COALESCE(ecology, 'Braunschatten fressen junge Purpurwürmer, Ankhege und ähnliche Kreaturen. Ihre bevorzugte Beute ist jedoch die Menschheit.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = 'a8c3c8f9-48d8-438a-85da-387e1a8ffc94' AND is_custom = FALSE;

-- Unicorn (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Einhörner leben nur in gemäßigten Waldgebieten, fernab menschlicher Behausungen. Diese wilden aber guten Kreaturen meiden den Kontakt mit allen außer Waldkreaturen (Dryaden, Feen, Kobolde und ähnliche); jedoch werden sie sich zeigen, um ihre Waldheimat zu verteidigen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Einhörner können einen Feind aus 219,5 m Entfernung spüren. Ebenso bewegen sich Einhörner sehr leise, so dass Gegner eine Strafe von -6 auf ihre Überraschungswürfe erhalten. Einhörner können mit ihren Vorderhufen ausschlagen und mit dem Horn stoßen, beides jede Runde. Aufgrund der magischen Natur des Horns hat es immer einen +2 Bonus zum Treffen. Einhörner können in den Kampf stürmen und das Horn wie eine Lanze verwenden. Um diesen Sturmangriff auszuführen, müssen mindestens 9,1 m freier Raum zwischen dem Einhorn und seinem Gegner liegen. Gegner, die von einem stürmenden Einhorn getroffen werden, erleiden 3-36 Schadenspunkte durch Aufspießen. Einhörner können nicht mit ihren Vorderhufen angreifen in der Runde, in der sie stürmen.'),
  habitat_society = COALESCE(habitat_society, 'Einhörner paaren sich fürs Leben und machen ihr Zuhause in einer offenen Waldlichtung des Forstes, den sie zu schützen gewählt haben. Dort, in die Stämme der Bäume, ritzen Einhörner eine Glyphe, erkennbar für Waldkreaturen, die anzeigt, dass der Wald unter Einhornschutz steht. Waldläufer haben eine 10%-Chance pro Stufe, korrekt zu bestimmen, ob ein Wald von Einhörnern bewacht wird. Sobald ein Wald einen Einhornbeschützer hat, wird kein anderes Einhorn diesen Wald betreten, es sei denn, der Wald ist sehr groß. Jede Familie von Einhörnern steckt ein Territorium von ungefähr 1036 Quadratkilometern ab.'),
  ecology         = COALESCE(ecology, 'Einhörner sind Pflanzenfresser, die von zarten Blättern und Gräsern leben. Ihre einzigen Feinde sind Greifen und jene Kreaturen, die Wälder zerstören, insbesondere Rote Drachen und Orks.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '760e55a6-1f37-447b-a84b-d16e08169ba5' AND is_custom = FALSE;

-- Urd (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese aggressiven, fliegenden Humanoiden sind entfernt mit Kobolden verwandt.'),
  combat_tactics  = COALESCE(combat_tactics, 'Urds jagen nachts in großen Schwärmen und nutzen ihre Infrasicht (18,3 m Reichweite), um Beute am Boden zu erspähen. Urds greifen an, indem sie Steine auf ihre Opfer fallen lassen. Diese "Steinbomben" wiegen 0,9 bis 1,4 kg pro Stück und sind mit gezackten Kanten und Vorsprüngen bedeckt. Urds lassen diese Steine mit großer Genauigkeit fallen. Nichtsahnende Opfer werden für den Angriffswurf als RK 10 behandelt. Aktiv ausweichende Gegner gelten als RK 2 vor Modifikationen durch Geschicklichkeit. Jeder Stein, der trifft, verursacht 2W4 Schadenspunkte. Etwa 75% der angetroffenen Urds tragen je eine Steinbombe. Die restlichen 25% tragen leichte Speere, die entweder als Speere oder als Wurfspieße verwendet werden können. Diese leichten Speere verursachen 1W4 Schadenspunkte pro Treffer.'),
  habitat_society = COALESCE(habitat_society, 'Urds leben in erweiterten Familien, die Gens genannt werden. Eine einzelne Gens kann 300 oder mehr erwachsene Männchen und Weibchen enthalten, plus eine Anzahl von Jungen und Eiern, die 50 Prozent der gesamten erwachsenen Population entspricht. Jede Gens wird von einem erblichen Häuptling kontrolliert, der beiden Geschlechts sein kann.'),
  ecology         = COALESCE(ecology, 'Urds legen wenig Wert auf Gold und andere schwere Metalle, da diese für Urds schwierig mitzufliegen sind. Sie schätzen fein gefertigte Lederrüstungen und handeln gerne für solche Gegenstände.'),
  no_appearing    = COALESCE(no_appearing, '3-300')
WHERE id = 'fb338773-ec81-4dbb-bf7f-a1d0ab8c1695' AND is_custom = FALSE;

-- Vampire (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Von allen chaotisch bösen untoten Kreaturen, die durch die Welt wandeln, ist keine furchtbarer als der Vampir. Lautlos durch die Nacht ziehend, machen Vampire ohne Gnade oder Mitleid Jagd auf die Lebenden. Außer wenn sie sich tief unter der Erde befinden, müssen sie zu den Särgen zurückkehren, in denen sie die Tagesstunden verbringen, und selbst im ersteren Fall müssen sie gelegentlich dorthin zurückkehren, um zu ruhen, denn ihre Macht wird durch Kontakt mit Erde aus ihren Gräbern erneuert.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn sie in Kampf verwickelt sind, sind Vampire wilde und furchtbare Gegner. Sie sind körperlich sehr stark, mit einem Stärke-Wert von 18/76, und erhalten einen Bonus von +2 auf Angriffe und +4 auf Schaden. Die zerschmetternden Schläge eines Vampirangriffs sind so heftig, dass sie 5-10 Schadenspunkte verursachen.'),
  habitat_society = COALESCE(habitat_society, 'Vampire leben in Gebieten des Todes und der Verwüstung, wo sie nicht an die Leben erinnert werden, die sie zurückgelassen haben. Ruinierte Schlösser oder Kapellen und große Friedhöfe sind beliebte Baue für sie, ebenso wie Stätten großer Tragödien oder Schlachten. Vampire fühlen oft eine starke Bindung zu bestimmten Gebieten mit morbider Bedeutung, wie dem Grab eines Selbstmörders oder dem Ort eines Mordes.'),
  ecology         = COALESCE(ecology, 'Der Vampir hat keinen Platz in der Welt lebender Kreaturen. Er ist ein Wesen der Finsternis, das nur existiert, um Böses und Chaos zu bringen. Fast ohne Ausnahme wird der Vampir von jenen gefürchtet und gehasst, die in den Regionen wohnen, in denen er sich entscheidet, sein Heim zu errichten. Die unnatürliche Gegenwart des Vampirs ist allgegenwärtig und wird Hunde und ähnliche Tiere dazu bringen, einen Alarmruf bei der Anwesenheit der Kreatur zu erheben.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '1f5f82ef-c0c2-430f-881e-467200e28331' AND is_custom = FALSE;

-- Weasel (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wiesel sind in den gemäßigten Wäldern der Welt weit verbreitet und in vielen unterirdischen Umgebungen anzutreffen. Es gibt zahlreiche Arten, aber sie ähneln sich alle in Aussehen und Gewohnheiten.'),
  combat_tactics  = COALESCE(combat_tactics, 'In der Regel greifen gewöhnliche Wiesel nicht an, es sei denn, sie werden in die Enge getrieben oder überrascht. Wenn sie jedoch zuschlagen, können ihre große Geschwindigkeit und ihre zuckenden Bewegungen sie etwas gefährlich machen. In den meisten Fällen beißen sie jedoch einmal zu und fliehen dann, bevor sich ihr Gegner erholt.'),
  habitat_society = COALESCE(habitat_society, 'Wiesel sind Einzelgänger, die Nagetiere und ähnliche kleine Tiere als Nahrung jagen. Wenn zwei Tiere angetroffen werden, handelt es sich oft um ein Pärchen.'),
  ecology         = COALESCE(ecology, 'Bei der Jagd greift das Wiesel gewöhnlich Tiere an, die größer sind als es selbst. Ein häufiges Ziel in besiedelten Gebieten sind domestiziertes Geflügel und ähnliche Vögel. Trotzdem leistet das gewöhnliche Wiesel den Bauern einen großen Dienst, indem es sich von kleinen Tieren ernährt, die andernfalls ihre Ernte schädigen oder zerstören könnten.'),
  no_appearing    = COALESCE(no_appearing, '1-2')
WHERE id = '64dabe1f-c354-4fb9-8dc7-e877601ba3af' AND is_custom = FALSE;

-- Wemic (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wemics sind die löwenartigen Gegenstücke zu Zentauren. Der Körper eines Wemic besteht aus einem Löwenkörper mit einem humanoiden Oberkörper, der dort entspringt, wo bei einem Löwen der Hals wäre. Ein typischer Wemic misst 3 m von Kopf bis Hinterteil. Wenn er sich in zentaurenartiger Haltung aufrichtet, ist der Wemic 1,8 bis 2,1 m groß. Der größte Teil des Körpers ist von dunklem, goldenem Fell bedeckt. Der Schwanz endet in einem Büschel aus langem, schwarzem Haar. Ausgewachsene Männchen haben außerdem eine Mähne aus langem schwarzem Haar; die Mähne bedeckt die Ober- und Rückseite des Kopfes und erstreckt sich bis zu Hals und Schultern. Männliche Jungtiere entwickeln diese Mähne in ihrem dritten Lebensjahr. Der Bauch ist mit kurzem, weißem Fell bedeckt. Die Nase kann schwarz oder rotbraun sein. Die Augen sind golden mit vertikal geschlitzten Pupillen. Die Zehen aller Gliedmaßen enden in Krallen. Die Krallen der Vorderbeine sind einziehbar.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wemics verwenden Vorderpfoten und Waffen zum Angriff. Eine Kralle führt einen bösartigen Schlag aus, der 1W4 Schadenspunkte verursacht. Normalerweise benutzt der Wemic seine Vorderbeine zum Kratzen und verwendet seine Hände, um eine Waffe zu führen.'),
  habitat_society = COALESCE(habitat_society, 'Die Gesellschaft der Wemics ist eine Mischung aus löwenartiger und ursprünglich menschlicher Kultur. Sie leben in Gruppen, die Rudel genannt werden. Ein typisches Rudel besteht aus 4W4 ausgewachsenen Männchen, 2W12 ausgewachsenen Weibchen und 1W12 Jungtieren. Bis zu 3W10 Rudel schließen sich oft zu einem Stamm zusammen, der von einem Häuptling angeführt wird. Der Häuptling hat eine Rüstungsklasse von 5, 6+4 Trefferwürfel, und seine Krallen verursachen 1W6 Schadenspunkte. Er erhält einen +1 Bonus auf seine Angriffswürfe mit jeder Waffe.'),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '2-16')
WHERE id = 'a8514d4e-2938-44c4-9911-3df9cd849556' AND is_custom = FALSE;

-- Whale (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Wale sind die größten Meeressäugetiere. Sie sind hochintelligente Kreaturen, die eine Reihe ökologischer Nischen besetzen. Zu den gewöhnlichen Walen gehören Plankton-Fresser wie Blau- oder Buckelwale und Fleischfresser wie Pottwale.'),
  combat_tactics  = COALESCE(combat_tactics, 'Alle gewöhnlichen Wale können mit ihren Schwänzen angreifen. Diese können einen zerschmetternden Schlag versetzen, der Schaden in Höhe der Hälfte der Trefferwürfel des Wals verursacht.'),
  habitat_society = COALESCE(habitat_society, 'Wale leben in stammesähnlichen Versammlungen, die Schulen genannt werden. Sie pflegen starke persönliche und familiäre Bindungen. Ihre Kultur basiert auf komplexen Gesängen, die unter Wasser meilenweit zu hören sind. Wale sind neugierig auf Humanoide, aber wenn sie angegriffen werden, können sie zu tödlichen Feinden werden. Wale beginnen selten einen Kampf. Wale sind neugierig auf andere intelligente Wesen. Sie begrüßen die Kommunikation mit anderen Lebewesen. Sie lügen nicht, aber sie offenbaren möglicherweise nicht alles, was sie wissen.'),
  ecology         = COALESCE(ecology, 'Obwohl sie in ihrer Gesinnung gegenüber Humanoiden neutral sind, ist ihre Gesinnung gegenüber dem Meeresleben im Allgemeinen rechtschaffen gut. Mit ihrer gewaltigen Größe, Kraft und Vielfalt sind sie die Herrscher des Meeres. Sie bewahren die Ordnung durch ihre Konflikte mit böse gesinnten Seeungeheuern.'),
  no_appearing    = COALESCE(no_appearing, '1-8')
WHERE id = '1682bf0c-cdda-4f3c-9246-a41393c41bef' AND is_custom = FALSE;

-- Wight (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'In längst vergangenen Zeiten bedeutete das Wort "wight" einfach "Mann". Im Laufe der Jahrhunderte ist es jedoch ausschließlich mit jenen Untoten in Verbindung gebracht worden, die typischerweise Grabhügel und Katakomben bewohnen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Gruftschrecken sind wilde und tödliche Gegner im Kampf. Wenn sie angegriffen werden, werden sie von keinen Waffen verletzt, die nicht aus Silber geschmiedet oder auf irgendeine Weise verzaubert sind.'),
  habitat_society = COALESCE(habitat_society, 'Wie die anderen Untoten, die die Welt heimsuchen, leben Gruftschrecken in Grabhügeln, Katakomben und anderen Grabstätten. Sie verabscheuen Licht und Orte, die von lebendigen Dingen erfüllt sind. Als Regel ist der Gruftschrecken hasserfüllt und böse und sucht seinen Hass auf das Leben zu befriedigen, indem er alle tötet, denen er begegnet.'),
  ecology         = COALESCE(ecology, 'Wie alle Untoten existieren Gruftschrecken gleichzeitig sowohl auf der Primären Materiellen als auch auf der Negativen Materiellen Ebene. Es ist diese mächtige Verbindung zur negativen Welt, die ihnen ihre furchteinflößende Stufenentzug-Fähigkeit verleiht. Weiterhin ist es dieser Entzug, der ihnen Nahrung verschafft.'),
  no_appearing    = COALESCE(no_appearing, '2-16 (2d8)')
WHERE id = '64d954e4-3f82-475b-b92f-f5bfb63a9dbb' AND is_custom = FALSE;

-- Will O'Wisp (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Das Irrlicht ist eine bösartige Entität, die ihr Zuhause in Sümpfen, Mooren und Moorlandschaften hat. Es ernährt sich, indem es ahnungslose Kreaturen in den Tod zwischen den natürlichen Gefahren solcher Orte lockt und sich von den Energien nährt, die ihre Todeskämpfe freisetzen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Grundsätzlich versuchen Irrlichter körperlichen Kampf mit anderen Kreaturen zu vermeiden und bevorzugen es, sie stattdessen in den Tod in den sie umgebenden Sümpfen zu führen. Wenn sie jedoch in die Enge getrieben werden, sind sie gefährliche Gegner, die mit größter Vorsicht angegriffen werden müssen. Im Kampf glühen sie blau, violett oder blassgrün.'),
  habitat_society = COALESCE(habitat_society, 'Größtenteils werden Irrlichter allein angetroffen. Bei seltenen Gelegenheiten (10% der Zeit) können Gruppen von bis zu drei in der Nähe eines besonders fruchtbaren Jagdgebiets gefunden werden. Im letzteren Fall werden sie zusammenarbeiten, um Opfer in die Fallen zu locken, die sie arrangiert haben.'),
  ecology         = COALESCE(ecology, 'Obwohl schwer mit Sicherheit zu sagen, deuten Beweise darauf hin, dass sich das Irrlicht von der Wut elektrischer Aktivität nährt, die von den Gehirnen panikerfüllter Individuen abgegeben wird, wenn sie erkennen, dass der Tod unvermeidlich ist. Um das Leiden ihrer Opfer zu verlängern und die Menge der "Nahrung" zu erhöhen, die sie abgeben, locken Irrlichter ihre Opfer typischerweise in Gebiete wie Treibsandgruben, die einen langsamen und furchteinflößenden Tod versprechen.'),
  no_appearing    = COALESCE(no_appearing, '1 or 1-3')
WHERE id = '42743a2d-925c-45a2-8d74-335d9552b508' AND is_custom = FALSE;

-- Wolverine (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Auch als Carcajou, Quickhatch und Glutton bekannt, ist dieses wilde Tier seit Anbeginn der Zeit die Geißel vieler arktischer Kulturen gewesen.'),
  combat_tactics  = COALESCE(combat_tactics, 'Wenn er in den Kampf zieht, wird der Vielfraß zu einem äußerst furchteinflößenden Gegner. Seine große Geschwindigkeit macht ihn schwer zu treffen (daher seine ordentliche Rüstungsklasse) und verleiht ihm einen +4 Bonus auf seinen Angriffswurf.'),
  habitat_society = COALESCE(habitat_society, 'Vielfraße sind Einzelgänger, die durch die Wälder kälterer Klimazonen wandern. Gelegentlich findet man sie auch in gemäßigteren Waldgebieten. Manchmal können zwei Vielfraße zusammen angetroffen werden, aber es handelt sich fast immer um ein Pärchen, das schon bald getrennte Wege gehen wird.'),
  ecology         = COALESCE(ecology, 'Zum größten Teil sind Vielfraße Fleischfresser, die kleine Säugetiere und Nagetiere als Beute nehmen. In Zeiten, in denen Nahrung knapp ist, ernähren sie sich von Aas, wenn sie keine eigenen Jagdtöt machen können. Darüber hinaus sind Vielfraße klug und geschickt darin, die von Menschen aufgestellten Fallen zu plündern.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '1043f9e8-a10b-48bb-bc8b-1346ad5fb4f0' AND is_custom = FALSE;

-- Worm (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Obwohl sie in der Größe stark variieren, haben alle Würmer in dieser Auflistung einige gemeinsame Eigenschaften. Sie sind alle Gräber mit langen, zylindrischen Körpern.'),
  combat_tactics  = COALESCE(combat_tactics, NULL),
  habitat_society = COALESCE(habitat_society, NULL),
  ecology         = COALESCE(ecology, NULL),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '41d90f49-43cb-4e81-9cd4-0f925d1d9d3a' AND is_custom = FALSE;

-- Wraith (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Der Schatten ist ein böser untoter Geist eines mächtigen Menschen, der menschliche Lebensenergie zu absorbieren sucht.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Berührung eines Schattens verursacht auf zwei Arten Schaden. Erstens fügt die frostende Wirkung der Berührung 1-6 Schadenspunkte zu, sogar bei Kreaturen, die immun gegen Kälte sind. Zweitens entzieht ein solcher Treffer dem Opfer eine Erfahrungsstufe. Dies schließt Trefferpunkte und alle Fähigkeiten ein, die mit dieser Stufe verbunden sind, wie Zauberwirken oder Kampffähigkeit. Der Schaden durch die Kälte kann normal geheilt werden, aber die Erfahrungspunkte sind für immer verloren und müssen wieder verdient oder magisch wiederhergestellt werden.'),
  habitat_society = COALESCE(habitat_society, 'Ein Schatten ist ein untoter Geist eines mächtigen, bösen Menschen. Als solcher wird er gewöhnlich in Gräbern oder Orten gefunden, wo solche Männer und Frauen gestorben wären. Da solche Männer und Frauen häufig zusammen begraben werden, im Fall der Wohlhabenden, oder mit ihren Familien, werden Schatten am häufigsten in Rudeln angetroffen. Jene, die allein starben oder begraben wurden, können trotzdem in Rudeln angetroffen werden, weil ein Mensch, der durch die Berührung eines Schattens stirbt, zu einem Schatten unter dem Einfluss seines Mörders wird. Der Schatz des Schattens sind gewöhnlich seine Besitztümer im Leben, die nun mit ihm begraben sind, oder die seiner Opfer. Schatten existieren nur, um das Böse zu verewigen, indem sie die Lebenskraft so vieler Menschen wie möglich absorbieren. Ein Charakter, der zu einem Schatten wird, ist nahezu unmöglich zu retten und erfordert eine besondere Quest.'),
  ecology         = COALESCE(ecology, 'Der Schatten hat keine eigentliche Nische und dient keinem nützlichen Zweck in der Natur und liefert keine Nebenprodukte, die andere nutzen können. Er benötigt keine Nahrung und tötet nur aus reinem Hass auf das Leben. Alle Kreaturen, die der Natur nahestehen, werden die Anwesenheit eines Schattens meiden. Er existiert mehr in der Negativen Materialebene als in der Primären Materialebene und ist daher kein natürlicher Teil dieser Welt.'),
  no_appearing    = COALESCE(no_appearing, '2-12 (2d6)')
WHERE id = 'ad8046ab-620b-4f3e-902c-9662d583c46e' AND is_custom = FALSE;

-- Wyvern (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Ein entfernter Verwandter des Drachen, der Wyvern ist eine riesige fliegende Echse mit einem giftigen Stachel in seinem Schwanz.'),
  combat_tactics  = COALESCE(combat_tactics, 'Ziemlich dumm, aber aggressiv, greifen Wyverns fast immer an. Im Kampf bevorzugt der Wyvern stets das Fliegen und wird jede Gelegenheit nutzen, sich in die Luft zu erheben und den Kampf fortzusetzen. Wenn er am Boden gefangen ist, beißt er (2-16 Schadenspunkte) und verwendet seinen Stachel (1-6 Schadenspunkte), wobei er das bequemste Ziel oder die bequemsten Ziele angreift. Der Schwanz ist sehr beweglich und kann leicht über den Rücken des Wyverns hinweg einen Gegner vor ihm treffen. Der Stachel injiziert Gift (Typ F) in die Wunde, gegen das das Opfer einen Rettungswurf gegen Gift bestehen muss oder stirbt. Selbst wenn der Rettungswurf erfolgreich ist, erleidet das Opfer 1-6 Punkte körperlichen Schaden durch den Stich.'),
  habitat_society = COALESCE(habitat_society, 'Der Wyvern ist ein Einzelgänger, der nur mit seinem Partner und seinen Jungen nistet. Er legt seinen Bau gern an Berghängen an, die Wälder, Dschungel oder manchmal Ebenen überblicken. Ein Wyvern macht seinen Bau in großen Höhlen, die an solchen Orten zu finden sind, und beansprucht ein Territorium von etwa 40,2 km Durchmesser. Wenn Wild knapp ist, jagt er mit einer kleinen Gruppe seiner eigenen Art. Nur junge Wyverns greifen andere ihrer Art an, normalerweise um neues Territorium zu etablieren. Ältere Wyverns lösen Streitigkeiten auf unbekannte Weise ohne tatsächlichen Kampf.'),
  ecology         = COALESCE(ecology, 'Ein erwachsener Wyvern verzehrt täglich das Äquivalent einer menschengroßen bis großen Kreatur. Das könnte ein Pferd, Schwein oder eine Handvoll Schafe bedeuten. Während er sie ganz frisst, werden die Knochen nicht verdaut, ebenso wenig wie Metallgegenstände. Der Wyvern frisst nur im Notfall Aas.'),
  no_appearing    = COALESCE(no_appearing, '1-6')
WHERE id = '33d7a62a-4208-4fe8-9f21-cf0d1c30c699' AND is_custom = FALSE;

-- Xorn (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Xorn sind auf der Elementarebene der Erde beheimatet.'),
  combat_tactics  = COALESCE(combat_tactics, 'Xorn greifen Fleischkreaturen nicht an, außer um sich selbst oder ihr Eigentum zu verteidigen, da sie Fleisch nicht verdauen können. Xorn hegen weder übermäßige Liebe noch Hass für Kreaturen der Primären Materialebene. Die einzige Ausnahme davon sind Personen, die eine beträchtliche Menge an Edelmetallen oder Mineralien mit sich führen, die sie bis zu 6,1 m weit riechen können. Die normalerweise friedlichen Xorn können recht aggressiv werden, wenn sie auf Nahrungssuche sind, besonders auf der Primären Materialebene, wo solche Nahrung schwerer zu finden ist als auf ihrer heimatischen Ebene. Xorn erwarten, dass ihnen ein angemessener Anteil für freien Durchgang gegeben wird, oder sie greifen an 90% Wahrscheinlichkeit, um an Nahrung zu gelangen.'),
  habitat_society = COALESCE(habitat_society, 'Ein Xorn wird normalerweise auf der Elementarebene der Erde gefunden. Er ist nur auf der Primären Materialebene, wenn er gewaltsam herbeigerufen wurde oder das Opfer eines interplanaren Unfalls war.'),
  ecology         = COALESCE(ecology, 'Auf der Primären Materialebene sind sie Besucher, die keine ökologische Funktion erfüllen. Auf ihrer eigenen Ebene sind sie Sammler, die nur Stein und Mineralien fressen. Die leeren Taschen im Stein werden schnell von verschiedenen Kreaturen der Ebene bewohnt. Dao jagen sie bekanntermaßen zum Vergnügen. Ebenso oft dienen Xorn den Dao als Sklaven.'),
  no_appearing    = COALESCE(no_appearing, '1-4')
WHERE id = '06417257-3e71-4507-b673-33aa7e149834' AND is_custom = FALSE;

-- Yellow Musk Creeper (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Die Gelbe Moschusschlingpflanze ist eine Pflanze, die Humanoide angreift, ihre Intelligenz entzieht und sie in Gelbe Moschuszombies verwandelt. Der Zombie dient der Pflanze für etwa zwei Monate und stirbt dann, wodurch die neue Pflanze, die in seinem Kopf eingebettet ist, sich von dem Körper ernähren kann.'),
  combat_tactics  = COALESCE(combat_tactics, 'Die Schlingpflanze ruht, es sei denn, eine Kreatur bewegt sich in 3 m Entfernung zu ihr. Wenn das geschieht, wenden sich die nächsten Blüten der Beute zu und greifen an. Dieser Angriff ist ein Pollenstoß, der nach Moschus riecht und das Gesicht des Opfers trifft, wenn der Angriffswurf erfolgreich ist. Das Opfer muss einen erfolgreichen Rettungswurf gegen Zauber ablegen oder wird verzaubert und läuft in die Pflanze hinein. Es wird jedem Versuch widerstehen, zurückgehalten zu werden. In der Runde, nachdem es in die Schlingpflanze hineingelaufen ist, heften sich Dutzende von Wurzeln an seinen Kopf und bohren sich in zwei Runden in sein Gehirn. Jede Runde danach verliert es 1-4 Punkte Intelligenz, während sein Gehirn verschlungen wird.'),
  habitat_society = COALESCE(habitat_society, 'Die Schlingpflanze findet sich hauptsächlich in Erdgebieten im Untergrund oder in den Tiefen von Wäldern und Dschungeln, wo wenig Licht auf sie fällt. Sie kann Bäume oder Felsen erklimmen, wie gewöhnlicher Efeu. Sie wird gelegentlich absichtlich gepflanzt, um ein bestimmtes Gebiet zu bewachen. Der Zombie kann sich bis zu 30,5 m von der Schlingpflanze entfernen.'),
  ecology         = COALESCE(ecology, 'Die Schlingpflanze greift jede Kreatur an, die größer als eine Hauskatze ist und sich nähert, aber sie kann nur Zombies aus menschengroßen Humanoiden erschaffen. Sie ernährt sich von den Körpern und von der Erde, in die sie gepflanzt ist. Die Knochen oder persönlichen Gegenstände derer, die sie tötet, werden von den Zombies nahe der Wurzel begraben. Der Zombie isst nicht, da er teilweise unterstützt und am Leben gehalten wird durch den Sämling in seinem Kopf. Die einzigen natürlichen Feinde der Schlingpflanze sind Krankheiten, Insekten und Nahrungsmangel.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '21b011d8-100c-4efb-a4de-a06d60af490a' AND is_custom = FALSE;

-- Yuan-ti, Histachii (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Einst Menschen, sind Yuan-ti-Histachii geistlose Abscheulichkeiten, die in reptilienhafte Humanoide verwandelt wurden, um ihren Yuan-ti-Meistern zu dienen. Am häufigsten findet man sie als Wächter der Yuan-ti-Brutkammern.'),
  combat_tactics  = COALESCE(combat_tactics, 'Histachii greifen jede nichtreptilienhafte Kreatur oder jeden Humanoiden bei Sicht an, es sei denn, ihre Yuan-ti-Meister geben ihnen gegenteilige Befehle. Als primitive Kämpfer stürmen die meisten Histachii direkt auf ihre Gegner zu und greifen mit ihren Klauen und Zähnen an. Um ihre Yuan-ti-Meister zu beschützen, kämpfen Histachii bis zum Tod.'),
  habitat_society = COALESCE(habitat_society, 'Yuan-ti erschaffen die meisten Histachii-Diener aus menschlichen Gefangenen. Sie können auch menschliche Anbeter verwandeln, die sich freiwillig bereit erklären, Histachii zu werden. Menschen werden zu Histachii, indem sie eine Destillation aus Yuan-ti-Gift gemischt mit bestimmten Kräutern und Wurzeln trinken. (Die Yuan-ti bereiten diese spezielle Mischung zu.) Wenn ein Mensch nicht bereit ist zu trinken, drücken die Yuan-ti ihren Gefangenen zu Boden und schütten ihm die Mischung in den Rachen.'),
  ecology         = COALESCE(ecology, 'Wie Yuan-ti sind Histachii strikt fleischfressend und fressen Ratten, Würmer und anderes Ungeziefer. Sie essen auch die Reste der Yuan-ti.'),
  no_appearing    = COALESCE(no_appearing, '2-20')
WHERE id = '86bfc43d-a09f-4541-9217-0ac5e6c763a9' AND is_custom = FALSE;

-- Yugoloth, Guardian (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Diese Yugoloths werden von bösen Magiern oder Priestern beschworen, um etwas Wichtiges zu bewachen. Yugoloth-Wächter verteidigen ihren Auftrag stets mit großer Wildheit.'),
  combat_tactics  = COALESCE(combat_tactics, 'Yugoloth-Wächter können dreimal täglich Feuer in einem Kegel von 9,1 m Länge mit 3 m Basisdurchmesser speien. Der Schaden hängt von der Art des atmenden Dämons ab. Niedere und geringere Yugoloths verursachen 3W6 bzw. 5W6 Schadenspunkte, während größere Yugoloths 7W6 Punkte pro Atemangriff zufügen. Ein erfolgreicher Rettungswurf gegen Atemangriff halbiert den Schaden. Yugoloth-Wächter setzen ihren Feueratem niemals ein, wenn das Feuer dem schaden könnte, was sie zu beschützen beauftragt wurden.'),
  habitat_society = COALESCE(habitat_society, 'Yugoloth-Wächter müssen jederzeit innerhalb von 82,3 m des Objekts bleiben, das sie zu beschützen beschworen wurden. Innerhalb dieses 82,3-Meter-Radius ziehen es Yugoloth-Wächter vor, im Kampf auf Distanz zu bleiben und ihren Atemangriff optimal einzusetzen.'),
  ecology         = COALESCE(ecology, 'Die Beschwörung eines Wächter-Dämons ist eine gefährliche Angelegenheit. Es besteht eine 10%ige Chance für jede Stufe, die der Beschwörer über der 7. Stufe liegt, dass sein Ersuchen um einen Wächter-Dämon gewährt wird (maximale Chance von 90%). Umgekehrt, falls die Beschwörung fehlschlägt, besteht eine 30%ige Chance (-2% pro Stufe des Beschwörers über der 10.), dass der Dämon Anstoß nimmt und sich hereinportet, um den Zauberkundigen zu erschlagen.'),
  no_appearing    = COALESCE(no_appearing, '1')
WHERE id = '6c68fbc1-87de-4b71-aa42-07ad292fb7c7' AND is_custom = FALSE;

-- Zombie (matched by name_en)
UPDATE monsters SET
  intro_text      = COALESCE(intro_text, 'Zombies sind geistlose, animierte Leichen, die von ihren Erschaffern kontrolliert werden, meist böse Magier oder Priester.'),
  combat_tactics  = COALESCE(combat_tactics, 'Zombies bewegen sich sehr langsam und greifen immer als letztes in einer Kampfrunde an. Sie erhalten nur einfache, einsätzige Befehle. Sie kämpfen immer, bis sie zurückgerufen oder vernichtet werden, und nur ein Priester kann sie vertreiben. Sie bewegen sich in einer geraden Linie auf ihre Gegner zu, mit ausgestreckten Armen, und versuchen ihre Opfer zu Tode zu kratzen oder zu schlagen. Wie die meisten Untoten sind Zombies immun gegen Schlaf, Bezaubern, Festhalten, Todesmagie, Gifte und kältebasierte Zauber. Ein Fläschchen Weihwasser fügt einem Zombie 2-8 Schadenspunkte zu.'),
  habitat_society = COALESCE(habitat_society, 'Zombies sind normalerweise in der Nähe von Friedhöfen, Verliesen und ähnlichen Beinhäusern zu finden. Sie befolgen die gesprochenen Befehle ihres Erschaffers, wie sie vor Ort oder zuvor gegeben wurden, von begrenzter Länge und unkomplizierter Bedeutung (etwa ein Dutzend einfache Wörter). Der tote Körper jedes humanoiden Wesens kann in einen Zombie verwandelt werden.'),
  ecology         = COALESCE(ecology, 'Zombies sind keine natürlichen Schöpfungen und haben keine Rolle in der Ökologie oder Natur.'),
  no_appearing    = COALESCE(no_appearing, '3-24')
WHERE id = '2fb7e1bb-3d99-4df5-9b3d-fd8e64ed2795' AND is_custom = FALSE;

-- ─── INSERTs (new monsters not previously seeded) ───────────────────

-- Argos (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Argos',
  'Argos',
  'Unknown',
  FALSE,
  'Space/Any Earth-based body',
  'Very rare',
  'Solitary',
  'Feed till consume 2×HD, then rest 2 hours/HD',
  'Omnivore',
  'Low to High (5-14)',
  'U',
  'Neutral evil',
  '1',
  10,
  '9, Fl 3 (B)',
  '5-10',
  5,
  5,
  '3 per victim',
  '1-4',
  'See below',
  'See below',
  25,
  'L',
  'Champion (16)',
  16,
  5,
  'Argos sind in denselben Gebieten des Wildraums zu finden wie die unheilbringenden Betrachter-Nationen. Ein Argos ähnelt einer riesigen Amöbe. Er hat ein großes, zentrales Auge mit einer dreiteiligen Pupille und hundert wimpernlose, unmenschliche Augen sowie viele scharfzähnige Mäuler. Ein Argos kann mehrere Pseudopoden ausstrecken, die jeweils mit einem reißzähnigen Maul enden, das als Hand zum Handhaben verschiedener Werkzeuge dient.',
  'Ein Argos kann mit einer bis drei Waffen oder Gegenständen angreifen, oder er kann ein Opfer in einem Pseudopod umhüllen und mit 1W3 Mäulern für je 1W4 Schadenspunkte angreifen. Er kann auf diese Weise so viele Feinde angreifen, wie er physisch erreichen kann.',
  'Argos sind Einzelgänger, obwohl es nicht ungewöhnlich ist, einen Argos-Wächter an Bord eines Augentyrann-Schiffes zu entdecken. Argos scheinen fähig zu sein, ihre eigene Lufthülle aufzufüllen und können daher allein wandernd in Asteroidenringen und Staubwolken angetroffen werden.',
  'Argos verschlingen alles, was sich bewegt und verdaulich ist. Sie ziehen es vor, ihre Fähigkeiten zu nutzen, um ihre Beute in Fallen zu locken und dann Individuen einzeln herauszupicken. Er sortiert durch die Werkzeuge und Waffen seiner Opfer und behält die nützlichen Gegenstände.'
);

-- Bat (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Fledermaus',
  'Bat',
  'Unknown',
  FALSE,
  'Any land',
  'Common',
  'Swarm',
  'Night',
  'Omnivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1-100',
  8,
  '1, Fl 24 (B)',
  '1-2 hp',
  1,
  20,
  '1',
  '1',
  'See below',
  'Nil',
  0,
  'T',
  'Unsteady (5-7)',
  5,
  15,
  'Fledermäuse sind in vielen Teilen der Welt verbreitete Tiere. Während gewöhnliche Fledermäuse lästig, aber harmlos sind, können größere Arten durchaus tödlich sein.',
  'Gewöhnliche Fledermäuse greifen nur an, wenn sie in die Enge getrieben werden und keine andere Möglichkeit haben. Wenn sie aufgeschreckt werden, neigen Fledermäuse dazu, verängstigt und verwirrt zu werden. Dies führt dazu, dass sie herumschwirren und oft in Dinge hineinfliegen. Der typische Fledermausschwarm löscht letztendlich Fackeln (1% Chance pro angetroffener Fledermaus pro Runde), verwirrt das Zauberwirken (Weisheitswurf erforderlich, um Zauber zu wirken), behindert die Fähigkeit der Kämpfenden, Waffen zu führen (durch einen -2 ETW0-Malus) und stört anderweitig. Unter idealen Flugbedingungen steigt die Rüstungsklasse einer Fledermaus von 8 auf 4.',
  'Obwohl Fledermäuse fast überall anzutreffen sind, bevorzugen sie warme und feuchte Klimazonen. Einige Arten halten Winterschlaf während der kalten Jahreszeit und wenige sind dafür bekannt zu wandern. Fledermäuse leben in Höhlen, dunklen Gebäuden oder feuchten Spalten, hängen tagsüber mit den Zehen und verlassen diese in der Dämmerung, um sich nachts zu ernähren. In großen, abgelegenen Höhlen können sich Tausende von Fledermäusen aufhalten.',
  'Die meisten Fledermäuse fressen Früchte oder Insekten, obwohl einige kleine Tiere oder Fische in ihre Ernährung einschließen. Die seltene Vampirfledermaus reist nachts, um das warme Blut lebender Säugetiere zu trinken, aber ihre Opfer sind selten Menschen oder Halbmenschen. Man muss darauf achten, die Vampirfledermaus nicht mit dem echten Vampir zu verwechseln. Fäulnismaden und Aaskriecher gehören zu den wenigen Kreaturen, die bekanntermaßen im Guano auf dem Boden großer, von Fledermäusen befallener Höhlen leben, was jede Expedition in solche Höhlen wahrhaft gefährlich macht. Wenn der üble Geruch des Guanos nicht ausreicht, um die härtesten Abenteurer zu bezwingen (ein einziger Konstitutionswurf, um bei Bewusstsein zu bleiben), dann sind es diese kriechenden Bewohner.'
);

-- Bear (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
