  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Bär',
  'Bear',
  'Unknown',
  FALSE,
  'Temperate land',
  'Common',
  'Family',
  'Day',
  'Omnivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1-3',
  7,
  '12',
  '3+3',
  3,
  17,
  '3',
  '1-3/1-3/1-6',
  'Hug',
  'Nil',
  0,
  'M',
  'Average (8-10)',
  8,
  175,
  'Ein ziemlich verbreitetes allesfressendes Säugetier, Bären neigen dazu, Menschen zu meiden, es sei denn, sie werden provoziert. Ausnahmen von dieser Regel können ein höchst unglückliches Ereignis sein.',
  'Obwohl Schwarzbären normalerweise nicht aggressiv sind, sind sie fähige Kämpfer, wenn sie bedrängt werden. Wenn ein Schwarzbär einen Pfotenttreffer mit 18 oder besser erzielt, umklammert er auch für 2-8 (2W4) Punkte zusätzlichen Schaden.',
  'Alle Bären haben ausgezeichnete Gehör- und Geruchssinne, aber eher schlechte Sehkraft. Die angegebene Größe ist ein Durchschnitt für die Varietät, und größere Individuen werden natürlich entsprechend mächtiger sein.',
  'Alle diese Bärenartigen sind allesfressend, obwohl der gigantische Höhlenbär zu einer fleischlastigen Ernährung neigt.'
);

