-- Catoblepas (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Catoblepas',
  'Catoblepas',
  'Unknown',
  FALSE,
  'Any swamp',
  'Very rare',
  'Solitary',
  'Day',
  'Omnivore',
  'Semi- (2-4)',
  '(C)',
  'Neutral',
  '1-2',
  7,
  '6',
  '6+2',
  6,
  15,
  '1',
  '1-6 + stun',
  'Gaze causes death',
  'Nil',
  0,
  'L',
  'Steady (11-12)',
  11,
  975,
  'Der Catoblepas ist eine bizarre, widerwärtige Kreatur, die in tristen Sümpfen und Marschen lebt. Seine furchteinflößendsten Merkmale sind seine großen, blutunterlaufenen Augen, aus denen ein tödlicher Strahl ausgeht.',
  'Im Kampf verlässt sich der Catoblepas auf zwei Angriffsformen. Zunächst setzt er seinen starken, schlangenartigen Schwanz ein, um seine Feinde zu schlagen und zu betäuben. Jeder, der vom Schwanz getroffen wird, erleidet 1-6 Schadenspunkte und hat eine Grundchance von 75%, für 1-10 Nahkampfrunden betäubt zu werden. Die Grundchance, betäubt zu werden, sinkt um 5% für jede Stufe über der ersten oder für jeden zusätzlichen Trefferwürfel bei Monstern und Tieren.',
  'Größtenteils ist der Catoblepas eine umherwandelnde Kreatur, die durch ihren Sumpf wandert und an Sumpfgräsern und ähnlichem knabbert. Einmal im Monat, gewöhnlich bei Vollmond, sucht der Catoblepas nach Fleisch, um seine Ernährung zu ergänzen. Zu dieser Zeit ist es am wahrscheinlichsten, dass Abenteurer auf den Catoblepas treffen.',
  'Der Catoblepas hat keine natürlichen Feinde, da sein Blick ihm mehr als ausreichenden Schutz vor selbst den wildesten Raubtieren bietet.'
);

-- Deepspawn (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Deepspawn',
  'Deepspawn',
  'Forgotten Realms Campaign Setting, Revised Edition',
  FALSE,
  'Any',
  'Very rare',
  'Solitary',
  'Any',
  'Omnivorous',
  'Genius (17-18)',
  'K,L,M,Q×2,V×2,X',
  'Chaotic evil',
  '1',
  6,
  '6, Sw 8',
  '14',
  14,
  7,
  '6',
  '3-12 ×3 (bites)/2-5 ×3 (slaps) or by weapon type ×3',
  'See below',
  'See below',
  77,
  'H',
  'Elite (15-16)',
  15,
  12,
  'Deepspawn sind berüchtigte Schrecken, die viele andere Arten von Monstern gebären; ein einzelner Deepspawn kann ein riesiges Gebiet gefährlich machen, selbst für wachsame, gut bewaffnete Abenteurer.',
  'Wenn sie gefunden werden, sind Deepspawn gewöhnlich halb begraben in einem Haufen rutschiger, sich verschiebender Münzen und anderer Schätze. Dies kann ihre Arme verbergen, sodass Tentakel und Mäuler, die aus dem Schatz hervorbrechen, zunächst wie Angriffe separater Kreaturen erscheinen können. Der Schatz kann Gegner behindern und sogar den Deepspawn vor einigen Schäden schützen (wie vom Spielleiter bestimmt).',
  'Deepspawn lassen es vor, ihre Nachkommen für sich kämpfen zu lassen und lagern in Höhlen, Verliesen oder Ruinen, die reichlich durch Fallen und Wächtermonster (ihre „Brut") geschützt sind. Wenn diese Verteidigungen durchdrungen werden, wird der Deepspawn gewöhnlich in einem leicht zu verteidigenden Raum oder Gebiet gefunden, immer mit mindestens einem oder mehreren Fluchtrouten.',
  'Deepspawn fressen alles Organische, bevorzugen aber frisches Fleisch. Durch irgendein noch unerklärtes natürliches Mittel kann ein Deepspawn jede Kreatur der Primären Materiellen Ebene „züchten" und gebären, die er jemals verschlungen hat (aber keine Untoten oder andere zweidimensionale Kreaturen). Die „Brut" hat die natürlichen Angriffe, einschließlich zauberähnlicher Kräfte, Gesinnung und Intelligenz ihrer Vorfahren, aber Klassenfähigkeiten und andere erlernte Fertigkeiten werden nicht erworben. Eine Brut „wächst" in 1W4 Tagen (variierend mit Größe und Komplexität) in einem Deepspawn, der Fleisch, Pflanzenmaterial und Wasser oder Blut zu sich nehmen muss, um die Geburt zu nähren. Der Deepspawn spaltet sich dann auf, um eine vollständig aktive Brut auszustoßen. Brut ist niemals feindselig gegenüber ihrem Elternteil und kann nicht dazu gebracht werden, ihn anzugreifen, selbst nicht durch magische Mittel. Brut kann innerhalb einer Runde nach dem Erscheinen angreifen oder sich verteidigen. Nach Wahl des Spielleiters können sie bestimmte Kräfte oder Fähigkeiten für ein paar Runden ungeschickt verwenden.'
);

-- Dog, Moon (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Mondhund',
  'Dog, Moon',
  'Unknown',
  FALSE,
  'Elysium and Prime',
  'Rare',
  'Solitary or small pack (see below)',
  'Any',
  'Carnivore',
  'High to exceptional (13-16)',
  'Nil',
  'Neutral good',
  '1 or 2-8 (see below)',
  10,
  '30, bipedal 9',
  '9+3',
  9,
  11,
  '1',
  '3-12',
  'Bay, howl',
  'Shadowy hypnotic pattern, +2 or better weapons to hit',
  25,
  'M',
  'Fanatic (17-18)',
  17,
  9,
  'Mondhunde werden oft fälschlicherweise für unheilvolle Monster gehalten, sind aber einheimische Kreaturen von Elysium und Verfechter der Sache des Guten. Sie erscheinen oft auf der Primären Materiellen Ebene, um das Böse zu bekämpfen, wo immer es sich zeigt.',
  'Wehe denen, die einen Kampf mit einem Mondhund beginnen. Diese Kreaturen des Guten sind mächtige Kämpfer und gnadenlos gegen das Böse. Ihr kraftvoller Biss verursacht 3-12 Schadenspunkte.',
  'Mondhunde sind auf der Ebene von Elysium beheimatet. Sie sind Verfechter des Guten und reisen oft durch die oberen Ebenen und die Primäre Materielle Ebene, um das Böse herauszufordern.',
  'Mondhunde kommunizieren oft mittels Telepathie mit Menschengemeinschaften, um Unruheherde unter ihnen zu lokalisieren.'
);

-- Dragon, Cloud (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Wolkendrache',
  'Dragon, Cloud',
  'Unknown',
  FALSE,
  'Tropical, subtropical, temperature/Clouds, mountains',
  'Very rare',
  'Solitary or clan',
  'Any',
  'Special',
  'Genius (17-18)',
  'Special',
  'Neutral',
  '1 (2-5)',
  10,
  '6, Fl 39 (C), Jp 3',
  '14 (base)',
  14,
  7,
  '3 + special',
  '1-10/1-10/3-36',
  'Special',
  'Varies',
  0,
  'G',
  'Fanatic (17)',
  17,
  0,
  'Wolkendrachen sind zurückgezogene Kreaturen, die Störungen nicht mögen. Sie unterhalten sich selten, aber wenn sie dazu überredet werden, neigen sie dazu, wortkarg und distanziert zu sein. Sie haben keinerlei Respekt vor Kreaturen, die nicht ohne Hilfe von Zaubern oder Gegenständen fliegen können.',
  'Wolkendrachen vermeiden Kämpfe genauso wahrscheinlich (indem sie Wolkenform annehmen), wie sie angreifen. Beim Angriff nutzen sie ihre Atemwaffe, um Gegner zu zerstreuen, dann wirken sie Fester Nebel und verwenden ihre Manipulationsfähigkeiten, um ihre Feinde zu blenden und zu desorientieren. Wenn sie sehr wütend sind, beschwören sie Stürme mit Wetter beherrschen-Zaubern, dann rufen sie Blitze. Sie verwenden gerne Stinkende Wolke und Winde beherrschen gegen fliegende Gegner.',
  'Wolkendrachen hausen in magischen Wolkeninseln, wo es mindestens einen kleinen, festen Boden für das Legen von Eiern und die Lagerung von Schätzen gibt. Sehr selten bewohnen sie wolkenverhangene Berggipfel.',
  'Wie alle Drachen können Wolkendrachen fast alles fressen. Sie scheinen sich hauptsächlich von Regenwasser, Hagelkörnern und gelegentlich etwas Silber zu ernähren.'
);

-- Elephant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Elefant',
  'Elephant',
  'Unknown',
  FALSE,
  'Subtropical to tropical jungle and plains',
  'Common',
  'Herd',
  'Dawn, dusk, early morning and evening',
  'Herbivore',
  'Semi- (2-4)',
  'Nil',
  'Neutral',
  '1-12',
  6,
  '15',
  '11',
  11,
  9,
  '5',
  '2-16/2-16/',
  'Nil',
  'Nil',
  0,
  'L',
  'Unsteady (7)',
  7,
  4,
  'Elefanten haben dicke, faltige Häute, die mit spärlichen und sehr groben Büscheln grauer Haare bedeckt sind. Das bekannteste Merkmal des Elefanten ist sein Rüssel, den er als Greifglied verwendet.',
  'Ein Elefant kann bis zu fünf Angriffe gleichzeitig in einem Kampf ausführen. Er kann mit jedem seiner beiden Stoßzähne Stichschaden von 2-16 Punkten (2W8) verursachen; Umklammerungsschaden von 2-12 Punkten mit seinem Rüssel; und 2-12 Punkte Trampelschaden mit jedem seiner Vorderfüße. Kein einzelner Gegner kann mehr als zwei dieser Angriffe gleichzeitig erleiden. Der Elefant kann jedoch bis zu sechs menschengroße Gegner gleichzeitig bekämpfen.',
  'Elefanten sind friedliche Pflanzenfresser, die in einer Herde reisen. Die Herde besteht aus männlichen und weiblichen Elefanten sowie ihrem Nachwuchs. Wird eine Herde von 10 oder mehr Elefanten angetroffen, befinden sich 1-4 Junge bei der Gruppe, die 20% bis 70% ausgewachsen sind. In der Herde existiert eine klare Hierarchie, wobei die älteren Männchen eine eindeutige Dominanzposition einnehmen.',
  'Elefanten werden häufig jung gefangen und ausgebildet. Sie sind gute Lasttiere, werden aber oft auch in der Kriegsführung als Reittiere und lebende Rammböcke eingesetzt.'
);

-- Frog (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
