  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Frosch',
  'Frog',
  'Unknown',
  FALSE,
  'Any fresh water',
  'Uncommon',
  'Pack',
  'Any',
  'Carnivore',
  'Non- (0)',
  'Nil',
  'Nil',
  '5-40',
  7,
  '3, Sw 9',
  '1-3',
  1,
  1,
  '1',
  '1-3/1-6/2-8',
  'Tongue and swallow whole',
  'Nil',
  0,
  'T',
  'Average (8)',
  8,
  1,
  'Riesenfrösche ähneln ihren gewöhnlicheren Verwandten in allem außer der Größe. Ihre enorme Größe bedeutet, dass sie größere Kreaturen als Nahrungsquelle betrachten, was kleine Kreaturen und sogar Halbmenschen zu möglicher Beute macht.',
  'Aufgrund seiner tarnenden Färbung überrascht ein Riesenfrosch Gegner leicht (-3 Malus auf Überraschungswürfe der Gegner), wenn er sich in seinem natürlichen Lebensraum befindet. Ein Riesenfrosch nutzt seine lange, klebrige Zunge, um sein Opfer zu fangen. Die Zunge ist dreimal so lang wie der Frosch selbst und trifft mit einem +4 Bonus auf den Angriffswurf. Die Zunge verursacht keinen Schaden, wenn sie trifft.',
  'Riesenfrösche leben in Gruppen, haben aber keine wirkliche Sozialstruktur. Sie sind aggressive Jäger und fressen Insekten, Fische und kleine Säugetiere. Große aquatische Raubtiere wie Riesenfische und Riesenschildkröten jagen oft auf sie.',
  NULL
);

-- Giant, Desert (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riese, Wüsten-',
  'Giant, Desert',
  'Unknown',
  FALSE,
  'Desert',
  'Very rare',
  'Tribal',
  'Day',
  'Omnivore',
  'Average (8-10)',
  'B',
  'Neutral',
  '2-20',
  1,
  '15',
  '13',
  13,
  7,
  '1',
  '1-10 or by weapon (2-12 +7)',
  'Hurling spears',
  'Camouflage',
  0,
  'H',
  'Elite (14)',
  14,
  5,
  'Wüstenriesen waren einst zahlreich in den Buschsteppen und Wüsten des Lands des Schicksals, aber sie sind einem göttlichen Fluch zum Opfer gefallen, der sie langsam, aber unaufhaltsam in Stein verwandelt. Sie wandern stets in Begleitung ihres Viehs und ihrer Reittiere durch das Land. Ihre große Zivilisation ist längst unter dem Sand verschwunden.',
  'Wüstenriesen kämpfen beritten, wenn sie können, obwohl Reittiere von passender Größe selten sind. Zu den Schlachtrössern gehören gigantische Echsen, riesige Insekten, riesige untote Pferde aus wechselnden Knochen und sogar Rocs. In der Vergangenheit dienten einige Wüstenriesen als Leibwächter und Söldner bei den mächtigsten Sultanen. Der Anblick einer Gruppe von Wüstenriesen, die sich zur Vorbereitung eines Angriffs aufstellen, hat mehr als eine Wüstenlegion zur Flucht veranlasst.',
  'Wüstenriesen sind nomadische Hirten und werden selten weit entfernt von ihren Herden angetroffen. Obwohl sie dafür verantwortlich sind, ganze Flusstäler in fruchtbaren Gebieten kahlzufressen, entschädigen sie Bauern oder Hirten am Rand dieser Territorien nicht für den Schaden, den sie anrichten könnten. Sie betrachten die Länder als ihr Eigentum und entschuldigen sich nicht für Überweidung oder sogar dafür, ihre Herden auf Feldfrüchten weiden zu lassen. Wenige Sultanate versuchen, sie von Ackerland zu vertreiben; die meisten versuchen, die Wüstenriesen mit Versprechungen einer Anstellung als Söldner wegzulocken. Einige versprechen reiche Geschenke aus Salz, Tuch, Gewürzen und Metall, wenn die Wüstenriesen nur in die leeren Viertel der Wüste zurückkehren.',
  'Wüstenriesen wandern hunderte von Kilometern und folgen den Regen mit ihren Herden. Wenn der Regen ausbleibt, verdorrt das Buschwerk und die Herden samt ihren Riesen verhungern. In diesen Zeiten können junge Männchen unter den Wüstenriesen Söldnerarbeit aufnehmen und das erhaltene Geld nutzen, um den gesamten Stamm zu unterstützen. Wenn eine Dürre Jahre andauert, werden mehr und mehr Riesen in die Städte getrieben, obwohl ihre absolute Zahl immer noch winzig ist im Vergleich zur Anzahl der Menschen und anderer kleinerer Völker.'
);

-- Giant, Jungle (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Dschungelriese',
  'Giant, Jungle',
  'Unknown',
  FALSE,
  'Tropical/jungle',
  'Uncommon',
  'Tribal/cooperative',
  'Day',
  'Carnivore',
  'Average to High (8-14)',
  'Q (A)',
  'Neutral',
  '1 or 1-6',
  3,
  '15, Cl 6',
  '11',
  11,
  9,
  '1 or 2',
  '2-16 +9 or 2-12 +9/2-12 +9',
  'Surprise, arrows',
  'See below',
  0,
  'H',
  'Champion (16)',
  16,
  6,
  'Mächtig, hager und streng fleischfressend sind Dschungelriesen ein Schrecken für alle Tiere der tropischen Wälder. Sie sind große Jäger und Pirschgänger, die imstande sind, ein riesiges Waldgebiet von allem Wild zu säubern und dann weiterzuziehen.',
  'Dschungelriesen verwenden 4,5 m lange Bögen, die gefertigt wurden, um ihre gewaltige Größe und Stärke zu nutzen. Diese Riesen sind sehr schnell mit ihren riesigen Bögen und können zwei Pfeile pro Runde abfeuern. Sie werden vergiftete Pfeile verwenden, um ihre Beute schneller zur Strecke zu bringen. Werden diese Pfeile im Kampf eingesetzt, müssen Gegner einen Rettungswurf gegen Lähmung mit -2 bestehen oder werden für 2-12 Runden bewegungsunfähig. Selbst humanoide Kreaturen mit der Stärke, einen Dschungelriesenbogen zu spannen, können ihn nicht benutzen, weil die Pfeile über 1,8 m lang sind (2W6 + 9 Schaden). Dschungelriesen werden gelegentlich den Stamm eines toten Baumes als Keule verwenden und 2W8 + 9 Schadenspunkte verursachen.',
  'Dschungelriesen sind freundlicher als die meisten anderen Riesenrassen und werden oft mit menschlichen Dschungelstämmen bei Jagden zusammenarbeiten. Die Riesen stellen Stärke und rohe Kraft zur Verfügung, und die Menschen bieten die Anzahl und Fertigkeit, um Tiere in Hinterhalte zu treiben.',
  'Dschungelriesen betrachten die meisten Kreaturen als Beute, aber jene, die sie als Mitjäger akzeptieren, respektieren sie als Gleichgestellte, unabhängig von deren Größe. Obwohl sie das ihnen so vertraute Dschungelgelände stark bevorzugen, sind sie oft gezwungen, die Bäume für die Savanne zu verlassen, wenn ihre Anzahl zu groß wird, um im Dschungel zu überleben. Sie denken nichts dabei, jede Schlange, Antilope, Katze, Warzenschwein, Strauß und Elefant zu essen, auf die sie treffen. Dschungelriesen in der Savanne kehren oft in den Wald zurück, weil ihre große Höhe die heimliche Jagd für sie auf offenem Gelände schwierig macht.'
);

-- Giant, Reef (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riffriesе',
  'Giant, Reef',
  'Unknown',
  FALSE,
  'Tropical or subtropical ocean/reef',
  'Very rare',
  'Solitary',
  'Day',
  'Omnivore',
  'Very (11-12)',
  'Z (A)',
  'Neutral good',
  '1 or 1-4',
  10,
  '15, Sw 12',
  '18',
  18,
  5,
  '1',
  '1-10 or by weapon (typically 2-20 + 10)',
  'Boulders, whirlpool',
  'Immune to water-based attacks',
  0,
  'H',
  'Fanatic (17)',
  17,
  12,
  'Riffriesen sind die Einzelgänger unter den Riesenarten, obwohl sie oft in bemerkenswert gut ausgestatteten Herrenhäusern leben, die von außen nicht mehr als Hütten zu sein scheinen. Manchmal werden sie Seeleute, aber ihre gewaltige Masse beschränkt sie auf die größten Schiffe. Riffriesen sind typischerweise 4,9 m groß und wiegen 1,8 kg. Riffriesen können 600 Jahre alt werden.',
  'Riffriesen kämpfen bevorzugt im oder unter Wasser, und sie sind erbitterte Kämpfer wenn sie erzürnt sind. Sie erleiden keine Abzüge beim Kampf im oder unter Wasser. Sie können nicht durch wasser- oder eisbasierte Angriffsformen verletzt werden. Sie greifen typischerweise mit Riesendreizäcken für 2-20 +10 Schadenspunkte an, sind aber auch dafür bekannt, gelegentlich mit einer gewaltigen Faust auszuholen (1W10 Schadenspunkte).',
  'Riffriesen sind oft für lange Zeiträume einsam, obwohl sie sich fürs Leben paaren. Wenn ihre Kinder die Pubertät erreichen, werden sie allein hinausgeschickt, um einen Insel- oder Rifflebensraum zu suchen, den sie ihr Zuhause nennen können.',
  'Riffriesen sind Aasfresser, die Korallriffe nach hundert verschiedenen Nahrungsquellen befischen und durchsuchen. Sie können ganze Fischschwärme fangen, und als versierte Taucher können sie Schatzhörter aus Perlen, Schwämmen und Korallen bergen. Ihre enorme Stärke erlaubt es ihnen, stundenlang zu schwimmen, ohne zu ermüden. Auf diese Weise können Riffriesen gewaltige Mengen von Gütern anhäufen, um sie gegen andere Gegenstände zu tauschen.'
);

-- Giff (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Giff',
  'Giff',
  'Unknown',
  FALSE,
  'Any',
  'Rare',
  'Platoon',
  'Day',
  'Omnivore',
  'Low (7)',
  'Nil',
  'Lawful neutral',
  '11-20',
  6,
  '6',
  '4',
  4,
  17,
  '2 or 1',
  '1-6 +7 or by weapon +7',
  'Head butt',
  'Can call on other giff',
  10,
  'L',
  'Elite (14)',
  14,
  420,
  'Die Giff sind eine Rasse von kraftvoll bemuskelten Söldnern. Sie sind zivilisiert, obwohl sie keine Magier in ihrer eigenen Rasse haben. Giff verdingen sich bei verschiedenen Gruppen im ganzen Universum als Söldner, Leibwächter, Vollstrecker und gewöhnliche Schläger.',
  'Die Giff sind militärisch denkend und organisieren sich in Trupps, Zügen, Kompanien, Korps und größeren Gruppen. Die Anzahl der Giff in einem Zug variiert je nach Jahreszeit, Situation und Gefahrenstufe. Ein Giff-"Zug", der angeheuert wurde, um ein Glücksspielunternehmen zu schützen, mag zwei zählen, während ein Zug, der angeheuert wurde, um eine Illithid-Festung zu erobern, weit über hundert zählen mag.',
  'Die Giff sind am glücklichsten unter ihrer eigenen Rasse - sie betrachten größere Rassen wie Riesen als bedrohlich und beklagen sich über die Zerbrechlichkeit der kleineren Rassen. Anders als die Draconen erleiden sie keine Nachteile, wenn sie von ihren Gefährten getrennt sind, aber sie bevorzugen einfach die Gesellschaft ihrer eigenen Spezies. Außerhalb ihrer eigenen Züge sind die Giff am glücklichsten in militärischen Organisationen mit einer starken Befehlskette.',
  'Wie die Draconen werden die Giff als von einer Welt stammend vermutet, die nicht mit einer großen Vielfalt intelligenter Spezies wie Elfen, Menschen, Zwerge und Betrachter gesegnet war. Weise zeigen auf die Giff als Beispiel dafür, was geschieht, wenn nur eine empfindungsfähige Spezies auf einem Planeten gefunden wird.'
);

-- Golem IV (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Golem IV',
  'Golem IV',
  'Unknown',
  FALSE,
  'Any',
  'Very rare',
  'Solitary',
  'Any',
  'Nil',
  'Non- (0)',
  'Nil',
  'Neutral',
  '1',
  10,
  '9',
  '15 (60 hp)',
  15,
  5,
  '2',
  '3d6/3d6',
  'See below',
  'See below',
  0,
  'M',
  'Fearless (20)',
  20,
  14,
  'Der Gargoyle-Golem ist ein steinernes Konstrukt, das dazu geschaffen wurde, ein bestimmtes Bauwerk zu bewachen. Er hat etwa die gleiche Größe und das gleiche Gewicht wie ein echter Gargoyle (1,8 m groß und 249,5 kg schwer). Obwohl sie Flügel haben, können sie nicht fliegen. Ein Gargoyle-Golem kann jedoch große Entfernungen springen (bis zu 30,5 m) und wird diese Fähigkeit oft nutzen, um sich auf Feinde fallen zu lassen, die sich einem Gebäude nähern, das der Golem beschützt.',
  'Wenn ein Gargoyle-Golem im Nahkampf angreift, tut er dies mit seinen beiden bekrallten Fäusten. Jede Faust muss dasselbe Ziel angreifen und verursacht 3W6 Schadenspunkte. Jeder, der von beiden Angriffen getroffen wird, muss einen Rettungswurf gegen Versteinerung bestehen oder wird zu Stein verwandelt. In der Runde nach der Versteinerung eines Opfers durch einen Gargoyle-Golem greift er dasselbe Ziel erneut an. Jeder Treffer des Golems gegen einen solchen Gegner zeigt an, dass der steinerne Körper zerbrochen ist und nicht wiederbelebt werden kann. Reinkarnation ist hingegen noch eine gangbare Option.',
  NULL,
  NULL
);

-- Grell, Colonial (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Grell, Kolonial',
  'Grell, Colonial',
  'Unknown',
  FALSE,
  'Any',
  'Rare',
  'Hive',
  'Any',
  'Carnivore',
  'Average (8-10)',
  'U (see below)',
  'Neutral evil',
  '1-10',
  5,
  'Fl 12 (D)',
  '5',
  5,
  15,
  '11',
  '1-4(×10)/1-6 or by weapon',
  'Magical items',
  'Nil',
  0,
  'M',
  'Elite (13-14)',
  13,
  2,
  'Der „zivilisierte" Grell ist eine koloniale Version (wie der Begriff bei Ameisen und anderen Kolonietieren verwendet wird) des unterirdischen Verwüsters von Oerth. Er ist ähnlich in Größe und Aussehen wie irdische Grells. Anders als seine einzelgängerischen Verwandten kann er jedoch über telepathische Verbindung sowohl mit Grell-Philosophen als auch dem hochintelligenten Grell-Patriarchen sprechen.',
  'Grell-Kampftaktiken ähneln denen ihrer geringeren Verwandten; sie nutzen ihre Schwebefähigkeit, um sich in den oberen Bereichen großer Kammern zu verstecken. Jedoch ermöglicht ihnen ihre Fähigkeit, in Gruppen zu agieren, bösartige Angriffe zu führen, wobei sie Spitzenspeere und Blitzenzen einsetzen. Spitzenspeere sind scharfkantige Metallspitzen, die durch Saugwirkung über die Spitzen der Tentakel eines Soldaten-Grells passen. Der Grell kann hiebende Angriffe ausführen, die 1-6 Schadenspunkte verursachen, oder stechen und dabei doppelten Schaden anrichten.',
  'Grells haben eine deutliche pyramidale Hierarchie. Der Patriarch steht an der Spitze, und eine zweite Kaste, die Philosophen, behandelt die unteren Kasten. Jede Grell-„Familie" bewohnt ein Schiff.',
  'Grells sind die wahren Verschwender der Weltraumvölker. Arrogant und bösartig jagen sie ein Gebiet bis zur Erschöpfung und ziehen dann weiter in fruchtbarere Regionen. Ihre (Wieder-)Entdeckung des menschlichen Raums bedeutet für diese Monster nur ein reiches Lager von Fleisch.'
);

-- Heucuva (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Heucuva',
  'Heucuva',
  'Unknown',
  FALSE,
  'Any',
  'Very rare',
  'Solitary',
  'Any',
  'Nil',
  'Semi- (2-4)',
  'C',
  'Chaotic evil',
  '1-10',
  3,
  '9',
  '2',
  2,
  19,
  '1',
  '1-6',
  'Disease',
  'Hit only by silver or +1 weapons',
  0,
  'M',
  'Steady (11)',
  11,
  270,
  'Der Heucuva ist ein untoter Geist, der einem Skelett ähnelt, aber gefährlicher und schwerer zu bannen ist.',
  'Der Heucuva greift an, indem er mit einer seiner Hände schlägt; die scharfen Fingerknochen sind imstande, Holz zu zerreißen. Ein Opfer muss einen erfolgreichen Rettungswurf gegen Gift würfeln oder wird von einer Krankheit befallen. Das Opfer erleidet täglich einen Verlust von je 1 Punkt Stärke und Konstitution. Ein Krankheit heilen-Zauber muss auf das Opfer gewirkt werden, um den Tod zu verhindern und die verlorenen Punkte wiederherzustellen.',
  'Heucuva wandeln durch die dunklen Orte der Welt. Sie können in unterirdischen Reichen sowie in den meisten gemäßigten oder tropischen Gebieten gefunden werden. Kälte scheint heucuvanische Aktivität zu verhindern, denn sie werden weder in hohen, verlassenen Bergen noch in kalten Gebieten gefunden.',
  'Heucuva sind bösartige Geister, die danach trachten, jene zu vernichten, die noch leben. Sie werden als Beispiele verwendet, um Priester an das Schicksal zu erinnern, das jene ereilt, die von ihrer Hingabe abweichen oder ihre Religion als Maske nutzen, um unfromme Taten zu verbergen. Pulverisierte Heucuva-Knochen können bei der Herstellung magischer Gegenstände verwendet werden, die dazu bestimmt sind, die Geister lebender Wesen zu korrumpieren oder Untote zu kontrollieren.'
);

-- Hippocampus (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Hippokampus',
  'Hippocampus',
  'Unknown',
  FALSE,
  'Fresh or salt water depths',
  'Rare',
  'Herd',
  'Any',
  'Herbivore',
  'Average (8-10)',
  'Nil',
  'Chaotic good',
  '2-8',
  5,
  'Sw 24',
  '4',
  4,
  17,
  '1',
  '1-4',
  'Nil',
  'Nil',
  0,
  'H',
  'Steady (11-12)',
  11,
  120,
  'Der Hippokampus ist das wertvollste aller Meeresrösser, ein Wesen, das Eigenschaften eines Pferdes und eines Fisches miteinander verbindet.',
  'Hippokampi sind normalerweise friedliche Wesen. Sie greifen nur an, wenn sie in die Enge getrieben werden oder wenn ein anderer Hippokampus oder ein Verbündeter bedroht wird. Sie sind schnell genug, um fast allem davonzuschwimmen, was sie angreifen möchte.',
  'Hippokampi sind die geschätzten Reittiere des Meeres. Sie können überall in tiefen Gewässern gefunden werden, in Süßwasserseen und Ozeanen. Sie können Süß- und Salzwasser gleichermaßen leicht atmen. Sie können auch Luft atmen, benötigen aber häufige Schlücke Wasser, um nicht auszutrocknen. Sie können sich nicht außerhalb des Wassers bewegen.',
  'Hippokampi sind eines der erfolgreichsten intelligenten, gut gesinnten Meeresungeheuer. Sie unterhalten Beziehungen zu Meermenschen und Meerelfen sowie zu Oberflächenbewohnern, die ihr Leben auf dem Wasser verbringen. Sie erbringen wertvolle Dienste als Reittiere, Führer und Verbündete. Hippokampus-Eier werden für 1.500 GM verkauft. Junge Hippokampi sind 2.500 GM wert. Jedoch bleiben Oberflächenbewohner, die von Hippokampi gerettet wurden, ihren ehemaligen Rettern so dankbar, dass sie jeden Händler angreifen können, der Eier oder Fohlen auf einem öffentlichen Markt verkauft, und versuchen, die Hippokampi ins Meer zurückzubringen.'
);

-- Horse (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Pferd',
  'Horse',
  'Unknown',
  FALSE,
  'Any non-mountainous',
  'Common',
  'Herd',
  'Day',
  'Herbivore',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1',
  7,
  '12',
  '3',
  3,
  17,
  '1',
  '1-3',
  'Nil',
  'Nil',
  0,
  'L',
  'Unsteady (5-7)',
  5,
  65,
  'Pferde sind große Vierbeiner, die oft als Transport-, Pack- oder Zugtiere von Menschen und Halbmenschen verwendet werden. Sie werden häufig wegen ihrer Geschwindigkeit und Schönheit gezüchtet.',
  'Schlachtrosse kämpfen ab der zweiten und den folgenden Runden eines Nahkampfes unabhängig vom Reiter. Andere Rassen kämpfen nur, wenn sie in die Enge getrieben werden. Die meisten greifen zweimal pro Runde an, indem sie mit ihren Vorderhufen ausschlagen.',
  'Die Tragezeit des Pferdes beträgt etwa 11 Monate. Stuten (weibliche Pferde) gebären normalerweise ein einzelnes Fohlen (junges Pferd). Zwillinge kommen vor, aber nur etwa 10% der Zeit (oder weniger). Sogar Drillinge sind möglich, aber extrem selten. Das Fohlen wird nach sechs Monaten entwöhnt. Es ist nach zwei bis drei Jahren ausgereift und gilt mit fünf Jahren als erwachsen. Die übliche Lebensspanne eines Pferdes beträgt 30-35 Jahre, obwohl seltene Ausnahmen ein Alter von 50 Jahren erreicht haben, und hart arbeitende Pferde selten über 12 Jahre alt werden.',
  'Moderne Pferde entwickelten sich in gemäßigten Ebenen und Grasländern. Haustierrassen können überall dort gefunden werden, wo Menschen leben (sogar in hohen Bergen, falls die örtlichen Straßen gut sind).'
);

-- Jackalwere (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Schakalwer',
  'Jackalwere',
  'Unknown',
  FALSE,
  'Any temperate',
  'Rare',
  'Pack',
  'Any',
  'Carnivore',
  'Very (11-12)',
  'C',
  'Chaotic evil',
  '1-4',
  4,
  '12',
  '4',
  4,
  17,
  '1',
  '2-8 (2d4)',
  'Gaze causes sleep',
  'Hit only by iron and +1 or better magical weapons',
  0,
  'S',
  'Steady (11-12)',
  11,
  270,
  'Der Schakalwer ist eine schreckliche und wilde Kreatur, die ahnungslose Reisende und andere Halbmenschen jagt, die sie aus dem Hinterhalt angreifen kann. Seine Fähigkeit, seine Gestalt nach Belieben zu verändern, macht ihn zu einem äußerst gefährlichen Feind.',
  'In seiner Schakalform entspricht das Monster den Werten aus dem Schakal-Eintrag. Ein aufmerksamer Beobachter wird jedoch feststellen, dass sich die Kreatur nicht in der für einen normalen Schakal typischen Weise verhält, da sie weitaus aggressiver ist.',
  'Wenn der Schakalwer ein Opfer ausfindig macht, nimmt er menschliche Gestalt an und nähert sich seiner Beute. Er wird versuchen, den Argwohn seines Ziels zu beschwichtigen, oft indem er vorgibt, verletzt oder anderweitig hilfsbedürftig zu sein, bis er seinen Blickangriff einsetzen kann. Wenn dies fehlschlägt und der Schakalwer mit entschlossenem Widerstand konfrontiert wird, entscheidet er basierend auf seiner Einschätzung der Stärke seines Opfers, ob er fliehen oder den Angriff fortsetzen soll.',
  'Schakalwer dienen nur den bösartigsten Humanoiden, und selbst dann nur, wenn sie die Gelegenheit haben, mehr Menschen und Halbmenschen zu erschlagen, als sie alleine könnten.'
);

-- Kirre (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Kirre',
  'Kirre',
  'Unknown',
  FALSE,
  'Forest ridge',
  'Rare',
  'Pack',
  'Day',
  'Carnivore',
  'Low (5-7)',
  'Nil (A)',
  'Neutral',
  '1',
  7,
  '15',
  '6+6',
  6,
  13,
  '7',
  '1-4/1-4/1-6/1-8/1-4/1-4/1-6',
  'Psionics',
  'Nil',
  0,
  'L',
  'Elite (13-14)',
  13,
  650,
  'Wissenschaft: Kraft projizieren; Hingaben: erweichen, Levitation.',
  'Da Kirre von Natur aus Raubtiere sind, sind sie sehr gut für den Kampf gerüstet. Diese Kreatur ist sehr schnell im Nahkampf und erhält daher einen -1 Modifikator auf ihre Initiativwürfe. Wenn der Spielleiter die "Optionalen Modifikatoren zur Initiative" verwendet, werden Kirre wie kleine Kreaturen behandelt und erhalten nur einen +3 Modifikator anstelle der normalen +6 für große Kreaturen.',
  'Kirre sind normalerweise Einzelgänger, bis ihre Paarungszeit naht, zu welchem Zeitpunkt sich ein Männchen und ein Weibchen zusammenschließen und Nachkommen zeugen. Kirre-Würfe bestehen aus drei bis fünf Jungen. Kirre sind Säugetiere, und Weibchen produzieren Milch für ihre Jungen. Junge Kirre überleben die ersten fünf Monate von Milch, danach beginnen sie feste Nahrung wie kleine Waldtiere und andere Säugetiere zu fressen.',
  'Kirre sind ein beliebtes Wild vieler Jagdstämme von Völkern, die in den Wäldern von Athas leben. Das Fleisch von Kirren gehört zu dem feinsten auf ganz Athas und wird von vielen begehrt. Abgesehen von einer Nahrungsquelle hat der Kirre auch andere Verwendungszwecke, wenn er getötet wird. Die Hörner der Kreatur können abgeschnitten und als Speerspitzen verwendet werden; in manchen Fällen können sie zu kunstvollen Dolchen geschnitzt werden. Außerdem hat der Schwanz eines Kirre einen scharfen Knochenstachel an seinem Ende, der entweder zu einer Pfeilspitze oder einem Pfeil verarbeitet werden kann.'
);

-- Lamia (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Lamia',
  'Lamia',
  'Unknown',
  FALSE,
  'Deserts, caves, and ruined cities',
  'Very rare',
  'Solitary',
  'Any',
  'Carnivore',
  'High (13-14)',
  'D',
  'Chaotic evil',
  '1',
  3,
  '24',
  '9',
  9,
  11,
  '1',
  '1-4 (weapon)',
  'See below',
  'Nil',
  0,
  'M',
  'Elite (14)',
  14,
  3,
  'Von allen Gefahren, die die Wüste birgt, können nur wenige mit der grausamen Rasse fleischfressender Kreaturen mithalten, die als Lamias bekannt sind. Diese halb-menschlichen, halb-vierfüßigen Tierhybriden setzen Betrug, Geschwindigkeit und Zauber ein, um unvorsichtige Abenteurer zu fangen, die es wagen, in ihre Ruinen zu wandern.',
  'Eine Lamia kann die folgenden Zauber einmal pro Tag anwenden: Person bezaubern, Spiegelbild, Suggestion und Illusion (wie ein Zauberstab). Für Zwecke der Dauer, Wirkung usw. nimm an, dass die Lamia ihre Zauber mit 9. Stufe Zauberfähigkeit wirkt. Diese Zauber werden typischerweise verwendet, um Personen zur Lamia zu locken und sie dann dort festzuhalten, damit die Kreatur sie in aller Ruhe verschlingen kann.',
  'Lamias leben in Ruinenstädten oder Höhlen, Orten in Wüsten- oder Ödlandgebieten. Diese bösen Kreaturen sind einsame Bestien, die sich vom Fleisch derer ernähren, die zu nahe an ihre Territorien heranwandern. In mageren Zeiten ergänzen sie ihre Ernährung durch die Jagd auf Wildtiere. Lamias wagen sich kaum jemals mehr als 16,1 km von ihren Bauen entfernt.',
  'Lamias sind legendäre Monster, die Reisende jagen oder verborgene Orte oder Machtgegenstände bewachen. Sie sind geheimnisvolle Kreaturen, die der Verbreitung von Chaos und Bösem in ihren Wohnstätten gewidmet zu sein scheinen.'
);

-- Lammasu (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Lammasu',
  'Lammasu',
  'Unknown',
  FALSE,
  'Warm, with visits to other climes',
  'Rare',
  'Pride',
  'Day',
  'Herbivore',
  'Genius (17-18)',
  'R,S,T',
  'Lawful good',
  '2-8',
  6,
  '12, Fl 24 (C)',
  '7+7',
  7,
  13,
  '2',
  '1-6/1-6',
  'See below',
  'See below',
  30,
  'L',
  'Elite (14)',
  14,
  4,
  'Der Lammasu, eine geflügelte löwenartige Gestalt mit menschlichem Kopf, hilft und beschützt rechtschaffen gute Personen. Sie sind im Allgemeinen freundlich und wohlwollend gegenüber allen guten Kreaturen.',
  'Da Lammasu um das Wohlergehen und die Sicherheit guter Wesen besorgt sind, greifen sie fast immer in den Kampf ein, wenn sie sehen, dass gute Kreaturen bedroht werden, und zwar auf die Art, die am wenigsten Schaden für die guten Wesen verursacht.',
  'Die Lammasu haben eine sehr strukturierte und rechtschaffene Gesellschaft, die ihre Gesinnung widerspiegelt. Sie sind in Rudeln organisiert, genau wie Löwen. Sie leben in alten, verlassenen Tempeln in warmen Gebieten. Diese Tempel haben ihre Weihe nicht verloren, und in gewisser Weise sind die Lammasu die selbsternannten ansässigen Wächter dieser hohen und heiligen Orte. In der Regel findet man nur ein Rudel Lammasu in einem Gebiet von 40 km; sie verteilen sich, damit sie schnell auf jeden bösen Ausbruch reagieren können.',
  'Lammasu verhindern, dass die Einöden völlig von bösen Kreaturen überrannt werden. Ihre Hilfe für Grenzsiedlungen ist von unermesslichem Wert.'
);

-- Leech (new)
