  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Blutegel',
  'Leech',
  'Unknown',
  FALSE,
  'Temperate/Swamps and marshes',
  'Uncommon',
  'Group',
  'Any',
  'Carnivore',
  'Non- (0)',
  'Nil',
  'Neutral',
  '4-16',
  9,
  '3, Sw 3',
  '1-4',
  1,
  1,
  '1',
  '1-4',
  'Drain blood',
  'Nil',
  0,
  'S',
  'Unsteady (7)',
  7,
  1,
  'Riesenblutegel sind grässliche, schneckenähnliche Kreaturen, die in feuchten, schleimigen Gebieten leben und das Blut warmblütiger Kreaturen saugen.',
  'Blutegel warten im Schlamm und Schleim auf Beute. Der erste Angriff heftet das Saugmaul des Riesenblutegels an. In der nächsten Runde und in jeder weiteren Runde entzieht er Blut und verursacht 1 Schadenspunkt pro Trefferwürfel des Blutegels. Es besteht nur eine 1%ige Chance, dass das Opfer den Angriff bemerkt, wenn er im Wasser erfolgt. Der Blutegel hat betäubenden Speichel, und sein Biss sowie der Blutentzug werden normalerweise nicht gespürt, bis Schwäche eintritt (der Verlust von 50% der Trefferpunkte) und das Opfer merkt, dass etwas nicht stimmt.',
  'Diese Kreaturen werden nur in den Gewässern von Sümpfen und Marschen gefunden. Riesenblutegel haben zwischen 1 und 4 Trefferwürfel; verschiedene große Kreaturen werden normalerweise in einer Gruppe gefunden.',
  NULL
);

