  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Lykanthrop, Werefledermaus',
  'Lycanthrope, Werebat',
  'Unknown',
  FALSE,
  'Temperate woodlands',
  'Rare',
  'Flock',
  'Night',
  'Blood',
  'Average (8-10)',
  'B',
  'Neutral evil',
  '1-4',
  5,
  '9, Fl 15 (D)',
  '4+2',
  4,
  17,
  '3',
  '1d4/1d4',
  'See below',
  'See below',
  0,
  'M',
  'Steady (11-12)',
  11,
  420,
  'Wie die anderen Lykanthrop-Arten, die in Ravenloft zu finden sind, existieren zwei Varianten der Werefledermaus - natürliche (oder echte) und infizierte. Echte Werefledermäuse sind jene Kreaturen, die von Werefledermaus-Eltern geboren wurden. Die Eltern können selbst entweder echte oder infizierte Werefledermäuse sein, aber der Nachwuchs von zwei beliebigen Werefledermäusen ist eine echte Werefledermaus. In den seltenen Fällen, in denen ein Kind mit einem Werefledermaus- und einem menschlichen Elternteil geboren wird, besteht eine 50%ige Chance, dass es eine echte Werefledermaus wird, und eine 25%ige Chance, dass es eine infizierte Werefledermaus wird.',
  'Die Art der Angriffe, die eine Werefledermaus einsetzt, hängt von ihrer Form ab. In menschlicher Form wird sie sich auf Waffen verlassen, um Schaden zu verursachen, denn ihre bloßen Hände verursachen nur 1W2 Punkte pro Angriff. Wenn irgend möglich, wird die Kreatur Kämpfe in dieser Form vermeiden.',
  'Werefledermäuse bevorzugen Höhlen in leicht bewaldeten, gemäßigten Gebieten als ihre Heimat. Von hier aus können sie ausfliegen und Beute suchen, von der sie das Blut ziehen können, das nötig ist, um ihren Durst zu stillen.',
  'Obwohl Werefledermäuse Menschen und Halbmenschen als Beute bevorzugen, ist bekannt, dass sie sich vom Blut anderer Säugetiere (wie Rinder und Pferde) ernähren, wenn bevorzugte Beute nicht verfügbar ist. Interessanterweise scheinen solche Tiere gegen die Lykanthropie immun zu sein, die diese dunklen Kreaturen verbreiten.'
);

