-- Manscorpion (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Menschenskorpion',
  'Manscorpion',
  'Unknown',
  FALSE,
  'Tropical or subtropical desert or caves',
  'Rare',
  'Squad, swarm, and city',
  'Any',
  'Carnivore',
  'Low to genius (5-18)',
  'J,K,M,Q (F,U×10)',
  'Neutral evil',
  '8 or more',
  5,
  '12',
  '8-12',
  8,
  8,
  '3',
  '2-5/2-5/1-4 (claw/claw/tail), or by weapon and 2-5/1-4',
  'Poison, possible spell use',
  'Nil',
  20,
  'L',
  'Champion to fanatic (15-18)',
  15,
  4,
  'Diese Schrecken, manchmal Tlincallis genannt, sind teils Mensch und teils Skorpion. Ein Menschenskorpion hat einen dunkelhäutigen menschlichen Oberkörper, sein Unterleib ist von knöchernen Platten geschützt, und seine Rippen und das Rückgrat ragen aus dem Körper hervor. Ihre Hände haben zwei dicke Finger und einen langen Daumen; die Hände werden oft für skorpionähnliche Klauen gehalten. Die Kreaturen sind haarlos, und ihre Gesichter sind schön und edel, abgesehen von den roten, glühenden Augen, die keine Pupillen haben.',
  'Die meisten Menschenskorpione haben niedrige bis durchschnittliche Intelligenz; sie patrouillieren ihr Territorium in Trupps von sechs Kriegern. Ein Truppenführer und ein Zauberwirker, beide mit 9 TW und höherer Intelligenz, sind ebenfalls anwesend. Der Zauberwirker hat die Fähigkeiten eines Priesters oder Magiers der 4. Stufe. Volle 50% von ihnen tragen mit Obsidian besetzte Keulen (behandle sie als Streitaxt) und Bolas oder Speere. Die übrigen verwenden nur ihre natürlichen Waffen.',
  'Menschenskorpione leben unter dem Wüstensand in Höhlen, die durch Tunnel verbunden sind, alle oberhalb von unterirdischen Städten mit 40-400 Individuen gelegen. Diese spiegeln oft große menschliche Städte wider, mit Gruben anstelle von Gebäuden und großen Schluchten wie umgekehrte Pyramiden.',
  'Menschenskorpione fressen praktisch jedes Fleisch, einschließlich Aas. Keine normalen Kreaturen jagen sie.'
);

-- Mephit, General Information (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Mephit',
  'Mephit, General Information',
  'Unknown',
  FALSE,
  NULL,
  'common',
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  NULL,
  10,
  '',
  '1',
  1,
  20,
  '1',
  '',
  NULL,
  NULL,
  0,
  'M',
  '',
  10,
  0,
  'Mephits sind bösartige Boten, die von mächtigen Kreaturenebenen-Wesen erschaffen werden, um böse Missionen auszuführen. Die 16 bekannten Arten von Mephits ziehen ihre Substanz aus den Elementaren, Paraelementaren und Quasielementaren Ebenen: Feuer, Strahlung, Wasser, Eis, Magma, Asche, Mineral, Dampf, Luft, Rauch, Erde, Schlamm, Staub, Salz, Blitz und Nebel. (Die Quasielementare Ebene des Dampfs beherbergt sowohl Dampf- als auch Nebel-Mephits. Allein unter den Elementaren Ebenen enthält die Ebene des Vakuums kein Leben, nicht einmal Mephits.)',
  'Im Kampf greifen Mephits entweder mit ihren Klauen oder ihrer Atemwaffe an. Der Schaden variiert je nach Art des angetroffenen Mephits; siehe die folgenden Einträge für Details. Sofern bei einem Angriff nicht ein Rettungswurf aufgelistet ist, ist kein Rettungswurf anwendbar.',
  'Mephits lieben es, hilflose Kreaturen zu quälen und mit ihren neuesten bösen Errungenschaften zu prahlen. Sie paffen an übelriechendem Tabak oder Pfeifenkraut. Sie geben sich pompöse, unmöglich lange Namen, wie "Garbenaferthal, Feenschlächter, Größter aller Dampf-Mephits, Liebling der Niederen Ebenen."',
  'Böse Mächte auf den Niederen Ebenen erschaffen Mephits mit einer Variante von Monsterbannungs IV, die Aspekte von Kontakt mit anderen Ebenen einbezieht. Sie nutzen die Substanz einer elementaren Ebene, um einen Diener zu erschaffen, gewöhnlich als Notlösung oder Ersatz für weniger loyale Untergebene. Mephits verraten ihre Erschaffer nicht, scheinen sie aber zu irritieren, und so führen sie kurze, lästige Leben. Schnell erschaffen und zerstört, haben sie keine vorbestimmte Lebensspanne.'
);

-- Morkoth (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Morkoth',
  'Morkoth',
  'Unknown',
  FALSE,
  'Any aquatic',
  'Very rare',
  'Solitary',
  'Night',
  'Carnivore',
  'Exceptional (15-16)',
  '(G)',
  'Chaotic evil',
  '1',
  3,
  'Sw 18',
  '7',
  7,
  13,
  '1',
  '1-10',
  'Hypnosis',
  'Spell reflection',
  0,
  'M',
  'Elite (14)',
  14,
  1,
  'Von allen Kreaturen, die in der Tiefe leben, übertrifft nur der Kraken den Morkoth an Bosheit und Grausamkeit. Auch als „Wraith der Tiefe" bekannt, lauert der Morkoth in Tunneln und hofft, seine Opfer in eine Falle zu locken, aus der sie nicht entkommen können.',
  'Ein Morkoth greift an, indem er mit seinem tintenfischähnlichen Schnabel zuschnappt, was 1W10 Schadenspunkte verursacht. Ein Morkoth lebt im Zentrum von sechs spiralförmigen Tunneln, die jeweils zu einer zentralen Kammer führen. Diese Tunnel sind schmal (nur eine Kreatur der Größe M kann gleichzeitig eintreten, keine der Größe G). Wenn ein Opfer über einen Tunnel hinweggeht, wird es von einem hypnotischen Muster angezogen, das es zur zentralen Kammer führt. Während das Opfer in die zentrale Kammer hineingezogen wird, nähert es sich dem Morkoth, ohne es zu bemerken, und muss einen erfolgreichen Rettungswurf gegen Zauber mit einer Strafe von -4 würfeln oder bezaubert werden. Ein bezaubertes Opfer wird nach Belieben des Morkoth verschlungen. Wenn der Morkoth das Opfer nicht bezaubert, bevor es auf 18,3 m herankommt, ist der hypnotische Effekt der Tunnel gebrochen.',
  'Morkoths sind normalerweise Einzelgänger. Sie gehen manchmal Bündnisse mit Kraken ein und bieten ihre Hilfe im Austausch für gelegentliche Sklaven an. Wenn sie von bösen Meereshhumanoiden um Hilfe gebeten werden, mögen Morkoths einen Handel eingehen, aber verraten oft ihre „Verbündeten" im günstigsten Moment.',
  'Den beliebtesten Theorien zufolge sind Morkoths eine Fischart mit menschlichen und tintenfischartigen Einflüssen. Gelehrte sind unsicher, ob diese Art durch Zufall oder Absicht entstanden ist. Morkoths sind fleischfressend und fressen fast jede Meereskreatur. Ihre gewöhnliche Nahrung sind Tiefwasserkreaturen wie Haie, Oktopi, Kuo-Toa und Sahuagin. Die Lebensspanne männlicher Morkoths beträgt etwa 80 bis 100 Jahre, während Weibchen nach der Eiablage sterben.'
);

-- Muckdweller (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Schlammwühler',
  'Muckdweller',
  'Unknown',
  FALSE,
  'Temperate or tropical/Swamp',
  'Rare',
  'Tribal',
  'Day',
  'Omnivore',
  'Average (8-10)',
  'Q, (J,K,L,M,N)',
  'Lawful evil',
  '5-20',
  6,
  '3, Sw 12',
  '½',
  1,
  20,
  '1',
  '1-2',
  'Water jet',
  'Nil',
  0,
  'T',
  'Average (10)',
  10,
  15,
  'Schlammwühler sind eine Spezies kleiner intelligenter zweibeiniger Lurche, die in Sümpfen, Marschen oder stillen Gewässern mit schlammigem Grund lauert. Es ist bekannt, dass sie Echsenmenschen und Kuo-toa dienen.',
  'Schlammwühler nutzen Hinterhalt-Techniken. Rudel von Schlammwühlern warten auf ein Opfer; wenn eines ankommt, spritzen mehrere Wasser (bis zu 9 m Reichweite) in die Augen des Opfers, was es vorübergehend blendet (ein erfolgreicher Rettungswurf gegen Zauberstäbe negiert dies, aber überraschte Kreaturen erhalten keinen Rettungswurf). Ein geblendetes Opfer kann in dieser Runde nicht handeln, verliert alle Geschicklichkeitsboni, und alle Angriffe gegen das Opfer erhalten einen +2 Bonus auf den Angriffswurf. Außerdem, wenn die Schlammwühler das Opfer in knietiefes schlammiges Wasser locken, verliert das Opfer alle Geschicklichkeitsboni und kämpft mit einem -1 Malus auf seinen Angriffswurf aufgrund des unebenen Untergrunds. Ist das Wasser hüfthoch, steigt der Malus auf -2; ist das Wasser brusthoch, beträgt der Malus -3. Ein Ring der freien Bewegung oder gleichwertige Magie negiert diese Mali. Diese Nachteile gelten nicht für die amphibischen Schlammwühler. Gewöhnlich kämpft ein Schlammwühler nur, wenn er in die Enge getrieben wird oder wenn er sicher ist, einen leichten Sieg erringen zu können.',
  'Der Bau dieser Kreaturen liegt unter Wasser, aber sie haben immer einen schlammigen, über Wasser liegenden Bereich zum Ausruhen, Sonnen und Fressen. Es gibt 5W4 Schlammwühler in jedem Bau. Sie horten glänzende Dinge (Gold, Edelsteine, usw.) in Schatzhorten in ihren oberirdischen Bauten. Werden 16 oder mehr Monster in diesem Bau angetroffen, haben sie doppelt so viele Schätze vom gegebenen Typ Q.',
  'Die allesfressenden Schlammwühler fressen Pflanzen, Insekten und Wassertiere, aber frisches, warmblütiges Fleisch ist ihre bevorzugte Nahrung.'
);

-- Mudman (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Schlammmann',
  'Mudman',
  'Unknown',
  FALSE,
  'Any pool',
  'Very rare',
  'Pack',
  'Any',
  'Dweomer',
  'Non- (0)',
  'Nil',
  'Neutral',
  '2-12 (2d6)',
  10,
  '3',
  '2',
  2,
  19,
  '1',
  'Special',
  'Mud-throwing, suffocation',
  'See below',
  0,
  'S',
  'Special',
  10,
  175,
  'Schlammmänner entstehen in Schlammtümpeln, wo verzauberte Flüsse (selbst schwach verzauberte, wie ein Bach, der eine magische Struktur erodiert) sich sammeln und verdunsten und dabei den Zauber konzentrieren. Da sie Kreaturen der Magie sind, werden Schlammmänner manchmal Zaubergeschöpfe genannt. Schlammmänner sind unintelligente Lebenskräfte mit nur einem Ziel - ihre Tümpel gegen Eindringlinge zu schützen.',
  'In ihrem ruhenden Zustand warten Schlammmänner unter der Oberfläche des Tümpels, verteilt auf dem Grund, und nähren sich vom Zauber. In diesem Zustand sind sie immun gegen alle Waffen, sogar magische. Zauber, die normalerweise einem Schlammmann schaden würden, wirken noch auf ihn, obwohl der Schaden gleichmäßig unter allen Schlammmännern im Tümpel aufgeteilt wird (die gesamte Gruppe zählt als eine Kreatur für diese Effekte, und Bruchteile werden abgerundet). Wenn eine Kreatur den Tümpel betritt, nehmen die Schlammmänner sofort ihre Anwesenheit wahr und brauchen nur eine einzige Runde, um ihre Substanz zusammenzuziehen und an die Oberfläche zu steigen, bereit zum Angriff in der folgenden Runde. Einmal vollständig geformt und stehend, kann ein Schlammmann durch magische Waffen verletzt werden.',
  'Schlammmänner haben zwei Zustände: Ruhe und Aktivität, wobei letztere ausschließlich das Töten von Eindringlingen beinhaltet. Der Tümpel eines Schlammmanns variiert in der Größe zwischen 20 und 61 m im Durchmesser. Solche Tümpel finden sich oft in der Nähe von Wasserfällen.',
  'Schlammmänner sind keine natürlichen Kreaturen und nicht Teil des Ökosystems. Sie versuchen alle natürlichen Kreaturen zu töten, denen sie begegnen, und haben keine natürlichen Feinde. Über einen langen Zeitraum absorbieren sie Fleisch, Holz und Knochen und extrahieren jeden Zauber, den sie daraus gewinnen können, daher besitzen sie selten irgendwelche Schätze - nur wenn sie innerhalb des letzten Monats von jemandem angegriffen wurden, der Schätze bei sich trug. Obwohl keine Verwendungen für den Schlamm eines Schlammmanns verzeichnet sind, ist es logisch, dass Magier seine magischen Eigenschaften nicht ignorieren würden.'
);

-- Mummy, Greater (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Große Mumie',
  'Mummy, Greater',
  'Unknown',
  FALSE,
  'Any/Desert, Subterranean',
  'Very rare',
  'Solitary',
  'Night',
  'None',
  'Genius (17-18)',
  'V (A×2)',
  'Lawful evil',
  '1',
  2,
  '9',
  '8+3 (base)',
  8,
  11,
  '1',
  '3d6',
  'See below',
  'See below',
  0,
  'M',
  'Fanatic (17-18)',
  17,
  8,
  'Große Mumien, auch bekannt als Anhktepots Kinder, sind eine mächtige Form der Untoten, die entstehen, wenn ein hochstufiger rechtschaffen böser Priester bestimmter Religionen mumifiziert und damit beauftragt wird, eine Begräbnisstätte zu bewachen. Sie kann jahrhundertelang als standhafter Beschützer ihres Baus überleben und tötet alle, die ihre heilige Ruhestätte entweihen würden.',
  'Große Mumien strahlen eine Aura der Furcht aus, die alle Kreaturen, die sie sehen, zu einem Furchtwurf zwingt. Ein Modifikator wird auf diesen Furchtwurf angewendet, basierend auf dem Alter des Monsters, wie in der Alters- und Fähigkeitentabelle am Ende dieses Abschnitts angegeben. Die Auswirkungen des Scheiterns auf diejenigen, die ihre Würfe verfehlen, werden wegen der enormen Macht und Präsenz dieser Kreatur verdoppelt. Die Aura der Mumie kann durch Furcht bannen, Mantel der Tapferkeit oder ähnliche Zauber besiegt werden.',
  'Große Mumien sind mächtige untote Kreaturen, die normalerweise aus den mumifizierten Überresten mächtiger, böser Priester erschaffen werden. Da dies der Fall ist, bezieht die große Mumie nun ihre mystischen Fähigkeiten aus bösen Mächten und der Dunkelheit. In seltenen Fällen dienten die mumifizierten Priester jedoch einem nicht-bösen Gott zu Lebzeiten und erhalten immer noch die Kräfte, die sie zu Lebzeiten hatten, von diesen Göttern.',
  'Die erste dieser Kreaturen ist dafür bekannt, von Anhktepot, dem Herrn von Har''akir, in den Jahren produziert worden zu sein, bevor er selbst untot wurde. Es wird geglaubt, dass die meisten, wenn nicht alle großen Mumien, die er in seinem Leben erschuf, entweder zerstört oder mit ihm nach Ravenloft gezogen wurden, als ihm eine Domäne gewährt wurde. Eine Anzahl dieser Kreaturen soll Anhktepot in seiner Domäne dienen und als seine Agenten in anderen Ländern fungieren, von denen er erfahren möchte, was in anderen Teilen von Ravenloft vor sich geht.'
);

-- Myconid (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Myconid',
  'Myconid',
  'Unknown',
  FALSE,
  'Subterranean',
  'Rare',
  'Communal',
  'Day',
  'Herbivore',
  'Average (8-10)',
  'S×2',
  'Lawful neutral',
  '1-12; 20-200 in lair',
  10,
  '9',
  '1-6',
  1,
  1,
  '1',
  '1d4×HD',
  'Spore Clouds',
  'Poisonous Skin',
  0,
  'T',
  'Steady (12) to Elite (13)',
  12,
  1,
  'Myconiden oder Pilzmenschen sind eine Rasse intelligenter Pilze, die in den entlegenen Gebieten der Unterwelt leben. Sie sind vorsichtige Kreaturen, die Gewalt verabscheuen; Myconiden haben kein Verlangen, irgendjemanden zu erobern und würden es vorziehen, in Ruhe gelassen zu werden.',
  'Pilzmenschen kämpfen, indem sie mit ihren gefalteten Händen schlagen und dabei 1W4 Schadenspunkte pro Trefferwürfel verursachen. So fügt ein 1-Trefferwürfel-Myconid 1W4 Schadenspunkte zu, ein 2-Trefferwürfel-Myconid verursacht 2W4 Schadenspunkte, usw., bis hin zum 6-Trefferwürfel-König, der bei einem Treffer 6W4 Schadenspunkte zufügt.',
  'Die Gesellschaft der Myconiden basiert auf "Kreisen", extrem engen sozialen Gruppen, die durch Gemeinschaftsarbeit und Verschmelzungssitzungen verbunden sind. Myconiden-Kreise bestehen normalerweise aus 20 Mitgliedern: vier von jeder Größe von 1-5 Trefferwürfeln (d.h. vier 1-TW, vier 2-TW, usw.). Jede Gemeinschaft besteht aus 1W10 Kreisen.',
  'Myconiden sind eine ungewöhnliche Pilzart. Sie züchten Pilze, die später verfaulen, und die Myconiden ernähren sich von diesen Bodennährstoffen.'
);

-- Naga (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Naga',
  'Naga',
  'Unknown',
  FALSE,
  'Any land',
  'Very rare',
  'Solitary',
  'Day',
  'Omnivore',
  'Exceptional (16)',
  'X (H)',
  'Lawful good',
  '1-2',
  3,
  '15',
  '11-12',
  11,
  9,
  '2',
  '1-6/2-8',
  'See below',
  'Nil',
  0,
  'H',
  'Champion (15)',
  15,
  7,
  'Naga sind schlangenartige Kreaturen mit menschlichen Köpfen, die hohe Intelligenz und magische Fähigkeiten besitzen. Sie bevorzugen wärmere Klimazonen und tendieren dazu, sich nicht weit von ihren Bauen zu entfernen.',
  'Naga stellen oft Fallen auf, um Eindringlinge zu fangen. Magische Zauber werden immer zuerst versucht, da Naga nur wenige Nahkampffähigkeiten haben. Sobald ihre Magie verbraucht ist, verlassen sich Naga auf ihre giftigen Bisse – nur die größten dieser Kreaturen können Opfer tatsächlich wie eine Riesenschlange umschlingen.',
  'Naga leben ein Einzelgängerleben und jagen oder sammeln Nahrung in einem Gebiet, das normalerweise nur einen viertel Quadratkilometer umfasst. Sie bevorzugen es, in einem tiefen Loch zu wohnen, aber manchmal findet man sie zusammengerollt in Ruinen oder in einem dunklen Raum. Während die Geschlechter unmöglich zu unterscheiden sind, besteht eine 10%ige Chance, dass eine Begegnung einen oder mehrere Partner einschließt. Diese Paarungen sind temporär, da eine schwangere Naga das Männchen schnell verlässt, um ihre Eier an einem abgeschiedenen Ort zu verstecken. Junge Naga ähneln Riesenschlangen, bis sie die Geschlechtsreife erreichen; dann taucht ihr menschenähnlicher Kopf nach einer langen und schmerzhaften Häutung auf.',
  'Während Naga keine Handelsgüter produzieren, überspannen ihre Leben viele Menschengenerationen und sie bewahren eine detaillierte mündliche Geschichte, sodass sie gute Informationsquellen sind. Sie sind oft jahrhundertelang Beschützer von Schätzen oder Artefakten. Ihre Häute können zu Schuppenrüstung +2 verarbeitet werden, und ihre Augen und Zähne wurden für den Gebrauch in arkanen Zaubern verkauft.'
);

-- Nymph (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Nymphe',
  'Nymph',
  'Unknown',
  FALSE,
  'Any',
  'Very rare',
  'Solitary',
  'Day',
  'None',
  'Exceptional (15-16)',
  'Q (Q×10,X)',
  'Neutral (good)',
  '1-4',
  9,
  '12',
  '3',
  3,
  17,
  '0',
  'Nil',
  'See below',
  'See below',
  50,
  'M',
  'Unsteady (7)',
  7,
  1,
  'So schön, dass ein Blick einen Mann blenden oder sogar töten kann, sind die Nymphen die Verkörperung der Lieblichkeit, ein Triumph der Natur.',
  'Neutral in ihren Bündnissen und Sorgen kämpfen Nymphen nicht, sondern fliehen, wenn sie mit einem Eindringling oder einer Gefahr konfrontiert werden. Nymphen können einmal pro Tag Dimensionstor wirken und druidische Priesterzauber auf der 7. Stufe anwenden, was einer Nymphe vier Zauber der 1. Stufe, zwei der 2. Stufe, zwei der 3. Stufe und einen der 4. Stufe einmal pro Tag gewährt. Der Anblick einer Nymphe verursacht permanente Blindheit, es sei denn, der Betrachter besteht einen Rettungswurf gegen Zauber. Ist die Nymphe nackt oder entkleidet sich, stirbt ein Betrachter, es sei denn, ein Rettungswurf gegen Zauber gelingt.',
  'Diese schönen Weiblichen bewohnen nur die lieblichsten Orte der Wildnis: klare Seen und Bäche, Gletscherpaläste, Meeresgrotten und kristalline Höhlen. Nymphen bevorzugen ein einsames Dasein, doch sehr gelegentlich versammeln sich einige wenige an einem Ort von spektakulärer Anmut, obwohl diese Zusammenkünfte selten länger als ein paar Monate dauern. Tiere aller Arten strömen zu einer Nymphe, um gestreichelt und liebkost zu werden, vergessen ihre natürlichen Feinde und versammeln sich um die liebliche Kreatur.',
  'Wie ein Druide glaubt eine Nymphe an die Heiligkeit der Natur und ihrer Umgebung und wird versuchen, ihren Bau sicher und rein zu halten. Sie wird verwundete Tiere heilen und gebrochene Bäume und Pflanzen wiederherstellen. Manchmal hilft sie sogar einem Menschen in Not (5% Chance). Da Nymphen viele Generationen leben, können sie eine Fülle von Informationen über die Geschichte eines Gebiets liefern und kennen oft geheime Orte, Verstecke und längst vergessene Eingänge. Wird ein Mann von einer Nymphe geküsst, sind alle schmerzhaften und belastenden Erinnerungen für den Rest des Tages vergessen - dies mag für manche ein Segen und für andere ein Fluch sein. Eine Locke aus Nymphenhaar kann zur Herstellung eines mächtigen Schlaftranks verwendet werden oder, wenn sie verzaubert und in ein Tuch eingewebt und in ein Kleidungsstück eingenäht wird, fügt sie magisch einen Punkt zum Charisma des Trägers hinzu. Die Tränen einer Nymphe können als Zutat für einen Liebestrank verwendet werden. Badet eine Frau in dem Teich einer Nymphe, erhöht sich ihr Charisma um zwei Punkte, bis sie wieder badet.'
);

-- Octopus, Giant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riesenkrake',
  'Octopus, Giant',
  'Unknown',
  FALSE,
  'Any salt water',
  'Rare',
  'Solitary',
  'Night',
  'Carnivore',
  'Animal (1)',
  '(R)',
  'Neutral (evil)',
  '1-3',
  7,
  '3, Sw 12',
  '8',
  8,
  13,
  '7',
  '1-4 (×6)/2-12',
  'Constriction',
  'Ink, color change',
  0,
  'L',
  'Elite (13)',
  13,
  2,
  'Die gefürchteten "Tintenfische" sind die Geißel der Seeleute und Fischer. Bösartig und gerissen sind Riesenkraken dafür bekannt, Schiffe anzugreifen, kleinere Fahrzeuge zu versenken und Besatzungsmitglieder von größeren Schiffen zu stehlen.',
  'Ein Krake greift bereitwillig Schwimmer oder kleine Schiffe an, um die Besatzung zu fressen. Mehrere sind dafür bekannt, zusammenzuarbeiten, um ein größeres Schiff zu überwältigen, und jedes von diesen Monstern ergriffene Fahrzeug verliert an Fahrt und kommt in drei Runden vollständig zum Stillstand.',
  'Während Kraken bei der Jagd auf eine Nahrungsquelle zusammenarbeiten, leben sie ein einzelgängerisches Dasein und bevorzugen es, sich in warmem Wasser mittlerer bis geringer Tiefe aufzuhalten. Baue werden in Schiffswracks und Unterwasserhöhlen angelegt; jeder dort gefundene Schatz ist nur ein zufälliger Überrest früherer Mahlzeiten. Als vollendete Jäger haben diese Monster große Geduld und decken ein sehr kleines Gebiet ab, während sie darauf warten, dass ihre Nahrung zu ihnen kommt. Die Paarungszeit kommt jeden Frühling. Wie die meisten Meerestiere lassen Kraken ihre Eier in einem Riff zurück, damit sie für sich selbst sorgen.',
  'Wenn Beute knapp ist oder falls es verwundet wurde, wendet sich ein Krake der Aasfresserei zu und frisst alles von kleinen Krustentieren bis zu Seetang. Überleben ist bei diesem Monster von höchster Wichtigkeit. Es bevorzugt die nächtliche Jagd, und oft ist ein Mann, der während der späten Nachtwache verschwunden ist, von einem Riesenkraken gepackt, schnell über die Reling gezogen und gefressen worden.'
);

-- Phoenix (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
