-- Rat (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Ratte',
  'Rat',
  'Unknown',
  FALSE,
  'Any',
  'Common',
  'Pack',
  'Night',
  'Scavenger',
  'Animal (1)',
  'Nil',
  'Neutral',
  '1-100',
  7,
  '15',
  '¼',
  1,
  20,
  '1',
  '1',
  'Disease',
  'Nil',
  0,
  'T',
  'Unreliable (2-4)',
  2,
  7,
  'Ratten sind langschwänzige Nagetiere von 12,7-30,5 cm Länge. Sie sind aggressiv, allesfressend und anpassungsfähig, und sie tragen oft Krankheiten.',
  'Ratten fliehen normalerweise vor allem, was größer ist als sie selbst, aber eine in die Enge getriebene Ratte wird alles tun, um zu überleben, und ein Rudel hungriger Ratten wird alles angreifen, um sich zu ernähren. Ratten greifen mit ihren scharfen Vorderzähnen an und tragen oft Krankheiten, so dass ein Rattenbiss eine 5%ige Chance hat, sein Opfer mit einer schweren Krankheit zu infizieren, es sei denn, das Opfer schafft einen erfolgreichen Rettungswurf gegen Gift. Normale Ratten fürchten Feuer, aber trotzen ihm, wenn sie sehr hungrig sind.',
  'Der Hauptzweck von Ratten ist es, Nahrung zu finden. Rudel graben sich oft in Nahrungsvorräte hinein und fressen sie. Ratten nisten fast überall und zerkauen Stoff, Papier oder Holz, um ein Nest zu bauen.',
  'Ratten sind sehr fruchtbar und vermehren sich drei- bis fünfmal im Jahr. Braune Ratten bringen 2W4+6 Junge pro Wurf hervor, während ein Wurf schwarzer Ratten nur 5-6 Junge enthält. Beide Rattenarten sind allesfressend. Braune Ratten gelten als aggressiver als schwarze Ratten. Ihre Zähne sind extrem kräftig; es ist bekannt, dass sie Löcher in Bleirohre nagen. Ratten haben eine Lebensspanne von zwei bis vier Jahren.'
);

-- Rat, Osquip (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Osquip-Ratte',
  'Rat, Osquip',
  'Unknown',
  FALSE,
  'Subterranean',
  'Uncommon',
  'Pack',
  'Night',
  'Carnivore',
  'Animal (1)',
  '(D)',
  'Neutral',
  '2-24',
  7,
  '12, Br ½',
  '3+1',
  3,
  16,
  '1',
  '2-12',
  'Nil',
  'Nil',
  0,
  'S',
  'Unsteady (7)',
  7,
  120,
  'Nicht alle Monster sind furchteinflößende Drachen und Riesen. Der Osquip ist ein mehrbeiniges riesiges Nagetier, das in Verlieskorridor und Kellern heimisch ist.',
  'Der Osquip ist wild und greift furchtlos an, manchmal taucht er aus einem seiner verborgenen Tunnel auf, um einen Überraschungsangriff zu landen (-5 Abzug auf die Überraschungswürfe der Gegner, wenn er sich in seinem Tunnelkomplex befindet). Er greift mit seinen kräftigen Kiefern an, die bei einem erfolgreichen Biss 2W6 Schadenspunkte verursachen. Er hat eine hohe Geschicklichkeit (seine Haut ist RK 9). Wenn die Schlacht gegen ihn läuft, versucht er in seine Tunnel zu fliehen; wenn er in die Enge getrieben wird, benutzt er seine Zähne, um einen Fluchttunnel zu graben. Seine Zähne sind scharf genug, um sich durch Stein zu graben.',
  'Die Kreatur hat oft ihren Bau inmitten eines Komplexes von Tunneln unter den Kellern von Gebäuden oder Verliesen. Das Tunnelsystem ist ziemlich ausgedehnt und die Eingänge dazu, die zu klein sind, um einer menschlichen oder anderen menschengroßen Kreatur bequemen Durchgang zu gewähren, sind sorgfältig versteckt (die Chance sie zu finden ist dieselbe wie die Chance eine Geheimtür zu finden).',
  'Osquips ernähren sich von Ratten, Mäusen und anderen kleinen Nagetieren, manchmal sogar von anderen Osquip-Rudeln. Wie alle Nagetiere sind sie Säugetiere, mit drei bis fünf Osquips pro Wurf. Sie haben eine Lebenserwartung von neun Jahren. Osquip-Leder ist weich und gut isoliert gegen kaltes und regnerisches Wetter; es wird von Gerbern und Schneidern zur Herstellung von Geldbeuteln und Mänteln verwendet.'
);

-- Remorhaz (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Remorhaz',
  'Remorhaz',
  'Unknown',
  FALSE,
  'Arctic plain',
  'Very rare',
  'Solitary',
  'Day',
  'Carnivore',
  'Animal (1)',
  'D',
  'Neutral',
  '1',
  10,
  '12',
  '7-14',
  7,
  7,
  '1',
  'Bite:',
  'Swallow whole, heat lash',
  'Melt metal',
  75,
  'G',
  'Elite (13-14)',
  13,
  5,
  'Remorhaz, manchmal auch als Polarwürmer bekannt, bewohnen nur eisige arktische Ödländer. Sie sind sehr aggressive Raubtiere, die jede Art von tierischer Materie verschlingen, einschließlich Menschen, Halbmenschen und Humanoiden; es ist sogar bekannt, dass sie Frostriesen angreifen.',
  'Im Kampf schlägt der Remorhaz mit seinen kleinen Flügeln und richtet das vordere Viertel seines Körpers auf. Dann schnellt er sich vor und stößt mit blendender Geschwindigkeit zu. Sie können Beute bei einem unmodifizierten Angriffswurf von 20 ganz verschlingen; jedes verschlungene Opfer wird durch die intensive Hitze im Inneren des Wesens sofort getötet. Wenn erregt, sondert der Remorhaz eine Substanz ab, die bewirkt, dass seine Eingeweide sehr heiß werden und seine Rückenauswüchse tatsächlich kirschrot vor überschüssiger Hitze glühen. Jede nichtmagische Waffe schmilzt durch Berührung mit seinem Rücken und jedes Wesen, das von diesen Oberflächen berührt wird, erleidet 10-100 Schadenspunkte.',
  'Ein Remorhaz-Bau besteht gewöhnlich aus einer Anzahl großer, glatt gerundeter Tunnel in Eis und Schnee oder Gestein, die allmählich zu einer großen zentralen Kammer hinabführen. Tunnel in Eis und Schnee werden sehr rutschig sein, da der heiße Rücken des Remorhaz wiederholt den Schnee schmilzt und ihn wieder gefrieren lässt. Die zentrale Kammer ist nur etwa doppelt so groß wie ein Remorhaz, während die zentrale Kammer eines nistenden Paares etwa viermal so groß ist und eisige Stalaktiten enthalten kann.',
  'Remorhaz sind Fleischfresser, die sich von einer Ernährung aus Hirschen, Elchen und sogar Eisbären ernähren. Sie paaren sich im Spätsommer und bleiben zwei Monate zusammen, bevor sie aufbrechen, um ein einsames Dasein zu führen. Remorhaz paaren sich jedes Jahr, können aber nur drei- oder viermal in ihrem Leben Nachkommen hervorbringen; das Weibchen legt ein Gelege von ein oder zwei graublau gefärbten Eiern und bleibt ständig bei den Eiern, rollt sich um sie, um sie warm zu halten; wenn die Eier auch nur eine Minute in der eisigen Kälte gelassen werden, schlüpfen sie nie. Junge Remorhaz haben bei der Geburt 1 Trefferwürfel und wachsen nach vier Monaten auf 7 Trefferwürfel an, wenn sie das Nest verlassen. Unreife Remorhaz haben schwächere Rüstung (+2 RK an allen Stellen); 1-3 Trefferwürfel-Remorhaz können nur beißen und verursachen 2-12 Schadenspunkte, während 4-6 Trefferwürfel-Wesen 3-18 Schadenspunkte verursachen. Von Geburt an haben die jungen Remorhaz alle Kräfte eines Erwachsenen.'
);

-- Sea Lion (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Seelöwe',
  'Sea Lion',
  'Unknown',
  FALSE,
  'Coastal marine',
  'Uncommon',
  'Packs',
  'Day',
  'Carnivore',
  'Semi- (2-4)',
  'B',
  'Neutral',
  '3-12',
  5,
  'Sw 18',
  '6',
  6,
  15,
  '3',
  '1-6/1-6/2-12',
  'Mauling',
  'Nil',
  0,
  'L',
  'Steady (12)',
  12,
  420,
  'Ein Seelöwe ist eine furchteinflößende Kreatur mit dem Kopf und den Vorderpfoten eines Löwen und dem Körper und Schwanz eines Fisches.',
  'Seelöwen sind wild und schwer zu bewältigen. Sie sind sehr territorial und greifen normalerweise alles an, was in ihr Revier eindringt, ungeachtet der Größe. Ihre bösartigen Zähne und gewaltigen Pfoten können es sogar mit den meisten Haien aufnehmen, die sie über alle anderen Kreaturen hassen. Seelöwen müssen denselben Gegner mit Pfoten und Zähnen angreifen und können ihre Attacken nicht aufteilen. Jede Kreatur, die von beiden Pfotenangiffen in derselben Runde getroffen wird, wird zerfleischt. Zerfleischte Kreaturen können nicht angreifen, falls sie dies in dieser Runde noch nicht getan haben, und müssen einen erfolgreichen Wurf zum Öffnen von Türen schaffen, um sich zu befreien. Beim Zerfleischen einer Kreatur folgt der Löwe mit einem Bissangriff mit einem +4 Bonus auf den Angriffswurf, der bei Erfolg doppelten Schaden verursacht.',
  'Seepferde und Seelöwen begegnen sich fast nie, da Seelöwen es vorziehen, in den flachen Küstenregionen zu leben, während Seepferde die Tiefen erkunden. Dies liegt hauptsächlich an ihren unterschiedlichen Ernährungsgewohnheiten. Seepferde fressen Plankton, während Seelöwen jede Art von Fleisch fressen, sei es ein Fisch, Dinosaurier oder wandernde Herdentiere, die am Wasserrand beim Trinken erwischt werden. Seelöwen haben keine Angst vor dem Land und es ist nicht ungewöhnlich, dass sich Seelöwen einige Dutzend Meter den Strand hinauf ziehen, um nach Mahlzeiten zu suchen. Obwohl diese Angriffe sehr selten sind, neigen Berichte über Seelöwen in der Nähe dazu, mehr Furcht in der allgemeinen Bevölkerung zu schüren als ein einfacher Haiangriff. Aber in einer Welt voller Kraken, Dinosaurier und Vampire sind Seelöwen eine relativ geringe Bedrohung.',
  'Seelöwen hassen Haie und unternehmen oft große Anstrengungen, sie zu jagen. Der Geschmack von Haien ist für Seelöwen anscheinend abscheulich und sie lassen den Kadaver immer ungefressen zurück, sodass es etwas rätselhaft ist, warum diese Rivalität existiert. Einige Gelehrte behaupten, dass es das Ergebnis von Konflikten zwischen den niederen Gottheiten der Natur ist, aber wahrscheinlicher ist es, dass zwei starke Raubtiere um die Vorherrschaft der Meere wetteifern.'
);

-- Selkie (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Selkie',
  'Selkie',
  'Unknown',
  FALSE,
  'Cold to subarctic waters',
  'Very rare',
  'Solitary or tribal',
  'Any',
  'Omnivore',
  'Average to exceptional (8-16)',
  'A (magic only), R',
  'Neutral (good)',
  '1 or 12-30',
  5,
  '12, Sw 36',
  '3+3',
  3,
  17,
  '1',
  '1-6 or by weapon type',
  'Nil',
  'Can change into human form',
  0,
  'M',
  'Steady (11-12)',
  11,
  175,
  'Selkies sind robbenartige Wesen, die die Fähigkeit besitzen, sich für jeweils einige Tage in Menschengestalt zu verwandeln.',
  'Da Selkies nicht schnell schwimmen können, während sie Waffen tragen, werden 90% der unter Wasser angetroffenen Selkies unbewaffnet sein. Sie verwenden ihre scharfen Zähne, wann immer sie in die Enge getrieben werden, bevorzugen aber ihre beeindruckende Geschwindigkeit unter Wasser zu nutzen, um überlegenen Gegnern zu entkommen. Falls sie an Land angetroffen werden, sind Selkies klug genug, menschliche Waffen zu tragen, höchstwahrscheinlich Schwerter, die sie aus Schiffswracks geborgen haben.',
  'Selkie-Gemeinschaften sind zwischen Männchen und Weibchen aufgeteilt, wobei die Weibchen gewöhnlich die Männchen übertreffen, da männliche Selkies die Jäger und Sammler in den oft gefährlichen Gewässern der Umgebung sind. Jedoch werden beide Aspekte der Selkie-"Gemeinschaft" (häuslich und versorgend) im Bau gleichermaßen respektiert, und keinem Geschlecht werden ungebührende Privilegien zugestanden.',
  'Selkies sind Allesfresser und bevorzugen Fische, Schalentiere, Krustentiere und verschiedene Arten von Seetang. Diejenigen, die die Oberfläche besucht haben, haben oft auch eine Vorliebe für menschliche Kost entwickelt. Selkies sind besonders anfällig für feinen Wein, was zu erwarten ist, da diese Rauschmittel unter den Meeren unbekannt sind.'
);

-- Skeleton, Giant (new)
