  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Sphinx',
  'Sphinx',
  'Unknown',
  FALSE,
  'Warm lands',
  'Very rare',
  'Solitary',
  'Day',
  'Carnivore',
  'Exceptional (15-16)',
  'U',
  'Chaotic good',
  '1',
  -2,
  '18, Fl 30 (D)',
  '12',
  12,
  9,
  '2',
  '2-12/2-12',
  'See below',
  'Nil',
  0,
  'L',
  'Fanatic (17)',
  17,
  7,
  'Androsphinxe sind riesige, geflügelte mythologische Kreaturen mit den Körpern männlicher Löwen und menschenähnlichen Gesichtszügen. Sie können die Sprachen der Gemeinen und aller Sphinxe sprechen.',
  'Die männliche oder Andro-Sphinx ist die mächtigste aller Sphinxe. Ihre riesigen Pranken können einen normalen Menschen mit nur einem Schlag töten. Wenn rohe Gewalt nicht erfolgreich ist, kann eine Androsphinx Zauber wie ein Priester der 6. Stufe wirken. Beachte, dass die meisten Androsphinxe diese Zauber eher zur Heilung und Verteidigung als für Schäden und Angriffe verwenden.',
  'Androsphinxe sind die einsamsten aller Sphinxe. Sie meiden Gynosphinxe, weil sie neidisch auf die höhere Intelligenz ihrer weiblichen Gegenstücke sind und ihre neutrale Veranlagung etwas schwer zu handhaben finden. Jedoch erliegen die meisten Androsphinxe schließlich mindestens einmal in ihrem Leben den Annäherungsversuchen einer Gynosphinx.',
  'Was am seltsamsten an Androsphinxen ist, ist nicht ihr kombiniertes Löwen-/Menschenaussehen (da es viele solche Kreuzungsmutationen in der Welt gibt), sondern ihr offensichtlicher Mangel an Zweck. Sie sind bei weitem die stärksten der Sphinxe, aber im Gegensatz zu ihren Gegenstücken haben sie kein wahres Verhaltensmuster, das allen Androsphinxen gemein ist. Sie verachten die Kommunikation mit Menschen und hassen Rätsel (hauptsächlich weil Gynosphinxe sie so sehr lieben). Es wird daher von jenen vorgeschlagen, die sich mit mythologischen Bestien und Wüstenkunde auskennen, dass Androsphinxe die Wächter der Sphinxe sind, böse (Hierako-), neutrale (Gyno- und Krio-) und gute (Andro-).'
);

-- Squid, Giant (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Riesenkalmar',
  'Squid, Giant',
  'Unknown',
  FALSE,
  'Any deep waters',
  'Rare',
  'Solitary',
  'Any',
  'Carnivore',
  'Non- (0)',
  'A',
  'Neutral',
  '1',
  7,
  'Sw 3, Jet 18',
  '12',
  12,
  9,
  '9',
  '1-6 (×8)/5-20',
  'Constriction',
  'See below',
  0,
  'G',
  'Elite (13)',
  13,
  5,
  'Riesenkalmare sind riesige Varianten der normalen, friedlichen, mit Tentakeln ausgestatteten Kopffüßer (schalenlose Wirbellose).',
  'Riesenkalmare greifen ihre Gegner bevorzugt mit ihren Tentakeln und umklammern sie, während sie die zappelnden Opfer in ihre gewaltigen Kiefer bringen. Bis zu acht Tentakel können einen Gegner angreifen, aber nur einer zur Zeit kann einen menschengroßen Gegner umklammern (die restlichen sind frei, alles andere in Reichweite anzugreifen). Die gummiartigen Tentakel sind so stark, dass sie nicht durch Gewalt gebrochen werden können und durchtrennt werden müssen. Die Tentakel eines Riesenkalmars treffen für 1W6 Schadenspunkte und umklammern für 2W6 Schadenspunkte jede Runde nach dem ursprünglichen Treffer. Der Schnabel eines Riesenkalmars verursacht 5W4 Schadenspunkte.',
  'Kraken haben eine Intelligenz von genial oder höher und kontrollieren oft ganze Regionen der Unterwasserwelt. Ihre Verstecke liegen Tausende von Fuß unter der Oberfläche und sie unterhalten riesige Höhlenkomplexe, wo sie menschliche Sklaven halten und züchten, um ihnen zu dienen und sie zu ernähren.',
  'Kraken können sowohl Luft als auch Wasser atmen und sind aggressive Jäger. Viele tropische Inseln wurden von Kraken vollständig von allen Bewohnern (Tieren und Menschen) befreit.'
);

-- Swanmay (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Schwanenjungfer',
  'Swanmay',
  'Unknown',
  FALSE,
  'Temperate wetlands',
  'Very rare',
  'Flock',
  'Any',
  'Omnivore',
  'Highly to Genius (13-18)',
  'See below',
  'As ranger',
  '1 or 2-5',
  7,
  '3 or 15, Fl 19 (D)',
  '2 to 12',
  2,
  20,
  'As swan or ranger',
  'As swan or by weapon',
  'See below',
  '+1 or better weapon to hit',
  2,
  'M',
  'Champion (15)',
  15,
  120,
  'Schwanenjungfern sind menschliche Frauen, die Schwanengestalt annehmen können. In menschlicher Form sind Schwanenjungfern von anderen Menschen nicht zu unterscheiden. Sie tragen normalerweise leichte Rüstung und führen Waldläufer-Ausrüstung mit sich, sowie ein Schwert, einen Dolch, einen Bogen und Pfeile. Diese Gegenstände sind von der Gestaltwandlung einer Schwanenjungfer unberührt, daher müssen sie versteckt werden. Schwanenjungfern können an einem Federzeichen, einem gefiederten Kleidungsstück oder einem Siegelring erkannt werden. Solche Gegenstände werden zu einem Teil des Gefieders der Schwäne oder werden am Bein getragen.',
  'In menschlicher Form funktioniert die Schwanenjungfer als Waldläufer. Um die Stufe und Trefferwürfel einer Schwanenjungfer zu bestimmen, werden 2W6 gewürfelt. Sie greift mit allen Waffen an, die sie besitzt.',
  'Schwanenjungfern sind Mitglieder einer besonderen Schwesternschaft von lykanthropischen Waldläufern. Anders als andere Lykanthropen erhalten sie ihre Gestaltwandlungsfähigkeit freiwillig durch einen besonderen Gegenstand: ein Federzeichen, ein Federkleidungsstück oder einen Siegelring. Solche Gegenstände offenbaren ihre magischen Auren, wenn sie einem Magie entdecken-Zauber ausgesetzt werden. Ohne den Gegenstand ist sie gezwungen, in ihrer aktuellen Form zu verharren. Die Zeichen funktionieren nur für Schwanenjungfern.',
  'Schwanenjungfern sind unabhängige Beschützerinnen der Wälder und Wildtiere. Sie widersetzen sich aktiv bösen Völkern oder Monstern, die sonst die Tierwelt und die Landschaft dezimieren könnten. Sie beschützen Schwäne mehr aus Sympathie für ihre Ähnlichkeit als aus irgendeiner Verwandtschaft.'
);

-- Tabaxi (new)
INSERT INTO monsters (
  name, name_en, source_book, is_custom,
  climate_terrain, frequency, organization, activity_cycle, diet,
  intelligence, treasure, alignment, no_appearing,
  ac, movement, hit_dice, hit_dice_value, thac0, attacks_per_round, damage,
  special_attacks, special_defenses, magic_resistance, size, morale, morale_value, xp_value,
  intro_text, combat_tactics, habitat_society, ecology
) VALUES (
  'Tabaxi',
  'Tabaxi',
  'Unknown',
  FALSE,
  'Tropical or subtropical jungle',
  'Rare',
  'Clan',
  'Any',
  'Carnivore',
  'Average to High (8-14)',
  'U',
  'Chaotic neutral',
  '2-8',
  6,
  '15',
  '2',
  2,
  19,
  '3',
  '1-3/1-3/1-3 or by weapon',
  'Rear claw rake for 1d4+1/1d4+1',
  'Surprise, surprised only on a 1',
  0,
  'M',
  'Steady (11-12)',
  11,
  420,
  'Tabaxi haben gefleckte Felle, deren Farbe von hellem Gelb bis zu bräunlichem Rot reicht. Diese anmutigen katzenartigen Humanoiden sind groß und schlank, mit einziehbaren Krallen und grünen oder gelben Augen.',
  'Tabaxi sind große Jäger, die schnelle, verstohlen Bewegungen mit natürlicher Tarnung kombinieren, um Beute zu überraschen. Feinde erleiden einen Malus von -2 auf Überraschungswürfe. Tabaxi sind klug und organisiert, treiben oft Beute in einen Hinterhalt (obwohl manche mit ihrer Beute spielen, bevor sie sie töten). Tabaxi können klettern und schwimmen und diese Fähigkeiten im Kampf einsetzen. Aufgrund ihrer Klugheit und ihres scharfen Geruchssinns sind Tabaxi fast unmöglich zu fangen.',
  'Tabaxi-Klans enthalten gleich viele Männchen und Weibchen, und ein vollständiger Klan hat 1W6+1 Jagdgruppen zu je 2W4 Tabaxi. Die Jagdgruppen bearbeiten das Gebiet um den Klanbau. Manche Baue sind vorübergehend, aber die meisten sind kleine Dörfer aus Ramadas (Hütten mit Grasdächern, die von hohen Pfählen gestützt werden und keine Wände haben). In einem Bau werden 3W4 Junge mit je 1 TW angetroffen. Ein Ältester mit 4 TW führt den Klan, und 50% der Anführer werden von einem Schamanen der 5. Stufe unterstützt. Ein Klan hat eine 10%ige Chance, einem Tabaxi-Lord Treue zu schulden; diese Klans neigen zu bösen, kriegerischen Wegen, und ihre Schamanen verehren böse Mächte. Schamanen anderer Klans verehren Mächte, die mit Sonnenlicht, Regen oder Tieren in Verbindung stehen.',
  'Tabaxi haben wenige natürliche Feinde. Als Nahrung bevorzugen sie die schweineähnlichen Pekaris und riesige Nagetiere namens Capybaras; nur ein sehr degenerierter Klan greift Mitglieder einer anderen intelligenten Spezies als Nahrung an. Tabaxi werden manchmal wegen ihrer Felle gejagt, die bis zu 250 GM wert sind. Ihre Häute und Krallen sind auch in manchen Arten natürlicher Magie nützlich.'
);

